class SingleParquetBatches(IterableDataset):
    """
    Stream batches from one Parquet file.
    Supports row-group based train/val/test splitting (approx by rows).
    """
    def __init__(
        self,
        parquet_file: str,
        feature_names: list[str],
        target_col: str = "y",
        batch_size: int = 64,
        shuffle_row_groups: bool = True,
        drop_last: bool = False,
        seed: int | None = 42,
        allowed_row_groups: list[int] | None = None,
        rows_hint: int | None = None,
    ):
        super().__init__()
        self.parquet_file = parquet_file
        self.feature_names = feature_names
        self.target_col = target_col
        self.batch_size = int(batch_size)
        self.shuffle_row_groups = shuffle_row_groups
        self.drop_last = drop_last
        self.seed = seed
        self.allowed_row_groups = allowed_row_groups  # subset for split
        self._num_rows = rows_hint
        self._num_batches = None
        self._rg_row_counts = None  # cached list of row counts per row group

    def _scan_row_groups(self):
        import pyarrow.parquet as pq
        pf = pq.ParquetFile(self.parquet_file)
        rg_counts = [pf.metadata.row_group(i).num_rows for i in range(pf.num_row_groups)]
        return pf, rg_counts

    def _ensure_row_count(self):
        if self._num_rows is not None and self._rg_row_counts is not None:
            return
        pf, rg_counts = self._scan_row_groups()
        if self.allowed_row_groups is not None:
            total = sum(rg_counts[i] for i in self.allowed_row_groups)
        else:
            total = sum(rg_counts)
        self._num_rows = total
        self._rg_row_counts = rg_counts

    def __len__(self):
        self._ensure_row_count()
        if self._num_rows == 0:
            return 0
        full = self._num_rows // self.batch_size
        if not self.drop_last and (self._num_rows % self.batch_size):
            full += 1
        self._num_batches = full
        return full

    def __iter__(self):
        import pyarrow.parquet as pq, numpy as np, torch, random
        if self.seed is not None:
            random.seed(self.seed)
        pf = pq.ParquetFile(self.parquet_file)

        # Establish row group list
        if self.allowed_row_groups is not None:
            rg_indices = list(self.allowed_row_groups)
        else:
            rg_indices = list(range(pf.num_row_groups))
        if self.shuffle_row_groups:
            random.shuffle(rg_indices)

        pending_X = []
        pending_y = []

        def emit_full():
            nonlocal pending_X, pending_y
            if not pending_X:
                return
            Xc = np.concatenate(pending_X, axis=0)
            yc = np.concatenate(pending_y, axis=0)
            bs = self.batch_size
            n_full = (Xc.shape[0] // bs) * bs
            for i in range(0, n_full, bs):
                yield torch.from_numpy(Xc[i:i+bs]), torch.from_numpy(yc[i:i+bs])
            rem_n = Xc.shape[0] - n_full
            if rem_n > 0:
                pending_X = [Xc[n_full:]]
                pending_y = [yc[n_full:]]
            else:
                pending_X = []
                pending_y = []

        for rg in rg_indices:
            tbl = pf.read_row_group(rg, columns=self.feature_names + [self.target_col])
            cols = [
                tbl.column(name).to_numpy(zero_copy_only=False).astype(np.float32, copy=False)
                for name in self.feature_names
            ]
            X_rg = np.column_stack(cols)
            y_rg = tbl.column(self.target_col).to_numpy(zero_copy_only=False).astype(np.float32, copy=False)
            if y_rg.ndim == 1:
                y_rg = y_rg.reshape(-1, 1)
            pending_X.append(X_rg)
            pending_y.append(y_rg)
            for out in emit_full():
                yield out

        # leftovers
        if pending_X and (not self.drop_last):
            Xc = np.concatenate(pending_X, axis=0)
            yc = np.concatenate(pending_y, axis=0)
            if Xc.shape[0]:
                yield torch.from_numpy(Xc), torch.from_numpy(yc)

    @staticmethod
    def make_splits(
        parquet_file: str,
        feature_names: list[str],
        target_col: str,
        batch_size: int,
        val_ratio: float,
        test_ratio: float,
        shuffle: bool,
        seed: int,
        drop_last: bool = False
    ):
        """
        Create train/val/test SingleParquetBatches by assigning whole row groups.
        Returns (train_ds, val_ds, test_ds, meta_dict)
        meta_dict: {'train_batches': int, ...}
        """
        import pyarrow.parquet as pq, random, math
        pf = pq.ParquetFile(parquet_file)
        rg_counts = [pf.metadata.row_group(i).num_rows for i in range(pf.num_row_groups)]
        rg_indices = list(range(len(rg_counts)))
        if shuffle:
            rnd = random.Random(seed)
            rnd.shuffle(rg_indices)

        total_rows = sum(rg_counts)
        val_target = int(total_rows * val_ratio)
        test_target = int(total_rows * test_ratio)

        # Greedy fill sets by row counts
        train_set, val_set, test_set = [], [], []
        val_rows = test_rows = 0

        for rg in rg_indices:
            if test_rows < test_target:
                test_set.append(rg)
                test_rows += rg_counts[rg]
            elif val_rows < val_target:
                val_set.append(rg)
                val_rows += rg_counts[rg]
            else:
                train_set.append(rg)

        # Fallback if any empty
        if not train_set:  # put largest group to train
            if val_set:
                train_set.append(val_set.pop())
            elif test_set:
                train_set.append(test_set.pop())

        def mk(indices):
            return SingleParquetBatches(
                parquet_file=parquet_file,
                feature_names=feature_names,
                target_col=target_col,
                batch_size=batch_size,
                shuffle_row_groups=shuffle,
                drop_last=drop_last,
                seed=seed,
                allowed_row_groups=indices
            )

        train_ds = mk(train_set)
        val_ds = mk(val_set) if val_set else None
        test_ds = mk(test_set) if test_set else None

        # Pre-compute lengths
        train_len = len(train_ds)
        val_len = len(val_ds) if val_ds else 0
        test_len = len(test_ds) if test_ds else 0

        return train_ds, val_ds, test_ds, {
            "train_batches": train_len,
            "val_batches": val_len,
            "test_batches": test_len
        }


class ParquetMonthBatches(IterableDataset):
    def __init__(
        self,
        parquet_root: str,
        feature_names: list[str],
        target_col: str = "y",
        batch_size: int = 64,
        month_keys: list[tuple[int, int]] | None = None,   # subset of months (year, month)
        shuffle_months: bool = True,
        shuffle_within_month: bool = True,
        drop_last: bool = False,
        seed: int | None = 42,
        pa_threads: int | None = None,         
        buffer_batches: int = 64,  # << NEW: control Arrow thread pool
        length_mode: str = "metadata",   # "metadata" | "none"
        rows_hint: int | None = None      # manually specify total rows to skip scan
    ):
        super().__init__()
        self.root = parquet_root.rstrip(os.sep)
        self.feature_names = feature_names
        self.target_col = target_col
        self.batch_size = batch_size
        self.shuffle_months = shuffle_months
        self.shuffle_within_month = shuffle_within_month
        self.drop_last = drop_last
        self.seed = seed
        self.buffer_batches = buffer_batches
        self.length_mode = length_mode
        self.rows_hint = rows_hint
        self._length_batches = None  # cache

        if pa_threads is not None:
            pa.set_cpu_count(int(pa_threads))
            print(f"🔧 PyArrow threads set to {pa.cpu_count()}")
        # If user did not set, do not override global default each instantiation

        if month_keys is None:
            month_keys = []
            for ydir in sorted(glob(f"{self.root}/year=*")):
                y = int(os.path.basename(ydir).split("=")[1])
                for mdir in sorted(glob(os.path.join(ydir, "month=*"))):
                    m = int(os.path.basename(mdir).split("=")[1])
                    month_keys.append((y, m))
        self.month_keys = month_keys

    # --- Arrow-based full-month load to pandas (used by row-split path) ---
    def _load_month_df(self, year: int, month: int, columns=None) -> pd.DataFrame:
        """Use PyArrow Dataset to read a single month to pandas."""
        month_dir = os.path.join(self.root, f"year={int(year)}", f"month={int(month):02d}")
        dataset = ds.dataset(month_dir, format="parquet")
        table = dataset.to_table(columns=columns, use_threads=True)
        if table.num_rows == 0:
            return pd.DataFrame(columns=columns or [])
        return table.to_pandas(types_mapper=pd.ArrowDtype)

    
    def _iter_month_in_batches(self, year: int, month: int, columns):
        import pyarrow.dataset as ds
        import numpy as np, torch, math, random
        from collections import deque

        month_dir = os.path.join(self.root, f"year={int(year)}", f"month={int(month):02d}")
        # Slightly larger Arrow batch helps amortize IO; tune 32k–256k
        scanner = ds.dataset(month_dir, format="parquet").scanner(
            columns=columns, use_threads=True, batch_size=self.batch_size * 16
        )

        bs = self.batch_size
        max_cached_rows = bs * max(2, int(self.buffer_batches))  # use your buffer_batches
        # Deques avoid repeated full concatenations; we track total rows separately
        X_chunks, y_chunks = deque(), deque()
        cached_rows = 0

        feat = self.feature_names
        tgt  = self.target_col

        def _emit_from_cache():
            nonlocal X_chunks, y_chunks, cached_rows
            # Concatenate just enough to fill one big block, then slice into fixed batches
            if cached_rows < bs:
                return
            X_cat = np.concatenate(list(X_chunks), axis=0)
            y_cat = np.concatenate(list(y_chunks), axis=0)
            n_full = (X_cat.shape[0] // bs) * bs
            if n_full == 0:
                return
            # yield in-place slices to avoid extra copies
            for i in range(0, n_full, bs):
                yield torch.from_numpy(X_cat[i:i+bs]), torch.from_numpy(y_cat[i:i+bs])
            # keep leftovers without re-concat storms
            rem = X_cat[n_full:]
            rem_y = y_cat[n_full:]
            X_chunks.clear(); y_chunks.clear()
            if rem.shape[0] > 0:
                X_chunks.append(rem); y_chunks.append(rem_y)
                cached_rows = rem.shape[0]
            else:
                cached_rows = 0

        for rb in scanner.to_batches():  # each is a RecordBatch (zero-copy Arrow arrays)
            if rb.num_rows == 0:
                continue

            # Arrow→NumPy (zero/low-copy). Ensure storage dtype is float32 to stay zero-copy.
            # Build features matrix column-wise
            cols = []
            for name in feat:
                arr = rb.column(name)                 # Arrow Array
                # combine_chunks() is not needed on RecordBatch; ensure numeric dtypes upfront in ETL
                col_np = arr.to_numpy(zero_copy_only=False)  # may reuse buffer
                cols.append(col_np.astype(np.float32, copy=False))
            X_np = np.column_stack(cols)

            y_np = rb.column(tgt).to_numpy(zero_copy_only=False).astype(np.float32, copy=False).reshape(-1, 1)

            # Optional per-batch shuffle via index (cheap and cache-friendly)
            if self.shuffle_within_month:
                idx = np.arange(rb.num_rows)
                # fast RNG without Python loop
                rng = np.random.default_rng(random.randint(0, 10_000))
                rng.shuffle(idx)
                X_np = X_np[idx]
                y_np = y_np[idx]

            X_chunks.append(X_np); y_chunks.append(y_np)
            cached_rows += rb.num_rows

            # Emit when cache exceeds threshold to amortize concatenations
            if cached_rows >= max_cached_rows:
                yield from _emit_from_cache()

        # Flush leftovers
        if not self.drop_last and cached_rows > 0:
            # Emit whatever remains (one last concat)
            X_cat = np.concatenate(list(X_chunks), axis=0)
            y_cat = np.concatenate(list(y_chunks), axis=0)
            yield torch.from_numpy(X_cat), torch.from_numpy(y_cat)

    
    # --- Arrow streaming in fixed-size torch batches (fast & memory-light) ---
    def _iter_month_in_batches_v1(self, year: int, month: int, columns):
        month_dir = os.path.join(self.root, f"year={int(year)}", f"month={int(month):02d}")
        scanner = ds.dataset(month_dir, format="parquet").scanner(columns=columns, use_threads=True)

        # Accumulators to stitch Arrow record batches into uniform batch_size tensors
        X_buf = []
        y_buf = []

        for batch in scanner.to_batches():
            df = batch.to_pandas()  # pandas chunk
            if df.empty:
                continue

            # Optional per-chunk shuffle (cheap and good-enough randomness)
            if self.shuffle_within_month:
                df = df.sample(frac=1.0, random_state=random.randint(0, 10_000))

            X_buf.append(df[self.feature_names].to_numpy(dtype=np.float32, copy=False))
            y_buf.append(df[self.target_col].to_numpy(dtype=np.float32, copy=False).reshape(-1, 1))

            # Emit fixed-size batches as buffer grows
            X_cat = np.concatenate(X_buf, axis=0)
            y_cat = np.concatenate(y_buf, axis=0)
            bs = self.batch_size
            n = (X_cat.shape[0] // bs) * bs
            i = 0
            while i < n:
                yield torch.from_numpy(X_cat[i:i+bs]), torch.from_numpy(y_cat[i:i+bs])
                i += bs

            # Keep leftover
            if i > 0:
                X_buf = [X_cat[i:]]
                y_buf = [y_cat[i:]]

        # Flush leftovers
        if X_buf:
            X_cat = np.concatenate(X_buf, axis=0)
            y_cat = np.concatenate(y_buf, axis=0)
            if not self.drop_last and len(X_cat):
                yield torch.from_numpy(X_cat), torch.from_numpy(y_cat)

    
    def __iter__(self):
        if self.seed is not None:
            random.seed(self.seed)

        # Worker-aware sharding
        try:
            from torch.utils.data import get_worker_info
            wi = get_worker_info()
        except Exception:
            wi = None

        keys = self.month_keys[:]
        if self.shuffle_months:
            random.shuffle(keys)

        if wi is not None:
            # partition months across workers: worker i takes keys[i::num_workers]
            keys = keys[wi.id::wi.num_workers]

        cols = self.feature_names + [self.target_col]
        for (yr, mo) in keys:
            yielded = False
            for xb, yb in self._iter_month_in_batches(yr, mo, columns=cols):
                yielded = True
                yield xb, yb
            if not yielded:
                continue
    
    def __iter__v1(self):
        if self.seed is not None:
            random.seed(self.seed)

        keys = self.month_keys[:]
        if self.shuffle_months:
            random.shuffle(keys)

        cols = self.feature_names + [self.target_col]
        for (yr, mo) in keys:
            # Stream this month in Arrow record-batches; no full-month pandas materialization
            yielded = False
            for xb, yb in self._iter_month_in_batches(yr, mo, columns=cols):
                yielded = True
                yield xb, yb
            # If month had no data, skip quietly
            if not yielded:
                continue

    @staticmethod
    def get_optimal_dask_config(max_ram_per_worker_gb=2):
        """
        Auto-configure optimal Dask worker/thread settings based on available system resources.

        Args:
            max_ram_per_worker_gb (int): Approx. RAM (in GB) to assign per worker.

        Returns:
            dict: {'n_workers': int, 'threads_per_worker': int}
        """
        total_cores = os.cpu_count()
        total_ram_gb = psutil.virtual_memory().total / 1e9

        # Estimate number of workers based on RAM
        n_workers_by_ram = int(total_ram_gb // max_ram_per_worker_gb)
        n_workers = min(total_cores, max(1, n_workers_by_ram))

        # Use at least 1 thread per worker; divide evenly
        threads_per_worker = max(1, total_cores // n_workers)

        print(f"🔧 Optimal config: {n_workers} workers, {threads_per_worker} threads each")

        return {
            "n_workers": n_workers,
            "threads_per_worker": threads_per_worker
        }
    
    
    def _scan_total_rows(self) -> int:
        import os, pyarrow.parquet as pq
        total = 0
        for (y, m) in self.month_keys:
            mdir = os.path.join(self.root, f"year={int(y)}", f"month={int(m):02d}")
            if not os.path.isdir(mdir):
                continue
            for fp in glob(os.path.join(mdir, "*.parquet")):
                try:
                    pf = pq.ParquetFile(fp)
                    total += sum(pf.metadata.row_group(i).num_rows for i in range(pf.num_row_groups))
                except Exception:
                    pass
        return total
    
    def __len__(self):
        """
        Needed for Accelerate / DataLoader length queries.
        Uses lightweight metadata scan (no row data read).
        """
        if self._length_batches is not None:
            return self._length_batches
        if self.length_mode == "none":
            # Fallback: pretend unknown, return 0 (Accelerate expects int; 0 will skip progress based on length)
            self._length_batches = 0
            return 0
        if self.rows_hint is not None:
            total_rows = int(self.rows_hint)
        else:
            total_rows = self._scan_total_rows()
        if total_rows == 0:
            self._length_batches = 0
            return 0
        full_batches = total_rows // self.batch_size
        if (not self.drop_last) and (total_rows % self.batch_size):
            full_batches += 1
        self._length_batches = full_batches
        return full_batches
    
    @staticmethod
    def make_parquet_loaders(
        parquet_root: str,
        feature_names: list[str],
        target_col: str = "y",
        batch_size: int = 64,
        split: bool = True,
        split_strategy: str = "month",  # "month" or "row"
        val_ratio: float = 0.1,
        test_ratio: float = 0.1,
        shuffle_months: bool = True,
        shuffle_within_month: bool = True,
        drop_last: bool = False,
        seed: int = 42,
        num_workers: int = 8,
        pin_memory: bool = True,
        return_batch_counts: bool = True
    ):
        """
        Returns:
        - if split=True: (train_loader, val_loader, test_loader)
        - else:          (train_loader, )
        """

        # discover all months
        month_keys_all = []
        for ydir in sorted(glob(f"{parquet_root.rstrip(os.sep)}/year=*")):
            y = int(os.path.basename(ydir).split("=")[1])
            for mdir in sorted(glob(os.path.join(ydir, "month=*"))):
                m = int(os.path.basename(mdir).split("=")[1])
                month_keys_all.append((y, m))
                
        def _estimate_batches(keys_subset):
            import math
            import pyarrow.dataset as ds
            total_rows = 0
            for (yr, mo) in keys_subset:
                month_dir = os.path.join(parquet_root.rstrip(os.sep), f"year={int(yr)}", f"month={int(mo):02d}")
                if not os.path.isdir(month_dir):
                    continue
                try:
                    dataset = ds.dataset(month_dir, format="parquet")
                    total_rows += dataset.count_rows()
                except Exception:
                    continue
            if total_rows == 0:
                return 0
            return int(math.ceil(total_rows / batch_size))        
        

        if not split:
            train_ds = ParquetMonthBatches(
                parquet_root=parquet_root,
                feature_names=feature_names,
                target_col=target_col,
                batch_size=batch_size,
                month_keys=month_keys_all,
                shuffle_months=shuffle_months,
                shuffle_within_month=shuffle_within_month,
                drop_last=drop_last,
                seed=seed,
            )
            train_loader = DataLoader(train_ds, batch_size=None, num_workers=num_workers, pin_memory=pin_memory)
            if return_batch_counts:
                train_batches = _estimate_batches(month_keys_all)
                # attach hint attribute for tqdm (%)
                setattr(train_loader, "total_batches", train_batches)
                return (train_loader, train_batches)
            return (train_loader, )

        # split=True
        import random
        if split_strategy == "month":
            rng = random.Random(seed)
            keys = month_keys_all[:]
            rng.shuffle(keys)

            n = len(keys)
            n_test = max(1, int(round(n * test_ratio))) if n > 2 else 1
            n_val  = max(1, int(round(n * val_ratio)))  if n > 2 else 1
            n_train = max(1, n - n_val - n_test)

            train_keys = keys[:n_train]
            val_keys   = keys[n_train:n_train+n_val]
            test_keys  = keys[n_train+n_val:]

            def _mk_ds(keys_subset, shuffle_months_subset):
                return ParquetMonthBatches(
                    parquet_root=parquet_root,
                    feature_names=feature_names,
                    target_col=target_col,
                    batch_size=batch_size,
                    month_keys=keys_subset,
                    shuffle_months=shuffle_months_subset,
                    shuffle_within_month=shuffle_within_month,
                    drop_last=drop_last,
                    seed=seed,
                )

            train_ds = _mk_ds(train_keys, shuffle_months_subset=True)
            val_ds   = _mk_ds(val_keys,   shuffle_months_subset=False)
            test_ds  = _mk_ds(test_keys,  shuffle_months_subset=False)
            
            train_loader = DataLoader(
                train_ds,
                batch_size=None,              # you yield torch tensors already
                num_workers=4,                # start with 4–8 per GPU
                pin_memory=True,
                persistent_workers=True,
                prefetch_factor=2             # try 2–4
            )
            
            val_loader = DataLoader(
                val_ds,
                batch_size=None,              # you yield torch tensors already
                num_workers=4,                # start with 4–8 per GPU
                pin_memory=True,
                persistent_workers=True,
                prefetch_factor=2             # try 2–4
            )

            test_loader = DataLoader(
                test_ds,
                batch_size=None,              # you yield torch tensors already
                num_workers=4,                # start with 4–8 per GPU
                pin_memory=True,
                persistent_workers=True,
                prefetch_factor=2             # try 2–4
            )

            if return_batch_counts:
                train_batches = _estimate_batches(train_keys)
                val_batches   = _estimate_batches(val_keys)
                test_batches  = _estimate_batches(test_keys)
                # attach attributes for progress %
                setattr(train_loader, "total_batches", train_batches)
                setattr(val_loader, "total_batches", val_batches)
                setattr(test_loader, "total_batches", test_batches)
                return train_loader, val_loader, test_loader, train_batches, val_batches, test_batches

            return train_loader, val_loader, test_loader

        elif split_strategy == "row":
            # Row-wise random split per month
            def _mk_row_filtered_ds(mode: str):
                class RowSplitWrapper(ParquetMonthBatches):
                    def __iter__(self_inner):
                        if self_inner.seed is not None:
                            random.seed(self_inner.seed)
                        keys = self_inner.month_keys[:]
                        if self_inner.shuffle_months:
                            random.shuffle(keys)
                        for (yr, mo) in keys:
                            df = self_inner._load_month_df(yr, mo, columns=self_inner.feature_names + [self_inner.target_col])
                            if df.empty:
                                continue
                            rnd = np.random.default_rng(self_inner.seed + yr*100 + mo)
                            p_val  = val_ratio
                            p_test = test_ratio
                            p_train = max(0.0, 1.0 - p_val - p_test)
                            if mode == "train":
                                mask = rnd.random(len(df)) < p_train
                            elif mode == "val":
                                r = rnd.random(len(df))
                                mask = (r >= p_train) & (r < p_train + p_val)
                            else: # "test"
                                r = rnd.random(len(df))
                                mask = r >= (p_train + p_val)
                            df = df.loc[mask]
                            if df.empty:
                                continue
                            if self_inner.shuffle_within_month:
                                df = df.sample(frac=1.0, random_state=random.randint(0, 10_000))
                            X = df[self_inner.feature_names].to_numpy(dtype=np.float32, copy=False)
                            y = df[self_inner.target_col].to_numpy(dtype=np.float32, copy=False).reshape(-1, 1)
                            n = X.shape[0]; bs = self_inner.batch_size
                            full = (n // bs) * bs
                            end = full if self_inner.drop_last else n
                            for i in range(0, end, bs):
                                yield torch.from_numpy(X[i:i+bs]), torch.from_numpy(y[i:i+bs])

                return RowSplitWrapper(
                    parquet_root=parquet_root,
                    feature_names=feature_names,
                    target_col=target_col,
                    batch_size=batch_size,
                    month_keys=month_keys_all,
                    shuffle_months=shuffle_months,
                    shuffle_within_month=shuffle_within_month,
                    drop_last=drop_last,
                    seed=seed,
                )

            train_loader = DataLoader(_mk_row_filtered_ds("train"), batch_size=None, num_workers=num_workers, pin_memory=pin_memory)
            val_loader   = DataLoader(_mk_row_filtered_ds("val"),   batch_size=None, num_workers=num_workers, pin_memory=pin_memory)
            test_loader  = DataLoader(_mk_row_filtered_ds("test"),  batch_size=None, num_workers=num_workers, pin_memory=pin_memory)
            return train_loader, val_loader, test_loader

        else:
            raise ValueError(f"Unknown split_strategy='{split_strategy}'. Use 'month' or 'row'.")
    
    
