    def download_eta_ts_of_point_join_locally(self, lon=-7.3531874, lat=31.7010234, start_date='2020-01-01', end_date='2020-12-31', product_name='landsat8', method='METRIC'):
        
        # Define the minimum and maximum longitude and latitude coordinates
        """lon_min = roi_lon_minmax_lat_minmax_tuple[0]
        lat_min = roi_lon_minmax_lat_minmax_tuple[1]
        lon_max = roi_lon_minmax_lat_minmax_tuple[2]
        lat_max = roi_lon_minmax_lat_minmax_tuple[3]"""
        
        # Create a rectangle polygon
        #roi = Polygon([(lon_min, lat_min), (lon_min, lat_max), (lon_max, lat_max), (lon_max, lat_min)])
        
        if self.backend == 'gee':
            
         
            if product_name == 'landsat8':
                output_ts = 'data/eta_ts_landsat8_' + '_'.join([method, str(lon), str(lat), start_date, end_date]) + '.csv'
                
                if os.path.exists(output_ts):
                    print(f"ETa time series already downloaded on: {output_ts}")
                else:
                    # Initialize the Earth Engine Python API with the credentials
                    ee.Initialize()
                    
                    poi = ee.Geometry.Point(lon, lat)
                    # Define the start and end dates for the image collection
                    start_date = start_date
                    end_date = end_date

                    # Filter the Sentinel-2 collection by date and polygon
                    # S2 for level 1 data instead of S2_HARMONIZED
                    raw_bands_collection = ee.ImageCollection("LANDSAT/LC08/C02/T1") \
                        .filterDate(start_date, end_date) \
                        .filterBounds(poi) \
                        .sort('CLOUDY_PIXEL_PERCENTAGE')
                        
                    reflectance_bands_collection = ee.ImageCollection("LANDSAT/LC08/C02/T1_L2") \
                        .filterDate(start_date, end_date) \
                        .filterBounds(poi) \
                        .sort('CLOUDY_PIXEL_PERCENTAGE')
                        
                    # Estimate LST and add it to the collection.
                    #raw_bands_collection = raw_bands_collection.map(self.calculate_lst_landsat8)
                    
                    
                    # joining condition
                    condition = ee.Filter.equals(leftField='system:time_start', rightField='system:time_start')
                    
                    # Join collections based on image ID
                    joined_collection = ee.Join.inner().apply(
                        reflectance_bands_collection,
                        raw_bands_collection,
                        condition
                    )
                    
                    
                    # Convert FeatureCollection to a list
                    feature_list = joined_collection.toList(joined_collection.size())

                    # Function to extract images from properties and add them as bands
                    def extract_images(feature):
                        feature = ee.Feature(feature)
                        
                        # Extract images from properties
                        image1 = ee.Image(feature.get("primary"))
                        image2 = ee.Image(feature.get("secondary"))
                        
                        # Optionally, you can add some preprocessing steps here
                        
                        # Add images as bands to an Image object
                        image = image1.addBands(image2)
                        
                        # Return the image
                        return image.set('system:time_start', feature.get('time_property')) # Set time if available

                    # Map over the list to apply the extraction function
                    final_collection = ee.ImageCollection.fromImages(feature_list.map(extract_images))

                    
                    final_collection = final_collection.select(['B4', 'B5', 'B6', ])
                    # Calculate NDVI
                    #reflectance_bands_collection = reflectance_bands_collection.map(self.estimate_ndvi_landsat8)
                        
                    
                    # Convert the image collection to a feature collection
                    joined_collection = final_collection.map(lambda image: image.reduceRegions(reducer=ee.Reducer.first(), collection=ee.FeatureCollection(poi)))
                    #reflectance_bands_ts = reflectance_bands_collection.map(lambda image: image.reduceRegions(reducer=ee.Reducer.first(), collection=ee.FeatureCollection(poi)))
                    #reflectance_bands_ts = reflectance_bands_collection.map(lambda image: image.reduceRegions(reducer=ee.Reducer.first(), collection=ee.FeatureCollection(poi)))

                    
                    
                    # Flatten the feature collection
                    raw_bands_ts_flattened_collection = joined_collection.flatten()
                    #reflectance_bands_ts_flattened_collection = reflectance_bands_ts.flatten()
                    
                    # export raw bands
                    # Define the export parameters
