    def map_eto_makkink(self, input_folder, output_folder,
                        ta_max_prefix='temperature_2m_max',
                        ta_min_prefix='temperature_2m_min',
                        rs_mean_prefix='surface_solar_radiation_downwards_sum',
                        elevation_path='elevation.tif',
                        prefix_eto='eto_mk', roi_bbox=None,
                        start_date=None, end_date=None,
                        unit_temperatures='k',
                        unit_radiation='j/m2',
                        c1=0.61, c2=0.12,
                        verbose=False):

        import os, re, time, rasterio
        import numpy as np
        import pandas as pd
        from glob import glob
        from tqdm import tqdm
        from rasterio.windows import from_bounds
        from dateutil.parser import parse as parse_date

        ti = time.time()
        os.makedirs(output_folder, exist_ok=True)
        rs_files = sorted(glob(os.path.join(input_folder, f"{rs_mean_prefix}_*.tif")))
        if not rs_files:
            print("❌ No input files found for rs_mean_*.tif")
            return

        file_groups = []
        seen_dates = set()
        for path in rs_files:
            match = re.search(r'(\d{8})', os.path.basename(path))
            if not match:
                continue
            date_str = match.group(1)

            if date_str in seen_dates:
                continue

            date = pd.to_datetime(date_str, format="%Y%m%d")
            if start_date and date < pd.to_datetime(parse_date(start_date)):
                continue
            if end_date and date > pd.to_datetime(parse_date(end_date)):
                continue

            group = {
                'ta_max': os.path.join(input_folder, f"{ta_max_prefix}_{date_str}.tif"),
                'ta_min': os.path.join(input_folder, f"{ta_min_prefix}_{date_str}.tif"),
                'rs_mean': os.path.join(input_folder, f"{rs_mean_prefix}_{date_str}.tif"),
                'elevation': elevation_path
            }

            if all(os.path.exists(p) for p in group.values()):
                file_groups.append((date_str, group))
                seen_dates.add(date_str)
            else:
                if verbose:
                    print(f"❌ Missing one or more files for date: {date_str}")

        existing_date_count = 0
        print(f"🛠 Processing {len(file_groups)} Makkink ETo dates...")
        for date_str, group in tqdm(file_groups, desc="Makkink ETo mapping", unit="date"):
            out_path = os.path.join(output_folder, f"{prefix_eto}_{date_str}.tif")
            if os.path.exists(out_path):
                existing_date_count += 1
                if verbose:
                    print(f"⚠️ Skipping existing file: {out_path}")
                continue

            try:
                arrays = {}
                meta = None
                for key, tif_path in group.items():
                    with rasterio.open(tif_path) as src:
                        if roi_bbox:
                            data, transform, m = GeospatialDataToolkit.crop_raster_aligned(src, roi_bbox)
                        else:
                            data = src.read(1).astype("float32")
                            m = src.meta.copy()
                        arrays[key] = data
                        meta = m

                ta_max = arrays['ta_max']
                ta_min = arrays['ta_min']
                if unit_temperatures.lower() == 'k':
                    ta_max -= 273.15
                    ta_min -= 273.15

                ta_mean = (ta_max + ta_min) / 2

                rs_mean = arrays['rs_mean']
                if unit_radiation.lower() == 'w/m2':
                    rs_mean *= 0.0864
                elif unit_radiation.lower() == 'j/m2':
                    rs_mean /= 1e6

                elevation = arrays['elevation']
                delta = GeospatialDataToolkit.slope_saturation_vapor_pressure_curve(ta_mean)
                gamma = GeospatialDataToolkit.psychrometric_constant(elevation, ta_mean)
                lam = GeospatialDataToolkit.latent_heat_of_vaporization(ta_mean)

                eto = ((c1 * delta * rs_mean) / ((delta + gamma) * lam)) - c2
                eto = np.clip(eto, 0, 15)

                with rasterio.open(out_path, 'w', **meta) as dst:
                    dst.write(eto.astype("float32"), 1)

                if verbose:
                    print(f"✅ Saved: {out_path}")

            except Exception as e:
                print(f"❌ Failed on {date_str}: {e}")

        duration = time.time() - ti
        print(f"🕒 Duration: {duration:.2f} seconds")
        print(f"✅ Processed {len(file_groups) - existing_date_count} rasters, skipped existing {existing_date_count} rasters.")
        print(f"📁 Output saved in: {output_folder}")
    
