    def download_modis_toa(
        self,
        band_list: list[str] | str,
        output_folder: str,
        roi: tuple[float, float, float, float] | str,
        start_date: str,
        end_date: str,
        *,
        platform: str = "terra",         # "terra" | "aqua" | "both"
        res_deg: float = 0.0045,         # ~500 m @ equator
        radius_m: int = 4000,            # resample radius (m)
        filename_prefix: str = "modis_toa",
        overwrite: bool = False,
        verbose: bool = True,
        edl_username: str | None = None,
        edl_password: str | None = None,
        login_strategy: str | None = None,
        temp_dir: str | None = None,
        use_dask: bool = True,
        n_workers: int | str = "auto",
        threads_per_worker: int | str = "auto",
        scheduler: str = "processes",
        n_roi_split: int | tuple[int, int] = 100,
        show_progress: bool = True,
        remove_cache: bool = False,
    ) -> dict:
        """
        Download MODIS HKM TOA reflectance (Bands B01..B07) and build daily mosaics.

        Memory-efficient behavior
        - Build from cache first (if any cached tiles/mosaics exist).
        - Search/pair swaths once across the date window.
        - Group pairs by day; for each day:
            • process all its pairs (tiles) → per-tile mosaics → final daily mosaics,
            • then clean cache/intermediates for that day:
                output/_earthaccess_cache (used HDFs),
                output/_granule_tifs (that day),
                output/_tile_mosaics (that day).
        """
        import os, re, math, warnings, tempfile
        from collections import defaultdict
        from datetime import datetime, timedelta

        import numpy as np
        import rasterio
        from rasterio.merge import merge as rio_merge
        from rasterio.transform import from_origin
        from rasterio.features import rasterize

        try:
            from tqdm.auto import tqdm
        except Exception:
            def tqdm(x, **k): return x  # no-op

        try:
            import earthaccess as ea
        except Exception as e:
            raise RuntimeError("earthaccess required. pip install earthaccess") from e

        try:
            from pyresample import geometry, kd_tree
        except Exception as e:
            raise RuntimeError("pyresample required. pip install pyresample") from e

        # Optional HDF5 (rare)
        try:
            import h5py as _h5
        except Exception:
            _h5 = None

        # IO
        os.makedirs(output_folder, exist_ok=True)
        cache_dir = os.path.join(output_folder, "_earthaccess_cache")
        os.makedirs(cache_dir, exist_ok=True)
        granule_tif_dir = os.path.join(output_folder, "_granule_tifs")
        os.makedirs(granule_tif_dir, exist_ok=True)
        tile_mosaic_dir = os.path.join(output_folder, "_tile_mosaics")
        os.makedirs(tile_mosaic_dir, exist_ok=True)

        tmp_root = temp_dir or os.path.join(output_folder, "_tmp")
        os.makedirs(tmp_root, exist_ok=True)
        tempfile.tempdir = tmp_root
        os.environ.setdefault("CPL_TMPDIR", tmp_root)
        os.environ.setdefault("GDAL_CACHEMAX", "256")

        # Bands
        ALL_BANDS = ["B01", "B02", "B03", "B04", "B05", "B06", "B07"]
        if isinstance(band_list, str) and band_list.lower() == "all":
            bands_wanted = set(ALL_BANDS)
        else:
            bands_wanted = {str(b).upper() for b in band_list}
            unknown = bands_wanted - set(ALL_BANDS)
            if unknown:
                raise ValueError(f"Unknown band(s): {sorted(unknown)}. Valid: {ALL_BANDS}")

        # ROI
        roi_geom = None
        try:
            import geopandas as gpd
            from shapely.ops import unary_union
        except Exception:
            gpd = None  # type: ignore
            unary_union = None  # type: ignore

        if isinstance(roi, str):
            if gpd is None or unary_union is None:
                raise RuntimeError("Vector ROI requires geopandas and shapely.")
            if not os.path.exists(roi):
                raise FileNotFoundError(f"ROI not found: {roi}")
            gdf = gpd.read_file(roi)
            if gdf.empty:
                raise ValueError("Vector ROI is empty.")
            if gdf.crs is None or str(gdf.crs).upper() not in ("EPSG:4326", "OGC:CRS84"):
                gdf = gdf.to_crs("EPSG:4326")
            roi_geom = unary_union([g for g in gdf.geometry if g is not None and not g.is_empty])
            if roi_geom.is_empty:
                raise ValueError("Vector ROI union is empty.")
            minx, miny, maxx, maxy = roi_geom.bounds
        else:
            minx, miny, maxx, maxy = map(float, roi)
            if (maxx - minx) <= 0 or (maxy - miny) <= 0:
                raise ValueError("ROI bbox must have positive area.")

        # Date range
        start_dt = datetime.strptime(start_date, "%Y-%m-%d")
        end_dt = datetime.strptime(end_date, "%Y-%m-%d")
        if end_dt < start_dt:
            raise ValueError("end_date < start_date")
        all_days = [(start_dt + timedelta(days=i)).strftime("%Y%m%d")
                    for i in range((end_dt - start_dt).days + 1)]

        # Tiling helpers
        def _norm_split(v):
            if isinstance(v, (list, tuple)) and len(v) == 2:
                ny = max(1, int(v[0])); nx = max(1, int(v[1])); return ny, nx
            n = max(1, int(v)); ny = int(math.sqrt(n)); nx = max(1, int(math.ceil(n / ny))); return ny, nx

        def _split_bbox(bbox, ny, nx):
            x0, y0, x1, y1 = bbox
            dx = (x1 - x0) / nx; dy = (y1 - y0) / ny
            return [(x0 + ix * dx, y0 + iy * dy, x0 + (ix + 1) * dx, y0 + (iy + 1) * dy)
                    for iy in range(ny) for ix in range(nx)]

        ny, nx = _norm_split(n_roi_split)
        if verbose:
            print(f"🔲 Splitting ROI into {ny}x{nx} = {ny*nx} tiles ...")
        tile_bboxes = _split_bbox((minx, miny, maxx, maxy), ny, nx)
        tile_tags = [f"{ty}x{tx}" for ty in range(ny) for tx in range(nx)]

        # Helpers shared in/out cache builder
        def _grid_def(bbox, res):
            x0, y0, x1, y1 = bbox
            W = int(math.ceil((x1 - x0) / res)); H = int(math.ceil((y1 - y0) / res))
            transform = from_origin(x0, y1, res, res)
            area = geometry.AreaDefinition("roi", "roi grid", "epsg4326",
                                        {"proj": "longlat", "datum": "WGS84"},
                                        W, H, [x0, y0, x1, y1])
            return area, transform, W, H

        def _mask(arr, transform, w, h):
            if roi_geom is None:
                return arr
            try:
                msk = rasterize([(roi_geom, 1)], out_shape=(h, w),
                                transform=transform, fill=0, dtype="uint8")
                out = arr.copy(); out[msk == 0] = np.nan; return out
            except Exception:
                return arr

        def _write_tif(path, arr, transform, w, h):
            prof = {
                "driver": "GTiff", "height": h, "width": w, "count": 1, "dtype": "float32",
                "crs": "EPSG:4326", "transform": transform, "compress": "deflate",
                "predictor": 2, "tiled": True, "blockxsize": 256, "blockysize": 256,
                "nodata": np.float32(np.nan)
            }
            os.makedirs(os.path.dirname(path) or ".", exist_ok=True)
            with rasterio.open(path, "w", **prof) as dst:
                dst.write(arr, 1)

        # Robust cache mosaic builder
        def _build_from_cached(days_filter: set[str] | None = None, _mask_fn=None) -> dict:
            if _mask_fn is None:
                _mask_fn = _mask

            per_granule_pat = re.compile(
                r'(?i)(?:^|[_-])(?P<band>B0[1-7])(?:[_-]|$).*?(?:^|[_-])(?P<day>\d{8})(?:[_-]|$).*?(?:^|[_-])tile(?P<tag>\d+x\d+)(?:[_-]|$)'
            )
            tile_mosaic_pat = re.compile(
                r'(?i)(?:^|[_-])(?P<band>B0[1-7])(?:[_-]|$).*?(?:^|[_-])(?P<day>\d{8})(?:[_-]|$).*?(?:^|[_-])tile(?P<tag>\d+x\d+)(?:[_-]|$)'
            )

            def _parse_name_generic(name: str):
                b = re.search(r'(?i)B0[1-7]', name)
                d = re.search(r'(?<!\d)(\d{8})(?!\d)', name)
                t = re.search(r'(?i)tile(\d+x\d+)', name)
                if b and d and t:
                    return b.group(0).upper(), d.group(1), t.group(1)
                return None

            wanted_days = set(days_filter) if days_filter else set(all_days)
            wanted_bands = set(bands_wanted)
            tag_set = set(tile_tags)

            per_tile_groups = defaultdict(list)

            try:
                it = os.scandir(granule_tif_dir)
            except FileNotFoundError:
                it = []
            for de in tqdm(it, desc="📦 Use cached tiles", unit="file", disable=not show_progress):
                if not getattr(de, "is_file", lambda: False)():
                    continue
                fn = de.name
                m = per_granule_pat.search(fn) or None
                if not m:
                    g = _parse_name_generic(fn)
                    if not g:
                        continue
                    band, day, tag = g
                else:
                    band = m.group("band").upper()
                    day = m.group("day")
                    tag = m.group("tag")
                if band not in wanted_bands or (wanted_days and day not in wanted_days) or tag not in tag_set:
                    continue
                per_tile_groups[(day, band, tag)].append(os.path.join(granule_tif_dir, fn))

            if not per_tile_groups:
                try:
                    it2 = os.scandir(tile_mosaic_dir)
                except FileNotFoundError:
                    it2 = []
                for de in tqdm(it2, desc="📦 Use cached tile mosaics", unit="file", disable=not show_progress):
                    if not getattr(de, "is_file", lambda: False)():
                        continue
                    fn = de.name
                    m = tile_mosaic_pat.search(fn) or None
                    if not m:
                        g = _parse_name_generic(fn)
                        if not g:
                            continue
                        band, day, tag = g
                    else:
                        band = m.group("band").upper()
                        day = m.group("day")
                        tag = m.group("tag")
                    if band not in wanted_bands or (wanted_days and day not in wanted_days) or tag not in tag_set:
                        continue
                    per_tile_groups[(day, band, tag)].append(os.path.join(tile_mosaic_dir, fn))

            if not per_tile_groups:
                finals = []
                for day in sorted(wanted_days):
                    for b in sorted(wanted_bands):
                        fp = os.path.join(output_folder, f"{filename_prefix}_{b}_{day}.tif")
                        if os.path.exists(fp):
                            finals.append(fp)
                if finals:
                    if verbose:
                        print(f"✅ Final outputs already exist for {len(finals)} file(s).")
                    return {
                        "processed_pairs": 0, "written": 0, "days_processed": 0,
                        "skipped_days": [], "paths": finals, "dashboard": None
                    }
                if verbose:
                    print("ℹ️ No cached per‑granule tiles or tile mosaics found for requested days.")
                return {"processed_pairs": 0, "written": 0, "days_processed": 0, "skipped_days": [], "paths": [], "dashboard": None}

            final_tile_mosaics = defaultdict(list)
            for (day, b, tag), tif_list in tqdm(sorted(per_tile_groups.items()),
                                                total=len(per_tile_groups),
                                                desc="🧬 Tile mosaics (cached)",
                                                unit="tile",
                                                disable=not show_progress):
                if not tif_list:
                    continue
                tile_out = os.path.join(tile_mosaic_dir, f"{filename_prefix}_{b}_{day}_tile{tag}.tif")
                if (not overwrite) and os.path.exists(tile_out):
                    final_tile_mosaics[(day, b)].append(tile_out)
                    continue
                try:
                    srcs = [rasterio.open(p) for p in tif_list]
                    mosaic, out_transform = rio_merge(srcs, method="first")
                    for s in srcs:
                        s.close()
                    if mosaic.ndim == 3 and mosaic.shape[0] == 1:
                        mosaic = mosaic[0]
                    mosaic = _mask_fn(mosaic, out_transform, mosaic.shape[1], mosaic.shape[0])
                    _write_tif(tile_out, mosaic.astype(np.float32, copy=False),
                            out_transform, mosaic.shape[1], mosaic.shape[0])
                    final_tile_mosaics[(day, b)].append(tile_out)
                except Exception as e:
                    if verbose:
                        print(f"⚠️ Tile mosaic (cached) failed {day} {b} tile{tag}: {e}")

            written = []
            days_processed = set()
            for (day, b), tile_paths in tqdm(sorted(final_tile_mosaics.items()),
                                            total=len(final_tile_mosaics),
                                            desc="🧷 Final mosaics (cached)",
                                            unit="day×band",
                                            disable=not show_progress):
                if not tile_paths:
                    continue
                out_fp = os.path.join(output_folder, f"{filename_prefix}_{b}_{day}.tif")
                if (not overwrite) and os.path.exists(out_fp):
                    continue
                try:
                    srcs = [rasterio.open(p) for p in tile_paths]
                    mosaic, out_transform = rio_merge(srcs, method="first")
                    for s in srcs:
                        s.close()
                    if mosaic.ndim == 3 and mosaic.shape[0] == 1:
                        mosaic = mosaic[0]
                    mosaic = _mask_fn(mosaic, out_transform, mosaic.shape[1], mosaic.shape[0])
                    _write_tif(out_fp, mosaic.astype(np.float32, copy=False),
                            out_transform, mosaic.shape[1], mosaic.shape[0])
                    written.append(out_fp)
                    days_processed.add(day)
                except Exception as e:
                    if verbose:
                        print(f"⚠️ Final mosaic (cached) failed {day} {b}: {e}")

            if verbose:
                print(f"✅ Cached mosaics complete. Days={len(days_processed)} Written={len(written)}")

            return {
                "processed_pairs": 0, "written": len(written), "days_processed": len(days_processed),
                "skipped_days": [], "paths": written, "dashboard": None
            }

        # Build from cache up-front, then drop already-done days
        try:
            has_cached_tiles = any((de.is_file() and de.name.lower().endswith(".tif")) for de in os.scandir(granule_tif_dir))
        except FileNotFoundError:
            has_cached_tiles = False
        try:
            has_tile_mosaics = any((de.is_file() and de.name.lower().endswith(".tif")) for de in os.scandir(tile_mosaic_dir))
        except FileNotFoundError:
            has_tile_mosaics = False

        if has_cached_tiles or has_tile_mosaics:
            if verbose:
                print("🧱 Found cached tiles. Building mosaics from cache before search/download ...")
            _build_from_cached(set(all_days), _mask_fn=_mask)

        if not overwrite:
            already_done = []
            for day in list(all_days):
                if all(os.path.exists(os.path.join(output_folder, f"{filename_prefix}_{b}_{day}.tif"))
                    for b in sorted(bands_wanted)):
                    already_done.append(day)
            if already_done and verbose:
                snippet = ", ".join(already_done[:6]) + (" ..." if len(already_done) > 6 else "")
                print(f"⏭️ Skipping {len(already_done)} day(s) (final outputs exist): {snippet}")
            all_days = [d for d in all_days if d not in set(already_done)]
            if not all_days:
                return {
                    "processed_pairs": 0, "written": 0, "days_processed": 0,
                    "skipped_days": already_done,
                    "paths": [os.path.join(output_folder, f"{filename_prefix}_{b}_{d}.tif")
                            for d in already_done for b in sorted(bands_wanted)
                            if os.path.exists(os.path.join(output_folder, f"{filename_prefix}_{b}_{d}.tif"))],
                    "dashboard": None
                }

        # Cache index to skip downloads
        cache_regex = re.compile(
            r'.*[_-]?(B0[1-7])[_-](\d{8})(?:[_-]A\d{11})?[_-]tile\d+x\d+\.tif$',
            re.IGNORECASE
        )
        day_band_hits: dict[str, set[str]] = defaultdict(set)
        try:
            files = [de for de in tqdm(os.scandir(granule_tif_dir),
                                    desc="🗂️ Index cache (scan dir)",
                                    unit="file",
                                    disable=not show_progress)]
        except FileNotFoundError:
            files = []
        for de in tqdm(files, desc="🗂️ Index cache", unit="file", disable=not show_progress):
            if not de.is_file():
                continue
            m = cache_regex.match(de.name)
            if not m:
                continue
            band = m.group(1).upper()
            day = m.group(2)
            day_band_hits[day].add(band)

        skipped_days = []
        needed_days = []
        for day in all_days:
            if (not overwrite) and day in day_band_hits and bands_wanted.issubset(day_band_hits[day]):
                skipped_days.append(day)
            else:
                needed_days.append(day)

        if verbose and skipped_days:
            print(f"⏭️ Skipping {len(skipped_days)} day(s) already cached.")
        if not needed_days:
            if verbose:
                print("🧱 All requested days appear cached. Building mosaics from cache ...")
            return _build_from_cached(set(all_days), _mask_fn=_mask)

        # Login
        if verbose:
            print("🔑 Logging into Earthdata ...")
        try:
            if edl_username and edl_password:
                ea.login(strategy="environment", username=edl_username, password=edl_password)
            elif login_strategy:
                ea.login(strategy=login_strategy)
            else:
                ea.login()
        except Exception as e:
            raise RuntimeError(f"earthaccess login failed: {e}")

        # Dask
        dask_client = None
        dask_cluster = None
        dashboard_url = None
        if use_dask:
            try:
                from dask.distributed import Client, LocalCluster, default_client, as_completed as _as_completed
                try:
                    dask_client = default_client()
                except Exception:
                    if n_workers == "auto":
                        n_workers = max(1, os.cpu_count() // 2)
                    if threads_per_worker == "auto":
                        threads_per_worker = 1 if scheduler == "processes" else max(1, os.cpu_count() // max(1, int(n_workers)))
                    dask_cluster = LocalCluster(
                        n_workers=int(n_workers),
                        threads_per_worker=int(threads_per_worker),
                        processes=(scheduler == "processes"),
                        dashboard_address=":0",
                    )
                    dask_client = Client(dask_cluster)
                dashboard_url = getattr(dask_client, "dashboard_link", None)
                if verbose and dashboard_url:
                    print(f"📊 Dask dashboard: {dashboard_url}")
            except Exception as e:
                if verbose:
                    print(f"⚠️ Dask disabled ({e}); running serial.")
                dask_client = None
                dask_cluster = None
                use_dask = False
                _as_completed = None  # type: ignore

        # MODIS helpers
        try:
            from pyhdf.SD import SD, SDC
        except Exception as e:
            raise RuntimeError("pyhdf required (HDF4). pip install pyhdf") from e

        def _granule_name(gran) -> str:
            # Direct path
            if isinstance(gran, str):
                return os.path.basename(gran)

            # UMM/meta dicts
            for attr in ("umm", "meta", "metadata"):
                d = getattr(gran, attr, None)
                if isinstance(d, dict):
                    for k in ("GranuleUR", "granuleUr", "title", "name", "filename"):
                        v = d.get(k)
                        if v:
                            return v

            # Assets (STAC-like)
            assets = getattr(gran, "assets", None)
            if isinstance(assets, dict):
                for v in assets.values():
                    href = (v or {}).get("href") or (v or {}).get("URL") or (v or {}).get("url")
                    if href:
                        return os.path.basename(href)

            # Links/data_links
            for attr in ("data_links", "links"):
                obj = getattr(gran, attr, None)
                try:
                    seq = obj() if callable(obj) else obj
                except Exception:
                    seq = None
                if not seq:
                    continue
                try:
                    for u in seq:
                        if isinstance(u, str):
                            if u.lower().endswith(".hdf"):
                                return os.path.basename(u)
                            base = os.path.basename(u)
                            if base:
                                return base
                        if isinstance(u, dict):
                            href = u.get("href") or u.get("URL") or u.get("url")
                            if href:
                                return os.path.basename(href)
                except Exception:
                    pass

            s = str(gran)
            m = re.search(r"(MOD[0-9A-Z]+\.A\d{7}\.\d{4}\.\d{3}\.\d+\.hdf)", s)
            if m:
                return m.group(1)
            return ""

        def _token(name):
            m = re.search(r'\.A(\d{7})\.(\d{4})\.', name or "")
            return f"A{m.group(1)}{m.group(2)}" if m else ""

        def _day_from_name(name: str) -> str:
            m = re.search(r"A(\d{4})(\d{3})(?:\.?\d{4})?", name or "")
            if m:
                year = int(m.group(1)); doy = int(m.group(2))
                return (datetime(year, 1, 1) + timedelta(days=doy - 1)).strftime("%Y%m%d")
            m2 = re.search(r"(?:^|[_-])(\d{8})(?:[_-]|$)", name or "")
            return m2.group(1) if m2 else ""

        def _open(gran):
            if isinstance(gran, str) and os.path.isfile(gran):
                return gran
            name = _granule_name(gran)
            cached = os.path.join(cache_dir, name) if name else None
            if cached and os.path.exists(cached):
                return cached
            paths = ea.download([gran], provider="LAADS", local_path=cache_dir)
            if isinstance(paths, dict):
                lp = next(iter(paths.values()), None)
            elif isinstance(paths, (list, tuple)):
                lp = paths[0] if paths else None
            else:
                lp = None
            if not lp or not os.path.exists(lp):
                raise FileNotFoundError("Download failed")
            if verbose:
                print(f"⬇️  Downloaded: {os.path.basename(lp)}")
            return lp

        def _attrs(ds):
            a = ds.attributes()
            return a.get("reflectance_scales"), a.get("reflectance_offsets")

        def _read_geo(p):
            # HDF5 (rare)
            if _h5:
                try:
                    with _h5.File(p, "r") as f:
                        if "Latitude" in f and "Longitude" in f:
                            lat = f["Latitude"][()].astype(np.float32)
                            lon = f["Longitude"][()].astype(np.float32)
                            lon = np.where(lon > 180, lon - 360, lon)
                            return lat, lon
                except Exception:
                    pass
            # HDF4
            sd = SD(p, SDC.READ)
            try:
                lat = sd.select("Latitude").get().astype(np.float32)
                lon = sd.select("Longitude").get().astype(np.float32)
                lon = np.where(lon > 180, lon - 360, lon)
                return lat, lon
            finally:
                sd.end()

        def _read_toa(p):
            out = {}
            sd = SD(p, SDC.READ)
            try:
                try:
                    ds250 = sd.select("EV_250_Aggr500_RefSB")
                    arr250 = ds250.get().astype(np.float32)
                    s250, o250 = _attrs(ds250)
                except Exception:
                    arr250 = None; s250 = o250 = None
                try:
                    ds500 = sd.select("EV_500_RefSB")
                    arr500 = ds500.get().astype(np.float32)
                    s500, o500 = _attrs(ds500)
                except Exception:
                    arr500 = None; s500 = o500 = None
            finally:
                sd.end()

            def _scale(v, i, dv):
                try:
                    a = np.array(v)
                    if a.ndim == 1 and i < a.size:
                        return float(a[i])
                    if a.size == 1:
                        return float(a.item())
                except Exception:
                    pass
                return float(dv)

            if arr250 is not None:
                for i, b in {0: "B01", 1: "B02"}.items():
                    a = arr250[i] * _scale(s250, i, 1.0) + _scale(o250, i, 0.0)
                    a[a < 0] = np.nan
                    out[b] = a.astype(np.float32)
            if arr500 is not None:
                for i, b in {0: "B03", 1: "B04", 2: "B05", 3: "B06", 4: "B07"}.items():
                    a = arr500[i] * _scale(s500, i, 1.0) + _scale(o500, i, 0.0)
                    a[a < 0] = np.nan
                    out[b] = a.astype(np.float32)
            return out

        def _align(lat, lon, band):
            gl, gs = lat.shape; bl, bs = band.shape
            if (gl, gs) == (bl, bs):
                return lat, lon
            if gl * 2 == bl and gs * 2 == bs:
                lat_u = np.repeat(np.repeat(lat, 2, axis=0), 2, axis=1)
                lon_u = np.repeat(np.repeat(lon, 2, axis=0), 2, axis=1)
                return lat_u, lon_u
            ry = max(1, round(bl / max(1, gl))); rx = max(1, round(bs / max(1, gs)))
            lat_u = np.repeat(np.repeat(lat, ry, axis=0), rx, axis=1)[:bl, :bs]
            lon_u = np.repeat(np.repeat(lon, ry, axis=0), rx, axis=1)[:bl, :bs]
            return lat_u, lon_u

        def _resample_to_grid(band, lat, lon, area, radius):
            lat, lon = _align(lat, lon, band)
            vals = band.ravel(); lats = lat.ravel(); lons = lon.ravel()
            m = np.isfinite(vals)
            if not m.any():
                return np.full(area.shape, np.nan, dtype=np.float32)
            vals = vals[m]; lats = lats[m]; lons = lons[m]
            sw = geometry.SwathDefinition(lons=lons, lats=lats)
            with warnings.catch_warnings():
                warnings.simplefilter("ignore")
                g = kd_tree.resample_nearest(sw, vals, area,
                                            radius_of_influence=max(1000, int(radius)),
                                            fill_value=np.nan, reduce_data=True, nprocs=1)
            return g.astype(np.float32)

        # Search once across the needed window
        if verbose:
            print(f"🔍 Searching granules for {len(needed_days)} day(s) ...")

        need_terra = platform.lower() in ("terra", "both")
        need_aqua = platform.lower() in ("aqua", "both")

        granules_l1b = []
        granules_geo = []

        full_start = datetime.strptime(needed_days[0], "%Y%m%d") if needed_days else start_dt
        full_end = datetime.strptime(needed_days[-1], "%Y%m%d") + timedelta(days=1) if needed_days else (end_dt + timedelta(days=1))

        def _search_once(short_name: str, sd, ed, bbox):
            return ea.search_data(
                short_name=short_name,
                temporal=(sd, ed),
                bounding_box=bbox,
                provider="LAADS",
                granule_name="*.hdf",
            )

        if need_terra:
            if verbose: print("🛰️ Searching MOD02HKM / MOD03 once for full range ...")
            granules_l1b += _search_once("MOD02HKM", full_start, full_end, (minx, miny, maxx, maxy))
            granules_geo += _search_once("MOD03",    full_start, full_end, (minx, miny, maxx, maxy))
        if need_aqua:
            if verbose: print("🛰️ Searching MYD02HKM / MYD03 once for full range ...")
            granules_l1b += _search_once("MYD02HKM", full_start, full_end, (minx, miny, maxx, maxy))
            granules_geo += _search_once("MYD03",    full_start, full_end, (minx, miny, maxx, maxy))

        # Pair L1B with GEO
        if verbose:
            print("🔗 Pairing L1B and GEO granules ...")

        wanted_days_set = set(needed_days)
        geo_by_token = {}
        for g in granules_geo:
            nm = _granule_name(g)
            geo_by_token[_token(nm)] = g

        pairs = []
        for l in granules_l1b:
            ln = _granule_name(l)
            dk = _day_from_name(ln)
            if dk and dk not in wanted_days_set:
                continue
            tn = _token(ln)
            gg = geo_by_token.get(tn)
            if gg:
                pairs.append((l, gg))

        if not pairs:
            # Try building purely from cache before giving up
            result = _build_from_cached(set(needed_days) if needed_days else set(all_days), _mask_fn=_mask)
            if result["written"] or result["days_processed"]:
                return result
            if verbose:
                print("ℹ️ No new granule pairs to process and nothing cached to mosaic.")
            return {
                "processed_pairs": 0, "written": 0, "days_processed": 0,
                "skipped_days": skipped_days, "paths": [], "dashboard": None
            }

        # Tile processor
        def _process_tile(sw_path, geo_path, bbox_t, tile_tag):
            out = []
            try:
                sw_name = os.path.basename(sw_path)
                day = _day_from_name(sw_name) or "unknown"
                area, transform, W, H = _grid_def(bbox_t, res_deg)

                # Reuse existing per‑granule per‑tile TIFFs if they all exist
                gtok = _token(sw_name)
                reuse_all = True
                for b in bands_wanted:
                    tif = os.path.join(granule_tif_dir, f"{filename_prefix}_{b}_{day}_{gtok}_tile{tile_tag}.tif")
                    if not ((not overwrite) and os.path.exists(tif)):
                        reuse_all = False
                        break
                if reuse_all:
                    for b in bands_wanted:
                        tif = os.path.join(granule_tif_dir, f"{filename_prefix}_{b}_{day}_{gtok}_tile{tile_tag}.tif")
                        out.append((day, b, tile_tag, tif))
                    return out

                lat, lon = _read_geo(geo_path)
                bands = _read_toa(sw_path)
                for b, arr in bands.items():
                    if b not in bands_wanted or arr is None or not np.isfinite(arr).any():
                        continue
                    grid = _resample_to_grid(arr, lat, lon, area, radius_m)
                    grid = _mask(grid, transform, W, H)
                    tif = os.path.join(granule_tif_dir, f"{filename_prefix}_{b}_{day}_{gtok}_tile{tile_tag}.tif")
                    if overwrite or not os.path.exists(tif):
                        _write_tif(tif, grid, transform, W, H)
                    out.append((day, b, tile_tag, tif))
                return out
            except Exception as e:
                if verbose:
                    print(f"⚠️ Tile {tile_tag} failed: {e}")
                return out

        # Group pairs by day for memory-efficient per-day processing
        pairs_by_day: dict[str, list[tuple]] = defaultdict(list)
        for l, g in pairs:
            d = _day_from_name(_granule_name(l))
            if d:
                pairs_by_day[d].append((l, g))

        # Per-day cleanup
        def _cleanup_day_artifacts(day: str, used_hdf_paths: list[str]):
            # Ensure final outputs exist for all requested bands
            all_ok = all(os.path.exists(os.path.join(output_folder, f"{filename_prefix}_{b}_{day}.tif"))
                        for b in bands_wanted)
            if not all_ok:
                if verbose:
                    print(f"⚠️ Cleanup skipped for {day}: not all final outputs exist.")
                return
            # Remove used HDFs
            for p in used_hdf_paths:
                try:
                    if p and os.path.isfile(p):
                        os.remove(p)
                except Exception:
                    pass
            # Purge per‑granule tiles and per‑tile mosaics for this day
            day_pat = re.compile(rf".*[_-]{day}([_-].*)?\.tif$", re.IGNORECASE)
            for ddir in (granule_tif_dir, tile_mosaic_dir):
                try:
                    for de in os.scandir(ddir):
                        if de.is_file() and day_pat.match(de.name):
                            try:
                                os.remove(de.path)
                            except Exception:
                                pass
                except FileNotFoundError:
                    pass
            if verbose:
                print(f"🧹 Cleaned cache and intermediates for {day}")

        # Process day-by-day
        written = []
        days_processed = set()
        day_list = sorted(d for d in pairs_by_day.keys() if d in needed_days)
        for day in tqdm(day_list, desc="📅 Days", unit="day", disable=not show_progress):
            day_pairs = pairs_by_day.get(day, [])
            if not day_pairs:
                continue
            if (not overwrite) and day in skipped_days:
                if verbose:
                    print(f"⏭️ Day {day} fully cached (skipped).")
                continue

            per_tile_groups_day = defaultdict(list)
            used_hdfs_day: list[str] = []

            # Process all pairs for the day
            for sw_g, geo_g in tqdm(day_pairs, desc=f"📦 Granule pairs {day}", unit="pair", disable=not show_progress):
                sw_path = _open(sw_g); used_hdfs_day.append(sw_path)
                geo_path = _open(geo_g); used_hdfs_day.append(geo_path)

                if use_dask and dask_client:
                    tasks = [dask_client.submit(_process_tile, sw_path, geo_path, bbox_t, tag)
                            for bbox_t, tag in zip(tile_bboxes, tile_tags)]
                    try:
                        from dask.distributed import as_completed as _as_completed
                    except Exception:
                        _as_completed = None
                    results = []
                    if _as_completed is not None:
                        pbar = tqdm(total=len(tasks), desc=f"🧠 Tiles (dask) {day}", unit="tile", disable=not show_progress)
                        for fut in _as_completed(tasks):
                            try:
                                results.append(fut.result())
                            except Exception as e:
                                if verbose:
                                    print(f"⚠️ Tile task failed: {e}")
                            pbar.update(1)
                        pbar.close()
                    else:
                        results = dask_client.gather(tasks)
                else:
                    results = []
                    for bbox_t, tag in tqdm(zip(tile_bboxes, tile_tags),
                                            total=len(tile_bboxes),
                                            desc=f"🧩 Tiles (serial) {day}",
                                            unit="tile",
                                            disable=not show_progress):
                        results.append(_process_tile(sw_path, geo_path, bbox_t, tag))

                for lst in results:
                    for d_, b_, tag_, tif_ in lst:
                        if d_ == day:
                            per_tile_groups_day[(day, b_, tag_)].append(tif_)

                # Optionally remove cached HDFs immediately per swath (kept day-level here)
                if remove_cache:
                    for p in (sw_path, geo_path):
                        try:
                            if p and os.path.isfile(p):
                                os.remove(p)
                        except Exception:
                            pass

            # Build per‑tile mosaics for this day
            final_tile_mosaics_day = defaultdict(list)
            for (d_, b_, tag_), tif_list in tqdm(sorted(per_tile_groups_day.items()),
                                                total=len(per_tile_groups_day),
                                                desc=f"🧬 Tile mosaics {day}",
                                                unit="tile",
                                                disable=not show_progress):
                if not tif_list:
                    continue
                tile_out = os.path.join(tile_mosaic_dir, f"{filename_prefix}_{b_}_{d_}_tile{tag_}.tif")
                if (not overwrite) and os.path.exists(tile_out):
                    final_tile_mosaics_day[(d_, b_)].append(tile_out)
                    continue
                try:
                    srcs = [rasterio.open(p) for p in tif_list]
                    mosaic, out_transform = rio_merge(srcs, method="first")
                    for s in srcs:
                        s.close()
                    if mosaic.ndim == 3 and mosaic.shape[0] == 1:
                        mosaic = mosaic[0]
                    mosaic = _mask(mosaic, out_transform, mosaic.shape[1], mosaic.shape[0])
                    _write_tif(tile_out, mosaic.astype(np.float32, copy=False),
                            out_transform, mosaic.shape[1], mosaic.shape[0])
                    final_tile_mosaics_day[(d_, b_)].append(tile_out)
                except Exception as e:
                    if verbose:
                        print(f"⚠️ Tile mosaic failed {d_} {b_} tile{tag_}: {e}")

            # Final mosaics for this day
            for (d_, b_), tile_paths in tqdm(sorted(final_tile_mosaics_day.items()),
                                            total=len(final_tile_mosaics_day),
                                            desc=f"🧷 Final mosaics {day}",
                                            unit="band",
                                            disable=not show_progress):
                if not tile_paths:
                    continue
                out_fp = os.path.join(output_folder, f"{filename_prefix}_{b_}_{d_}.tif")
                if (not overwrite) and os.path.exists(out_fp):
                    continue
                try:
                    srcs = [rasterio.open(p) for p in tile_paths]
                    mosaic, out_transform = rio_merge(srcs, method="first")
                    for s in srcs:
                        s.close()
                    if mosaic.ndim == 3 and mosaic.shape[0] == 1:
                        mosaic = mosaic[0]
                    mosaic = _mask(mosaic, out_transform, mosaic.shape[1], mosaic.shape[0])
                    _write_tif(out_fp, mosaic.astype(np.float32, copy=False),
                            out_transform, mosaic.shape[1], mosaic.shape[0])
                    written.append(out_fp)
                except Exception as e:
                    if verbose:
                        print(f"⚠️ Final mosaic failed {d_} {b_}: {e}")

            days_processed.add(day)
            _cleanup_day_artifacts(day, used_hdfs_day)

        if verbose:
            print(f"✅ Done. Days processed={len(days_processed)} | Skipped={len(skipped_days)} | Written={len(written)}")

        # Teardown dask
        if use_dask and ('dask_client' in locals()) and dask_client:
            try:
                dask_client.close()
                if dask_cluster:
                    dask_cluster.close()
            except Exception:
                pass

        return {
            "processed_pairs": sum(len(v) for v in pairs_by_day.values()),
            "written": len(written),
            "days_processed": len(days_processed),
            "skipped_days": skipped_days,
            "paths": written,
            "dashboard": dashboard_url if use_dask else None,
        }
    
    
    def download_modis_toa_working_not_day_by_day(
        self,
        band_list: list[str] | str,
        output_folder: str,
        roi: tuple[float, float, float, float] | str,
        start_date: str,
        end_date: str,
        *,
        platform: str = "terra",         # "terra" | "aqua" | "both"
        res_deg: float = 0.0045,         # ~500 m @ equator
        radius_m: int = 4000,            # resample radius (m)
        filename_prefix: str = "modis_toa",
        overwrite: bool = False,
        verbose: bool = True,
        edl_username: str | None = None,
        edl_password: str | None = None,
        login_strategy: str | None = None,
        temp_dir: str | None = None,
        use_dask: bool = True,
        n_workers: int | str = "auto",
        threads_per_worker: int | str = "auto",
        scheduler: str = "processes",
        n_roi_split: int | tuple[int, int] = 100,
        show_progress: bool = True,
        remove_cache: bool = False,
    ) -> dict:
        """
        Download MODIS HKM TOA reflectance (Bands B01..B07) and build daily mosaics.

        Behavior
        - Searches once per product across the whole date window, pairs L1B/GEO by MODIS token.
        - Processes ROI in tiles to reduce RAM; supports Dask for per-tile parallelism.
        - Respects cache:
          - First tries to build mosaics from cached per‑granule tiles (_granule_tifs) or tile mosaics,
            then drops already-finished days.
          - Skips days where all requested bands already have cached per‑granule tiles.
          - Reuses per‑granule per‑tile TIFFs for a given swath if present.
          - Reuses per‑tile mosaics and final mosaics if overwrite=False.

        Output
        - {output_folder}/_granule_tifs/{prefix}_{Band}_{YYYYMMDD}_{AYYYYDOYHHMM}_tile{ty}x{tx}.tif
        - {output_folder}/_tile_mosaics/{prefix}_{Band}_{YYYYMMDD}_tile{ty}x{tx}.tif
        - {output_folder}/{prefix}_{Band}_{YYYYMMDD}.tif
        """
        import os, re, math, warnings, tempfile
        from collections import defaultdict
        from datetime import datetime, timedelta

        import numpy as np
        import rasterio
        from rasterio.merge import merge as rio_merge
        from rasterio.transform import from_origin
        from rasterio.features import rasterize

        try:
            from tqdm.auto import tqdm
        except Exception:
            def tqdm(x, **k): return x  # no-op

        try:
            import earthaccess as ea
        except Exception as e:
            raise RuntimeError("earthaccess required. pip install earthaccess") from e

        try:
            from pyresample import geometry, kd_tree
        except Exception as e:
            raise RuntimeError("pyresample required. pip install pyresample") from e

        # Optional HDF5 support (some MOD03/MYD03 are HDF5; most are HDF4)
        try:
            import h5py  # noqa: F401
        except Exception:
            h5py = None  # type: ignore

        # IO
        os.makedirs(output_folder, exist_ok=True)
        cache_dir = os.path.join(output_folder, "_earthaccess_cache")
        os.makedirs(cache_dir, exist_ok=True)
        granule_tif_dir = os.path.join(output_folder, "_granule_tifs")
        os.makedirs(granule_tif_dir, exist_ok=True)
        tile_mosaic_dir = os.path.join(output_folder, "_tile_mosaics")
        os.makedirs(tile_mosaic_dir, exist_ok=True)

        tmp_root = temp_dir or os.path.join(output_folder, "_tmp")
        os.makedirs(tmp_root, exist_ok=True)
        tempfile.tempdir = tmp_root
        os.environ.setdefault("CPL_TMPDIR", tmp_root)
        os.environ.setdefault("GDAL_CACHEMAX", "256")

        # Bands
        ALL_BANDS = ["B01", "B02", "B03", "B04", "B05", "B06", "B07"]
        if isinstance(band_list, str) and band_list.lower() == "all":
            bands_wanted = set(ALL_BANDS)
        else:
            bands_wanted = {str(b).upper() for b in band_list}
            unknown = bands_wanted - set(ALL_BANDS)
            if unknown:
                raise ValueError(f"Unknown band(s): {sorted(unknown)}. Valid: {ALL_BANDS}")

        # ROI
        roi_geom = None
        try:
            import geopandas as gpd
            from shapely.ops import unary_union
        except Exception:
            gpd = None  # type: ignore
            unary_union = None  # type: ignore

        if isinstance(roi, str):
            if gpd is None or unary_union is None:
                raise RuntimeError("Vector ROI requires geopandas and shapely.")
            if not os.path.exists(roi):
                raise FileNotFoundError(f"ROI not found: {roi}")
            gdf = gpd.read_file(roi)
            if gdf.empty:
                raise ValueError("Vector ROI is empty.")
            if gdf.crs is None or str(gdf.crs).upper() not in ("EPSG:4326", "OGC:CRS84"):
                gdf = gdf.to_crs("EPSG:4326")
            roi_geom = unary_union([g for g in gdf.geometry if g is not None and not g.is_empty])
            if roi_geom.is_empty:
                raise ValueError("Vector ROI union is empty.")
            minx, miny, maxx, maxy = roi_geom.bounds
        else:
            minx, miny, maxx, maxy = map(float, roi)
            if (maxx - minx) <= 0 or (maxy - miny) <= 0:
                raise ValueError("ROI bbox must have positive area.")

        # Date range
        start_dt = datetime.strptime(start_date, "%Y-%m-%d")
        end_dt = datetime.strptime(end_date, "%Y-%m-%d")
        if end_dt < start_dt:
            raise ValueError("end_date < start_date")
        all_days = [(start_dt + timedelta(days=i)).strftime("%Y%m%d")
                    for i in range((end_dt - start_dt).days + 1)]

        # Tiling helpers
        def _norm_split(v):
            if isinstance(v, (list, tuple)) and len(v) == 2:
                ny = max(1, int(v[0])); nx = max(1, int(v[1])); return ny, nx
            n = max(1, int(v)); ny = int(math.sqrt(n)); nx = max(1, int(math.ceil(n / ny))); return ny, nx

        def _split_bbox(bbox, ny, nx):
            x0, y0, x1, y1 = bbox
            dx = (x1 - x0) / nx; dy = (y1 - y0) / ny
            return [(x0 + ix * dx, y0 + iy * dy, x0 + (ix + 1) * dx, y0 + (iy + 1) * dy)
                    for iy in range(ny) for ix in range(nx)]

        ny, nx = _norm_split(n_roi_split)
        if verbose:
            print(f"🔲 Splitting ROI into {ny}x{nx} = {ny*nx} tiles ...")
        tile_bboxes = _split_bbox((minx, miny, maxx, maxy), ny, nx)
        tile_tags = [f"{ty}x{tx}" for ty in range(ny) for tx in range(nx)]

        # ---------- Helpers shared by cache builder and main flow ----------
        def _grid_def(bbox, res):
            x0, y0, x1, y1 = bbox
            W = int(math.ceil((x1 - x0) / res)); H = int(math.ceil((y1 - y0) / res))
            transform = from_origin(x0, y1, res, res)
            area = geometry.AreaDefinition("roi", "roi grid", "epsg4326",
                                           {"proj": "longlat", "datum": "WGS84"},
                                           W, H, [x0, y0, x1, y1])
            return area, transform, W, H

        def _mask(arr, transform, w, h):
            if roi_geom is None:
                return arr
            try:
                msk = rasterize([(roi_geom, 1)], out_shape=(h, w),
                                transform=transform, fill=0, dtype="uint8")
                out = arr.copy(); out[msk == 0] = np.nan; return out
            except Exception:
                return arr

        def _write_tif(path, arr, transform, w, h):
            prof = {
                "driver": "GTiff", "height": h, "width": w, "count": 1, "dtype": "float32",
                "crs": "EPSG:4326", "transform": transform, "compress": "deflate",
                "predictor": 2, "tiled": True, "blockxsize": 256, "blockysize": 256,
                "nodata": np.float32(np.nan)
            }
            os.makedirs(os.path.dirname(path) or ".", exist_ok=True)
            with rasterio.open(path, "w", **prof) as dst:
                dst.write(arr, 1)

        # ---------- Build mosaics from cached tiles (robust scanning) ----------
        def _build_from_cached(days_filter: set[str] | None = None, _mask_fn=None) -> dict:
            if _mask_fn is None:
                _mask_fn = _mask

            # Accept many name styles. We only require Band, Day (YYYYMMDD), and tileYxX.
            per_granule_pat = re.compile(
                r'(?i)(?:^|[_-])(?P<band>B0[1-7])(?:[_-]|$).*?(?:^|[_-])(?P<day>\d{8})(?:[_-]|$).*?(?:^|[_-])tile(?P<tag>\d+x\d+)(?:[_-]|$)'
            )
            tile_mosaic_pat = re.compile(
                r'(?i)(?:^|[_-])(?P<band>B0[1-7])(?:[_-]|$).*?(?:^|[_-])(?P<day>\d{8})(?:[_-]|$).*?(?:^|[_-])tile(?P<tag>\d+x\d+)(?:[_-]|$)'
            )

            def _parse_name_generic(name: str):
                b = re.search(r'(?i)B0[1-7]', name)
                d = re.search(r'(?<!\d)(\d{8})(?!\d)', name)
                t = re.search(r'(?i)tile(\d+x\d+)', name)
                if b and d and t:
                    return b.group(0).upper(), d.group(1), t.group(1)
                return None

            wanted_days = set(days_filter) if days_filter else set(all_days)
            wanted_bands = set(bands_wanted)
            tag_set = set(tile_tags)

            per_tile_groups = defaultdict(list)  # (day, band, tag) -> [paths]

            # Scan per‑granule tiles
            try:
                it = os.scandir(granule_tif_dir)
            except FileNotFoundError:
                it = []
            for de in tqdm(it, desc="📦 Use cached tiles", unit="file", disable=not show_progress):
                if not getattr(de, "is_file", lambda: False)():
                    continue
                fn = de.name
                m = per_granule_pat.search(fn)
                if not m:
                    m2 = _parse_name_generic(fn)
                    if not m2:
                        continue
                    band, day, tag = m2
                else:
                    band = m.group("band").upper()
                    day = m.group("day")
                    tag = m.group("tag")
                if band not in wanted_bands or (wanted_days and day not in wanted_days) or tag not in tag_set:
                    continue
                per_tile_groups[(day, band, tag)].append(os.path.join(granule_tif_dir, fn))

            # If none, scan _tile_mosaics (will re-merge but fine)
            if not per_tile_groups:
                try:
                    it2 = os.scandir(tile_mosaic_dir)
                except FileNotFoundError:
                    it2 = []
                for de in tqdm(it2, desc="📦 Use cached tile mosaics", unit="file", disable=not show_progress):
                    if not getattr(de, "is_file", lambda: False)():
                        continue
                    fn = de.name
                    m = tile_mosaic_pat.search(fn)
                    if not m:
                        m2 = _parse_name_generic(fn)
                        if not m2:
                            continue
                        band, day, tag = m2
                    else:
                        band = m.group("band").upper()
                        day = m.group("day")
                        tag = m.group("tag")
                    if band not in wanted_bands or (wanted_days and day not in wanted_days) or tag not in tag_set:
                        continue
                    per_tile_groups[(day, band, tag)].append(os.path.join(tile_mosaic_dir, fn))

            # If still nothing, but final outputs exist, report them
            if not per_tile_groups:
                finals = []
                for day in sorted(wanted_days):
                    for b in sorted(wanted_bands):
                        fp = os.path.join(output_folder, f"{filename_prefix}_{b}_{day}.tif")
                        if os.path.exists(fp):
                            finals.append(fp)
                if finals:
                    if verbose:
                        print(f"✅ Final outputs already exist for {len(finals)} file(s).")
                    return {
                        "processed_pairs": 0,
                        "written": 0,
                        "days_processed": 0,
                        "skipped_days": [],
                        "paths": finals,
                        "dashboard": None,
                    }
                if verbose:
                    print("ℹ️ No cached per‑granule tiles or tile mosaics found for requested days.")
                return {"processed_pairs": 0, "written": 0, "days_processed": 0, "skipped_days": [], "paths": [], "dashboard": None}

            # Build per‑tile mosaics
            final_tile_mosaics = defaultdict(list)  # (day, band) -> [tile mosaic paths]
            for (day, b, tag), tif_list in tqdm(sorted(per_tile_groups.items()),
                                                total=len(per_tile_groups),
                                                desc="🧬 Tile mosaics (cached)",
                                                unit="tile",
                                                disable=not show_progress):
                if not tif_list:
                    continue
                tile_out = os.path.join(tile_mosaic_dir, f"{filename_prefix}_{b}_{day}_tile{tag}.tif")
                if (not overwrite) and os.path.exists(tile_out):
                    final_tile_mosaics[(day, b)].append(tile_out)
                    continue
                try:
                    srcs = [rasterio.open(p) for p in tif_list]
                    mosaic, out_transform = rio_merge(srcs, method="first")
                    for s in srcs:
                        s.close()
                    if mosaic.ndim == 3 and mosaic.shape[0] == 1:
                        mosaic = mosaic[0]
                    mosaic = _mask_fn(mosaic, out_transform, mosaic.shape[1], mosaic.shape[0])
                    _write_tif(tile_out, mosaic.astype(np.float32, copy=False),
                               out_transform, mosaic.shape[1], mosaic.shape[0])
                    final_tile_mosaics[(day, b)].append(tile_out)
                except Exception as e:
                    if verbose:
                        print(f"⚠️ Tile mosaic (cached) failed {day} {b} tile{tag}: {e}")

            # Final daily mosaics
            written = []
            days_processed = set()
            for (day, b), tile_paths in tqdm(sorted(final_tile_mosaics.items()),
                                             total=len(final_tile_mosaics),
                                             desc="🧷 Final mosaics (cached)",
                                             unit="day×band",
                                             disable=not show_progress):
                if not tile_paths:
                    continue
                out_fp = os.path.join(output_folder, f"{filename_prefix}_{b}_{day}.tif")
                if (not overwrite) and os.path.exists(out_fp):
                    continue
                try:
                    srcs = [rasterio.open(p) for p in tile_paths]
                    mosaic, out_transform = rio_merge(srcs, method="first")
                    for s in srcs:
                        s.close()
                    if mosaic.ndim == 3 and mosaic.shape[0] == 1:
                        mosaic = mosaic[0]
                    mosaic = _mask_fn(mosaic, out_transform, mosaic.shape[1], mosaic.shape[0])
                    _write_tif(out_fp, mosaic.astype(np.float32, copy=False),
                               out_transform, mosaic.shape[1], mosaic.shape[0])
                    written.append(out_fp)
                    days_processed.add(day)
                except Exception as e:
                    if verbose:
                        print(f"⚠️ Final mosaic (cached) failed {day} {b}: {e}")

            if verbose:
                print(f"✅ Cached mosaics complete. Days={len(days_processed)} Written={len(written)}")

            return {
                "processed_pairs": 0,
                "written": len(written),
                "days_processed": len(days_processed),
                "skipped_days": [],
                "paths": written,
                "dashboard": None
            }

        # ---------- Build-from-cache first, then drop already-done days ----------
        try:
            has_cached_tiles = any((de.is_file() and de.name.lower().endswith(".tif")) for de in os.scandir(granule_tif_dir))
        except FileNotFoundError:
            has_cached_tiles = False
        try:
            has_tile_mosaics = any((de.is_file() and de.name.lower().endswith(".tif")) for de in os.scandir(tile_mosaic_dir))
        except FileNotFoundError:
            has_tile_mosaics = False

        if has_cached_tiles or has_tile_mosaics:
            if verbose:
                print("🧱 Found cached tiles. Building mosaics from cache before search/download ...")
            _build_from_cached(set(all_days), _mask_fn=_mask)

        if not overwrite:
            already_done = []
            for day in list(all_days):
                if all(os.path.exists(os.path.join(output_folder, f"{filename_prefix}_{b}_{day}.tif")) for b in sorted(bands_wanted)):
                    already_done.append(day)
            if already_done and verbose:
                snippet = ", ".join(already_done[:6]) + (" ..." if len(already_done) > 6 else "")
                print(f"⏭️ Skipping {len(already_done)} day(s) (final outputs exist): {snippet}")
            all_days = [d for d in all_days if d not in set(already_done)]
            if not all_days:
                return {
                    "processed_pairs": 0,
                    "written": 0,
                    "days_processed": 0,
                    "skipped_days": already_done,
                    "paths": [os.path.join(output_folder, f"{filename_prefix}_{b}_{d}.tif")
                              for d in already_done for b in sorted(bands_wanted)
                              if os.path.exists(os.path.join(output_folder, f"{filename_prefix}_{b}_{d}.tif"))],
                    "dashboard": None
                }

        # ---------- Cache scan to skip search for fully-cached days ----------
        cache_regex = re.compile(
            r'.*[_-]?(B0[1-7])[_-](\d{8})(?:[_-]A\d{11})?[_-]tile\d+x\d+\.tif$',
            re.IGNORECASE
        )
        day_band_hits: dict[str, set[str]] = defaultdict(set)

        try:
            files = [de for de in tqdm(os.scandir(granule_tif_dir),
                                       desc="🗂️ Index cache (scan dir)",
                                       unit="file",
                                       disable=not show_progress)]
        except FileNotFoundError:
            files = []

        matched = 0
        for de in tqdm(files, desc="🗂️ Index cache", unit="file", disable=not show_progress):
            if not de.is_file():
                continue
            m = cache_regex.match(de.name)
            if not m:
                continue
            matched += 1
            band = m.group(1).upper()
            day = m.group(2)
            day_band_hits[day].add(band)

        if verbose:
            print(f"🧩 Cache index matched {matched} tile TIFF(s) in {granule_tif_dir}")

        skipped_days = []
        needed_days = []
        for day in all_days:
            if (not overwrite) and day in day_band_hits and bands_wanted.issubset(day_band_hits[day]):
                skipped_days.append(day)
                if verbose:
                    print(f"{day}: skipped downloading HDF because it exists (cached tiles found).")
            else:
                needed_days.append(day)

        if verbose and skipped_days:
            print(f"⏭️ Skipping {len(skipped_days)} day(s) already cached.")
        if not needed_days:
            if verbose:
                print("🧱 All requested days appear cached. Building mosaics from cache ...")
            return _build_from_cached(set(all_days), _mask_fn=_mask)

        # ---------- Login ----------
        if verbose:
            print("🔑 Logging into Earthdata ...")
        try:
            if edl_username and edl_password:
                ea.login(strategy="environment", username=edl_username, password=edl_password)
            elif login_strategy:
                ea.login(strategy=login_strategy)
            else:
                ea.login()
        except Exception as e:
            raise RuntimeError(f"earthaccess login failed: {e}")

        # ---------- Dask ----------
        dask_client = None
        dask_cluster = None
        dashboard_url = None
        if use_dask:
            try:
                from dask.distributed import Client, LocalCluster, default_client
                try:
                    dask_client = default_client()
                except Exception:
                    if n_workers == "auto":
                        n_workers = max(1, os.cpu_count() // 2)
                    if threads_per_worker == "auto":
                        threads_per_worker = 1 if scheduler == "processes" else max(1, os.cpu_count() // max(1, int(n_workers)))
                    dask_cluster = LocalCluster(
                        n_workers=int(n_workers),
                        threads_per_worker=int(threads_per_worker),
                        processes=(scheduler == "processes"),
                        dashboard_address=":0",
                    )
                    dask_client = Client(dask_cluster)
                dashboard_url = getattr(dask_client, "dashboard_link", None)
                if verbose and dashboard_url:
                    print(f"📊 Dask dashboard: {dashboard_url}")
            except Exception as e:
                if verbose:
                    print(f"⚠️ Dask disabled ({e}); running serial.")
                dask_client = None
                dask_cluster = None
                use_dask = False

        # ---------- MODIS helpers ----------
        try:
            from pyhdf.SD import SD, SDC
        except Exception as e:
            raise RuntimeError("pyhdf required (HDF4). pip install pyhdf") from e

        def _granule_name(gran) -> str:
            import os, re
            # Direct string path
            if isinstance(gran, str):
                return os.path.basename(gran)

            # Common metadata dicts
            for attr in ("umm", "meta", "metadata"):
                d = getattr(gran, attr, None)
                if isinstance(d, dict):
                    for k in ("GranuleUR", "granuleUr", "title", "name", "filename"):
                        v = d.get(k)
                        if v:
                            return v

            # Assets (STAC-like)
            assets = getattr(gran, "assets", None)
            if isinstance(assets, dict):
                for v in assets.values():
                    href = (v or {}).get("href") or (v or {}).get("URL") or (v or {}).get("url")
                    if href:
                        return os.path.basename(href)

            # Links/data_links may be methods or lists
            for attr in ("data_links", "links"):
                obj = getattr(gran, attr, None)
                try:
                    seq = obj() if callable(obj) else obj
                except Exception:
                    seq = None
                if not seq:
                    continue
                try:
                    for u in seq:
                        # plain URL string
                        if isinstance(u, str):
                            if u.lower().endswith(".hdf"):
                                return os.path.basename(u)
                            base = os.path.basename(u)
                            if base:
                                return base
                        # dict-like link
                        if isinstance(u, dict):
                            href = u.get("href") or u.get("URL") or u.get("url")
                            if href:
                                return os.path.basename(href)
                except Exception:
                    pass

            # Fallback: parse from string representation
            s = str(gran)
            m = re.search(r"(MOD[0-9A-Z]+\.A\d{7}\.\d{4}\.\d{3}\.\d+\.hdf)", s)
            if m:
                return m.group(1)

            return ""

        def _token(name):
            # MOD02HKM.AYYYYDOY.HHMM. -> AYYYYDOYHHMM
            m = re.search(r'\.A(\d{7})\.(\d{4})\.', name or "")
            return f"A{m.group(1)}{m.group(2)}" if m else ""

        def _day_from_name(name: str) -> str:
            # Prefer MODIS token AYYYYDOYHHMM when present
            m = re.search(r"A(\d{4})(\d{3})(?:\.?\d{4})?", name or "")
            if m:
                year = int(m.group(1)); doy = int(m.group(2))
                return (datetime(year, 1, 1) + timedelta(days=doy - 1)).strftime("%Y%m%d")
            # Fallback: 8-digit date found in cached file names ..._YYYYMMDD_...
            m2 = re.search(r"(?:^|[_-])(\d{8})(?:[_-]|$)", name or "")
            return m2.group(1) if m2 else ""

        def _open(gran):
            if isinstance(gran, str) and os.path.isfile(gran):
                return gran
            name = _granule_name(gran)
            cached = os.path.join(cache_dir, name) if name else None
            if cached and os.path.exists(cached):
                return cached
            paths = ea.download([gran], provider="LAADS", local_path=cache_dir)
            if isinstance(paths, dict):
                lp = next(iter(paths.values()), None)
            elif isinstance(paths, (list, tuple)):
                lp = paths[0] if paths else None
            else:
                lp = None
            if not lp or not os.path.exists(lp):
                raise FileNotFoundError("Download failed")
            if verbose:
                print(f"⬇️  Downloaded: {os.path.basename(lp)}")
            return lp

        def _attrs(ds):
            a = ds.attributes()
            return a.get("reflectance_scales"), a.get("reflectance_offsets")

        def _read_geo(p):
            # Try HDF5 first (rare)
            if h5py:
                try:
                    import h5py as _h5
                    with _h5.File(p, "r") as f:
                        if "Latitude" in f and "Longitude" in f:
                            lat = f["Latitude"][()].astype(np.float32)
                            lon = f["Longitude"][()].astype(np.float32)
                            lon = np.where(lon > 180, lon - 360, lon)
                            return lat, lon
                except Exception:
                    pass
            # HDF4 fallback
            sd = SD(p, SDC.READ)
            try:
                lat = sd.select("Latitude").get().astype(np.float32)
                lon = sd.select("Longitude").get().astype(np.float32)
                lon = np.where(lon > 180, lon - 360, lon)
                return lat, lon
            finally:
                sd.end()

        def _read_toa(p):
            out = {}
            sd = SD(p, SDC.READ)
            try:
                try:
                    ds250 = sd.select("EV_250_Aggr500_RefSB")
                    arr250 = ds250.get().astype(np.float32)
                    s250, o250 = _attrs(ds250)
                except Exception:
                    arr250 = None; s250 = o250 = None
                try:
                    ds500 = sd.select("EV_500_RefSB")
                    arr500 = ds500.get().astype(np.float32)
                    s500, o500 = _attrs(ds500)
                except Exception:
                    arr500 = None; s500 = o500 = None
            finally:
                sd.end()

            def _scale(v, i, dv):
                try:
                    a = np.array(v)
                    if a.ndim == 1 and i < a.size:
                        return float(a[i])
                    if a.size == 1:
                        return float(a.item())
                except Exception:
                    pass
                return float(dv)

            if arr250 is not None:
                for i, b in {0: "B01", 1: "B02"}.items():
                    a = arr250[i] * _scale(s250, i, 1.0) + _scale(o250, i, 0.0)
                    a[a < 0] = np.nan
                    out[b] = a.astype(np.float32)
            if arr500 is not None:
                for i, b in {0: "B03", 1: "B04", 2: "B05", 3: "B06", 4: "B07"}.items():
                    a = arr500[i] * _scale(s500, i, 1.0) + _scale(o500, i, 0.0)
                    a[a < 0] = np.nan
                    out[b] = a.astype(np.float32)
            return out

        def _align(lat, lon, band):
            gl, gs = lat.shape; bl, bs = band.shape
            if (gl, gs) == (bl, bs):
                return lat, lon
            if gl * 2 == bl and gs * 2 == bs:
                lat_u = np.repeat(np.repeat(lat, 2, axis=0), 2, axis=1)
                lon_u = np.repeat(np.repeat(lon, 2, axis=0), 2, axis=1)
                return lat_u, lon_u
            ry = max(1, round(bl / max(1, gl))); rx = max(1, round(bs / max(1, gs)))
            lat_u = np.repeat(np.repeat(lat, ry, axis=0), rx, axis=1)[:bl, :bs]
            lon_u = np.repeat(np.repeat(lon, ry, axis=0), rx, axis=1)[:bl, :bs]
            return lat_u, lon_u

        def _resample_to_grid(band, lat, lon, area, radius):
            lat, lon = _align(lat, lon, band)
            vals = band.ravel(); lats = lat.ravel(); lons = lon.ravel()
            m = np.isfinite(vals)
            if not m.any():
                return np.full(area.shape, np.nan, dtype=np.float32)
            vals = vals[m]; lats = lats[m]; lons = lons[m]
            sw = geometry.SwathDefinition(lons=lons, lats=lats)
            with warnings.catch_warnings():
                warnings.simplefilter("ignore")
                g = kd_tree.resample_nearest(sw, vals, area,
                                             radius_of_influence=max(1000, int(radius)),
                                             fill_value=np.nan, reduce_data=True, nprocs=1)
            return g.astype(np.float32)

        # ---------- Search granules (one-shot per product) ----------
        if verbose:
            print(f"🔍 Searching granules for {len(needed_days)} day(s) ...")

        need_terra = platform.lower() in ("terra", "both")
        need_aqua = platform.lower() in ("aqua", "both")

        granules_l1b = []
        granules_geo = []

        # include end-day boundary
        full_start = datetime.strptime(needed_days[0], "%Y%m%d") if needed_days else start_dt
        full_end = datetime.strptime(needed_days[-1], "%Y%m%d") + timedelta(days=1) if needed_days else (end_dt + timedelta(days=1))

        def _search_once(short_name: str, sd, ed, bbox):
            return ea.search_data(
                short_name=short_name,
                temporal=(sd, ed),
                bounding_box=bbox,
                provider="LAADS",
                granule_name="*.hdf",
            )

        if need_terra:
            if verbose: print("🛰️ Searching MOD02HKM / MOD03 once for full range ...")
            granules_l1b += _search_once("MOD02HKM", full_start, full_end, (minx, miny, maxx, maxy))
            granules_geo += _search_once("MOD03",    full_start, full_end, (minx, miny, maxx, maxy))
        if need_aqua:
            if verbose: print("🛰️ Searching MYD02HKM / MYD03 once for full range ...")
            granules_l1b += _search_once("MYD02HKM", full_start, full_end, (minx, miny, maxx, maxy))
            granules_geo += _search_once("MYD03",    full_start, full_end, (minx, miny, maxx, maxy))

        # Pair L1B with GEO by token, keep only needed days
        if verbose:
            print("🔗 Pairing L1B and GEO granules ...")

        wanted_days_set = set(needed_days)

        geo_by_token = {}
        for g in granules_geo:
            nm = _granule_name(g)
            geo_by_token[_token(nm)] = g

        pairs = []
        for l in granules_l1b:
            ln = _granule_name(l)
            dk = _day_from_name(ln)
            if dk and dk not in wanted_days_set:
                continue
            tn = _token(ln)
            gg = geo_by_token.get(tn)
            if gg:
                pairs.append((l, gg))

        if not pairs:
            # Try building purely from cache before giving up
            result = _build_from_cached(set(needed_days) if needed_days else set(all_days), _mask_fn=_mask)
            if result["written"] or result["days_processed"]:
                return result
            if verbose:
                print("ℹ️ No new granule pairs to process and nothing cached to mosaic.")
            return {
                "processed_pairs": 0,
                "written": 0,
                "days_processed": 0,
                "skipped_days": skipped_days,
                "paths": [],
                "dashboard": dashboard_url
            }

        # ---------- Process pairs ----------
        per_tile_groups = defaultdict(list)  # (day, band, tile_tag) -> [tif paths]

        def _process_tile(sw_path, geo_path, bbox_t, tile_tag):
            out = []
            try:
                sw_name = os.path.basename(sw_path)
                day = _day_from_name(sw_name) or "unknown"
                area, transform, W, H = _grid_def(bbox_t, res_deg)

                # Reuse existing per‑granule per‑tile TIFFs if they all exist
                gtok = _token(sw_name)
                reuse_all = True
                for b in bands_wanted:
                    tif = os.path.join(granule_tif_dir, f"{filename_prefix}_{b}_{day}_{gtok}_tile{tile_tag}.tif")
                    if not ((not overwrite) and os.path.exists(tif)):
                        reuse_all = False
                        break
                if reuse_all:
                    for b in bands_wanted:
                        tif = os.path.join(granule_tif_dir, f"{filename_prefix}_{b}_{day}_{gtok}_tile{tile_tag}.tif")
                        out.append((day, b, tile_tag, tif))
                    return out

                lat, lon = _read_geo(geo_path)
                bands = _read_toa(sw_path)
                for b, arr in bands.items():
                    if b not in bands_wanted or arr is None or not np.isfinite(arr).any():
                        continue
                    grid = _resample_to_grid(arr, lat, lon, area, radius_m)
                    grid = _mask(grid, transform, W, H)
                    tif = os.path.join(granule_tif_dir, f"{filename_prefix}_{b}_{day}_{gtok}_tile{tile_tag}.tif")
                    if overwrite or not os.path.exists(tif):
                        _write_tif(tif, grid, transform, W, H)
                    out.append((day, b, tile_tag, tif))
                return out
            except Exception as e:
                if verbose:
                    print(f"⚠️ Tile {tile_tag} failed: {e}")
                return out

        pair_iter = tqdm(pairs, desc="📦 Granule pairs", unit="pair", disable=not show_progress)
        for sw_g, geo_g in pair_iter:
            sw_nm = _granule_name(sw_g)
            day_current = _day_from_name(sw_nm)
            if (not overwrite) and day_current in skipped_days:
                if verbose:
                    print(f"⏭️ Day {day_current} cached (skipping pair).")
                continue

            sw_path = _open(sw_g)
            geo_path = _open(geo_g)

            # Tiles
            if use_dask and dask_client:
                tasks = [dask_client.submit(_process_tile, sw_path, geo_path, bbox_t, tag)
                         for bbox_t, tag in zip(tile_bboxes, tile_tags)]
                # progress
                try:
                    from dask.distributed import as_completed as _as_completed
                except Exception:
                    _as_completed = None
                results = []
                if _as_completed is not None:
                    pbar = tqdm(total=len(tasks), desc="🧠 Tiles (dask)", unit="tile", disable=not show_progress)
                    for fut in _as_completed(tasks):
                        try:
                            results.append(fut.result())
                        except Exception as e:
                            if verbose:
                                print(f"⚠️ Tile task failed: {e}")
                        pbar.update(1)
                    pbar.close()
                else:
                    results = dask_client.gather(tasks)
            else:
                results = []
                for bbox_t, tag in tqdm(zip(tile_bboxes, tile_tags),
                                        total=len(tile_bboxes),
                                        desc="🧩 Tiles (serial)",
                                        unit="tile",
                                        disable=not show_progress):
                    results.append(_process_tile(sw_path, geo_path, bbox_t, tag))

            # Collect outputs
            for lst in results:
                for day, b, tag, tif in lst:
                    if day != "unknown":
                        per_tile_groups[(day, b, tag)].append(tif)

            if remove_cache:
                for p in (sw_path, geo_path):
                    try:
                        if p and os.path.isfile(p):
                            os.remove(p)
                    except Exception:
                        pass
                if verbose:
                    print("🧹 Removed cached HDFs for completed swath.")

        # ---------- Build per‑tile mosaics ----------
        final_tile_mosaics = defaultdict(list)  # (day, band) -> [tile mosaic paths]
        for (day, b, tag), tif_list in tqdm(sorted(per_tile_groups.items()),
                                            total=len(per_tile_groups),
                                            desc="🧬 Tile mosaics",
                                            unit="tile",
                                            disable=not show_progress):
            if not tif_list:
                continue
            tile_out = os.path.join(tile_mosaic_dir, f"{filename_prefix}_{b}_{day}_tile{tag}.tif")
            if (not overwrite) and os.path.exists(tile_out):
                final_tile_mosaics[(day, b)].append(tile_out)
                continue
            try:
                srcs = [rasterio.open(p) for p in tif_list]
                mosaic, out_transform = rio_merge(srcs, method="first")
                for s in srcs:
                    s.close()
                if mosaic.ndim == 3 and mosaic.shape[0] == 1:
                    mosaic = mosaic[0]
                mosaic = _mask(mosaic, out_transform, mosaic.shape[1], mosaic.shape[0])
                _write_tif(tile_out, mosaic.astype(np.float32, copy=False),
                           out_transform, mosaic.shape[1], mosaic.shape[0])
                final_tile_mosaics[(day, b)].append(tile_out)
            except Exception as e:
                if verbose:
                    print(f"⚠️ Tile mosaic failed {day} {b} tile{tag}: {e}")

        # ---------- Final mosaics ----------
        written = []
        days_processed = set()
        for (day, b), tile_paths in tqdm(sorted(final_tile_mosaics.items()),
                                         total=len(final_tile_mosaics),
                                         desc="🧷 Final mosaics",
                                         unit="day×band",
                                         disable=not show_progress):
            if not tile_paths:
                continue
            out_fp = os.path.join(output_folder, f"{filename_prefix}_{b}_{day}.tif")
            if (not overwrite) and os.path.exists(out_fp):
                continue
            try:
                srcs = [rasterio.open(p) for p in tile_paths]
                mosaic, out_transform = rio_merge(srcs, method="first")
                for s in srcs:
                    s.close()
                if mosaic.ndim == 3 and mosaic.shape[0] == 1:
                    mosaic = mosaic[0]
                mosaic = _mask(mosaic, out_transform, mosaic.shape[1], mosaic.shape[0])
                _write_tif(out_fp, mosaic.astype(np.float32, copy=False),
                           out_transform, mosaic.shape[1], mosaic.shape[0])
                written.append(out_fp)
                days_processed.add(day)
            except Exception as e:
                if verbose:
                    print(f"⚠️ Final mosaic failed {day} {b}: {e}")

        if verbose:
            print(f"✅ Done. Days processed={len(days_processed)} | Skipped={len(skipped_days)} | Written={len(written)}")

        # Teardown dask
        if use_dask and ('dask_client' in locals()) and dask_client:
            try:
                dask_client.close()
                if dask_cluster:
                    dask_cluster.close()
            except Exception:
                pass

        return {
            "processed_pairs": len(pairs),
            "written": len(written),
            "days_processed": len(days_processed),
            "skipped_days": skipped_days,
            "paths": written,
            "dashboard": dashboard_url,
        }


    def download_modis_toa_v13_11(
        self,
        band_list: list[str] | str,
        output_folder: str,
        roi: tuple[float, float, float, float] | str,
        start_date: str,
        end_date: str,
        *,
        platform: str = "terra",         # "terra" | "aqua" | "both"
        res_deg: float = 0.0045,         # ~500 m @ equator
        radius_m: int = 4000,
        filename_prefix: str = "modis_toa",
        overwrite: bool = False,
        verbose: bool = True,
        edl_username: str | None = None,
        edl_password: str | None = None,
        login_strategy: str | None = None,
        temp_dir: str | None = None,
        use_dask: bool = True,
        n_workers: int | str = "auto",
        threads_per_worker: int | str = "auto",
        scheduler: str = "processes",
        n_roi_split: int | tuple[int, int] = 100,
        show_progress: bool = True,
        remove_cache: bool = False,
    ) -> dict:
        import os, re, math, warnings, tempfile
        from collections import defaultdict
        from datetime import datetime, timedelta
        from glob import glob

        import numpy as np
        import rasterio
        from rasterio.merge import merge as rio_merge
        from rasterio.transform import from_origin
        from rasterio.features import rasterize

        try:
            from tqdm.auto import tqdm
        except Exception:
            def tqdm(x, **k): return x  # fallback no-op

        # IO
        os.makedirs(output_folder, exist_ok=True)
        cache_dir = os.path.join(output_folder, "_earthaccess_cache")
        os.makedirs(cache_dir, exist_ok=True)
        granule_tif_dir = os.path.join(output_folder, "_granule_tifs")
        os.makedirs(granule_tif_dir, exist_ok=True)
        tile_mosaic_dir = os.path.join(output_folder, "_tile_mosaics")
        os.makedirs(tile_mosaic_dir, exist_ok=True)

        tmp_root = temp_dir or os.path.join(output_folder, "_tmp")
        os.makedirs(tmp_root, exist_ok=True)
        tempfile.tempdir = tmp_root
        os.environ.setdefault("CPL_TMPDIR", tmp_root)
        os.environ.setdefault("GDAL_CACHEMAX", "256")

        # Bands
        ALL_BANDS = ["B01", "B02", "B03", "B04", "B05", "B06", "B07"]
        if isinstance(band_list, str) and band_list.lower() == "all":
            bands_wanted = set(ALL_BANDS)
        else:
            bands_wanted = {str(b).upper() for b in band_list}
            unknown = bands_wanted - set(ALL_BANDS)
            if unknown:
                raise ValueError(f"Unknown band(s): {sorted(unknown)}. Valid: {ALL_BANDS}")

        # ROI
        roi_geom = None
        minx = miny = maxx = maxy = None
        try:
            import geopandas as gpd
            from shapely.ops import unary_union
        except Exception:
            gpd = None
            unary_union = None

        if isinstance(roi, str):
            if gpd is None or unary_union is None:
                raise RuntimeError("Vector ROI requires geopandas and shapely.")
            if not os.path.exists(roi):
                raise FileNotFoundError(f"ROI not found: {roi}")
            gdf = gpd.read_file(roi)
            if gdf.empty:
                raise ValueError("Vector ROI is empty.")
            if gdf.crs is None or str(gdf.crs).upper() not in ("EPSG:4326", "OGC:CRS84"):
                gdf = gdf.to_crs("EPSG:4326")
            roi_geom = unary_union([g for g in gdf.geometry if g is not None and not g.is_empty])
            if roi_geom.is_empty:
                raise ValueError("Vector ROI union is empty.")
            minx, miny, maxx, maxy = roi_geom.bounds
        else:
            minx, miny, maxx, maxy = map(float, roi)
            if (maxx - minx) <= 0 or (maxy - miny) <= 0:
                raise ValueError("ROI bbox must have positive area.")

        # Date range
        start_dt = datetime.strptime(start_date, "%Y-%m-%d")
        end_dt = datetime.strptime(end_date, "%Y-%m-%d")
        if end_dt < start_dt:
            raise ValueError("end_date < start_date")
        all_days = [(start_dt + timedelta(days=i)).strftime("%Y%m%d")
                    for i in range((end_dt - start_dt).days + 1)]

        # Tiling helpers
        def _norm_split(v):
            if isinstance(v, (list, tuple)) and len(v) == 2:
                ny = max(1, int(v[0])); nx = max(1, int(v[1])); return ny, nx
            n = max(1, int(v)); ny = int(math.sqrt(n)); nx = max(1, int(math.ceil(n / ny))); return ny, nx

        def _split_bbox(bbox, ny, nx):
            x0, y0, x1, y1 = bbox
            dx = (x1 - x0) / nx; dy = (y1 - y0) / ny
            return [(x0 + ix * dx, y0 + iy * dy, x0 + (ix + 1) * dx, y0 + (iy + 1) * dy)
                    for iy in range(ny) for ix in range(nx)]

        ny, nx = _norm_split(n_roi_split)
        
        print(f"🔲 Splitting ROI into {ny}x{nx} = {ny*nx} tiles ...")
        tile_bboxes = _split_bbox((minx, miny, maxx, maxy), ny, nx)
        tile_tags = [f"{ty}x{tx}" for ty in range(ny) for tx in range(nx)]
        
        
        # ---------- Build from cache first (before searching/downloading) ----------
        # If any cached per‑granule tiles exist, build per‑tile mosaics and final outputs now.
        try:
            has_cached_tiles = any(
                (de.is_file() and de.name.lower().endswith(".tif"))
                for de in os.scandir(granule_tif_dir)
            )
        except FileNotFoundError:
            has_cached_tiles = False
        try:
            has_tile_mosaics = any(
                (de.is_file() and de.name.lower().endswith(".tif"))
                for de in os.scandir(tile_mosaic_dir)
            )
        except FileNotFoundError:
            has_tile_mosaics = False

        if has_cached_tiles or has_tile_mosaics:
            if verbose:
                print("🧱 Found cached tiles. Building mosaics from cache before search/download ...")
            # Build mosaics from any cached tiles for requested days
            _build_from_cached(set(all_days))

        # After building from cache, if overwrite=False, drop days that already have final outputs
        if not overwrite:
            already_done = []
            for day in list(all_days):
                if all(os.path.exists(os.path.join(output_folder, f"{filename_prefix}_{b}_{day}.tif"))
                       for b in sorted(bands_wanted)):
                    already_done.append(day)
            if already_done and verbose:
                print(f"⏭️ Skipping {len(already_done)} day(s) (final outputs exist): "
                      f"{', '.join(already_done[:6])}{' ...' if len(already_done) > 6 else ''}")
            # keep only days that still need work
            all_days = [d for d in all_days if d not in set(already_done)]

            # If all days are done from cache, return early
            if not all_days:
                return {
                    "processed_pairs": 0,
                    "written": 0,
                    "days_processed": 0,
                    "skipped_days": already_done,
                    "paths": [os.path.join(output_folder, f"{filename_prefix}_{b}_{d}.tif")
                              for d in already_done for b in sorted(bands_wanted)
                              if os.path.exists(os.path.join(output_folder, f"{filename_prefix}_{b}_{d}.tif"))],
                    "dashboard": None
                }
        
        

        # ---------- Cache scan with progress ----------
        # We consider a day "cached" if every requested band has at least one tile TIFF for that day
         # Accept patterns like:
        #   anyPrefix_B0X_YYYYMMDD_Ayyyydoyhhmm_tileYxX.tif
        #   anyPrefix-B0X-YYYYMMDD-tileYxX.tif
        #   anyPrefix_B0X_YYYYMMDD_tileYxX.tif
        cache_regex = re.compile(
            r'.*[_-]?(B0[1-7])[_-](\d{8})(?:[_-]A\d{11})?[_-]tile\d+x\d+\.tif$',
            re.IGNORECASE
        )
        day_band_hits: dict[str, set[str]] = defaultdict(set)

        try:
            # fast scandir with tqdm wrapper
            files = [de for de in tqdm(
                os.scandir(granule_tif_dir),
                desc="🗂️ Index cache (scan dir)",
                unit="file",
                disable=not show_progress
            )]
        except FileNotFoundError:
            files = []

        matched = 0
        for de in tqdm(files, desc="🗂️ Index cache", unit="file", disable=not show_progress):
            if not de.is_file():
                continue
            m = cache_regex.match(de.name)
            if not m:
                continue
            matched += 1
            band = m.group(1).upper()
            day = m.group(2)
            day_band_hits[day].add(band)

        if verbose:
            print(f"🧩 Cache index matched {matched} tile TIFF(s) in {granule_tif_dir}")

        skipped_days = []
        needed_days = []
        for day in all_days:
            if (not overwrite) and day in day_band_hits and bands_wanted.issubset(day_band_hits[day]):
                skipped_days.append(day)
                if verbose:
                    print(f"{day}: skipped downloading HDF because it exists (cached tiles found).")
            else:
                needed_days.append(day)

        if verbose and skipped_days:
            print(f"⏭️ Skipping {len(skipped_days)} day(s) already cached.")

        if not needed_days:
            if verbose:
                print("🧱 All requested days appear cached. Building mosaics from cache ...")
            return _build_from_cached(set(all_days))

        # ---------- Login (progress print) ----------
        if verbose:
            print("🔑 Logging into Earthdata ...")
        try:
            import earthaccess as ea
            if edl_username and edl_password:
                ea.login(strategy="environment", username=edl_username, password=edl_password)
            elif login_strategy:
                ea.login(strategy=login_strategy)
            else:
                ea.login()
        except Exception as e:
            raise RuntimeError(f"earthaccess login failed: {e}")

        # ---------- External deps for processing ----------
        try:
            from pyresample import geometry, kd_tree
        except Exception as e:
            raise RuntimeError("pyresample required. pip install pyresample") from e
        try:
            from pyhdf.SD import SD, SDC
        except Exception as e:
            raise RuntimeError("pyhdf required (HDF4). pip install pyhdf") from e
        try:
            import h5py
        except Exception:
            h5py = None

        # ---------- Dask ----------
        dask_client = None
        dask_cluster = None
        dashboard_url = None
        if use_dask:
            try:
                from dask.distributed import Client, LocalCluster, default_client, as_completed
                try:
                    dask_client = default_client()
                except Exception:
                    if n_workers == "auto":
                        n_workers = max(1, os.cpu_count() // 2)
                    if threads_per_worker == "auto":
                        threads_per_worker = 1 if scheduler == "processes" else max(1, os.cpu_count() // max(1, int(n_workers)))
                    dask_cluster = LocalCluster(
                        n_workers=int(n_workers),
                        threads_per_worker=int(threads_per_worker),
                        processes=(scheduler == "processes"),
                        dashboard_address=":0",
                    )
                    dask_client = Client(dask_cluster)
                dashboard_url = getattr(dask_client, "dashboard_link", None)
                if verbose and dashboard_url:
                    print(f"📊 Dask dashboard: {dashboard_url}")
            except Exception as e:
                if verbose:
                    print(f"⚠️ Dask disabled ({e}); running serial.")
                dask_client = None
                dask_cluster = None
                use_dask = False
                as_completed = None  # type: ignore

        # ---------- Helpers ----------
        def _granule_name(gran) -> str:
            import os, re
            # Direct string path
            if isinstance(gran, str):
                return os.path.basename(gran)

            # Common metadata dicts
            for attr in ("umm", "meta", "metadata"):
                d = getattr(gran, attr, None)
                if isinstance(d, dict):
                    for k in ("GranuleUR", "granuleUr", "title", "name", "filename"):
                        v = d.get(k)
                        if v:
                            return v

            # Assets (STAC-like)
            assets = getattr(gran, "assets", None)
            if isinstance(assets, dict):
                for v in assets.values():
                    href = (v or {}).get("href") or (v or {}).get("URL") or (v or {}).get("url")
                    if href:
                        return os.path.basename(href)

            # Links/data_links may be methods or lists
            for attr in ("data_links", "links"):
                obj = getattr(gran, attr, None)
                try:
                    seq = obj() if callable(obj) else obj
                except Exception:
                    seq = None
                if not seq:
                    continue
                try:
                    for u in seq:
                        # plain URL string
                        if isinstance(u, str):
                            if u.lower().endswith(".hdf"):
                                return os.path.basename(u)
                            # keep last segment if present
                            base = os.path.basename(u)
                            if base:
                                return base
                        # dict-like link
                        if isinstance(u, dict):
                            href = u.get("href") or u.get("URL") or u.get("url")
                            if href:
                                return os.path.basename(href)
                except Exception:
                    pass

            # Fallback: parse from string representation
            s = str(gran)
            m = re.search(r"(MOD[0-9A-Z]+\.A\d{7}\.\d{4}\.\d{3}\.\d+\.hdf)", s)
            if m:
                return m.group(1)

            return ""

        def _token(name):
            # MOD02HKM.AYYYYDOY.HHMM. -> AYYYYDOYHHMM
            m = re.search(r'\.A(\d{7})\.(\d{4})\.', name or "")
            return f"A{m.group(1)}{m.group(2)}" if m else ""

        def _day_from_name(name: str) -> str:
            # Prefer MODIS token AYYYYDOYHHMM when present
            m = re.search(r"A(\d{4})(\d{3})(?:\.?\d{4})?", name or "")
            if m:
                year = int(m.group(1)); doy = int(m.group(2))
                return (datetime(year, 1, 1) + timedelta(days=doy - 1)).strftime("%Y%m%d")
            # Fallback: 8-digit date found in cached file names ..._YYYYMMDD_...
            m2 = re.search(r"(?:^|[_-])(\d{8})(?:[_-]|$)", name or "")
            return m2.group(1) if m2 else ""

        def _open(gran):
            if isinstance(gran, str) and os.path.isfile(gran):
                return gran
            name = _granule_name(gran)
            cached = os.path.join(cache_dir, name) if name else None
            if cached and os.path.exists(cached):
                return cached
            paths = ea.download([gran], provider="LAADS", local_path=cache_dir)
            if isinstance(paths, dict):
                lp = next(iter(paths.values()), None)
            elif isinstance(paths, (list, tuple)):
                lp = paths[0] if paths else None
            else:
                lp = None
            if not lp or not os.path.exists(lp):
                raise FileNotFoundError("Download failed")
            if verbose:
                print(f"⬇️  Downloaded: {os.path.basename(lp)}")
            return lp

        def _attrs(ds):
            a = ds.attributes()
            return a.get("reflectance_scales"), a.get("reflectance_offsets")

        def _read_geo(p):
            if h5py:
                try:
                    with h5py.File(p, "r") as f:
                        if "Latitude" in f and "Longitude" in f:
                            lat = f["Latitude"][()].astype(np.float32)
                            lon = f["Longitude"][()].astype(np.float32)
                            lon = np.where(lon > 180, lon - 360, lon)
                            return lat, lon
                except Exception:
                    pass
            sd = SD(p, SDC.READ)
            try:
                lat = sd.select("Latitude").get().astype(np.float32)
                lon = sd.select("Longitude").get().astype(np.float32)
                lon = np.where(lon > 180, lon - 360, lon)
                return lat, lon
            finally:
                sd.end()

        def _read_toa(p):
            out = {}
            sd = SD(p, SDC.READ)
            try:
                try:
                    ds250 = sd.select("EV_250_Aggr500_RefSB")
                    arr250 = ds250.get().astype(np.float32)
                    s250, o250 = _attrs(ds250)
                except Exception:
                    arr250 = None; s250 = o250 = None
                try:
                    ds500 = sd.select("EV_500_RefSB")
                    arr500 = ds500.get().astype(np.float32)
                    s500, o500 = _attrs(ds500)
                except Exception:
                    arr500 = None; s500 = o500 = None
            finally:
                sd.end()

            def _scale(v, i, dv):
                try:
                    a = np.array(v)
                    if a.ndim == 1 and i < a.size:
                        return float(a[i])
                    if a.size == 1:
                        return float(a.item())
                except Exception:
                    pass
                return float(dv)

            if arr250 is not None:
                for i, b in {0: "B01", 1: "B02"}.items():
                    a = arr250[i] * _scale(s250, i, 1.0) + _scale(o250, i, 0.0)
                    a[a < 0] = np.nan
                    out[b] = a.astype(np.float32)
            if arr500 is not None:
                for i, b in {0: "B03", 1: "B04", 2: "B05", 3: "B06", 4: "B07"}.items():
                    a = arr500[i] * _scale(s500, i, 1.0) + _scale(o500, i, 0.0)
                    a[a < 0] = np.nan
                    out[b] = a.astype(np.float32)
            return out

        def _align(lat, lon, band):
            gl, gs = lat.shape; bl, bs = band.shape
            if (gl, gs) == (bl, bs):
                return lat, lon
            if gl * 2 == bl and gs * 2 == bs:
                lat_u = np.repeat(np.repeat(lat, 2, axis=0), 2, axis=1)
                lon_u = np.repeat(np.repeat(lon, 2, axis=0), 2, axis=1)
                return lat_u, lon_u
            ry = max(1, round(bl / max(1, gl))); rx = max(1, round(bs / max(1, gs)))
            lat_u = np.repeat(np.repeat(lat, ry, axis=0), rx, axis=1)[:bl, :bs]
            lon_u = np.repeat(np.repeat(lon, ry, axis=0), rx, axis=1)[:bl, :bs]
            return lat_u, lon_u

        def _grid_def(bbox, res):
            x0, y0, x1, y1 = bbox
            W = int(math.ceil((x1 - x0) / res)); H = int(math.ceil((y1 - y0) / res))
            transform = from_origin(x0, y1, res, res)
            area = geometry.AreaDefinition("roi", "roi grid", "epsg4326",
                                           {"proj": "longlat", "datum": "WGS84"},
                                           W, H, [x0, y0, x1, y1])
            return area, transform, W, H

        def _resample_to_grid(band, lat, lon, area, radius):
            lat, lon = _align(lat, lon, band)
            vals = band.ravel(); lats = lat.ravel(); lons = lon.ravel()
            m = np.isfinite(vals)
            if not m.any():
                return np.full(area.shape, np.nan, dtype=np.float32)
            vals = vals[m]; lats = lats[m]; lons = lons[m]
            sw = geometry.SwathDefinition(lons=lons, lats=lats)
            with warnings.catch_warnings():
                warnings.simplefilter("ignore")
                g = kd_tree.resample_nearest(sw, vals, area,
                                             radius_of_influence=max(1000, int(radius)),
                                             fill_value=np.nan, reduce_data=True, nprocs=1)
            return g.astype(np.float32)

        def _mask(arr, transform, w, h):
            if roi_geom is None:
                return arr
            try:
                msk = rasterize([(roi_geom, 1)], out_shape=(h, w),
                                transform=transform, fill=0, dtype="uint8")
                out = arr.copy(); out[msk == 0] = np.nan; return out
            except Exception:
                return arr

        def _write_tif(path, arr, transform, w, h):
            prof = {
                "driver": "GTiff", "height": h, "width": w, "count": 1, "dtype": "float32",
                "crs": "EPSG:4326", "transform": transform, "compress": "deflate",
                "predictor": 2, "tiled": True, "blockxsize": 256, "blockysize": 256,
                "nodata": np.float32(np.nan)
            }
            os.makedirs(os.path.dirname(path) or ".", exist_ok=True)
            with rasterio.open(path, "w", **prof) as dst:
                dst.write(arr, 1)

        
        # ---------- Build mosaics from cached per‑granule tiles ----------
        def _build_from_cached(days_filter: set[str] | None = None) -> dict:
            """
            Build mosaics from cache:
              1) Prefer per‑granule tile TIFFs in _granule_tifs (match many name styles).
              2) If none found, try tile mosaics in _tile_mosaics.
              3) If final outputs already exist, just report them.
            """
            import re, os
            from collections import defaultdict

            # Accept a wide variety of filename layouts
            # Examples that should match:
            #   terra_toa_B02_20160111_A20160111225_tile4x3.tif
            #   terra-toa-20160111-B02-tile4x3.tif
            #   terra_toa-20160111_tile4x3_B02.tif
            per_granule_pat = re.compile(
                r'(?i)(?:^|[_-])(?P<band>B0[1-7])(?:[_-]|$).*?(?:^|[_-])(?P<day>\d{8})(?:[_-]|$).*?(?:^|[_-])tile(?P<tag>\d+x\d+)(?:[_-]|$)'
            )
            # Tile mosaics (no granule token)
            tile_mosaic_pat = re.compile(
                r'(?i)(?:^|[_-])(?P<band>B0[1-7])(?:[_-]|$).*?(?:^|[_-])(?P<day>\d{8})(?:[_-]|$).*?(?:^|[_-])tile(?P<tag>\d+x\d+)(?:[_-]|$)'
            )

            # Generic fallback: find band/day/tag anywhere in name
            def _parse_name_generic(name: str):
                b = re.search(r'(?i)B0[1-7]', name)
                d = re.search(r'(?<!\d)(\d{8})(?!\d)', name)
                t = re.search(r'(?i)tile(\d+x\d+)', name)
                if b and d and t:
                    return b.group(0).upper(), d.group(1), t.group(1)
                return None

            # Normalize filters
            tile_tag_set = set(tile_tags)
            wanted_days = set(days_filter) if days_filter else set(all_days)
            wanted_bands = set(bands_wanted)

            # 1) Scan per‑granule tiles
            per_tile_groups = defaultdict(list)  # (day, band, tag) -> [tif paths]
            total_scanned = total_matched = band_filtered = day_filtered = tag_filtered = 0

            try:
                it = os.scandir(granule_tif_dir)
            except FileNotFoundError:
                it = []

            for de in tqdm(it, desc="📦 Use cached tiles", unit="file", disable=not show_progress):
                if not getattr(de, "is_file", lambda: False)():
                    continue
                total_scanned += 1
                fn = de.name

                m = per_granule_pat.search(fn)
                if m:
                    band = m.group("band").upper()
                    day = m.group("day")
                    tag = m.group("tag")
                else:
                    m2 = _parse_name_generic(fn)
                    if not m2:
                        continue
                    band, day, tag = m2

                # filters
                if band not in wanted_bands:
                    band_filtered += 1
                    continue
                if wanted_days and day not in wanted_days:
                    day_filtered += 1
                    continue
                if tag not in tile_tag_set:
                    # allow older runs with different tiling to be ignored here
                    tag_filtered += 1
                    continue

                total_matched += 1
                per_tile_groups[(day, band, tag)].append(os.path.join(granule_tif_dir, fn))

            if verbose:
                print(f"🧩 Cached scan: scanned={total_scanned} matched={total_matched} "
                      f"(rejects: band={band_filtered} day={day_filtered} tag={tag_filtered})")

            # 2) If none, scan _tile_mosaics
            if not per_tile_groups:
                try:
                    it2 = os.scandir(tile_mosaic_dir)
                except FileNotFoundError:
                    it2 = []
                for de in tqdm(it2, desc="📦 Use cached tile mosaics", unit="file", disable=not show_progress):
                    if not getattr(de, "is_file", lambda: False)():
                        continue
                    fn = de.name
                    m = tile_mosaic_pat.search(fn)
                    if not m:
                        m2 = _parse_name_generic(fn)
                        if not m2:
                            continue
                        band, day, tag = m2
                    else:
                        band = m.group("band").upper()
                        day = m.group("day")
                        tag = m.group("tag")
                    if band not in wanted_bands or (wanted_days and day not in wanted_days):
                        continue
                    if tag not in tile_tag_set:
                        continue
                    per_tile_groups[(day, band, tag)].append(os.path.join(tile_mosaic_dir, fn))

            # 3) If still nothing, but final outputs exist, report them
            if not per_tile_groups:
                finals = []
                for day in sorted(wanted_days):
                    for b in sorted(wanted_bands):
                        fp = os.path.join(output_folder, f"{filename_prefix}_{b}_{day}.tif")
                        if os.path.exists(fp):
                            finals.append(fp)
                if finals:
                    if verbose:
                        print(f"✅ Final outputs already exist for {len(finals)} file(s).")
                    return {
                        "processed_pairs": 0,
                        "written": 0,
                        "days_processed": 0,
                        "skipped_days": [],
                        "paths": finals,
                        "dashboard": None,
                    }
                if verbose:
                    print("ℹ️ No cached per‑granule tiles or tile mosaics found for requested days.")
                return {
                    "processed_pairs": 0,
                    "written": 0,
                    "days_processed": 0,
                    "skipped_days": [],
                    "paths": [],
                    "dashboard": None
                }

            # Build per‑tile mosaics
            final_tile_mosaics = defaultdict(list)  # (day, band) -> [tile mosaic paths]
            for (day, b, tag), tif_list in tqdm(sorted(per_tile_groups.items()),
                                                total=len(per_tile_groups),
                                                desc="🧬 Tile mosaics (cached)",
                                                unit="tile",
                                                disable=not show_progress):
                if not tif_list:
                    continue
                tile_out = os.path.join(tile_mosaic_dir, f"{filename_prefix}_{b}_{day}_tile{tag}.tif")
                if (not overwrite) and os.path.exists(tile_out):
                    final_tile_mosaics[(day, b)].append(tile_out)
                    continue
                try:
                    srcs = [rasterio.open(p) for p in tif_list]
                    mosaic, out_transform = rio_merge(srcs, method="first")
                    for s in srcs:
                        s.close()
                    if mosaic.ndim == 3 and mosaic.shape[0] == 1:
                        mosaic = mosaic[0]
                    mosaic = _mask(mosaic, out_transform, mosaic.shape[1], mosaic.shape[0])
                    _write_tif(tile_out, mosaic.astype(np.float32, copy=False),
                               out_transform, mosaic.shape[1], mosaic.shape[0])
                    final_tile_mosaics[(day, b)].append(tile_out)
                except Exception as e:
                    if verbose:
                        print(f"⚠️ Tile mosaic (cached) failed {day} {b} tile{tag}: {e}")

            # Final daily mosaics
            written = []
            days_processed = set()
            for (day, b), tile_paths in tqdm(sorted(final_tile_mosaics.items()),
                                             total=len(final_tile_mosaics),
                                             desc="🧷 Final mosaics (cached)",
                                             unit="day×band",
                                             disable=not show_progress):
                if not tile_paths:
                    continue
                out_fp = os.path.join(output_folder, f"{filename_prefix}_{b}_{day}.tif")
                if (not overwrite) and os.path.exists(out_fp):
                    continue
                try:
                    srcs = [rasterio.open(p) for p in tile_paths]
                    mosaic, out_transform = rio_merge(srcs, method="first")
                    for s in srcs:
                        s.close()
                    if mosaic.ndim == 3 and mosaic.shape[0] == 1:
                        mosaic = mosaic[0]
                    mosaic = _mask(mosaic, out_transform, mosaic.shape[1], mosaic.shape[0])
                    _write_tif(out_fp, mosaic.astype(np.float32, copy=False),
                               out_transform, mosaic.shape[1], mosaic.shape[0])
                    written.append(out_fp)
                    days_processed.add(day)
                except Exception as e:
                    if verbose:
                        print(f"⚠️ Final mosaic (cached) failed {day} {b}: {e}")

            if verbose:
                print(f"✅ Cached mosaics complete. Days={len(days_processed)} Written={len(written)}")

            return {
                "processed_pairs": 0,
                "written": len(written),
                "days_processed": len(days_processed),
                "skipped_days": [],
                "paths": written,
                "dashboard": None
            } 
        
        # ---------- Search granules per needed day ----------
        if verbose:
            print(f"🔍 Searching granules for {len(needed_days)} day(s) ...")
        def _search_once(short_name: str, sd, ed, bbox):
            # one call per product over the full window
            return ea.search_data(
                short_name=short_name,
                temporal=(sd, ed),
                bounding_box=bbox,
                provider="LAADS",
                granule_name="*.hdf",
            )

        need_terra = platform.lower() in ("terra", "both")
        need_aqua = platform.lower() in ("aqua", "both")

        # One-shot searches (much faster than per-day)
        granules_l1b = []
        granules_geo = []

        full_start = start_dt
        # include end day boundary
        full_end = end_dt + timedelta(days=1)

        if need_terra:
            if verbose: print("🛰️ Searching MOD02HKM / MOD03 once for full range ...")
            granules_l1b += _search_once("MOD02HKM", full_start, full_end, (minx, miny, maxx, maxy))
            granules_geo += _search_once("MOD03",    full_start, full_end, (minx, miny, maxx, maxy))
        if need_aqua:
            if verbose: print("🛰️ Searching MYD02HKM / MYD03 once for full range ...")
            granules_l1b += _search_once("MYD02HKM", full_start, full_end, (minx, miny, maxx, maxy))
            granules_geo += _search_once("MYD03",    full_start, full_end, (minx, miny, maxx, maxy))
            

        # Pair L1B with GEO by token (and keep only needed days)
        if verbose:
            print("🔗 Pairing L1B and GEO granules ...")

        wanted_days_set = set(needed_days)

        def _day_from_name(name: str) -> str:
            m = re.search(r"A(\d{4})(\d{3})(?:\.?\d{4})?", name or "")
            if m:
                year = int(m.group(1)); doy = int(m.group(2))
                return (datetime(year, 1, 1) + timedelta(days=doy - 1)).strftime("%Y%m%d")
            m2 = re.search(r"(?:^|[_-])(\d{8})(?:[_-]|$)", name or "")
            return m2.group(1) if m2 else ""

        geo_by_token = {}
        for g in granules_geo:
            nm = _granule_name(g)
            geo_by_token[_token(nm)] = g

        pairs = []
        for l in granules_l1b:
            ln = _granule_name(l)
            dk = _day_from_name(ln)
            if dk and dk not in wanted_days_set:
                continue
            tn = _token(ln)
            gg = geo_by_token.get(tn)
            if gg:
                pairs.append((l, gg))

        if not pairs:
            # Try building purely from cache before giving up
            result = _build_from_cached(set(needed_days) if needed_days else set(all_days))
            if result["written"] or result["days_processed"]:
                return result
            if verbose:
                print("ℹ️ No new granule pairs to process and nothing cached to mosaic.")
            return {
                "processed_pairs": 0,
                "written": 0,
                "days_processed": 0,
                "skipped_days": skipped_days,
                "paths": [],
                "dashboard": dashboard_url
            }

        # ---------- Process pairs (progress) ----------
        per_tile_groups = defaultdict(list)  # (day, band, tile_tag) -> [tif paths]

        def _process_tile(sw_path, geo_path, bbox_t, tile_tag):
            out = []
            try:
                sw_name = os.path.basename(sw_path)
                day = _day_from_name(sw_name) or "unknown"
                area, transform, W, H = _grid_def(bbox_t, res_deg)

                # If all band×tile already exist, reuse and exit
                gtok = _token(sw_name)
                reuse_all = True
                for b in bands_wanted:
                    tif = os.path.join(granule_tif_dir, f"{filename_prefix}_{b}_{day}_{gtok}_tile{tile_tag}.tif")
                    if not ((not overwrite) and os.path.exists(tif)):
                        reuse_all = False
                        break
                if reuse_all:
                    for b in bands_wanted:
                        tif = os.path.join(granule_tif_dir, f"{filename_prefix}_{b}_{day}_{gtok}_tile{tile_tag}.tif")
                        out.append((day, b, tile_tag, tif))
                    return out

                lat, lon = _read_geo(geo_path)
                bands = _read_toa(sw_path)
                for b, arr in bands.items():
                    if b not in bands_wanted or arr is None or not np.isfinite(arr).any():
                        continue
                    grid = _resample_to_grid(arr, lat, lon, area, radius_m)
                    grid = _mask(grid, transform, W, H)
                    tif = os.path.join(granule_tif_dir, f"{filename_prefix}_{b}_{day}_{gtok}_tile{tile_tag}.tif")
                    if overwrite or not os.path.exists(tif):
                        _write_tif(tif, grid, transform, W, H)
                    out.append((day, b, tile_tag, tif))
                return out
            except Exception as e:
                if verbose:
                    print(f"⚠️ Tile {tile_tag} failed: {e}")
                return out

        pair_iter = tqdm(pairs, desc="📦 Granule pairs", unit="pair", disable=not show_progress)
        for sw_g, geo_g in pair_iter:
            # Skip day again if cached (defensive)
            sw_nm = _granule_name(sw_g)
            day_current = _day_from_name(sw_nm)
            if (not overwrite) and day_current in skipped_days:
                if verbose:
                    print(f"⏭️ Day {day_current} cached (skipping pair).")
                continue

            sw_path = _open(sw_g)
            geo_path = _open(geo_g)

            # Tile processing with progress
            if use_dask and dask_client:
                # queue tasks
                tasks = [dask_client.submit(_process_tile, sw_path, geo_path, bbox_t, tag)
                         for bbox_t, tag in zip(tile_bboxes, tile_tags)]
                # progress with as_completed if available
                try:
                    from dask.distributed import as_completed as _as_completed
                except Exception:
                    _as_completed = None
                results = []
                if _as_completed is not None:
                    pbar = tqdm(total=len(tasks), desc="🧠 Tiles (dask)", unit="tile", disable=not show_progress)
                    for fut in _as_completed(tasks):
                        try:
                            results.append(fut.result())
                        except Exception as e:
                            if verbose:
                                print(f"⚠️ Tile task failed: {e}")
                        pbar.update(1)
                    pbar.close()
                else:
                    # fallback: gather once
                    if show_progress:
                        tqdm([], total=0, desc="🚚 Queueing", disable=False)
                    results = dask_client.gather(tasks)
            else:
                results = []
                for bbox_t, tag in tqdm(zip(tile_bboxes, tile_tags),
                                        total=len(tile_bboxes),
                                        desc="🧩 Tiles (serial)",
                                        unit="tile",
                                        disable=not show_progress):
                    results.append(_process_tile(sw_path, geo_path, bbox_t, tag))

            # Collect outputs
            for lst in results:
                for day, b, tag, tif in lst:
                    if day != "unknown":
                        per_tile_groups[(day, b, tag)].append(tif)

            if remove_cache:
                for p in (sw_path, geo_path):
                    try:
                        if p and os.path.isfile(p):
                            os.remove(p)
                    except Exception:
                        pass
                if verbose:
                    print("🧹 Removed cached HDFs for completed swath.")

        # ---------- Build tile mosaics (progress) ----------
        final_tile_mosaics = defaultdict(list)  # (day, band) -> [tile mosaic paths]
        for (day, b, tag), tif_list in tqdm(sorted(per_tile_groups.items()),
                                            total=len(per_tile_groups),
                                            desc="🧬 Tile mosaics",
                                            unit="tile",
                                            disable=not show_progress):
            if not tif_list:
                continue
            tile_out = os.path.join(tile_mosaic_dir, f"{filename_prefix}_{b}_{day}_tile{tag}.tif")
            if (not overwrite) and os.path.exists(tile_out):
                final_tile_mosaics[(day, b)].append(tile_out)
                continue
            try:
                srcs = [rasterio.open(p) for p in tif_list]
                mosaic, out_transform = rio_merge(srcs, method="first")
                for s in srcs:
                    s.close()
                if mosaic.ndim == 3 and mosaic.shape[0] == 1:
                    mosaic = mosaic[0]
                mosaic = _mask(mosaic, out_transform, mosaic.shape[1], mosaic.shape[0])
                _write_tif(tile_out, mosaic.astype(np.float32, copy=False),
                           out_transform, mosaic.shape[1], mosaic.shape[0])
                final_tile_mosaics[(day, b)].append(tile_out)
            except Exception as e:
                if verbose:
                    print(f"⚠️ Tile mosaic failed {day} {b} tile{tag}: {e}")

        # ---------- Final mosaics (progress) ----------
        written = []
        days_processed = set()
        for (day, b), tile_paths in tqdm(sorted(final_tile_mosaics.items()),
                                         total=len(final_tile_mosaics),
                                         desc="🧷 Final mosaics",
                                         unit="day×band",
                                         disable=not show_progress):
            if not tile_paths:
                continue
            out_fp = os.path.join(output_folder, f"{filename_prefix}_{b}_{day}.tif")
            if (not overwrite) and os.path.exists(out_fp):
                continue
            try:
                srcs = [rasterio.open(p) for p in tile_paths]
                mosaic, out_transform = rio_merge(srcs, method="first")
                for s in srcs:
                    s.close()
                if mosaic.ndim == 3 and mosaic.shape[0] == 1:
                    mosaic = mosaic[0]
                mosaic = _mask(mosaic, out_transform, mosaic.shape[1], mosaic.shape[0])
                _write_tif(out_fp, mosaic.astype(np.float32, copy=False),
                           out_transform, mosaic.shape[1], mosaic.shape[0])
                written.append(out_fp)
                days_processed.add(day)
            except Exception as e:
                if verbose:
                    print(f"⚠️ Final mosaic failed {day} {b}: {e}")

        if verbose:
            print(f"✅ Done. Days processed={len(days_processed)} | Skipped={len(skipped_days)} | Written={len(written)}")

        # Teardown dask
        if use_dask and ('dask_client' in locals()) and dask_client:
            try:
                dask_client.close()
                if dask_cluster:
                    dask_cluster.close()
            except Exception:
                pass

        return {
            "processed_pairs": len(pairs),
            "written": len(written),
            "days_processed": len(days_processed),
            "skipped_days": skipped_days,
            "paths": written,
            "dashboard": dashboard_url,
        }
    
    def download_modis_toa_working(
        self,
        band_list: list[str] | str,
        output_folder: str,
        roi: tuple[float, float, float, float] | str,
        start_date: str,
        end_date: str,
        *,
        platform: str = "terra",         # "terra" | "aqua" | "both"
        res_deg: float = 0.0045,         # ~500 m @ equator
        radius_m: int = 4000,
        filename_prefix: str = "modis_toa",
        overwrite: bool = False,
        verbose: bool = True,
        edl_username: str | None = None,
        edl_password: str | None = None,
        login_strategy: str | None = None,
        temp_dir: str | None = None,
        use_dask: bool = True,
        n_workers: int | str = "auto",
        threads_per_worker: int | str = "auto",
        scheduler: str = "processes",
        n_roi_split: int | tuple[int, int] = 100,
        show_progress: bool = True,
        remove_cache: bool = False,
    ) -> dict:
        import os, re, math, warnings, tempfile
        from collections import defaultdict
        from datetime import datetime, timedelta
        from glob import glob

        import numpy as np
        import rasterio
        from rasterio.merge import merge as rio_merge
        from rasterio.transform import from_origin
        from rasterio.features import rasterize

        try:
            from tqdm.auto import tqdm
        except Exception:
            def tqdm(x, **k): return x  # fallback no-op

        # IO
        os.makedirs(output_folder, exist_ok=True)
        cache_dir = os.path.join(output_folder, "_earthaccess_cache")
        os.makedirs(cache_dir, exist_ok=True)
        granule_tif_dir = os.path.join(output_folder, "_granule_tifs")
        os.makedirs(granule_tif_dir, exist_ok=True)
        tile_mosaic_dir = os.path.join(output_folder, "_tile_mosaics")
        os.makedirs(tile_mosaic_dir, exist_ok=True)

        tmp_root = temp_dir or os.path.join(output_folder, "_tmp")
        os.makedirs(tmp_root, exist_ok=True)
        tempfile.tempdir = tmp_root
        os.environ.setdefault("CPL_TMPDIR", tmp_root)
        os.environ.setdefault("GDAL_CACHEMAX", "256")

        # Bands
        ALL_BANDS = ["B01", "B02", "B03", "B04", "B05", "B06", "B07"]
        if isinstance(band_list, str) and band_list.lower() == "all":
            bands_wanted = set(ALL_BANDS)
        else:
            bands_wanted = {str(b).upper() for b in band_list}
            unknown = bands_wanted - set(ALL_BANDS)
            if unknown:
                raise ValueError(f"Unknown band(s): {sorted(unknown)}. Valid: {ALL_BANDS}")

        # ROI
        roi_geom = None
        minx = miny = maxx = maxy = None
        try:
            import geopandas as gpd
            from shapely.ops import unary_union
        except Exception:
            gpd = None
            unary_union = None

        if isinstance(roi, str):
            if gpd is None or unary_union is None:
                raise RuntimeError("Vector ROI requires geopandas and shapely.")
            if not os.path.exists(roi):
                raise FileNotFoundError(f"ROI not found: {roi}")
            gdf = gpd.read_file(roi)
            if gdf.empty:
                raise ValueError("Vector ROI is empty.")
            if gdf.crs is None or str(gdf.crs).upper() not in ("EPSG:4326", "OGC:CRS84"):
                gdf = gdf.to_crs("EPSG:4326")
            roi_geom = unary_union([g for g in gdf.geometry if g is not None and not g.is_empty])
            if roi_geom.is_empty:
                raise ValueError("Vector ROI union is empty.")
            minx, miny, maxx, maxy = roi_geom.bounds
        else:
            minx, miny, maxx, maxy = map(float, roi)
            if (maxx - minx) <= 0 or (maxy - miny) <= 0:
                raise ValueError("ROI bbox must have positive area.")

        # Date range
        start_dt = datetime.strptime(start_date, "%Y-%m-%d")
        end_dt = datetime.strptime(end_date, "%Y-%m-%d")
        if end_dt < start_dt:
            raise ValueError("end_date < start_date")
        all_days = [(start_dt + timedelta(days=i)).strftime("%Y%m%d")
                    for i in range((end_dt - start_dt).days + 1)]

        # Tiling helpers
        def _norm_split(v):
            if isinstance(v, (list, tuple)) and len(v) == 2:
                ny = max(1, int(v[0])); nx = max(1, int(v[1])); return ny, nx
            n = max(1, int(v)); ny = int(math.sqrt(n)); nx = max(1, int(math.ceil(n / ny))); return ny, nx

        def _split_bbox(bbox, ny, nx):
            x0, y0, x1, y1 = bbox
            dx = (x1 - x0) / nx; dy = (y1 - y0) / ny
            return [(x0 + ix * dx, y0 + iy * dy, x0 + (ix + 1) * dx, y0 + (iy + 1) * dy)
                    for iy in range(ny) for ix in range(nx)]

        ny, nx = _norm_split(n_roi_split)
        tile_bboxes = _split_bbox((minx, miny, maxx, maxy), ny, nx)
        tile_tags = [f"{ty}x{tx}" for ty in range(ny) for tx in range(nx)]

        # ---------- Cache scan with progress ----------
        # We consider a day "cached" if every requested band has at least one tile TIFF for that day
        # Pattern: ANYPREFIX_B0X_YYYYMMDD_A???????????_tileYxX.tif
        cache_regex = re.compile(
            r'.*[_-]?(B0[1-7])[_-](\d{8})(?:[_-]A\d{11})?[_-]tile\d+x\d+\.tif$',
            re.IGNORECASE
        )
        day_band_hits: dict[str, set[str]] = defaultdict(set)

        try:
            # fast scandir with tqdm wrapper
            files = [de for de in tqdm(
                os.scandir(granule_tif_dir),
                desc="🗂️ Index cache (scan dir)",
                unit="file",
                disable=not show_progress
            )]
        except FileNotFoundError:
            files = []

        matched = 0
        for de in tqdm(files, desc="🗂️ Index cache", unit="file", disable=not show_progress):
            if not de.is_file():
                continue
            m = cache_regex.match(de.name)
            if not m:
                continue
            matched += 1
            band = m.group(1).upper()
            day = m.group(2)
            day_band_hits[day].add(band)

        if verbose:
            print(f"🧩 Cache index matched {matched} tile TIFF(s) in {granule_tif_dir}")

        skipped_days = []
        needed_days = []
        for day in all_days:
            if (not overwrite) and day in day_band_hits and bands_wanted.issubset(day_band_hits[day]):
                skipped_days.append(day)
                if verbose:
                    print(f"{day}: skipped downloading HDF because it exists (cached tiles found).")
            else:
                needed_days.append(day)

        if verbose and skipped_days:
            print(f"⏭️ Skipping {len(skipped_days)} day(s) already cached.")

        if not needed_days:
            if verbose:
                print("✅ Nothing to do. All requested days are cached.")
            return {
                "processed_pairs": 0,
                "written": 0,
                "days_processed": 0,
                "skipped_days": skipped_days,
                "paths": [],
                "dashboard": None
            }

        # ---------- Login (progress print) ----------
        if verbose:
            print("🔑 Logging into Earthdata ...")
        try:
            import earthaccess as ea
            if edl_username and edl_password:
                ea.login(strategy="environment", username=edl_username, password=edl_password)
            elif login_strategy:
                ea.login(strategy=login_strategy)
            else:
                ea.login()
        except Exception as e:
            raise RuntimeError(f"earthaccess login failed: {e}")

        # ---------- External deps for processing ----------
        try:
            from pyresample import geometry, kd_tree
        except Exception as e:
            raise RuntimeError("pyresample required. pip install pyresample") from e
        try:
            from pyhdf.SD import SD, SDC
        except Exception as e:
            raise RuntimeError("pyhdf required (HDF4). pip install pyhdf") from e
        try:
            import h5py
        except Exception:
            h5py = None

        # ---------- Dask ----------
        dask_client = None
        dask_cluster = None
        dashboard_url = None
        if use_dask:
            try:
                from dask.distributed import Client, LocalCluster, default_client, as_completed
                try:
                    dask_client = default_client()
                except Exception:
                    if n_workers == "auto":
                        n_workers = max(1, os.cpu_count() // 2)
                    if threads_per_worker == "auto":
                        threads_per_worker = 1 if scheduler == "processes" else max(1, os.cpu_count() // max(1, int(n_workers)))
                    dask_cluster = LocalCluster(
                        n_workers=int(n_workers),
                        threads_per_worker=int(threads_per_worker),
                        processes=(scheduler == "processes"),
                        dashboard_address=":0",
                    )
                    dask_client = Client(dask_cluster)
                dashboard_url = getattr(dask_client, "dashboard_link", None)
                if verbose and dashboard_url:
                    print(f"📊 Dask dashboard: {dashboard_url}")
            except Exception as e:
                if verbose:
                    print(f"⚠️ Dask disabled ({e}); running serial.")
                dask_client = None
                dask_cluster = None
                use_dask = False
                as_completed = None  # type: ignore

        # ---------- Helpers ----------
        def _granule_name(gran) -> str:
            import os, re
            # Direct string path
            if isinstance(gran, str):
                return os.path.basename(gran)

            # Common metadata dicts
            for attr in ("umm", "meta", "metadata"):
                d = getattr(gran, attr, None)
                if isinstance(d, dict):
                    for k in ("GranuleUR", "granuleUr", "title", "name", "filename"):
                        v = d.get(k)
                        if v:
                            return v

            # Assets (STAC-like)
            assets = getattr(gran, "assets", None)
            if isinstance(assets, dict):
                for v in assets.values():
                    href = (v or {}).get("href") or (v or {}).get("URL") or (v or {}).get("url")
                    if href:
                        return os.path.basename(href)

            # Links/data_links may be methods or lists
            for attr in ("data_links", "links"):
                obj = getattr(gran, attr, None)
                try:
                    seq = obj() if callable(obj) else obj
                except Exception:
                    seq = None
                if not seq:
                    continue
                try:
                    for u in seq:
                        # plain URL string
                        if isinstance(u, str):
                            if u.lower().endswith(".hdf"):
                                return os.path.basename(u)
                            # keep last segment if present
                            base = os.path.basename(u)
                            if base:
                                return base
                        # dict-like link
                        if isinstance(u, dict):
                            href = u.get("href") or u.get("URL") or u.get("url")
                            if href:
                                return os.path.basename(href)
                except Exception:
                    pass

            # Fallback: parse from string representation
            s = str(gran)
            m = re.search(r"(MOD[0-9A-Z]+\.A\d{7}\.\d{4}\.\d{3}\.\d+\.hdf)", s)
            if m:
                return m.group(1)

            return ""

        def _token(name):
            # MOD02HKM.AYYYYDOY.HHMM. -> AYYYYDOYHHMM
            m = re.search(r'\.A(\d{7})\.(\d{4})\.', name or "")
            return f"A{m.group(1)}{m.group(2)}" if m else ""

        def _day_from_name(name: str) -> str:
            # Prefer MODIS token AYYYYDOYHHMM when present
            m = re.search(r"A(\d{4})(\d{3})(?:\.?\d{4})?", name or "")
            if m:
                year = int(m.group(1)); doy = int(m.group(2))
                return (datetime(year, 1, 1) + timedelta(days=doy - 1)).strftime("%Y%m%d")
            # Fallback: 8-digit date found in cached file names ..._YYYYMMDD_...
            m2 = re.search(r"(?:^|[_-])(\d{8})(?:[_-]|$)", name or "")
            return m2.group(1) if m2 else ""

        def _open(gran):
            if isinstance(gran, str) and os.path.isfile(gran):
                return gran
            name = _granule_name(gran)
            cached = os.path.join(cache_dir, name) if name else None
            if cached and os.path.exists(cached):
                return cached
            paths = ea.download([gran], provider="LAADS", local_path=cache_dir)
            if isinstance(paths, dict):
                lp = next(iter(paths.values()), None)
            elif isinstance(paths, (list, tuple)):
                lp = paths[0] if paths else None
            else:
                lp = None
            if not lp or not os.path.exists(lp):
                raise FileNotFoundError("Download failed")
            if verbose:
                print(f"⬇️ Downloaded: {os.path.basename(lp)}")
            return lp

        def _attrs(ds):
            a = ds.attributes()
            return a.get("reflectance_scales"), a.get("reflectance_offsets")

        def _read_geo(p):
            if h5py:
                try:
                    with h5py.File(p, "r") as f:
                        if "Latitude" in f and "Longitude" in f:
                            lat = f["Latitude"][()].astype(np.float32)
                            lon = f["Longitude"][()].astype(np.float32)
                            lon = np.where(lon > 180, lon - 360, lon)
                            return lat, lon
                except Exception:
                    pass
            sd = SD(p, SDC.READ)
            try:
                lat = sd.select("Latitude").get().astype(np.float32)
                lon = sd.select("Longitude").get().astype(np.float32)
                lon = np.where(lon > 180, lon - 360, lon)
                return lat, lon
            finally:
                sd.end()

        def _read_toa(p):
            out = {}
            sd = SD(p, SDC.READ)
            try:
                try:
                    ds250 = sd.select("EV_250_Aggr500_RefSB")
                    arr250 = ds250.get().astype(np.float32)
                    s250, o250 = _attrs(ds250)
                except Exception:
                    arr250 = None; s250 = o250 = None
                try:
                    ds500 = sd.select("EV_500_RefSB")
                    arr500 = ds500.get().astype(np.float32)
                    s500, o500 = _attrs(ds500)
                except Exception:
                    arr500 = None; s500 = o500 = None
            finally:
                sd.end()

            def _scale(v, i, dv):
                try:
                    a = np.array(v)
                    if a.ndim == 1 and i < a.size:
                        return float(a[i])
                    if a.size == 1:
                        return float(a.item())
                except Exception:
                    pass
                return float(dv)

            if arr250 is not None:
                for i, b in {0: "B01", 1: "B02"}.items():
                    a = arr250[i] * _scale(s250, i, 1.0) + _scale(o250, i, 0.0)
                    a[a < 0] = np.nan
                    out[b] = a.astype(np.float32)
            if arr500 is not None:
                for i, b in {0: "B03", 1: "B04", 2: "B05", 3: "B06", 4: "B07"}.items():
                    a = arr500[i] * _scale(s500, i, 1.0) + _scale(o500, i, 0.0)
                    a[a < 0] = np.nan
                    out[b] = a.astype(np.float32)
            return out

        def _align(lat, lon, band):
            gl, gs = lat.shape; bl, bs = band.shape
            if (gl, gs) == (bl, bs):
                return lat, lon
            if gl * 2 == bl and gs * 2 == bs:
                lat_u = np.repeat(np.repeat(lat, 2, axis=0), 2, axis=1)
                lon_u = np.repeat(np.repeat(lon, 2, axis=0), 2, axis=1)
                return lat_u, lon_u
            ry = max(1, round(bl / max(1, gl))); rx = max(1, round(bs / max(1, gs)))
            lat_u = np.repeat(np.repeat(lat, ry, axis=0), rx, axis=1)[:bl, :bs]
            lon_u = np.repeat(np.repeat(lon, ry, axis=0), rx, axis=1)[:bl, :bs]
            return lat_u, lon_u

        def _grid_def(bbox, res):
            x0, y0, x1, y1 = bbox
            W = int(math.ceil((x1 - x0) / res)); H = int(math.ceil((y1 - y0) / res))
            transform = from_origin(x0, y1, res, res)
            area = geometry.AreaDefinition("roi", "roi grid", "epsg4326",
                                           {"proj": "longlat", "datum": "WGS84"},
                                           W, H, [x0, y0, x1, y1])
            return area, transform, W, H

        def _resample_to_grid(band, lat, lon, area, radius):
            lat, lon = _align(lat, lon, band)
            vals = band.ravel(); lats = lat.ravel(); lons = lon.ravel()
            m = np.isfinite(vals)
            if not m.any():
                return np.full(area.shape, np.nan, dtype=np.float32)
            vals = vals[m]; lats = lats[m]; lons = lons[m]
            sw = geometry.SwathDefinition(lons=lons, lats=lats)
            with warnings.catch_warnings():
                warnings.simplefilter("ignore")
                g = kd_tree.resample_nearest(sw, vals, area,
                                             radius_of_influence=max(1000, int(radius)),
                                             fill_value=np.nan, reduce_data=True, nprocs=1)
            return g.astype(np.float32)

        def _mask(arr, transform, w, h):
            if roi_geom is None:
                return arr
            try:
                msk = rasterize([(roi_geom, 1)], out_shape=(h, w),
                                transform=transform, fill=0, dtype="uint8")
                out = arr.copy(); out[msk == 0] = np.nan; return out
            except Exception:
                return arr

        def _write_tif(path, arr, transform, w, h):
            prof = {
                "driver": "GTiff", "height": h, "width": w, "count": 1, "dtype": "float32",
                "crs": "EPSG:4326", "transform": transform, "compress": "deflate",
                "predictor": 2, "tiled": True, "blockxsize": 256, "blockysize": 256,
                "nodata": np.float32(np.nan)
            }
            os.makedirs(os.path.dirname(path) or ".", exist_ok=True)
            with rasterio.open(path, "w", **prof) as dst:
                dst.write(arr, 1)

        # ---------- Search granules per needed day ----------
        if verbose:
            print(f"🔍 Searching granules for {len(needed_days)} day(s) ...")
        def _search(product, sd, ed, bbox):
            import earthaccess as ea
            return ea.search_data(
                short_name=product,
                temporal=(sd, ed),
                bounding_box=bbox,
                provider="LAADS",
                granule_name="*.hdf",
            )

        granules_l1b = []
        granules_geo = []
        need_terra = platform.lower() in ("terra", "both")
        need_aqua = platform.lower() in ("aqua", "both")

        for day in tqdm(needed_days, desc="📅 Days", unit="day", disable=not show_progress):
            day_dt = datetime.strptime(day, "%Y%m%d")
            sd = day_dt
            ed = day_dt + timedelta(days=1)
            if need_terra:
                granules_l1b += _search("MOD02HKM", sd, ed, (minx, miny, maxx, maxy))
                granules_geo += _search("MOD03", sd, ed, (minx, miny, maxx, maxy))
            if need_aqua:
                granules_l1b += _search("MYD02HKM", sd, ed, (minx, miny, maxx, maxy))
                granules_geo += _search("MYD03", sd, ed, (minx, miny, maxx, maxy))

        # Pair L1B with GEO by token
        if verbose:
            print("🔗 Pairing L1B and GEO granules ...")
        geo_by_token = {}
        for g in granules_geo:
            nm = _granule_name(g)
            geo_by_token[_token(nm)] = g
        pairs = []
        for l in granules_l1b:
            tn = _token(_granule_name(l))
            gg = geo_by_token.get(tn)
            if gg:
                pairs.append((l, gg))

        if not pairs:
            if verbose:
                print("ℹ️ No new granule pairs to process.")
            return {
                "processed_pairs": 0,
                "written": 0,
                "days_processed": 0,
                "skipped_days": skipped_days,
                "paths": [],
                "dashboard": dashboard_url
            }

        # ---------- Process pairs (progress) ----------
        per_tile_groups = defaultdict(list)  # (day, band, tile_tag) -> [tif paths]

        def _process_tile(sw_path, geo_path, bbox_t, tile_tag):
            out = []
            try:
                sw_name = os.path.basename(sw_path)
                day = _day_from_name(sw_name) or "unknown"
                area, transform, W, H = _grid_def(bbox_t, res_deg)

                # If all band×tile already exist, reuse and exit
                gtok = _token(sw_name)
                reuse_all = True
                for b in bands_wanted:
                    tif = os.path.join(granule_tif_dir, f"{filename_prefix}_{b}_{day}_{gtok}_tile{tile_tag}.tif")
                    if not ((not overwrite) and os.path.exists(tif)):
                        reuse_all = False
                        break
                if reuse_all:
                    for b in bands_wanted:
                        tif = os.path.join(granule_tif_dir, f"{filename_prefix}_{b}_{day}_{gtok}_tile{tile_tag}.tif")
                        out.append((day, b, tile_tag, tif))
                    return out

                lat, lon = _read_geo(geo_path)
                bands = _read_toa(sw_path)
                for b, arr in bands.items():
                    if b not in bands_wanted or arr is None or not np.isfinite(arr).any():
                        continue
                    grid = _resample_to_grid(arr, lat, lon, area, radius_m)
                    grid = _mask(grid, transform, W, H)
                    tif = os.path.join(granule_tif_dir, f"{filename_prefix}_{b}_{day}_{gtok}_tile{tile_tag}.tif")
                    if overwrite or not os.path.exists(tif):
                        _write_tif(tif, grid, transform, W, H)
                    out.append((day, b, tile_tag, tif))
                return out
            except Exception as e:
                if verbose:
                    print(f"⚠️ Tile {tile_tag} failed: {e}")
                return out

        pair_iter = tqdm(pairs, desc="📦 Granule pairs", unit="pair", disable=not show_progress)
        for sw_g, geo_g in pair_iter:
            # Skip day again if cached (defensive)
            sw_nm = _granule_name(sw_g)
            day_current = _day_from_name(sw_nm)
            if (not overwrite) and day_current in skipped_days:
                if verbose:
                    print(f"⏭️ Day {day_current} cached (skipping pair).")
                continue

            sw_path = _open(sw_g)
            geo_path = _open(geo_g)

            # Tile processing with progress
            if use_dask and dask_client:
                # queue tasks
                tasks = [dask_client.submit(_process_tile, sw_path, geo_path, bbox_t, tag)
                         for bbox_t, tag in zip(tile_bboxes, tile_tags)]
                # progress with as_completed if available
                try:
                    from dask.distributed import as_completed as _as_completed
                except Exception:
                    _as_completed = None
                results = []
                if _as_completed is not None:
                    pbar = tqdm(total=len(tasks), desc="🧠 Tiles (dask)", unit="tile", disable=not show_progress)
                    for fut in _as_completed(tasks):
                        try:
                            results.append(fut.result())
                        except Exception as e:
                            if verbose:
                                print(f"⚠️ Tile task failed: {e}")
                        pbar.update(1)
                    pbar.close()
                else:
                    # fallback: gather once
                    if show_progress:
                        tqdm([], total=0, desc="🚚 Queueing", disable=False)
                    results = dask_client.gather(tasks)
            else:
                results = []
                for bbox_t, tag in tqdm(zip(tile_bboxes, tile_tags),
                                        total=len(tile_bboxes),
                                        desc="🧩 Tiles (serial)",
                                        unit="tile",
                                        disable=not show_progress):
                    results.append(_process_tile(sw_path, geo_path, bbox_t, tag))

            # Collect outputs
            for lst in results:
                for day, b, tag, tif in lst:
                    if day != "unknown":
                        per_tile_groups[(day, b, tag)].append(tif)

            if remove_cache:
                for p in (sw_path, geo_path):
                    try:
                        if p and os.path.isfile(p):
                            os.remove(p)
                    except Exception:
                        pass
                if verbose:
                    print("🧹 Removed cached HDFs for completed swath.")

        # ---------- Build tile mosaics (progress) ----------
        final_tile_mosaics = defaultdict(list)  # (day, band) -> [tile mosaic paths]
        for (day, b, tag), tif_list in tqdm(sorted(per_tile_groups.items()),
                                            total=len(per_tile_groups),
                                            desc="🧬 Tile mosaics",
                                            unit="tile",
                                            disable=not show_progress):
            if not tif_list:
                continue
            tile_out = os.path.join(tile_mosaic_dir, f"{filename_prefix}_{b}_{day}_tile{tag}.tif")
            if (not overwrite) and os.path.exists(tile_out):
                final_tile_mosaics[(day, b)].append(tile_out)
                continue
            try:
                srcs = [rasterio.open(p) for p in tif_list]
                mosaic, out_transform = rio_merge(srcs, method="first")
                for s in srcs:
                    s.close()
                if mosaic.ndim == 3 and mosaic.shape[0] == 1:
                    mosaic = mosaic[0]
                mosaic = _mask(mosaic, out_transform, mosaic.shape[1], mosaic.shape[0])
                _write_tif(tile_out, mosaic.astype(np.float32, copy=False),
                           out_transform, mosaic.shape[1], mosaic.shape[0])
                final_tile_mosaics[(day, b)].append(tile_out)
            except Exception as e:
                if verbose:
                    print(f"⚠️ Tile mosaic failed {day} {b} tile{tag}: {e}")

        # ---------- Final mosaics (progress) ----------
        written = []
        days_processed = set()
        for (day, b), tile_paths in tqdm(sorted(final_tile_mosaics.items()),
                                         total=len(final_tile_mosaics),
                                         desc="🧷 Final mosaics",
                                         unit="day×band",
                                         disable=not show_progress):
            if not tile_paths:
                continue
            out_fp = os.path.join(output_folder, f"{filename_prefix}_{b}_{day}.tif")
            if (not overwrite) and os.path.exists(out_fp):
                continue
            try:
                srcs = [rasterio.open(p) for p in tile_paths]
                mosaic, out_transform = rio_merge(srcs, method="first")
                for s in srcs:
                    s.close()
                if mosaic.ndim == 3 and mosaic.shape[0] == 1:
                    mosaic = mosaic[0]
                mosaic = _mask(mosaic, out_transform, mosaic.shape[1], mosaic.shape[0])
                _write_tif(out_fp, mosaic.astype(np.float32, copy=False),
                           out_transform, mosaic.shape[1], mosaic.shape[0])
                written.append(out_fp)
                days_processed.add(day)
            except Exception as e:
                if verbose:
                    print(f"⚠️ Final mosaic failed {day} {b}: {e}")

        if verbose:
            print(f"✅ Done. Days processed={len(days_processed)} | Skipped={len(skipped_days)} | Written={len(written)}")

        # Teardown dask
        if use_dask and ('dask_client' in locals()) and dask_client:
            try:
                dask_client.close()
                if dask_cluster:
                    dask_cluster.close()
            except Exception:
                pass

        return {
            "processed_pairs": len(pairs),
            "written": len(written),
            "days_processed": len(days_processed),
            "skipped_days": skipped_days,
            "paths": written,
            "dashboard": dashboard_url,
        }
    
    
    def download_modis_toa_v27(
        self,
        band_list: list[str] | str,
        output_folder: str,
        roi: tuple[float, float, float, float] | str,
        start_date: str,
        end_date: str,
        *,
        platform: str = "terra",         # "terra" | "aqua" | "both"
        res_deg: float = 0.0045,         # ~500 m @ equator (~500m)
        radius_m: int = 4000,            # resample radius (m)
        filename_prefix: str = "modis_toa",
        overwrite: bool = False,
        verbose: bool = True,
        edl_username: str | None = None,
        edl_password: str | None = None,
        login_strategy: str | None = None,
        temp_dir: str | None = None,
        use_dask: bool = True,
        n_workers: int | str = "auto",
        threads_per_worker: int | str = "auto",
        scheduler: str = "processes",
        n_roi_split: int | tuple[int, int] = 100,
        show_progress: bool = True,
        remove_cache: bool = False,
    ) -> dict:
        """
        Download MODIS HKM TOA reflectance (Bands B01..B07) and build daily mosaics.
        Skip any day whose per‑granule tile TIFFs are already cached in: output_folder/_granule_tifs
        Cached file pattern (prefix ignored):
            <anyPrefix>_B0X_YYYYMMDD_AYYYYDOYHHMM_tileYxX.tif
        If ALL requested bands have at least one tile file for a date, that date is skipped.
        """
        import os, re, math, warnings, tempfile
        from datetime import datetime, timedelta
        from collections import defaultdict

        import numpy as np
        import rasterio
        from rasterio.merge import merge as rio_merge
        from rasterio.transform import from_origin
        from rasterio.features import rasterize

        try:
            import earthaccess as ea
        except Exception as e:
            raise RuntimeError("earthaccess required. pip install earthaccess") from e
        try:
            from pyresample import geometry, kd_tree
        except Exception as e:
            raise RuntimeError("pyresample required. pip install pyresample") from e
        try:
            from pyhdf.SD import SD, SDC
        except Exception as e:
            raise RuntimeError("pyhdf required (HDF4). pip install pyhdf") from e
        try:
            import h5py
        except Exception:
            h5py = None
        try:
            import geopandas as gpd
            from shapely.ops import unary_union
        except Exception:
            gpd = None
            unary_union = None
        try:
            from tqdm.auto import tqdm as _tqdm
        except Exception:
            _tqdm = None

        # ---- ROI ----
        roi_geom = None
        if isinstance(roi, str):
            if gpd is None or unary_union is None:
                raise RuntimeError("Vector ROI requires geopandas & shapely")
            if not os.path.exists(roi):
                raise FileNotFoundError(roi)
            gdf = gpd.read_file(roi)
            if gdf.empty:
                raise ValueError("ROI vector empty")
            if gdf.crs is None or str(gdf.crs).upper() not in ("EPSG:4326","OGC:CRS84"):
                gdf = gdf.to_crs("EPSG:4326")
            roi_geom = unary_union([geom for geom in gdf.geometry if geom and not geom.is_empty])
            if roi_geom.is_empty:
                raise ValueError("ROI geometry empty after union")
            minx, miny, maxx, maxy = roi_geom.bounds
        else:
            minx, miny, maxx, maxy = map(float, roi)
            if maxx <= minx or maxy <= miny:
                raise ValueError("Invalid ROI bbox")

        # ---- IO dirs ----
        os.makedirs(output_folder, exist_ok=True)
        cache_dir = os.path.join(output_folder, "_earthaccess_cache")
        os.makedirs(cache_dir, exist_ok=True)
        granule_tif_dir = os.path.join(output_folder, "_granule_tifs")
        os.makedirs(granule_tif_dir, exist_ok=True)
        tile_mosaic_dir = os.path.join(output_folder, "_tile_mosaics")
        os.makedirs(tile_mosaic_dir, exist_ok=True)
        tmp_root = temp_dir or os.path.join(output_folder, "_tmp")
        os.makedirs(tmp_root, exist_ok=True)
        tempfile.tempdir = tmp_root

        # ---- Bands ----
        ALL_BANDS = ["B01","B02","B03","B04","B05","B06","B07"]
        if isinstance(band_list,str) and band_list.lower()=="all":
            bands_wanted = set(ALL_BANDS)
        else:
            bands_wanted = {b.upper() for b in band_list}
            bad = bands_wanted - set(ALL_BANDS)
            if bad:
                raise ValueError(f"Unknown bands: {sorted(bad)}")

        # ---- Dask ----
        dask_client = None
        dask_cluster = None
        dashboard_url = None
        if use_dask:
            try:
                from dask.distributed import Client, LocalCluster, default_client
                try:
                    dask_client = default_client()
                except Exception:
                    if n_workers == "auto":
                        n_workers = max(1, os.cpu_count()//2)
                    if threads_per_worker == "auto":
                        threads_per_worker = 1 if scheduler=="processes" else max(1, os.cpu_count()//max(1,int(n_workers)))
                    dask_cluster = LocalCluster(
                        n_workers=int(n_workers),
                        threads_per_worker=int(threads_per_worker),
                        processes=(scheduler=="processes"),
                        dashboard_address=":0"
                    )
                    dask_client = Client(dask_cluster)
                dashboard_url = getattr(dask_client,"dashboard_link",None)
                if verbose and dashboard_url:
                    print(f"Dask dashboard: {dashboard_url}")
            except Exception as e:
                if verbose:
                    print(f"Dask disabled ({e})")
                use_dask=False

        # ---- Date range ----
        start_dt = datetime.strptime(start_date,"%Y-%m-%d")
        end_dt   = datetime.strptime(end_date,"%Y-%m-%d")
        if end_dt < start_dt:
            raise ValueError("end_date < start_date")
        all_days = [(start_dt + timedelta(days=i)).strftime("%Y%m%d")
                    for i in range((end_dt-start_dt).days+1)]

        # ---- Cache scan (skip days) ----
        cache_regex = re.compile(r'^.+_(B0[1-7])_(\d{8})_A\d{11}_tile\d+x\d+\.tif$', re.IGNORECASE)
        day_band_hits: dict[str,set[str]] = defaultdict(set)
        for fn in os.listdir(granule_tif_dir):
            m = cache_regex.match(fn)
            if not m:
                continue
            band = m.group(1).upper()
            day  = m.group(2)
            day_band_hits[day].add(band)

        skipped_days = []
        needed_days = []
        for day in all_days:
            if day in day_band_hits and bands_wanted.issubset(day_band_hits[day]) and not overwrite:
                skipped_days.append(day)
            else:
                needed_days.append(day)

        if verbose:
            if skipped_days:
                print(f"Skip {len(skipped_days)} day(s) (all bands cached): {', '.join(skipped_days[:8])}{' ...' if len(skipped_days)>8 else ''}")
            if not needed_days:
                print("All requested days already cached.")

        if not needed_days:
            if dask_client:
                try:
                    dask_client.close()
                    if dask_cluster: dask_cluster.close()
                except Exception: pass
            return {
                "processed_pairs": 0,
                "written": 0,
                "days_processed": 0,
                "skipped_days": skipped_days,
                "paths": [],
                "dashboard": dashboard_url
            }

        # ---- Login ----
        if verbose:
            print("Logging into Earthdata ...")
        try:
            if edl_username and edl_password:
                ea.login(strategy="environment", username=edl_username, password=edl_password)
            elif login_strategy:
                ea.login(strategy=login_strategy)
            else:
                ea.login()
        except Exception as e:
            raise RuntimeError(f"earthaccess login failed: {e}")

        # ---- Helpers ----
        def _granule_name(g):
            if isinstance(g,str): return os.path.basename(g)
            for attr in ("umm","meta","metadata"):
                d = getattr(g,attr,None)
                if isinstance(d,dict):
                    for k in ("GranuleUR","granuleUr","title","name","filename"):
                        v=d.get(k)
                        if v: return v
            links = getattr(g,"data_links",None) or getattr(g,"links",None) or []
            for u in links:
                if isinstance(u,str) and u.endswith(".hdf"):
                    return os.path.basename(u)
            return ""
        def _token(name):
            m=re.search(r'\.A(\d{7})\.(\d{4})\.',name)
            return f"A{m.group(1)}{m.group(2)}" if m else re.sub(r'[^A-Za-z0-9]+','',os.path.splitext(name)[0])[-22:]
        def _day(name):
            m=re.search(r'\.A(\d{4})(\d{3})\.\d{4}\.',name)
            if not m: return ""
            year=int(m.group(1)); doy=int(m.group(2))
            return (datetime(year,1,1)+timedelta(days=doy-1)).strftime("%Y%m%d")
        def _open(gran):
            if isinstance(gran,str) and os.path.isfile(gran): return gran
            # cached?
            n=_granule_name(gran)
            c=os.path.join(cache_dir,n)
            if n and os.path.exists(c): return c
            paths=ea.download([gran],provider="LAADS",local_path=cache_dir)
            if isinstance(paths,dict): lp=next(iter(paths.values()),None)
            elif isinstance(paths,(list,tuple)): lp=paths[0] if paths else None
            else: lp=None
            if not lp or not os.path.exists(lp): raise FileNotFoundError("Download failed")
            if verbose: print(f"Downloaded: {os.path.basename(lp)}")
            return lp
        def _read_geo(p):
            if h5py:
                try:
                    with h5py.File(p,'r') as f:
                        if 'Latitude' in f and 'Longitude' in f:
                            lat=f['Latitude'][()].astype(np.float32)
                            lon=f['Longitude'][()].astype(np.float32)
                            lon=np.where(lon>180,lon-360,lon)
                            return lat,lon
                except Exception: pass
            sd=SD(p,SDC.READ)
            try:
                lat=sd.select("Latitude").get().astype(np.float32)
                lon=sd.select("Longitude").get().astype(np.float32)
                lon=np.where(lon>180,lon-360,lon)
                return lat,lon
            finally:
                sd.end()
        def _attrs(ds):
            a=ds.attributes()
            return a.get("reflectance_scales"), a.get("reflectance_offsets")
        def _read_toa(p):
            out={}
            sd=SD(p,SDC.READ)
            try:
                try:
                    ds250=sd.select("EV_250_Aggr500_RefSB")
                    arr250=ds250.get().astype(np.float32)
                    s250,o250=_attrs(ds250)
                except Exception:
                    arr250=None; s250=o250=None
                try:
                    ds500=sd.select("EV_500_RefSB")
                    arr500=ds500.get().astype(np.float32)
                    s500,o500=_attrs(ds500)
                except Exception:
                    arr500=None; s500=o500=None
            finally:
                sd.end()
            def scale(v,i,defv):
                try:
                    a=np.array(v)
                    if a.ndim==1 and i<a.size: return float(a[i])
                    if a.size==1: return float(a.item())
                except Exception: pass
                return float(defv)
            if arr250 is not None:
                for i,b in {0:"B01",1:"B02"}.items():
                    a=arr250[i]; a=a*scale(s250,i,1.0)+scale(o250,i,0.0); a[a<0]=np.nan
                    out[b]=a
            if arr500 is not None:
                for i,b in {0:"B03",1:"B04",2:"B05",3:"B06",4:"B07"}.items():
                    a=arr500[i]; a=a*scale(s500,i,1.0)+scale(o500,i,0.0); a[a<0]=np.nan
                    out[b]=a
            return out
        def _align(lat,lon,band):
            gl,gs=lat.shape; bl,bs=band.shape
            if gl*2==bl and gs*2==bs:
                lat=np.repeat(np.repeat(lat,2,axis=0),2,axis=1)
                lon=np.repeat(np.repeat(lon,2,axis=0),2,axis=1)
            elif (gl,gs)!=(bl,bs):
                ry=bl//gl if gl and bl%gl==0 else 1
                rx=bs//gs if gs and bs%gs==0 else 1
                lat=np.repeat(np.repeat(lat,ry,axis=0),rx,axis=1)[:bl,:bs]
                lon=np.repeat(np.repeat(lon,ry,axis=0),rx,axis=1)[:bl,:bs]
            return lat,lon
        def _grid(band,lat,lon,area,radius):
            lat,lon=_align(lat,lon,band)
            vals=band.ravel(); lats=lat.ravel(); lons=lon.ravel()
            m=np.isfinite(vals)
            if not m.any():
                return np.full(area.shape,np.nan,dtype=np.float32)
            vals=vals[m]; lats=lats[m]; lons=lons[m]
            sw=geometry.SwathDefinition(lons=lons,lats=lats)
            with warnings.catch_warnings():
                warnings.simplefilter("ignore")
                g=kd_tree.resample_nearest(sw,vals,area,radius_of_influence=radius,fill_value=np.nan,nprocs=1,reduce_data=True)
            return g.astype(np.float32)
        def _write(path,arr,transform,w,h):
            prof={"driver":"GTiff","height":h,"width":w,"count":1,"dtype":"float32","crs":"EPSG:4326","transform":transform,
                  "compress":"deflate","predictor":2,"tiled":True,"blockxsize":256,"blockysize":256,"nodata":np.float32(np.nan)}
            os.makedirs(os.path.dirname(path) or ".",exist_ok=True)
            with rasterio.open(path,"w",**prof) as dst: dst.write(arr,1)
        def _mask(arr,transform,w,h):
            if roi_geom is None: return arr
            try:
                m=rasterize([(roi_geom,1)],out_shape=(h,w),transform=transform,fill=0,dtype="uint8",all_touched=False)
                out=arr.copy(); out[m==0]=np.nan; return out
            except Exception: return arr
        # ---- Grid helper ----
        def _grid_def(bbox,res):
            x0,y0,x1,y1=bbox
            W=int(math.ceil((x1-x0)/res)); H=int(math.ceil((y1-y0)/res))
            transform=from_origin(x0,y1,res,res)
            area=geometry.AreaDefinition("roi","roi","epsg4326",{"proj":"longlat","datum":"WGS84"},W,H,[x0,y0,x1,y1])
            return area,transform,W,H
        def _split_bbox(bbox,ny,nx):
            x0,y0,x1,y1=bbox
            dx=(x1-x0)/nx; dy=(y1-y0)/ny
            return [(x0+ix*dx,y0+iy*dy,x0+(ix+1)*dx,y0+(iy+1)*dy) for iy in range(ny) for ix in range(nx)]
        def _norm_split(v):
            if isinstance(v,(list,tuple)) and len(v)==2:
                ny=max(1,int(v[0])); nx=max(1,int(v[1])); return ny,nx
            n=max(1,int(v)); ny=int(math.sqrt(n)); nx=max(1,int(math.ceil(n/ny))); return ny,nx

        # ---- Tiling setup ----
        ny,nx=_norm_split(n_roi_split)
        tile_bboxes=_split_bbox((minx,miny,maxx,maxy),ny,nx)
        tile_tags=[f"{ty}x{tx}" for ty in range(ny) for tx in range(nx)]

        # ---- Search helper ----
        def _search(product,sd,ed,bbox):
            return ea.search_data(short_name=product,temporal=(sd,ed),bounding_box=bbox,provider="LAADS",granule_name="*.hdf")

        # ---- Collect granules only for needed days ----
        # Build per-day temporal windows (single day)
        granules_l1b=[]; granules_geo=[]
        need_terra = platform.lower() in ("terra","both")
        need_aqua  = platform.lower() in ("aqua","both")
        for day in needed_days:
            day_dt=datetime.strptime(day,"%Y%m%d")
            sd=day_dt
            ed=day_dt+timedelta(days=1)  # include day boundary
            if need_terra:
                granules_l1b += _search("MOD02HKM",sd,ed,(minx,miny,maxx,maxy))
                granules_geo += _search("MOD03",sd,ed,(minx,miny,maxx,maxy))
            if need_aqua:
                granules_l1b += _search("MYD02HKM",sd,ed,(minx,miny,maxx,maxy))
                granules_geo += _search("MYD03",sd,ed,(minx,miny,maxx,maxy))

        # Pair L1B with GEO by token
        geo_by_token={}
        for g in granules_geo:
            nm=_granule_name(g)
            geo_by_token[_token(nm)]=g
        pairs=[]
        for l in granules_l1b:
            tn=_token(_granule_name(l))
            gg=geo_by_token.get(tn)
            if gg: pairs.append((l,gg))
        if not pairs:
            if verbose: print("No new granule pairs to process.")
            if dask_client:
                try: dask_client.close(); 
                except Exception: pass
            return {
                "processed_pairs":0,
                "written":0,
                "days_processed":0,
                "skipped_days":skipped_days,
                "paths":[],
                "dashboard":dashboard_url
            }

        # ---- Process pairs ----
        per_tile_groups=defaultdict(list)  # (day, band, tile_tag) -> [tif paths]

        def _process_tile(sw_path,geo_path,bbox_t,tile_tag):
            out=[]
            try:
                sw_name=os.path.basename(sw_path)
                day=_day(sw_name) or "unknown"
                area,transform,W,H=_grid_def(bbox_t,res_deg)
                lat,lon=_read_geo(geo_path)
                bands=_read_toa(sw_path)
                for b,arr in bands.items():
                    if b not in bands_wanted: continue
                    if arr is None or not np.isfinite(arr).any(): continue
                    grid=_grid(arr,lat,lon,area,radius_m)
                    grid=_mask(grid,transform,W,H)
                    gtok=_token(sw_name)
                    tif=os.path.join(granule_tif_dir,f"{filename_prefix}_{b}_{day}_{gtok}_tile{tile_tag}.tif")
                    if not (os.path.exists(tif) and not overwrite):
                        _write(tif,grid,transform,W,H)
                    out.append((day,b,tile_tag,tif))
                return out
            except Exception as e:
                if verbose: print(f"Tile {tile_tag} failed: {e}")
                return out

        pair_iter = pairs if not (_tqdm and show_progress) else _tqdm(pairs,desc="Granule pairs",unit="pair")

        for sw_g,geo_g in pair_iter:
            sw_path=_open(sw_g); geo_path=_open(geo_g)
            # skip if day already cached wholly (defensive)
            sw_name=_granule_name(sw_g)
            day=_day(sw_name)
            if day in skipped_days and not overwrite:
                if verbose: print(f"Day {day} already cached (skipped).")
                if remove_cache:
                    for p in (sw_path,geo_path):
                        try:
                            if p and os.path.isfile(p): os.remove(p)
                        except Exception: pass
                continue
            # tile loop
            futures=[]
            if use_dask and dask_client:
                for bbox_t, tag in zip(tile_bboxes,tile_tags):
                    futures.append(dask_client.submit(_process_tile,sw_path,geo_path,bbox_t,tag))
                results=dask_client.gather(futures)
            else:
                results=[_process_tile(sw_path,geo_path,b,t) for b,t in zip(tile_bboxes,tile_tags)]
            for lst in results:
                for day,b,tag,tif in lst:
                    if day!="unknown":
                        per_tile_groups[(day,b,tag)].append(tif)
            if remove_cache:
                for p in (sw_path,geo_path):
                    try:
                        if p and os.path.isfile(p): os.remove(p)
                    except Exception: pass

        # ---- Build tile mosaics ----
        final_tile_mosaics=defaultdict(list)  # (day, band) -> [tile mosaic paths]
        for (day,b,tag), tif_list in sorted(per_tile_groups.items()):
            if not tif_list: continue
            tile_out=os.path.join(tile_mosaic_dir,f"{filename_prefix}_{b}_{day}_tile{tag}.tif")
            if os.path.exists(tile_out) and not overwrite:
                final_tile_mosaics[(day,b)].append(tile_out); continue
            try:
                srcs=[rasterio.open(p) for p in tif_list]
                mosaic, tr = rio_merge(srcs, method="first")
                for s in srcs: s.close()
                if mosaic.ndim==3: mosaic=mosaic[0]
                mosaic=_mask(mosaic,tr,mosaic.shape[1],mosaic.shape[0])
                _write(tile_out,mosaic,tr,mosaic.shape[1],mosaic.shape[0])
                final_tile_mosaics[(day,b)].append(tile_out)
            except Exception as e:
                if verbose: print(f"Tile mosaic fail {day} {b} {tag}: {e}")

        # ---- Final daily mosaics ----
        written=[]
        days_processed=set()
        for (day,b), paths in sorted(final_tile_mosaics.items()):
            if not paths: continue
            out_fp=os.path.join(output_folder,f"{filename_prefix}_{b}_{day}.tif")
            if os.path.exists(out_fp) and not overwrite:
                continue
            try:
                srcs=[rasterio.open(p) for p in paths]
                mosaic, tr = rio_merge(srcs, method="first")
                for s in srcs: s.close()
                if mosaic.ndim==3: mosaic=mosaic[0]
                mosaic=_mask(mosaic,tr,mosaic.shape[1],mosaic.shape[0])
                _write(out_fp,mosaic,tr,mosaic.shape[1],mosaic.shape[0])
                written.append(out_fp)
                days_processed.add(day)
            except Exception as e:
                if verbose: print(f"Final mosaic fail {day} {b}: {e}")

        if verbose:
            print(f"Done. Days processed={len(days_processed)} Skipped={len(skipped_days)} Written={len(written)}")

        if dask_client:
            try:
                dask_client.close()
                if dask_cluster: dask_cluster.close()
            except Exception: pass

        return {
            "processed_pairs": len(pairs),
            "written": len(written),
            "days_processed": len(days_processed),
            "skipped_days": skipped_days,
            "paths": written,
            "dashboard": dashboard_url
        }
    
    
    def download_modis_toa_v24(
        self,
        band_list: list[str] | str,
        output_folder: str,
        roi: tuple[float, float, float, float] | str,
        start_date: str,
        end_date: str,
        *,
        platform: str = "terra",         # "terra" | "aqua" | "both"
        res_deg: float = 0.0045,         # ~500 m @ equator
        radius_m: int = 4000,            # swath->grid nearest-neighbor radius (m)
        filename_prefix: str = "modis_toa",
        overwrite: bool = False,
        verbose: bool = True,
        edl_username: str | None = None,
        edl_password: str | None = None,
        login_strategy: str | None = None,
        temp_dir: str | None = None,
        # parallel knobs (used inside each tile)
        use_dask: bool = True,
        n_workers: int | str = "auto",
        threads_per_worker: int | str = "auto",
        scheduler: str = "processes",
        # Split ROI bbox into ny x nx tiles (sequential tiles → low RAM)
        n_roi_split: int | tuple[int, int] = 100,
        # Progress bars for tiles and per-tile granules
        show_progress: bool = True,
        # delete current swath HDFs right after tiles are finished (before downloading next one)
        remove_cache: bool = False,
    ) -> dict:
        """
        Download MODIS L1B TOA reflectance (HKM, 500 m) and write one GeoTIFF per band per day.

        Behavior
        - One swath pair at a time; within the swath, all tiles are processed in parallel (Dask if enabled).
        - If remove_cache=True, the pair’s cached HDFs are removed immediately after its tiles finish.
        - Skips existing work:
        - reuses per‑granule per‑tile TIFFs if present,
        - reuses per‑tile mosaics if present,
        - reuses final mosaics if present.

        Output
        - {output_folder}/_granule_tifs/{prefix}_{Band}_{YYYYMMDD}_{GranToken}_tile{ty}x{tx}.tif
        - {output_folder}/_tile_mosaics/{prefix}_{Band}_{YYYYMMDD}_tile{ty}x{tx}.tif
        - {output_folder}/{prefix}_{Band}_{YYYYMMDD}.tif
        """
        # -------- imports (scoped to keep class import surface small) --------
        import os, re, math, warnings, tempfile
        from collections import defaultdict
        from datetime import datetime, timedelta

        import numpy as np
        import rasterio
        from rasterio.merge import merge as rio_merge
        from rasterio.transform import from_origin
        from rasterio.features import rasterize

        try:
            import earthaccess as ea
        except Exception as e:
            raise RuntimeError("earthaccess is required. pip install earthaccess") from e

        try:
            from pyresample import geometry, kd_tree
        except Exception as e:
            raise RuntimeError("pyresample is required. pip install pyresample") from e

        try:
            from pyhdf.SD import SD, SDC  # HDF4 reader
        except Exception as e:
            raise RuntimeError("pyhdf is required for MODIS HDF4. pip install pyhdf") from e

        try:
            import h5py  # rare, some distributions use HDF5
        except Exception:
            h5py = None

        try:
            import geopandas as gpd
            from shapely.ops import unary_union
        except Exception:
            gpd = None
            unary_union = None

        # -------- progress bar --------
        try:
            from tqdm.auto import tqdm as _tqdm
        except Exception:
            _tqdm = None

        # -------- Dask --------
        dask_client = None
        dask_cluster = None
        dashboard_url = None
        if use_dask:
            try:
                from dask.distributed import Client, LocalCluster, default_client
                try:
                    dask_client = default_client()
                except Exception:
                    # spin a lightweight local cluster
                    if n_workers == "auto":
                        n_workers = max(1, os.cpu_count() // 2)
                    if threads_per_worker == "auto":
                        threads_per_worker = 1 if scheduler == "processes" else max(1, (os.cpu_count() // max(1, int(n_workers))))
                    dask_cluster = LocalCluster(
                        n_workers=int(n_workers),
                        threads_per_worker=int(threads_per_worker),
                        processes=(scheduler == "processes"),
                        dashboard_address=":0",
                    )
                    dask_client = Client(dask_cluster)
                dashboard_url = getattr(dask_client, "dashboard_link", None)
                if verbose and dashboard_url:
                    print(f"📊 Dask dashboard: {dashboard_url}")
            except Exception as e:
                if verbose:
                    print(f"⚠️ Dask not available ({e}); falling back to serial per-tile.")
                dask_client = None
                dask_cluster = None

        # -------- ROI parsing (bbox or vector) --------
        roi_geom = None
        if isinstance(roi, str):
            if gpd is None or unary_union is None:
                raise RuntimeError("Reading vector ROI requires geopandas and shapely. pip install geopandas shapely")
            if not os.path.exists(roi):
                raise FileNotFoundError(f"ROI vector not found: {roi}")
            if verbose:
                print(f"📐 Reading ROI vector: {roi}")
            gdf = gpd.read_file(roi)
            if gdf.empty:
                raise ValueError("Vector ROI is empty.")
            if gdf.crs is None or str(gdf.crs).upper() not in ("EPSG:4326", "OGC:CRS84"):
                gdf = gdf.to_crs("EPSG:4326")
            roi_geom = unary_union([geom for geom in gdf.geometry if geom is not None and not geom.is_empty])
            if roi_geom.is_empty:
                raise ValueError("Vector ROI union is empty.")
            minx, miny, maxx, maxy = roi_geom.bounds
        else:
            minx, miny, maxx, maxy = map(float, roi)
            if (maxx - minx) <= 0 or (maxy - miny) <= 0:
                raise ValueError("ROI bbox must have positive area.")

        # -------- IO and temp dirs --------
        os.makedirs(output_folder, exist_ok=True)
        cache_dir = os.path.join(output_folder, "_earthaccess_cache")
        os.makedirs(cache_dir, exist_ok=True)
        granule_tif_dir = os.path.join(output_folder, "_granule_tifs")
        os.makedirs(granule_tif_dir, exist_ok=True)
        tile_mosaic_dir = os.path.join(output_folder, "_tile_mosaics")
        os.makedirs(tile_mosaic_dir, exist_ok=True)

        tmp_root = temp_dir or os.path.join(output_folder, "_tmp")
        os.makedirs(tmp_root, exist_ok=True)
        os.environ.setdefault("TEMP", tmp_root)
        os.environ.setdefault("TMP", tmp_root)
        os.environ.setdefault("TMPDIR", tmp_root)
        os.environ.setdefault("CPL_TMPDIR", tmp_root)
        os.environ.setdefault("GDAL_CACHEMAX", "256")
        tempfile.tempdir = tmp_root

        # -------- bands wanted --------
        HKM_DATASETS = [
            ("EV_250_Aggr500_RefSB", {0: "B01", 1: "B02"}),
            ("EV_500_RefSB",         {0: "B03", 1: "B04", 2: "B05", 3: "B06", 4: "B07"}),
        ]
        ALL_BANDS = ["B01", "B02", "B03", "B04", "B05", "B06", "B07"]
        if isinstance(band_list, str) and band_list.lower() == "all":
            bands_wanted = set(ALL_BANDS)
        else:
            bands_wanted = set([str(b).upper() for b in band_list])
            unknown = bands_wanted - set(ALL_BANDS)
            if unknown:
                raise ValueError(f"Unknown band(s): {sorted(unknown)}. Valid: {ALL_BANDS}")

        # -------- earthaccess login --------
        if verbose:
            print("🔐 Logging into Earthdata (LAADS/DAAC) ...")
        try:
            if edl_username and edl_password:
                ea.login(strategy="environment", username=edl_username, password=edl_password)
            elif login_strategy:
                ea.login(strategy=login_strategy)
            else:
                ea.login()  # default (netrc/interactive)
        except Exception as e:
            raise RuntimeError(f"earthaccess login failed: {e}")

        # -------- helpers --------
        def _granule_name(granule) -> str:
            if isinstance(granule, str):
                return os.path.basename(granule)
            try:
                # UMM
                umm = getattr(granule, "umm", None) or {}
                ur = umm.get("GranuleUR") or umm.get("granuleUr") or ""
                if ur:
                    return ur
            except Exception:
                pass
            for attr in ("meta", "metadata"):
                d = getattr(granule, attr, None)
                if isinstance(d, dict):
                    for k in ("GranuleUR", "granuleUr", "title", "name", "filename"):
                        if k in d and d[k]:
                            return d[k]
            links = getattr(granule, "data_links", None) or getattr(granule, "links", None) or []
            try:
                for u in links:
                    if isinstance(u, str) and u.lower().startswith("http") and u.endswith(".hdf"):
                        return os.path.basename(u)
            except Exception:
                pass
            assets = getattr(granule, "assets", None)
            if isinstance(assets, dict):
                for v in assets.values():
                    href = (v or {}).get("href")
                    if href:
                        return os.path.basename(href)
            return ""

        def _granule_token(name: str) -> str:
            """
            Return token AYYYYDOYHHMM (no dot) to match cached TIFFs like:
            terra_toa_B02_20160111_A20160111225_tile4x3.tif
            """
            m = re.search(r"\.A(\d{7})\.(\d{4})\.", name or "")
            if m:
                return f"A{m.group(1)}{m.group(2)}"
            # accept already-merged token form
            m2 = re.search(r"\.A(\d{11})\.", name or "")
            if m2:
                return f"A{m2.group(1)}"
            base = os.path.splitext(os.path.basename(name or "gran"))[0]
            return re.sub(r"[^A-Za-z0-9]+", "", base)[-22:] or "gran"
        
        

        # Function to test if ALL band×tile TIFFs exist for a swath (day_key, token)
        def _all_granule_tile_tifs_exist(day_key: str, token: str) -> bool:
            if not day_key or not token:
                return False
            for b in bands_wanted:
                for tag in tile_tags:
                    path = os.path.join(
                        granule_tif_dir,
                        f"{filename_prefix}_{b}_{day_key}_{token}_tile{tag}.tif"
                    )
                    if not os.path.exists(path):
                        return False
            return True

        # Register existing TIFFs for a granule (day_key, token)
        def _register_existing_granule_tile_tifs(day_key: str, token: str):
            for b in bands_wanted:
                for tag in tile_tags:
                    path = os.path.join(
                        granule_tif_dir,
                        f"{filename_prefix}_{b}_{day_key}_{token}_tile{tag}.tif"
                    )
                    if os.path.exists(path):
                        per_tile_groups_global[(day_key, b, tag)].append(path)

        def day_key_from_name(name: str) -> str:
            # Prefer MODIS token: AYYYYDOY[. or nothing][HHMM]
            m = re.search(r"A(\d{4})(\d{3})(?:\.?\d{4})?", name or "")
            if m:
                year = int(m.group(1))
                doy = int(m.group(2))
                dt = datetime(year, 1, 1) + timedelta(days=doy - 1)
                return dt.strftime("%Y%m%d")
            # Fallback: 8-digit date found in cached filenames (e.g., ..._20160101_...)
            m2 = re.search(r"(?:^|[_-])(\d{8})(?:[_-]|$)", name or "")
            if m2:
                return m2.group(1)
            return ""

        def _day_key_from_any(granule, local_path: str | None):
            nm = _granule_name(granule)
            if not nm and local_path:
                nm = os.path.basename(local_path)
            if not nm:
                return ""
            dk = day_key_from_name(nm)
            return dk or ""

        def _cached_local_path_for_granule(granule) -> str | None:
            links = getattr(granule, "data_links", None) or getattr(granule, "links", None) or []
            try:
                for url in links:
                    if isinstance(url, str) and url.lower().startswith("http"):
                        name = os.path.basename(url)
                        cand = os.path.join(cache_dir, name)
                        if os.path.exists(cand):
                            return cand
            except Exception:
                pass
            name = _granule_name(granule)
            if name:
                cand = os.path.join(cache_dir, os.path.basename(name))
                if os.path.exists(cand):
                    return cand
            return None

        def open_granule_filelike(granule) -> str:
            if isinstance(granule, str) and os.path.isfile(granule):
                return granule
            cached = _cached_local_path_for_granule(granule)
            if cached:
                return cached
            paths = ea.download([granule], provider="LAADS", local_path=cache_dir)
            if isinstance(paths, dict):
                local_path = next(iter(paths.values()), None)
            elif isinstance(paths, (list, tuple)):
                local_path = paths[0] if paths else None
            else:
                local_path = None
            if not local_path or (not os.path.exists(local_path)):
                raise FileNotFoundError("earthaccess returned no local path for granule")
            if verbose:
                print(f"⬇️  Downloaded: {os.path.basename(local_path)}")
            return local_path

        def read_latlon_from_mod03(geo_path: str):
            # Try HDF5 path (rare for MOD03/MYD03)
            if h5py is not None:
                try:
                    with h5py.File(geo_path, "r") as f:
                        if "Latitude" in f and "Longitude" in f:
                            lat = f["Latitude"][()].astype(np.float32)
                            lon = f["Longitude"][()].astype(np.float32)
                            lon = np.where(lon > 180.0, lon - 360.0, lon)
                            return lat, lon
                except Exception:
                    pass
            # HDF4 (common)
            sd = SD(geo_path, SDC.READ)
            try:
                lat_ds = sd.select("Latitude")
                lon_ds = sd.select("Longitude")
                lat = lat_ds.get().astype(np.float32)
                lon = lon_ds.get().astype(np.float32)
                lon = np.where(lon > 180.0, lon - 360.0, lon)
                return lat, lon
            finally:
                sd.end()

        def _attr_value(attrs: dict, key: str, default=None):
            for k in (key, key.upper(), key.lower()):
                if k in attrs:
                    return attrs[k]
            return default

        def _as_scalar(value, idx, fallback):
            try:
                arr = np.array(value)
                if arr.ndim == 1 and idx < arr.size:
                    return float(arr[idx])
                if arr.size == 1:
                    return float(arr.item())
            except Exception:
                pass
            try:
                return float(value)
            except Exception:
                return float(fallback)

        def read_toa_from_mod02hkm(l1b_path: str) -> dict[str, np.ndarray]:
            out: dict[str, np.ndarray] = {}
            sd = SD(l1b_path, SDC.READ)
            try:
                # Read 250m aggregated (B01, B02)
                try:
                    ds_250 = sd.select("EV_250_Aggr500_RefSB")
                    data_250 = ds_250.get().astype(np.float32)  # shape (bands, lines, samples)
                    attrs_250 = ds_250.attributes()
                    scales_250 = _attr_value(attrs_250, "reflectance_scales", None)
                    offsets_250 = _attr_value(attrs_250, "reflectance_offsets", None)
                except Exception:
                    data_250, scales_250, offsets_250 = None, None, None

                # Read 500m (B03..B07)
                try:
                    ds_500 = sd.select("EV_500_RefSB")
                    data_500 = ds_500.get().astype(np.float32)
                    attrs_500 = ds_500.attributes()
                    scales_500 = _attr_value(attrs_500, "reflectance_scales", None)
                    offsets_500 = _attr_value(attrs_500, "reflectance_offsets", None)
                except Exception:
                    data_500, scales_500, offsets_500 = None, None, None
            finally:
                sd.end()

            # Apply calibration; ignore negative fill values
            if data_250 is not None:
                for i, bname in {0: "B01", 1: "B02"}.items():
                    band = data_250[i, :, :].astype(np.float32, copy=False)
                    sf = _as_scalar(scales_250, i, 1.0) if scales_250 is not None else 1.0
                    of = _as_scalar(offsets_250, i, 0.0) if offsets_250 is not None else 0.0
                    band = band * sf + of
                    band[band < 0] = np.nan
                    out[bname] = band

            if data_500 is not None:
                for i, bname in {0: "B03", 1: "B04", 2: "B05", 3: "B06", 4: "B07"}.items():
                    band = data_500[i, :, :].astype(np.float32, copy=False)
                    sf = _as_scalar(scales_500, i, 1.0) if scales_500 is not None else 1.0
                    of = _as_scalar(offsets_500, i, 0.0) if offsets_500 is not None else 0.0
                    band = band * sf + of
                    band[band < 0] = np.nan
                    out[bname] = band

            return out

        def _align_geo_to_band(lat, lon, band_arr: np.ndarray):
            lat = np.array(lat, dtype=np.float32, copy=False)
            lon = np.array(lon, dtype=np.float32, copy=False)
            bl, bs = band_arr.shape
            gl, gs = lat.shape
            # MOD03 typically at 1km; L1B HKM 500m => 2x upsample
            if (gl, gs) == (bl, bs):
                return lat, lon
            if gl * 2 == bl and gs * 2 == bs:
                # simple nearest upsample to match
                lat_u = np.repeat(np.repeat(lat, 2, axis=0), 2, axis=1)
                lon_u = np.repeat(np.repeat(lon, 2, axis=0), 2, axis=1)
                return lat_u, lon_u
            # fallback: resize by simple nearest ratio
            ry = max(1, round(bl / max(1, gl)))
            rx = max(1, round(bs / max(1, gs)))
            lat_u = np.repeat(np.repeat(lat, ry, axis=0), rx, axis=1)
            lon_u = np.repeat(np.repeat(lon, ry, axis=0), rx, axis=1)
            lat_u = lat_u[:bl, :bs]
            lon_u = lon_u[:bl, :bs]
            return lat_u, lon_u

        def make_target_grid(bbox, res_deg_):
            x0, y0, x1, y1 = bbox
            width = int(math.ceil((x1 - x0) / res_deg_))
            height = int(math.ceil((y1 - y0) / res_deg_))
            transform = from_origin(x0, y1, res_deg_, res_deg_)
            area_def = geometry.AreaDefinition(
                "roi_ll",
                "regular latlon grid",
                "epsg4326",
                {"proj": "longlat", "datum": "WGS84"},
                width,
                height,
                [x0, y0, x1, y1],
            )
            return area_def, transform, width, height

        def _normalize_split(n) -> tuple[int, int]:
            if isinstance(n, (list, tuple)) and len(n) == 2:
                ny = max(1, int(n[0]))
                nx = max(1, int(n[1]))
                return ny, nx
            n = max(1, int(n))
            # make a roughly square grid
            ny = int(math.sqrt(n))
            nx = max(1, int(math.ceil(n / ny)))
            return ny, nx

        def _split_bbox(bbox: tuple[float, float, float, float], ny: int, nx: int):
            x0, y0, x1, y1 = bbox
            dx = (x1 - x0) / nx
            dy = (y1 - y0) / ny
            tiles = []
            for iy in range(ny):
                for ix in range(nx):
                    tiles.append((x0 + ix * dx, y0 + iy * dy, x0 + (ix + 1) * dx, y0 + (iy + 1) * dy))
            return tiles

        def swath_to_grid(band_arr, lat_, lon_, area_def_, radius_):
            lat_a, lon_a = _align_geo_to_band(lat_, lon_, band_arr)
            vals = band_arr.astype(np.float32, copy=False).ravel()
            lats = lat_a.ravel()
            lons = lon_a.ravel()
            valid = np.isfinite(vals)
            if not np.any(valid):
                return np.full((area_def_.shape[0], area_def_.shape[1]), np.nan, dtype=np.float32)
            vals = vals[valid]
            lats = lats[valid]
            lons = lons[valid]
            swath_def = geometry.SwathDefinition(lons=lons, lats=lats)
            with warnings.catch_warnings():
                warnings.simplefilter("ignore")
                grid = kd_tree.resample_nearest(
                    swath_def,
                    vals,
                    area_def_,
                    radius_of_influence=max(1000, int(radius_)),
                    fill_value=np.nan,
                    reduce_data=True,
                    nprocs=1,
                )
            return grid.astype(np.float32, copy=False)

        def write_single_band_tif(path, arr, transform, width, height):
            profile = {
                "driver": "GTiff",
                "height": int(height),
                "width": int(width),
                "count": 1,
                "dtype": "float32",
                "crs": "EPSG:4326",
                "transform": transform,
                "compress": "deflate",
                "predictor": 2,
                "tiled": True,
                "blockxsize": 256,
                "blockysize": 256,
                "nodata": np.float32(np.nan),
            }
            os.makedirs(os.path.dirname(path) or ".", exist_ok=True)
            with rasterio.open(path, "w", **profile) as dst:
                dst.write(arr.astype(np.float32, copy=False), 1)

        def _apply_roi_mask_if_needed(arr2d: np.ndarray, transform, width, height):
            if roi_geom is None:
                return arr2d
            try:
                m = rasterize(
                    [(roi_geom, 1)],
                    out_shape=(int(height), int(width)),
                    transform=transform,
                    fill=0,
                    dtype="uint8",
                    all_touched=False,
                )
                out = arr2d.copy()
                out[m == 0] = np.nan
                return out
            except Exception:
                return arr2d

        
        def _tokens_for_name(name: str) -> list[str]:
            toks = []
            m = re.search(r"\.A(\d{7})\.(\d{4})\.", name or "")
            if m:
                toks.append(f"A{m.group(1)}{m.group(2)}")   # no-dot canonical
                toks.append(f"A{m.group(1)}.{m.group(2)}")  # dotted, for safety
            else:
                base = os.path.splitext(os.path.basename(name or "gran"))[0]
                toks.append(re.sub(r"[^A-Za-z0-9]+", "", base)[-22:] or "gran")
            # dedupe
            seen, out = set(), []
            for t in toks:
                if t not in seen:
                    out.append(t); seen.add(t)
            return out

        def _all_granule_tile_tifs_exist_any_prefix(day_key: str, tokens: list[str]) -> tuple[bool, dict]:
            if not day_key or not tokens:
                return False, {"reason": "no day/token"}
            for tag in tile_tags:
                for b in bands_wanted:
                    found = False
                    tried = []
                    for tok in tokens:
                        pat = os.path.join(granule_tif_dir, f"*_{b}_{day_key}_{tok}_tile{tag}.tif")
                        tried.append(pat)
                        if glob(pat):
                            found = True
                            break
                    if not found:
                        return False, {"reason": "missing tile", "band": b, "tile": tag, "tried": tried}
            return True, {}

        def _register_existing_granule_tile_tifs_any_prefix(day_key: str, tokens: list[str], per_tile_groups_global):
            for tag in tile_tags:
                for b in bands_wanted:
                    for tok in tokens:
                        for p in glob(os.path.join(granule_tif_dir, f"*_{b}_{day_key}_{tok}_tile{tag}.tif")):
                            per_tile_groups_global[(day_key, b, tag)].append(p)
        
        # -------- search LAADS --------
        def search(product, start_dt, end_dt, bbox):
            return ea.search_data(
                short_name=product,
                temporal=(start_dt, end_dt),
                bounding_box=bbox,
                provider="LAADS",
                granule_name="*.hdf",
            )

        def pair_l1b_with_geo(l1b_list, geo_list):
            geo_by_tok = {}
            for g in geo_list:
                name_g = _granule_name(g)
                tok_g = _granule_token(name_g)
                geo_by_tok[tok_g] = g
            pairs_ = []
            for sw in l1b_list:
                name_sw = _granule_name(sw)
                tok_sw = _granule_token(name_sw)
                g = geo_by_tok.get(tok_sw)
                if g is not None:
                    pairs_.append((sw, g))
            return pairs_

        start_dt = datetime.strptime(start_date, "%Y-%m-%d")
        end_dt = datetime.strptime(end_date, "%Y-%m-%d")
        l1b, geo = [], []
        use_terra = platform.lower() in ("terra", "both")
        use_aqua = platform.lower() in ("aqua", "both")
        if use_terra:
            l1b += search("MOD02HKM", start_dt, end_dt, (minx, miny, maxx, maxy))
            geo += search("MOD03", start_dt, end_dt, (minx, miny, maxx, maxy))
        if use_aqua:
            l1b += search("MYD02HKM", start_dt, end_dt, (minx, miny, maxx, maxy))
            geo += search("MYD03", start_dt, end_dt, (minx, miny, maxx, maxy))

        pairs = pair_l1b_with_geo(l1b, geo)
        if not pairs:
            if verbose:
                print("⚠️ No matching L1B/GEO pairs found for the search window/ROI.")
            if dask_client:
                try:
                    dask_client.close()
                    if dask_cluster:
                        dask_cluster.close()
                except Exception:
                    pass
            return {"processed_pairs": 0, "written": 0, "days": 0, "paths": [], "dashboard": dashboard_url}

        # -------- skip whole days if all final outputs already exist --------
        if not overwrite:
            def _pair_day_key(p):
                sw = p[0]
                dk = _day_key_from_any(sw, _cached_local_path_for_granule(sw))
                return dk or None

            day_keys = set(filter(None, (_pair_day_key(p) for p in pairs)))
            skip_days = set()
            for d in day_keys:
                all_exist = all(os.path.exists(os.path.join(output_folder, f"{filename_prefix}_{b}_{d}.tif")) for b in bands_wanted)
                if all_exist:
                    skip_days.add(d)
            if skip_days and verbose:
                print(f"⏭️  Skipping {len(skip_days)} day(s) with all final outputs present.")
            if skip_days:
                pairs = [p for p in pairs if _pair_day_key(p) not in skip_days]

        if not pairs:
            if verbose:
                print("⚠️ Nothing to process after skipping fully-done days.")
            if dask_client:
                try:
                    dask_client.close()
                    if dask_cluster:
                        dask_cluster.close()
                except Exception:
                    pass
            return {"processed_pairs": 0, "written": 0, "days": 0, "paths": [], "dashboard": dashboard_url}

        # -------- tiling --------
        ny, nx = _normalize_split(n_roi_split)
        tile_bboxes = _split_bbox((minx, miny, maxx, maxy), ny, nx)
        # Precompute tile tags
        tile_tags = [f"{ty}x{tx}" for ty in range(ny) for tx in range(nx)]
        
        def _tile_tag(idx1: int) -> str:
            ty, tx = divmod(idx1 - 1, nx)
            return f"{ty}x{tx}"

        # -------- worker: compute one swath pair for one tile --------
        def _process_pair_tile(sw_path: str, geo_path: str, bbox_t, tile_tag: str):
            res = []  # list of ("tif", day_key, band, tif_path, tile_tag)
            try:
                # parse IDs
                sw_name = _granule_name(sw_path)
                gtok = _granule_token(sw_name)
                day_key = day_key_from_name(sw_name) or ""
                if not day_key:
                    day_key = day_key_from_name(os.path.basename(sw_path)) or "unknown"

                # target grid for tile
                area_def_t, transform_t, width_t, height_t = make_target_grid(bbox_t, res_deg)

                # Check per-granule per-tile tifs existence per band
                existing_tile_tifs = []
                missing_bands = []
                for bname in sorted(bands_wanted):
                    tif_path = os.path.join(
                        granule_tif_dir,
                        f"{filename_prefix}_{bname}_{day_key}_{gtok}_tile{tile_tag}.tif"
                    )
                    if (not overwrite) and os.path.exists(tif_path):
                        existing_tile_tifs.append(("tif", day_key, bname, tif_path, tile_tag))
                    else:
                        missing_bands.append(bname)

                if (not overwrite) and len(existing_tile_tifs) == len(bands_wanted):
                    return existing_tile_tifs

                # open geo and bands
                lat, lon = read_latlon_from_mod03(geo_path)
                bands = read_toa_from_mod02hkm(sw_path)
                if not bands:
                    return existing_tile_tifs  # might be empty

                # append existing ones first
                if existing_tile_tifs:
                    res.extend(existing_tile_tifs)

                # compute missing only
                for bname, arr in bands.items():
                    if bname not in bands_wanted:
                        continue
                    if (not overwrite) and (bname not in missing_bands):
                        continue
                    if arr is None or not np.isfinite(arr).any():
                        continue
                    grid = swath_to_grid(arr, lat, lon, area_def_t, radius_m)
                    grid = _apply_roi_mask_if_needed(grid, transform_t, width_t, height_t)
                    tif_path = os.path.join(
                        granule_tif_dir,
                        f"{filename_prefix}_{bname}_{day_key}_{gtok}_tile{tile_tag}.tif"
                    )
                    write_single_band_tif(tif_path, grid, transform_t, width_t, height_t)
                    res.append(("tif", day_key, bname, tif_path, tile_tag))

                return res
            except Exception as e:
                if verbose:
                    print(f"❌ Tile {tile_tag} failed for {os.path.basename(sw_path)}: {e}")
                return res

        per_tile_groups_global = defaultdict(list)
        pair_iter = pairs
        if show_progress and _tqdm is not None:
            pair_iter = _tqdm(pairs, desc="Granules (serial, tiles parallel)", unit="gran")

        for sw_g, geo_g in pair_iter:
            # -------- PRE-CHECK: reuse cached per‑granule tiles; avoid HDF download --------
            if not overwrite:
                try:
                    sw_name_meta = _granule_name(sw_g) or ""
                    day_meta = day_key_from_name(sw_name_meta)
                    tokens = _tokens_for_name(sw_name_meta) if sw_name_meta else []
                    all_ok, dbg = _all_granule_tile_tifs_exist_any_prefix(day_meta, tokens)
                    if all_ok:
                        _register_existing_granule_tile_tifs_any_prefix(day_meta, tokens, per_tile_groups_global)
                        if verbose and day_meta:
                            # requested message format
                            print(f"{day_meta}: skipped downloading HDF because it exists (cached tiles found).")
                        # optional cleanup of any lingering HDFs for this swath
                        if remove_cache:
                            for base_name in (sw_name_meta, _granule_name(geo_g) or ""):
                                if not base_name:
                                    continue
                                cand = os.path.join(cache_dir, os.path.basename(base_name))
                                try:
                                    if os.path.isfile(cand):
                                        os.remove(cand)
                                except Exception:
                                    pass
                        continue
                    else:
                        if verbose and dbg.get("reason") == "missing tile":
                            # show first missing pattern to help diagnose mismatches
                            tried = dbg.get("tried") or []
                            if tried:
                                print(f"Missing cached tile → band={dbg['band']} tile={dbg['tile']} | tried: {tried[0]}")
                except Exception:
                    # best-effort pre-check
                    pass

            
            # -------- NORMAL FLOW (download or reuse cached HDFs) --------
            sw_path = None
            geo_path = None
            try:
                sw_path = open_granule_filelike(sw_g)
                geo_path = open_granule_filelike(geo_g)

                sw_name = _granule_name(sw_g) or os.path.basename(sw_path)
                day_key = day_key_from_name(sw_name) or day_key_from_name(os.path.basename(sw_path)) or "unknown"
                token = _granule_token(sw_name)

                # Final day outputs present → skip whole swath
                if (not overwrite) and day_key != "unknown":
                    if all(os.path.exists(os.path.join(output_folder, f"{filename_prefix}_{b}_{day_key}.tif")) for b in bands_wanted):
                        if verbose:
                            print(f"⏭️  Skip swath (final outputs exist for {day_key}).")
                        continue

                # Submit/gather per-tile tasks
                futures = []
                results_lists = []
                for idx1, bbox_t in enumerate(tile_bboxes, start=1):
                    tag = _tile_tag(idx1, nx)
                    if use_dask and dask_client:
                        futures.append(dask_client.submit(_process_pair_tile, sw_path, geo_path, bbox_t, tag))
                    else:
                        results_lists.append(_process_pair_tile(sw_path, geo_path, bbox_t, tag))
                if futures:
                    results_lists = dask_client.gather(futures)

                for lst in results_lists:
                    for rec in (lst or []):
                        if not rec or rec[0] != "tif":
                            continue
                        _, dk_rec, bname, tif_path, tile_tag = rec
                        if dk_rec != "unknown":
                            per_tile_groups_global[(dk_rec, bname, tile_tag)].append(tif_path)
            finally:
                if remove_cache:
                    for p in (sw_path, geo_path):
                        try:
                            if p and os.path.isfile(p):
                                os.remove(p)
                        except Exception:
                            pass
                    if verbose and (sw_path or geo_path):
                        print("🧹 Removed cached HDFs for completed swath.")

        # -------- build per-tile mosaics across granules --------
        final_tile_mosaics = defaultdict(list)  # (day_key, band) -> [tile mosaic path]
        for (day_key, bname, tile_tag), tif_list in sorted(per_tile_groups_global.items()):
            if not tif_list:
                continue
            tile_out = os.path.join(tile_mosaic_dir, f"{filename_prefix}_{bname}_{day_key}_tile{tile_tag}.tif")
            if (not overwrite) and os.path.exists(tile_out):
                final_tile_mosaics[(day_key, bname)].append(tile_out)
                continue
            try:
                srcs = [rasterio.open(p) for p in tif_list]
                mosaic, out_transform = rio_merge(srcs, method="first")
                for s in srcs:
                    s.close()
                # drop band axis if present
                if mosaic.ndim == 3 and mosaic.shape[0] == 1:
                    mosaic = mosaic[0]
                # apply ROI mask again to clean edges (cheap)
                mosaic = _apply_roi_mask_if_needed(mosaic, out_transform, mosaic.shape[1], mosaic.shape[0])
                write_single_band_tif(tile_out, mosaic.astype(np.float32, copy=False), out_transform, mosaic.shape[1], mosaic.shape[0])
                final_tile_mosaics[(day_key, bname)].append(tile_out)
            except Exception as me:
                if verbose:
                    print(f"❌ Tile mosaic failed for {bname} {day_key} [tile {tile_tag}]: {me}")

        # -------- final mosaics over tiles --------
        written_paths = []
        days = set()
        for (day_key, bname), tile_paths in sorted(final_tile_mosaics.items()):
            if not tile_paths:
                continue
            out_fp = os.path.join(output_folder, f"{filename_prefix}_{bname}_{day_key}.tif")
            if (not overwrite) and os.path.exists(out_fp):
                continue
            try:
                srcs = [rasterio.open(p) for p in tile_paths]
                mosaic, out_transform = rio_merge(srcs, method="first")
                for s in srcs:
                    s.close()
                if mosaic.ndim == 3 and mosaic.shape[0] == 1:
                    mosaic = mosaic[0]
                mosaic = _apply_roi_mask_if_needed(mosaic, out_transform, mosaic.shape[1], mosaic.shape[0])
                write_single_band_tif(out_fp, mosaic.astype(np.float32, copy=False), out_transform, mosaic.shape[1], mosaic.shape[0])
                written_paths.append(out_fp)
                days.add(day_key)
            except Exception as me:
                if verbose:
                    print(f"❌ Final mosaic failed for {bname} {day_key}: {me}")

        if verbose:
            print(f"✅ MODIS TOA complete. Tiles={ny}x{nx} Pairs={len(pairs)} Days={len(days)} Written={len(written_paths)}")

        if dask_client:
            try:
                dask_client.close()
                if dask_cluster:
                    dask_cluster.close()
            except Exception:
                pass

        return {
            "processed_pairs": len(pairs),
            "written": len(written_paths),
            "days": len(days),
            "paths": written_paths,
            "dashboard": dashboard_url,
        }
    
    def download_modis_toa_v21(
        self,
        band_list: list[str] | str,
        output_folder: str,
        roi: tuple[float, float, float, float] | str,
        start_date: str,
        end_date: str,
        *,
        platform: str = "terra",         # "terra" | "aqua" | "both"
        res_deg: float = 0.0045,         # ~500 m @ equator
        radius_m: int = 4000,            # swath->grid nearest-neighbor radius (m)
        filename_prefix: str = "modis_toa",
        overwrite: bool = False,
        verbose: bool = True,
        edl_username: str | None = None,
        edl_password: str | None = None,
        login_strategy: str | None = None,
        temp_dir: str | None = None,
        # parallel knobs (used inside each tile)
        use_dask: bool = True,
        n_workers: int | str = "auto",
        threads_per_worker: int | str = "auto",
        scheduler: str = "processes",
        # Split ROI bbox into ny x nx tiles (sequential tiles → low RAM)
        n_roi_split: int | tuple[int, int] = 100,
        # Progress bars for tiles and per-tile granules
        show_progress: bool = True,
        # delete current swath HDFs right after tiles are finished (before downloading next one)
        remove_cache: bool = False,
    ) -> dict:
        """
        Download MODIS L1B TOA reflectance (HKM, 500 m) and write one GeoTIFF per band per day.

        Behavior
        - One swath pair at a time; within the swath, all tiles are processed in parallel (Dask if enabled).
        - If remove_cache=True, the pair’s cached HDFs are removed immediately after its tiles finish.
        - Skips existing work:
        - reuses per‑granule per‑tile TIFFs if present,
        - reuses per‑tile mosaics if present,
        - reuses final mosaics if present.

        Output
        - {output_folder}/_granule_tifs/{prefix}_{Band}_{YYYYMMDD}_{GranToken}_tile{ty}x{tx}.tif
        - {output_folder}/_tile_mosaics/{prefix}_{Band}_{YYYYMMDD}_tile{ty}x{tx}.tif
        - {output_folder}/{prefix}_{Band}_{YYYYMMDD}.tif
        """
        # -------- imports (scoped to keep class import surface small) --------
        import os, re, math, warnings, tempfile
        from collections import defaultdict
        from datetime import datetime, timedelta

        import numpy as np
        import rasterio
        from rasterio.merge import merge as rio_merge
        from rasterio.transform import from_origin
        from rasterio.features import rasterize

        try:
            import earthaccess as ea
        except Exception as e:
            raise RuntimeError("earthaccess is required. pip install earthaccess") from e

        try:
            from pyresample import geometry, kd_tree
        except Exception as e:
            raise RuntimeError("pyresample is required. pip install pyresample") from e

        try:
            from pyhdf.SD import SD, SDC  # HDF4 reader
        except Exception as e:
            raise RuntimeError("pyhdf is required for MODIS HDF4. pip install pyhdf") from e

        try:
            import h5py  # rare, some distributions use HDF5
        except Exception:
            h5py = None

        try:
            import geopandas as gpd
            from shapely.ops import unary_union
        except Exception:
            gpd = None
            unary_union = None

        # -------- progress bar --------
        try:
            from tqdm.auto import tqdm as _tqdm
        except Exception:
            _tqdm = None

        # -------- Dask --------
        dask_client = None
        dask_cluster = None
        dashboard_url = None
        if use_dask:
            try:
                from dask.distributed import Client, LocalCluster, default_client
                try:
                    dask_client = default_client()
                except Exception:
                    # spin a lightweight local cluster
                    if n_workers == "auto":
                        n_workers = max(1, os.cpu_count() // 2)
                    if threads_per_worker == "auto":
                        threads_per_worker = 1 if scheduler == "processes" else max(1, (os.cpu_count() // max(1, int(n_workers))))
                    dask_cluster = LocalCluster(
                        n_workers=int(n_workers),
                        threads_per_worker=int(threads_per_worker),
                        processes=(scheduler == "processes"),
                        dashboard_address=":0",
                    )
                    dask_client = Client(dask_cluster)
                dashboard_url = getattr(dask_client, "dashboard_link", None)
                if verbose and dashboard_url:
                    print(f"📊 Dask dashboard: {dashboard_url}")
            except Exception as e:
                if verbose:
                    print(f"⚠️ Dask not available ({e}); falling back to serial per-tile.")
                dask_client = None
                dask_cluster = None

        # -------- ROI parsing (bbox or vector) --------
        roi_geom = None
        if isinstance(roi, str):
            if gpd is None or unary_union is None:
                raise RuntimeError("Reading vector ROI requires geopandas and shapely. pip install geopandas shapely")
            if not os.path.exists(roi):
                raise FileNotFoundError(f"ROI vector not found: {roi}")
            if verbose:
                print(f"📐 Reading ROI vector: {roi}")
            gdf = gpd.read_file(roi)
            if gdf.empty:
                raise ValueError("Vector ROI is empty.")
            if gdf.crs is None or str(gdf.crs).upper() not in ("EPSG:4326", "OGC:CRS84"):
                gdf = gdf.to_crs("EPSG:4326")
            roi_geom = unary_union([geom for geom in gdf.geometry if geom is not None and not geom.is_empty])
            if roi_geom.is_empty:
                raise ValueError("Vector ROI union is empty.")
            minx, miny, maxx, maxy = roi_geom.bounds
        else:
            minx, miny, maxx, maxy = map(float, roi)
            if (maxx - minx) <= 0 or (maxy - miny) <= 0:
                raise ValueError("ROI bbox must have positive area.")

        # -------- IO and temp dirs --------
        os.makedirs(output_folder, exist_ok=True)
        cache_dir = os.path.join(output_folder, "_earthaccess_cache")
        os.makedirs(cache_dir, exist_ok=True)
        granule_tif_dir = os.path.join(output_folder, "_granule_tifs")
        os.makedirs(granule_tif_dir, exist_ok=True)
        tile_mosaic_dir = os.path.join(output_folder, "_tile_mosaics")
        os.makedirs(tile_mosaic_dir, exist_ok=True)

        tmp_root = temp_dir or os.path.join(output_folder, "_tmp")
        os.makedirs(tmp_root, exist_ok=True)
        os.environ.setdefault("TEMP", tmp_root)
        os.environ.setdefault("TMP", tmp_root)
        os.environ.setdefault("TMPDIR", tmp_root)
        os.environ.setdefault("CPL_TMPDIR", tmp_root)
        os.environ.setdefault("GDAL_CACHEMAX", "256")
        tempfile.tempdir = tmp_root

        # -------- bands wanted --------
        HKM_DATASETS = [
            ("EV_250_Aggr500_RefSB", {0: "B01", 1: "B02"}),
            ("EV_500_RefSB",         {0: "B03", 1: "B04", 2: "B05", 3: "B06", 4: "B07"}),
        ]
        ALL_BANDS = ["B01", "B02", "B03", "B04", "B05", "B06", "B07"]
        if isinstance(band_list, str) and band_list.lower() == "all":
            bands_wanted = set(ALL_BANDS)
        else:
            bands_wanted = set([str(b).upper() for b in band_list])
            unknown = bands_wanted - set(ALL_BANDS)
            if unknown:
                raise ValueError(f"Unknown band(s): {sorted(unknown)}. Valid: {ALL_BANDS}")

        # -------- earthaccess login --------
        if verbose:
            print("🔐 Logging into Earthdata (LAADS/DAAC) ...")
        try:
            if edl_username and edl_password:
                ea.login(strategy="environment", username=edl_username, password=edl_password)
            elif login_strategy:
                ea.login(strategy=login_strategy)
            else:
                ea.login()  # default (netrc/interactive)
        except Exception as e:
            raise RuntimeError(f"earthaccess login failed: {e}")

        # -------- helpers --------
        def _granule_name(granule) -> str:
            if isinstance(granule, str):
                return os.path.basename(granule)
            try:
                # UMM
                umm = getattr(granule, "umm", None) or {}
                ur = umm.get("GranuleUR") or umm.get("granuleUr") or ""
                if ur:
                    return ur
            except Exception:
                pass
            for attr in ("meta", "metadata"):
                d = getattr(granule, attr, None)
                if isinstance(d, dict):
                    for k in ("GranuleUR", "granuleUr", "title", "name", "filename"):
                        if k in d and d[k]:
                            return d[k]
            links = getattr(granule, "data_links", None) or getattr(granule, "links", None) or []
            try:
                for u in links:
                    if isinstance(u, str) and u.lower().startswith("http") and u.endswith(".hdf"):
                        return os.path.basename(u)
            except Exception:
                pass
            assets = getattr(granule, "assets", None)
            if isinstance(assets, dict):
                for v in assets.values():
                    href = (v or {}).get("href")
                    if href:
                        return os.path.basename(href)
            return ""

        def _granule_token(name: str) -> str:
            # Use Ayyyydoy.hhmm if present else make a compact token
            m = re.search(r"\.A(\d{7})\.(\d{4})\.", name or "")
            if m:
                return f"A{m.group(1)}.{m.group(2)}"
            base = os.path.splitext(os.path.basename(name or "gran"))[0]
            return re.sub(r"[^A-Za-z0-9]+", "", base)[-22:] or "gran"

        def day_key_from_name(name: str) -> str:
            m = re.search(r"\.A(\d{4})(\d{3})\.\d{4}\.", name or "")
            if not m:
                return ""
            year = int(m.group(1))
            doy = int(m.group(2))
            dt = datetime(year, 1, 1) + timedelta(days=doy - 1)
            return dt.strftime("%Y%m%d")

        def _day_key_from_any(granule, local_path: str | None):
            nm = _granule_name(granule)
            if not nm and local_path:
                nm = os.path.basename(local_path)
            if not nm:
                return ""
            dk = day_key_from_name(nm)
            return dk or ""

        def _cached_local_path_for_granule(granule) -> str | None:
            links = getattr(granule, "data_links", None) or getattr(granule, "links", None) or []
            try:
                for url in links:
                    if isinstance(url, str) and url.lower().startswith("http"):
                        name = os.path.basename(url)
                        cand = os.path.join(cache_dir, name)
                        if os.path.exists(cand):
                            return cand
            except Exception:
                pass
            name = _granule_name(granule)
            if name:
                cand = os.path.join(cache_dir, os.path.basename(name))
                if os.path.exists(cand):
                    return cand
            return None

        def open_granule_filelike(granule) -> str:
            if isinstance(granule, str) and os.path.isfile(granule):
                return granule
            cached = _cached_local_path_for_granule(granule)
            if cached:
                return cached
            paths = ea.download([granule], provider="LAADS", local_path=cache_dir)
            if isinstance(paths, dict):
                local_path = next(iter(paths.values()), None)
            elif isinstance(paths, (list, tuple)):
                local_path = paths[0] if paths else None
            else:
                local_path = None
            if not local_path or (not os.path.exists(local_path)):
                raise FileNotFoundError("earthaccess returned no local path for granule")
            if verbose:
                print(f"⬇️  Downloaded: {os.path.basename(local_path)}")
            return local_path

        def read_latlon_from_mod03(geo_path: str):
            # Try HDF5 path (rare for MOD03/MYD03)
            if h5py is not None:
                try:
                    with h5py.File(geo_path, "r") as f:
                        if "Latitude" in f and "Longitude" in f:
                            lat = f["Latitude"][()].astype(np.float32)
                            lon = f["Longitude"][()].astype(np.float32)
                            lon = np.where(lon > 180.0, lon - 360.0, lon)
                            return lat, lon
                except Exception:
                    pass
            # HDF4 (common)
            sd = SD(geo_path, SDC.READ)
            try:
                lat_ds = sd.select("Latitude")
                lon_ds = sd.select("Longitude")
                lat = lat_ds.get().astype(np.float32)
                lon = lon_ds.get().astype(np.float32)
                lon = np.where(lon > 180.0, lon - 360.0, lon)
                return lat, lon
            finally:
                sd.end()

        def _attr_value(attrs: dict, key: str, default=None):
            for k in (key, key.upper(), key.lower()):
                if k in attrs:
                    return attrs[k]
            return default

        def _as_scalar(value, idx, fallback):
            try:
                arr = np.array(value)
                if arr.ndim == 1 and idx < arr.size:
                    return float(arr[idx])
                if arr.size == 1:
                    return float(arr.item())
            except Exception:
                pass
            try:
                return float(value)
            except Exception:
                return float(fallback)

        def read_toa_from_mod02hkm(l1b_path: str) -> dict[str, np.ndarray]:
            out: dict[str, np.ndarray] = {}
            sd = SD(l1b_path, SDC.READ)
            try:
                # Read 250m aggregated (B01, B02)
                try:
                    ds_250 = sd.select("EV_250_Aggr500_RefSB")
                    data_250 = ds_250.get().astype(np.float32)  # shape (bands, lines, samples)
                    attrs_250 = ds_250.attributes()
                    scales_250 = _attr_value(attrs_250, "reflectance_scales", None)
                    offsets_250 = _attr_value(attrs_250, "reflectance_offsets", None)
                except Exception:
                    data_250, scales_250, offsets_250 = None, None, None

                # Read 500m (B03..B07)
                try:
                    ds_500 = sd.select("EV_500_RefSB")
                    data_500 = ds_500.get().astype(np.float32)
                    attrs_500 = ds_500.attributes()
                    scales_500 = _attr_value(attrs_500, "reflectance_scales", None)
                    offsets_500 = _attr_value(attrs_500, "reflectance_offsets", None)
                except Exception:
                    data_500, scales_500, offsets_500 = None, None, None
            finally:
                sd.end()

            # Apply calibration; ignore negative fill values
            if data_250 is not None:
                for i, bname in {0: "B01", 1: "B02"}.items():
                    band = data_250[i, :, :].astype(np.float32, copy=False)
                    sf = _as_scalar(scales_250, i, 1.0) if scales_250 is not None else 1.0
                    of = _as_scalar(offsets_250, i, 0.0) if offsets_250 is not None else 0.0
                    band = band * sf + of
                    band[band < 0] = np.nan
                    out[bname] = band

            if data_500 is not None:
                for i, bname in {0: "B03", 1: "B04", 2: "B05", 3: "B06", 4: "B07"}.items():
                    band = data_500[i, :, :].astype(np.float32, copy=False)
                    sf = _as_scalar(scales_500, i, 1.0) if scales_500 is not None else 1.0
                    of = _as_scalar(offsets_500, i, 0.0) if offsets_500 is not None else 0.0
                    band = band * sf + of
                    band[band < 0] = np.nan
                    out[bname] = band

            return out

        def _align_geo_to_band(lat, lon, band_arr: np.ndarray):
            lat = np.array(lat, dtype=np.float32, copy=False)
            lon = np.array(lon, dtype=np.float32, copy=False)
            bl, bs = band_arr.shape
            gl, gs = lat.shape
            # MOD03 typically at 1km; L1B HKM 500m => 2x upsample
            if (gl, gs) == (bl, bs):
                return lat, lon
            if gl * 2 == bl and gs * 2 == bs:
                # simple nearest upsample to match
                lat_u = np.repeat(np.repeat(lat, 2, axis=0), 2, axis=1)
                lon_u = np.repeat(np.repeat(lon, 2, axis=0), 2, axis=1)
                return lat_u, lon_u
            # fallback: resize by simple nearest ratio
            ry = max(1, round(bl / max(1, gl)))
            rx = max(1, round(bs / max(1, gs)))
            lat_u = np.repeat(np.repeat(lat, ry, axis=0), rx, axis=1)
            lon_u = np.repeat(np.repeat(lon, ry, axis=0), rx, axis=1)
            lat_u = lat_u[:bl, :bs]
            lon_u = lon_u[:bl, :bs]
            return lat_u, lon_u

        def make_target_grid(bbox, res_deg_):
            x0, y0, x1, y1 = bbox
            width = int(math.ceil((x1 - x0) / res_deg_))
            height = int(math.ceil((y1 - y0) / res_deg_))
            transform = from_origin(x0, y1, res_deg_, res_deg_)
            area_def = geometry.AreaDefinition(
                "roi_ll",
                "regular latlon grid",
                "epsg4326",
                {"proj": "longlat", "datum": "WGS84"},
                width,
                height,
                [x0, y0, x1, y1],
            )
            return area_def, transform, width, height

        def _normalize_split(n) -> tuple[int, int]:
            if isinstance(n, (list, tuple)) and len(n) == 2:
                ny = max(1, int(n[0]))
                nx = max(1, int(n[1]))
                return ny, nx
            n = max(1, int(n))
            # make a roughly square grid
            ny = int(math.sqrt(n))
            nx = max(1, int(math.ceil(n / ny)))
            return ny, nx

        def _split_bbox(bbox: tuple[float, float, float, float], ny: int, nx: int):
            x0, y0, x1, y1 = bbox
            dx = (x1 - x0) / nx
            dy = (y1 - y0) / ny
            tiles = []
            for iy in range(ny):
                for ix in range(nx):
                    tiles.append((x0 + ix * dx, y0 + iy * dy, x0 + (ix + 1) * dx, y0 + (iy + 1) * dy))
            return tiles

        def swath_to_grid(band_arr, lat_, lon_, area_def_, radius_):
            lat_a, lon_a = _align_geo_to_band(lat_, lon_, band_arr)
            vals = band_arr.astype(np.float32, copy=False).ravel()
            lats = lat_a.ravel()
            lons = lon_a.ravel()
            valid = np.isfinite(vals)
            if not np.any(valid):
                return np.full((area_def_.shape[0], area_def_.shape[1]), np.nan, dtype=np.float32)
            vals = vals[valid]
            lats = lats[valid]
            lons = lons[valid]
            swath_def = geometry.SwathDefinition(lons=lons, lats=lats)
            with warnings.catch_warnings():
                warnings.simplefilter("ignore")
                grid = kd_tree.resample_nearest(
                    swath_def,
                    vals,
                    area_def_,
                    radius_of_influence=max(1000, int(radius_)),
                    fill_value=np.nan,
                    reduce_data=True,
                    nprocs=1,
                )
            return grid.astype(np.float32, copy=False)

        def write_single_band_tif(path, arr, transform, width, height):
            profile = {
                "driver": "GTiff",
                "height": int(height),
                "width": int(width),
                "count": 1,
                "dtype": "float32",
                "crs": "EPSG:4326",
                "transform": transform,
                "compress": "deflate",
                "predictor": 2,
                "tiled": True,
                "blockxsize": 256,
                "blockysize": 256,
                "nodata": np.float32(np.nan),
            }
            os.makedirs(os.path.dirname(path) or ".", exist_ok=True)
            with rasterio.open(path, "w", **profile) as dst:
                dst.write(arr.astype(np.float32, copy=False), 1)

        def _apply_roi_mask_if_needed(arr2d: np.ndarray, transform, width, height):
            if roi_geom is None:
                return arr2d
            try:
                m = rasterize(
                    [(roi_geom, 1)],
                    out_shape=(int(height), int(width)),
                    transform=transform,
                    fill=0,
                    dtype="uint8",
                    all_touched=False,
                )
                out = arr2d.copy()
                out[m == 0] = np.nan
                return out
            except Exception:
                return arr2d

        # -------- search LAADS --------
        def search(product, start_dt, end_dt, bbox):
            return ea.search_data(
                short_name=product,
                temporal=(start_dt, end_dt),
                bounding_box=bbox,
                provider="LAADS",
                granule_name="*.hdf",
            )

        def pair_l1b_with_geo(l1b_list, geo_list):
            geo_by_tok = {}
            for g in geo_list:
                name_g = _granule_name(g)
                tok_g = _granule_token(name_g)
                geo_by_tok[tok_g] = g
            pairs_ = []
            for sw in l1b_list:
                name_sw = _granule_name(sw)
                tok_sw = _granule_token(name_sw)
                g = geo_by_tok.get(tok_sw)
                if g is not None:
                    pairs_.append((sw, g))
            return pairs_

        start_dt = datetime.strptime(start_date, "%Y-%m-%d")
        end_dt = datetime.strptime(end_date, "%Y-%m-%d")
        l1b, geo = [], []
        use_terra = platform.lower() in ("terra", "both")
        use_aqua = platform.lower() in ("aqua", "both")
        if use_terra:
            l1b += search("MOD02HKM", start_dt, end_dt, (minx, miny, maxx, maxy))
            geo += search("MOD03", start_dt, end_dt, (minx, miny, maxx, maxy))
        if use_aqua:
            l1b += search("MYD02HKM", start_dt, end_dt, (minx, miny, maxx, maxy))
            geo += search("MYD03", start_dt, end_dt, (minx, miny, maxx, maxy))

        pairs = pair_l1b_with_geo(l1b, geo)
        if not pairs:
            if verbose:
                print("⚠️ No matching L1B/GEO pairs found for the search window/ROI.")
            if dask_client:
                try:
                    dask_client.close()
                    if dask_cluster:
                        dask_cluster.close()
                except Exception:
                    pass
            return {"processed_pairs": 0, "written": 0, "days": 0, "paths": [], "dashboard": dashboard_url}

        # -------- skip whole days if all final outputs already exist --------
        if not overwrite:
            def _pair_day_key(p):
                sw = p[0]
                dk = _day_key_from_any(sw, _cached_local_path_for_granule(sw))
                return dk or None

            day_keys = set(filter(None, (_pair_day_key(p) for p in pairs)))
            skip_days = set()
            for d in day_keys:
                all_exist = all(os.path.exists(os.path.join(output_folder, f"{filename_prefix}_{b}_{d}.tif")) for b in bands_wanted)
                if all_exist:
                    skip_days.add(d)
            if skip_days and verbose:
                print(f"⏭️  Skipping {len(skip_days)} day(s) with all final outputs present.")
            if skip_days:
                pairs = [p for p in pairs if _pair_day_key(p) not in skip_days]

        if not pairs:
            if verbose:
                print("⚠️ Nothing to process after skipping fully-done days.")
            if dask_client:
                try:
                    dask_client.close()
                    if dask_cluster:
                        dask_cluster.close()
                except Exception:
                    pass
            return {"processed_pairs": 0, "written": 0, "days": 0, "paths": [], "dashboard": dashboard_url}

        # -------- tiling --------
        ny, nx = _normalize_split(n_roi_split)
        tile_bboxes = _split_bbox((minx, miny, maxx, maxy), ny, nx)
        def _tile_tag(idx1: int) -> str:
            ty, tx = divmod(idx1 - 1, nx)
            return f"{ty}x{tx}"

        # -------- worker: compute one swath pair for one tile --------
        def _process_pair_tile(sw_path: str, geo_path: str, bbox_t, tile_tag: str):
            res = []  # list of ("tif", day_key, band, tif_path, tile_tag)
            try:
                # parse IDs
                sw_name = _granule_name(sw_path)
                gtok = _granule_token(sw_name)
                day_key = day_key_from_name(sw_name) or ""
                if not day_key:
                    day_key = day_key_from_name(os.path.basename(sw_path)) or "unknown"

                # target grid for tile
                area_def_t, transform_t, width_t, height_t = make_target_grid(bbox_t, res_deg)

                # Check per-granule per-tile tifs existence per band
                existing_tile_tifs = []
                missing_bands = []
                for bname in sorted(bands_wanted):
                    tif_path = os.path.join(
                        granule_tif_dir,
                        f"{filename_prefix}_{bname}_{day_key}_{gtok}_tile{tile_tag}.tif"
                    )
                    if (not overwrite) and os.path.exists(tif_path):
                        existing_tile_tifs.append(("tif", day_key, bname, tif_path, tile_tag))
                    else:
                        missing_bands.append(bname)

                if (not overwrite) and len(existing_tile_tifs) == len(bands_wanted):
                    return existing_tile_tifs

                # open geo and bands
                lat, lon = read_latlon_from_mod03(geo_path)
                bands = read_toa_from_mod02hkm(sw_path)
                if not bands:
                    return existing_tile_tifs  # might be empty

                # append existing ones first
                if existing_tile_tifs:
                    res.extend(existing_tile_tifs)

                # compute missing only
                for bname, arr in bands.items():
                    if bname not in bands_wanted:
                        continue
                    if (not overwrite) and (bname not in missing_bands):
                        continue
                    if arr is None or not np.isfinite(arr).any():
                        continue
                    grid = swath_to_grid(arr, lat, lon, area_def_t, radius_m)
                    grid = _apply_roi_mask_if_needed(grid, transform_t, width_t, height_t)
                    tif_path = os.path.join(
                        granule_tif_dir,
                        f"{filename_prefix}_{bname}_{day_key}_{gtok}_tile{tile_tag}.tif"
                    )
                    write_single_band_tif(tif_path, grid, transform_t, width_t, height_t)
                    res.append(("tif", day_key, bname, tif_path, tile_tag))

                return res
            except Exception as e:
                if verbose:
                    print(f"❌ Tile {tile_tag} failed for {os.path.basename(sw_path)}: {e}")
                return res

        per_tile_groups_global = defaultdict(list)   # (day_key, band, tile_tag) -> [granule tile tifs]
        pair_iter = pairs
        if show_progress and _tqdm is not None:
            pair_iter = _tqdm(pairs, desc="Granules (serial, tiles parallel)", unit="gran")

        for sw_g, geo_g in pair_iter:
            # Reuse cached per-granule tile TIFFs (no download) if they all exist
            if not overwrite:
                try:
                    # Use metadata names to avoid any download
                    sw_meta_name = _granule_name(sw_g) or ""
                    geo_meta_name = _granule_name(geo_g) or ""
                    meta_name = sw_meta_name or geo_meta_name
                    if meta_name:
                        dk_meta = day_key_from_name(meta_name)
                        gtok_meta = _granule_token(meta_name)
                    else:
                        dk_meta = ""
                        gtok_meta = ""
                    if dk_meta:
                        all_exist_tiles = True
                        existing_tile_tifs = []  # (day_key, band, tile_tag, path)
                        for idx1, _bbox_t in enumerate(tile_bboxes, start=1):
                            ty, tx = divmod(idx1 - 1, nx)
                            tag = f"{ty}x{tx}"
                            for b in sorted(bands_wanted):
                                tp = os.path.join(
                                    granule_tif_dir,
                                    f"{filename_prefix}_{b}_{dk_meta}_{gtok_meta}_tile{tag}.tif"
                                )
                                if os.path.exists(tp):
                                    existing_tile_tifs.append((dk_meta, b, tag, tp))
                                else:
                                    all_exist_tiles = False
                                    break
                            if not all_exist_tiles:
                                break
                        if all_exist_tiles:
                            # Register cached tifs so downstream mosaics can reuse them
                            for dk_, b_, tag_, p_ in existing_tile_tifs:
                                per_tile_groups_global[(dk_, b_, tag_)].append(p_)
                            if verbose:
                                print(f"⏭️  Skip swath {gtok_meta} (all per-tile TIFFs cached) — no download.")
                            # Optionally clear any leftover cached HDFs for this swath
                            if remove_cache:
                                for base_name in (sw_meta_name, geo_meta_name):
                                    if not base_name:
                                        continue
                                    cand = os.path.join(cache_dir, os.path.basename(base_name))
                                    try:
                                        if os.path.isfile(cand):
                                            os.remove(cand)
                                    except Exception:
                                        pass
                            continue
                except Exception:
                    # best-effort; fall back to normal flow
                    pass

            sw_path = None
            geo_path = None
            try:
                sw_path = open_granule_filelike(sw_g)   # uses cache if present; downloads only if missing
                geo_path = open_granule_filelike(geo_g)

                sw_name = _granule_name(sw_g) or os.path.basename(sw_path)
                day_key = day_key_from_name(sw_name) or day_key_from_name(os.path.basename(sw_path)) or "unknown"

                # If all final outputs for the day exist, skip this pair but still optionally cleanup HDFs
                if (not overwrite) and day_key != "unknown":
                    all_exist = all(os.path.exists(os.path.join(output_folder, f"{filename_prefix}_{b}_{day_key}.tif"))
                                    for b in bands_wanted)
                    if all_exist:
                        if verbose:
                            print(f"⏭️  Skip swath (final outputs exist for {day_key}).")
                        continue

                # Submit/gather per-tile tasks
                futures = []
                results_lists = []
                for idx1, bbox_t in enumerate(tile_bboxes, start=1):
                    tag = _tile_tag(idx1)
                    if use_dask and dask_client:
                        futures.append(dask_client.submit(_process_pair_tile, sw_path, geo_path, bbox_t, tag))
                    else:
                        results_lists.append(_process_pair_tile(sw_path, geo_path, bbox_t, tag))
                if futures:
                    results_lists = dask_client.gather(futures)

                # Collect produced per-granule tile tifs
                for lst in results_lists:
                    for rec in (lst or []):
                        if not rec or rec[0] != "tif":
                            continue
                        _, day_key_rec, bname, tif_path, tile_tag = rec
                        if day_key_rec != "unknown":
                            per_tile_groups_global[(day_key_rec, bname, tile_tag)].append(tif_path)
            finally:
                # remove cached HDFs right after finishing this swath (if requested)
                if remove_cache:
                    for p in (sw_path, geo_path):
                        try:
                            if p and os.path.isfile(p):
                                os.remove(p)
                        except Exception:
                            pass
                    if verbose and (sw_path or geo_path):
                        print("🧹 Removed cached HDFs for completed swath.")

        # -------- build per-tile mosaics across granules --------
        final_tile_mosaics = defaultdict(list)  # (day_key, band) -> [tile mosaic path]
        for (day_key, bname, tile_tag), tif_list in sorted(per_tile_groups_global.items()):
            if not tif_list:
                continue
            tile_out = os.path.join(tile_mosaic_dir, f"{filename_prefix}_{bname}_{day_key}_tile{tile_tag}.tif")
            if (not overwrite) and os.path.exists(tile_out):
                final_tile_mosaics[(day_key, bname)].append(tile_out)
                continue
            try:
                srcs = [rasterio.open(p) for p in tif_list]
                mosaic, out_transform = rio_merge(srcs, method="first")
                for s in srcs:
                    s.close()
                # drop band axis if present
                if mosaic.ndim == 3 and mosaic.shape[0] == 1:
                    mosaic = mosaic[0]
                # apply ROI mask again to clean edges (cheap)
                mosaic = _apply_roi_mask_if_needed(mosaic, out_transform, mosaic.shape[1], mosaic.shape[0])
                write_single_band_tif(tile_out, mosaic.astype(np.float32, copy=False), out_transform, mosaic.shape[1], mosaic.shape[0])
                final_tile_mosaics[(day_key, bname)].append(tile_out)
            except Exception as me:
                if verbose:
                    print(f"❌ Tile mosaic failed for {bname} {day_key} [tile {tile_tag}]: {me}")

        # -------- final mosaics over tiles --------
        written_paths = []
        days = set()
        for (day_key, bname), tile_paths in sorted(final_tile_mosaics.items()):
            if not tile_paths:
                continue
            out_fp = os.path.join(output_folder, f"{filename_prefix}_{bname}_{day_key}.tif")
            if (not overwrite) and os.path.exists(out_fp):
                continue
            try:
                srcs = [rasterio.open(p) for p in tile_paths]
                mosaic, out_transform = rio_merge(srcs, method="first")
                for s in srcs:
                    s.close()
                if mosaic.ndim == 3 and mosaic.shape[0] == 1:
                    mosaic = mosaic[0]
                mosaic = _apply_roi_mask_if_needed(mosaic, out_transform, mosaic.shape[1], mosaic.shape[0])
                write_single_band_tif(out_fp, mosaic.astype(np.float32, copy=False), out_transform, mosaic.shape[1], mosaic.shape[0])
                written_paths.append(out_fp)
                days.add(day_key)
            except Exception as me:
                if verbose:
                    print(f"❌ Final mosaic failed for {bname} {day_key}: {me}")

        if verbose:
            print(f"✅ MODIS TOA complete. Tiles={ny}x{nx} Pairs={len(pairs)} Days={len(days)} Written={len(written_paths)}")

        if dask_client:
            try:
                dask_client.close()
                if dask_cluster:
                    dask_cluster.close()
            except Exception:
                pass

        return {
            "processed_pairs": len(pairs),
            "written": len(written_paths),
            "days": len(days),
            "paths": written_paths,
            "dashboard": dashboard_url,
        }
    
    
    
    def download_modis_toa_vector(
        self,
        band_list: list[str] | str,
        output_folder: str,
        roi: tuple[float, float, float, float] | str,
        start_date: str,
        end_date: str,
        *,
        platform: str = "terra",         # "terra" | "aqua" | "both"
        res_deg: float = 0.0045,         # ~500 m @ equator
        radius_m: int = 4000,            # swath->grid nearest-neighbor radius (m)
        filename_prefix: str = "modis_toa",
        overwrite: bool = False,
        verbose: bool = True,
        edl_username: str | None = None,
        edl_password: str | None = None,
        login_strategy: str | None = None,
        temp_dir: str | None = None,
        # parallel knobs (used inside each tile)
        use_dask: bool = True,
        n_workers: int | str = "auto",
        threads_per_worker: int | str = "auto",
        scheduler: str = "processes",
        # Split ROI bbox into ny x nx tiles (sequential tiles → low RAM)
        n_roi_split: int | tuple[int, int] = 1,
        # Progress bars for tiles and per-tile granules
        show_progress: bool = True,
    ) -> dict:
        """
        Download MODIS L1B TOA reflectance (HKM, 500 m) and write one GeoTIFF per band per day.

        - ROI can be a bbox (minx,miny,maxx,maxy) or a vector file (.geojson/.json/.shp/.parquet).
          Vector is reprojected to EPSG:4326; bbox from it is used for tiling, and outputs are masked to geometry.
        - Processes ROI in tiles (ny×nx) to reduce memory.
        - Per-granule tile rasters -> per-tile daily mosaics -> final daily mosaics clipped to ROI.
        """
        import os, re, math, warnings, tempfile, logging
        from collections import defaultdict
        from datetime import datetime, timedelta

        import numpy as np

        # Optional progress
        try:
            from tqdm.auto import tqdm as _tqdm
        except Exception:
            _tqdm = None

        # IO deps
        try:
            import earthaccess as ea
        except Exception as e:
            raise RuntimeError("earthaccess is required. pip install earthaccess") from e
        try:
            import rasterio
            from rasterio.merge import merge as rio_merge
            from rasterio.transform import from_origin
            from rasterio.features import rasterize
            from pyresample import geometry, kd_tree
        except Exception as e:
            raise RuntimeError("Dependencies missing. pip install rasterio pyresample") from e
        try:
            import h5py  # optional
        except Exception:
            h5py = None

        # Vector ROI reading (fiona + geopandas), per your snippet
        roi_geom = None
        if isinstance(roi, (tuple, list)) and len(roi) == 4:
            minx, miny, maxx, maxy = tuple(map(float, roi))
        elif isinstance(roi, str) and os.path.exists(roi):
            import fiona
            import geopandas as gpd
            from shapely.ops import unary_union

            ext = os.path.splitext(roi)[1].lower()
            if verbose:
                print(f"📂 Reading vector file: {roi} (format: {ext})")

            try:
                if ext in ['.geojson', '.json']:
                    with fiona.open(roi) as src_vec:
                        gdf = gpd.GeoDataFrame.from_features(src_vec, crs=src_vec.crs)
                elif ext == '.shp':
                    gdf = gpd.read_file(roi)
                elif ext == '.parquet':
                    gdf = gpd.read_parquet(roi)
                else:
                    raise ValueError(f"Unsupported vector format: {ext}")

                # Reproject to WGS84 for this pipeline
                if gdf.crs is None or str(gdf.crs).upper() not in ("EPSG:4326", "OGC:CRS84"):
                    gdf = gdf.to_crs("EPSG:4326")

                # Bbox for tiling
                minx, miny, maxx, maxy = map(float, gdf.total_bounds)
                # Unified geometry for masking
                roi_geom = unary_union([geom for geom in gdf.geometry if geom and not geom.is_empty])

                if roi_geom.is_empty:
                    raise ValueError("ROI geometry is empty after union.")
            except Exception as e:
                raise RuntimeError(f"Failed to read vector ROI '{roi}': {e}") from e
        else:
            raise ValueError("roi must be a 4‑tuple bbox or a path to a valid vector file (shp/geojson/parquet).")

        if (maxx - minx) <= 0 or (maxy - miny) <= 0:
            raise ValueError("ROI bbox must have positive area.")

        # ---------- IO and environment ----------
        os.makedirs(output_folder, exist_ok=True)
        cache_dir = os.path.join(output_folder, "_earthaccess_cache")
        os.makedirs(cache_dir, exist_ok=True)
        granule_tif_dir = os.path.join(output_folder, "_granule_tifs")
        os.makedirs(granule_tif_dir, exist_ok=True)
        tile_mosaic_dir = os.path.join(output_folder, "_tile_mosaics")
        os.makedirs(tile_mosaic_dir, exist_ok=True)

        tmp_root = temp_dir or os.path.join(output_folder, "_tmp")
        os.makedirs(tmp_root, exist_ok=True)
        os.environ.setdefault("TEMP", tmp_root)
        os.environ.setdefault("TMP", tmp_root)
        os.environ.setdefault("TMPDIR", tmp_root)
        os.environ.setdefault("CPL_TMPDIR", tmp_root)
        os.environ.setdefault("GDAL_CACHEMAX", "256")
        tempfile.tempdir = tmp_root

        # ---------- Dask (inside each tile only) ----------
        dask_client = None
        dask_cluster = None
        dashboard_url = None
        if use_dask:
            try:
                from dask.distributed import Client, LocalCluster
                if n_workers == "auto":
                    n_workers = max(1, (os.cpu_count() or 2) - 1)
                if threads_per_worker == "auto":
                    threads_per_worker = 1 if scheduler == "processes" else max(1, (os.cpu_count() or 2) // int(n_workers))
                dask_cluster = LocalCluster(
                    n_workers=int(n_workers),
                    threads_per_worker=int(threads_per_worker),
                    processes=(scheduler == "processes"),
                    silence_logs=logging.CRITICAL,
                )
                dask_client = Client(dask_cluster, set_as_default=True)
                dask_client.wait_for_workers(int(n_workers))
                dashboard_url = getattr(dask_client, "dashboard_link", None)
                if verbose:
                    print(f"⚙️  Dask ready: workers={n_workers}, threads/worker={threads_per_worker}, mode={scheduler}")
                    if dashboard_url:
                        print(f"📊 Dask dashboard: {dashboard_url}")
            except Exception as e:
                if verbose:
                    print(f"⚠️ Dask unavailable ({e}). Running serial.")
                use_dask = False
                dask_client = None
                dask_cluster = None

        # ---------- Bands and datasets ----------
        HKM_DATASETS = [
            ("EV_250_Aggr500_RefSB", {0: "B01", 1: "B02"}),
            ("EV_500_RefSB",         {0: "B03", 1: "B04", 2: "B05", 3: "B06", 4: "B07"}),
        ]
        ALL_BANDS = ["B01", "B02", "B03", "B04", "B05", "B06", "B07"]
        if isinstance(band_list, str) and band_list.lower() == "all":
            bands_wanted = set(ALL_BANDS)
        else:
            bands_wanted = set([str(b).upper() for b in band_list])
            unknown = bands_wanted - set(ALL_BANDS)
            if unknown:
                raise ValueError(f"Unknown bands requested: {sorted(unknown)}")

        # ---------- Login ----------
        if verbose:
            print("🔐 Logging into earthaccess (LAADS)...")
        try:
            if edl_username and edl_password:
                ea.login(strategy=(login_strategy or "interactive"), username=edl_username, password=edl_password, persist=True)
            elif login_strategy:
                ea.login(strategy=login_strategy, persist=True)
            else:
                ea.login(persist=True)
        except Exception as e:
            raise RuntimeError(f"earthaccess login failed: {e}")

        # ---------- Helpers ----------
        def _granule_name(granule) -> str:
            if isinstance(granule, str):
                return os.path.basename(granule)
            try:
                umm = getattr(granule, "umm", None)
                if isinstance(umm, dict):
                    for k in ("GranuleUR", "GranuleID", "title"):
                        v = umm.get(k)
                        if isinstance(v, str) and v:
                            return v
            except Exception:
                pass
            for attr in ("meta", "metadata"):
                try:
                    md = getattr(granule, attr, None)
                    if isinstance(md, dict):
                        for k in ("granule_ur", "GranuleUR", "title"):
                            v = md.get(k)
                            if isinstance(v, str) and v:
                                return v
                except Exception:
                    pass
            links = getattr(granule, "data_links", None) or getattr(granule, "links", None) or []
            try:
                if callable(links):
                    links = links()
            except Exception:
                links = []
            for url in links:
                if not url:
                    continue
                base = os.path.basename(str(url).split("?")[0])
                if base:
                    return base
            try:
                assets = getattr(granule, "assets", None)
                if isinstance(assets, dict):
                    for a in assets.values():
                        href = a.get("href") if isinstance(a, dict) else None
                        if href:
                            base = os.path.basename(str(href).split("?")[0])
                            if base:
                                return base
            except Exception:
                pass
            return ""

        def token_Ayyyydoy_hhmm(name: str) -> str | None:
            m = re.search(r"\.A(\d{7})\.(\d{4})\.", name or "")
            return f"A{m.group(1)}.{m.group(2)}" if m else None

        def day_key_from_name(name: str) -> str:
            m = re.search(r"\.A(\d{4})(\d{3})\.\d{4}\.", name or "")
            if not m:
                m2 = re.search(r"(20\d{6})", name or "")
                if m2:
                    return m2.group(1)
                raise ValueError(f"Cannot parse day key from name: {name}")
            year, doy = int(m.group(1)), int(m.group(2))
            dt = datetime(year, 1, 1) + timedelta(days=doy - 1)
            return dt.strftime("%Y%m%d")

        def _day_key_from_any(granule, local_path: str | None):
            name = _granule_name(granule)
            if not name and local_path:
                name = os.path.basename(local_path)
            try:
                return day_key_from_name(name)
            except Exception:
                return None

        def _granule_token(name: str) -> str:
            m = re.search(r"\.A(\d{7})\.(\d{4})\.", name or "")
            if m:
                return f"A{m.group(1)}{m.group(2)}"
            base = os.path.splitext(os.path.basename(name or "gran"))[0]
            return re.sub(r"[^A-Za-z0-9]+", "", base)[-22:] or "gran"

        def _cached_local_path_for_granule(granule) -> str | None:
            links = getattr(granule, "data_links", None) or getattr(granule, "links", None) or []
            try:
                if callable(links):
                    links = links()
            except Exception:
                links = []
            for url in links:
                if not url:
                    continue
                base = os.path.basename(str(url).split("?")[0])
                if base:
                    fp = os.path.join(cache_dir, base)
                    if os.path.exists(fp):
                        return fp
            name = _granule_name(granule)
            if name:
                for cand in (name, f"{name}.hdf", f"{name}.HDF", f"{name}.h5", f"{name}.he5"):
                    fp = os.path.join(cache_dir, cand)
                    if os.path.exists(fp):
                        return fp
                try:
                    for f in os.listdir(cache_dir):
                        if f.startswith(os.path.splitext(name)[0]):
                            fp = os.path.join(cache_dir, f)
                            if os.path.isfile(fp):
                                return fp
                except Exception:
                    pass
            return None

        def open_granule_filelike(granule) -> str:
            cached = _cached_local_path_for_granule(granule)
            if cached:
                if verbose:
                    print(f"Using cached HDF: {os.path.basename(cached)}")
                return cached
            paths = ea.download([granule], provider="LAADS", local_path=cache_dir)
            if isinstance(paths, dict):
                local_path = next(iter(paths.values()), None)
                if isinstance(local_path, (list, tuple)):
                    local_path = local_path[0] if local_path else None
            elif isinstance(paths, (list, tuple)):
                local_path = paths[0] if paths else None
            else:
                local_path = paths
            if not local_path or (not os.path.exists(local_path)):
                raise RuntimeError("Download failed or returned no local path.")
            if verbose:
                print(f"Downloaded HDF: {os.path.basename(local_path)}")
            return local_path

        def read_latlon_from_mod03(geo_path: str):
            # try HDF5 (rare)
            if h5py is not None:
                try:
                    with h5py.File(geo_path, "r") as g:
                        for lat_key, lon_key in [
                            ("MODIS_Swath_Type_GEO/Geolocation Fields/Latitude", "MODIS_Swath_Type_GEO/Geolocation Fields/Longitude"),
                            ("MODIS_Swath_Type_L1B/Geolocation Fields/Latitude", "MODIS_Swath_Type_L1B/Geolocation Fields/Longitude"),
                        ]:
                            if lat_key in g and lon_key in g:
                                lat = np.array(g[lat_key], dtype=np.float32)
                                lon = np.array(g[lon_key], dtype=np.float32)
                                return lat, lon
                except Exception:
                    pass
            # HDF4 via pyhdf
            try:
                from pyhdf.SD import SD, SDC
            except Exception as e:
                raise RuntimeError("pyhdf is required to read MOD03 (HDF4). conda install -c conda-forge pyhdf") from e
            sd = SD(geo_path, SDC.READ)
            try:
                lat = sd.select("Latitude")[:]
                lon = sd.select("Longitude")[:]
                return np.array(lat, dtype=np.float32), np.array(lon, dtype=np.float32)
            finally:
                sd.end()

        def read_toa_from_mod02hkm(l1b_path: str) -> dict[str, np.ndarray]:
            out: dict[str, np.ndarray] = {}
            try:
                from pyhdf.SD import SD, SDC
            except Exception as e:
                raise RuntimeError("pyhdf is required to read MOD02HKM (HDF4). conda install -c conda-forge pyhdf") from e

            def _attr_value(attrs, key):
                try:
                    return attrs.get(key, (None,))[0]
                except Exception:
                    return None

            def _as_scalar(v, idx, default_scalar):
                if v is None:
                    return float(default_scalar)
                if isinstance(v, (list, tuple, np.ndarray)):
                    try:
                        return float(v[idx])
                    except Exception:
                        try:
                            return float(v[0])
                        except Exception:
                            return float(default_scalar)
                try:
                    return float(v)
                except Exception:
                    return float(default_scalar)

            sd = SD(l1b_path, SDC.READ)
            try:
                for dset_name, band_map in HKM_DATASETS:
                    if dset_name not in sd.datasets():
                        continue
                    ds = sd.select(dset_name)
                    data = ds[:]  # (bands, lines, samples)
                    attrs = ds.attributes(full=1)

                    scale_raw = (
                        _attr_value(attrs, "scale_factor")
                        or _attr_value(attrs, "reflectance_scales")
                        or _attr_value(attrs, "radiance_scales")
                        or 1.0
                    )
                    offset_raw = (
                        _attr_value(attrs, "add_offset")
                        or _attr_value(attrs, "reflectance_offsets")
                        or _attr_value(attrs, "radiance_offsets")
                        or 0.0
                    )
                    fill_raw = _attr_value(attrs, "_FillValue")

                    if data.ndim != 3:
                        continue

                    for bi, bname in band_map.items():
                        if bi >= data.shape[0]:
                            continue
                        scale_i = _as_scalar(scale_raw, bi, 1.0)
                        offset_i = _as_scalar(offset_raw, bi, 0.0)
                        arr = data[bi].astype(np.float32, copy=False)
                        if fill_raw is not None:
                            try:
                                fill_i = _as_scalar(fill_raw, bi, np.nan)
                                if np.isfinite(fill_i):
                                    mask = arr == fill_i
                                    if np.any(mask):
                                        arr[mask] = np.nan
                            except Exception:
                                pass
                        if scale_i != 1.0 or offset_i != 0.0:
                            arr = arr * scale_i + offset_i
                        out[bname] = arr
            finally:
                sd.end()
            return out

        def _align_geo_to_band(lat, lon, band_arr: np.ndarray):
            lat = np.array(lat, dtype=np.float32, copy=False)
            lon = np.array(lon, dtype=np.float32, copy=False)
            lon = np.where(lon > 180.0, lon - 360.0, lon)
            lat = np.clip(lat, -90.0, 90.0)
            bl, bs = int(band_arr.shape[-2]), int(band_arr.shape[-1])
            gl, gs = int(lat.shape[-2]), int(lat.shape[-1])
            if (gl, gs) == (bs, bl):
                lat, lon = lat.T, lon.T
                gl, gs = lat.shape
            if (gl, gs) != (bl, bs):
                rl = bl // gl if gl and (bl % gl == 0) else 1
                rs = bs // gs if gs and (bs % gs == 0) else 1
                if rl == rs and rl in (2,):
                    lat = np.repeat(np.repeat(lat, rl, axis=0), rl, axis=1)
                    lon = np.repeat(np.repeat(lon, rl, axis=0), rl, axis=1)
                    gl, gs = lat.shape
            if (gl, gs) != (bl, bs):
                raise ValueError(f"Geolocation/band shape mismatch: latlon={gl}x{gs} vs band={bl}x{bs}")
            return lat, lon

        def swath_to_grid(band_arr, lat_, lon_, area_def_, radius_):
            lat_a, lon_a = _align_geo_to_band(lat_, lon_, band_arr)
            vals = band_arr.astype(np.float32, copy=False).ravel()
            lats = lat_a.ravel()
            lons = lon_a.ravel()
            valid = np.isfinite(vals)
            if not np.any(valid):
                return np.full((area_def_.shape[0], area_def_.shape[1]), np.nan, dtype=np.float32)
            vals = vals[valid]
            lats = lats[valid]
            lons = lons[valid]
            swath_def = geometry.SwathDefinition(lons=lons, lats=lats)
            with warnings.catch_warnings():
                warnings.simplefilter("ignore", category=RuntimeWarning)
                grid = kd_tree.resample_nearest(
                    swath_def,
                    vals,
                    area_def_,
                    radius_of_influence=radius_,
                    fill_value=np.nan,
                    nprocs=1,
                    reduce_data=True,
                )
            return grid.astype(np.float32, copy=False)

        def write_single_band_tif(path, arr, transform, width, height):
            profile = {
                "driver": "GTiff",
                "height": int(height),
                "width": int(width),
                "count": 1,
                "dtype": "float32",
                "crs": "EPSG:4326",
                "transform": transform,
                "compress": "deflate",
                "predictor": 2,
                "tiled": True,
                "blockxsize": 256,
                "blockysize": 256,
                "nodata": np.float32(np.nan),
            }
            os.makedirs(os.path.dirname(path) or ".", exist_ok=True)
            with rasterio.open(path, "w", **profile) as dst:
                dst.write(arr, 1)

        def make_target_grid(bbox, res_deg_):
            x0, y0, x1, y1 = bbox
            width = int(math.ceil((x1 - x0) / res_deg_))
            height = int(math.ceil((y1 - y0) / res_deg_))
            transform = from_origin(x0, y1, res_deg_, res_deg_)
            area_def = geometry.AreaDefinition(
                "roi_ll",
                "regular latlon grid",
                "epsg4326",
                {"proj": "longlat", "datum": "WGS84"},
                width,
                height,
                [x0, y0, x1, y1],
            )
            return area_def, transform, width, height

        def _normalize_split(n) -> tuple[int, int]:
            if isinstance(n, (list, tuple)) and len(n) == 2:
                return max(1, int(n[0])), max(1, int(n[1]))
            n = max(1, int(n))
            return n, n

        def _split_bbox(bbox: tuple[float, float, float, float], ny: int, nx: int):
            x0, y0, x1, y1 = bbox
            dx = (x1 - x0) / nx
            dy = (y1 - y0) / ny
            tiles = []
            for iy in range(ny):
                ty0 = y0 + iy * dy
                ty1 = ty0 + dy
                for ix in range(nx):
                    tx0 = x0 + ix * dx
                    tx1 = tx0 + dx
                    tiles.append((tx0, ty0, tx1, ty1))
            return tiles

        def search(product, start_dt, end_dt, bbox):
            return ea.search_data(
                short_name=product,
                temporal=(start_dt, end_dt),
                bounding_box=bbox,
                provider="LAADS",
                granule_name="*.hdf",
            )

        def pair_l1b_with_geo(l1b_list, geo_list):
            geo_by_token = {}
            for g in geo_list:
                tok = token_Ayyyydoy_hhmm(_granule_name(g) or "")
                if tok:
                    geo_by_token[tok] = g
            pairs_ = []
            for sw in l1b_list:
                tok = token_Ayyyydoy_hhmm(_granule_name(sw) or "")
                if tok and tok in geo_by_token:
                    pairs_.append((sw, geo_by_token[tok]))
            return pairs_

        # ---------- Search ----------
        start_dt = datetime.strptime(start_date, "%Y-%m-%d")
        end_dt = datetime.strptime(end_date, "%Y-%m-%d")
        l1b, geo = [], []
        use_terra = platform.lower() in ("terra", "both")
        use_aqua = platform.lower() in ("aqua", "both")
        if use_terra:
            l1b += search("MOD02HKM", start_dt, end_dt, (minx, miny, maxx, maxy))
            geo += search("MOD03", start_dt, end_dt, (minx, miny, maxx, maxy))
        if use_aqua:
            l1b += search("MYD02HKM", start_dt, end_dt, (minx, miny, maxx, maxy))
            geo += search("MYD03", start_dt, end_dt, (minx, miny, maxx, maxy))

        pairs = pair_l1b_with_geo(l1b, geo)
        if not pairs:
            if verbose:
                print("No matching MODIS L1B/MOD03 pairs found for the criteria.")
            if dask_client:
                try:
                    dask_client.close()
                    if dask_cluster:
                        dask_cluster.close()
                except Exception:
                    pass
            return {"processed_pairs": 0, "written": 0, "days": 0, "paths": [], "dashboard": dashboard_url}

        # ---------- Skip whole days if outputs exist ----------
        if not overwrite:
            def _pair_day_key(p):
                sw_g, _ = p
                try:
                    return day_key_from_name(_granule_name(sw_g))
                except Exception:
                    return None

            day_keys = set(filter(None, (_pair_day_key(p) for p in pairs)))
            skip_days = set()
            for d in day_keys:
                all_exist = all(os.path.exists(os.path.join(output_folder, f"{filename_prefix}_{b}_{d}.tif"))
                                for b in bands_wanted)
                if all_exist:
                    skip_days.add(d)
                    if verbose:
                        dtf = datetime.strptime(d, "%Y%m%d").strftime("%Y-%m-%d")
                        print(f"Skipping {dtf} (all outputs present).")
            if skip_days:
                pairs = [p for p in pairs if _pair_day_key(p) not in skip_days]
                if not pairs:
                    if dask_client:
                        try:
                            dask_client.close()
                            if dask_cluster:
                                dask_cluster.close()
                        except Exception:
                            pass
                    return {"processed_pairs": 0, "written": 0, "days": 0, "paths": [], "dashboard": dashboard_url}

        # ---------- ROI tiling ----------
        ny, nx = _normalize_split(n_roi_split)
        tile_bboxes = _split_bbox((minx, miny, maxx, maxy), ny, nx)

        # Mask helper (applies only when vector ROI provided)
        def _apply_roi_mask_if_needed(arr2d: np.ndarray, transform, width, height):
            if roi_geom is None:
                return arr2d
            try:
                mask = rasterize(
                    [(roi_geom, 1)],
                    out_shape=(int(height), int(width)),
                    transform=transform,
                    fill=0,
                    all_touched=False,
                    dtype="uint8",
                )
                out = arr2d.copy()
                out[mask == 0] = np.nan
                return out
            except Exception as e:
                if verbose:
                    print(f"⚠️ ROI rasterize failed, skipping mask on this tile: {e}")
                return arr2d

        # Per-pair per-tile worker
        def _process_pair_tile(sw_g, geo_g, area_def_t, transform_t, width_t, height_t, tile_tag: str):
            res = []
            sw_path = None
            geo_path = None
            try:
                sw_path = open_granule_filelike(sw_g)
                geo_path = open_granule_filelike(geo_g)
                sw_name = _granule_name(sw_g) or os.path.basename(sw_path)
                day_key = _day_key_from_any(sw_g, sw_path) or "unknown"

                if day_key != "unknown" and (not overwrite):
                    all_exist = all(os.path.exists(os.path.join(output_folder, f"{filename_prefix}_{b}_{day_key}.tif"))
                                    for b in bands_wanted)
                    if all_exist:
                        return []

                lat, lon = read_latlon_from_mod03(geo_path)
                bands = read_toa_from_mod02hkm(sw_path)
                if not bands:
                    return []

                gtok = _granule_token(sw_name)
                for bname, arr in bands.items():
                    if bname not in bands_wanted:
                        continue
                    if arr is None or not np.isfinite(arr).any():
                        continue
                    grid = swath_to_grid(arr, lat, lon, area_def_t, radius_m)
                    grid = _apply_roi_mask_if_needed(grid, transform_t, width_t, height_t)
                    tif_path = os.path.join(
                        granule_tif_dir,
                        f"{filename_prefix}_{bname}_{day_key}_{gtok}_tile{tile_tag}.tif"
                    )
                    write_single_band_tif(tif_path, grid, transform_t, width_t, height_t)
                    res.append(("tif", day_key, bname, tif_path, tile_tag))
                return res
            except Exception as e:
                if verbose:
                    dbg = os.path.basename(sw_path) if sw_path else _granule_name(sw_g)
                    print(f"❌ Failed processing {dbg} [tile {tile_tag}]: {e}")
                return []

        final_tile_mosaics = defaultdict(list)  # (day, band) -> [tile mosaic paths]

        # Tile progress
        tile_iter = enumerate(tile_bboxes, start=1)
        if show_progress and _tqdm is not None:
            tile_iter = _tqdm(tile_iter, total=len(tile_bboxes), desc=f"Tiles {ny}x{nx}", unit="tile")

        for idx1, bbox_t in tile_iter:
            area_def_t, transform_t, width_t, height_t = make_target_grid(bbox_t, res_deg)
            ty, tx = divmod(idx1 - 1, nx)
            tile_tag = f"{ty}x{tx}"
            if verbose and (not show_progress or _tqdm is None):
                print(f"🧩 Tile {tile_tag} bbox={bbox_t} grid=({height_t},{width_t})")

            # Per-tile scheduling
            results_t = []
            if use_dask and dask_client:
                from dask import delayed
                from dask.distributed import as_completed
                tasks = [delayed(_process_pair_tile)(sw_g, geo_g, area_def_t, transform_t, width_t, height_t, tile_tag)
                         for (sw_g, geo_g) in pairs]
                futures = [dask_client.compute(t) for t in tasks]

                inner_pbar = None
                if show_progress and _tqdm is not None:
                    inner_pbar = _tqdm(total=len(futures), desc=f"Tile {tile_tag}", unit="gran", leave=False)

                for f in as_completed(futures):
                    try:
                        results_t.append(f.result())
                    except Exception as e:
                        if verbose:
                            print(f"❌ Granule failed on tile {tile_tag}: {e}")
                    if inner_pbar is not None:
                        inner_pbar.update(1)

                if inner_pbar is not None:
                    inner_pbar.close()
                try:
                    dask_client.cancel(futures)
                except Exception:
                    pass
            else:
                gran_iter = pairs
                if show_progress and _tqdm is not None:
                    gran_iter = _tqdm(pairs, desc=f"Tile {tile_tag}", unit="gran", leave=False)
                for sw_g, geo_g in gran_iter:
                    results_t.append(_process_pair_tile(sw_g, geo_g, area_def_t, transform_t, width_t, height_t, tile_tag))

            # Group per day+band and mosaic across granules for this tile
            per_tile_groups = defaultdict(list)  # (day, band) -> [granule tile tif]
            for lst in results_t:
                for rec in lst:
                    if not rec:
                        continue
                    kind, day_key, bname, tif_path, _ = rec
                    if kind == "tif" and day_key != "unknown":
                        per_tile_groups[(day_key, bname)].append(tif_path)

            for (day_key, bname), tif_list in sorted(per_tile_groups.items()):
                if not tif_list:
                    continue
                tile_out = os.path.join(tile_mosaic_dir, f"{filename_prefix}_{bname}_{day_key}_tile{tile_tag}.tif")
                if (not overwrite) and os.path.exists(tile_out):
                    final_tile_mosaics[(day_key, bname)].append(tile_out)
                    continue
                try:
                    srcs = [rasterio.open(p) for p in tif_list]
                    mosaic, out_transform = rio_merge(srcs, method="first")
                    for s in srcs:
                        s.close()
                    if mosaic.ndim == 3 and mosaic.shape[0] == 1:
                        mosaic = mosaic[0]
                    mosaic = _apply_roi_mask_if_needed(mosaic, out_transform, mosaic.shape[1], mosaic.shape[0])
                    write_single_band_tif(
                        tile_out,
                        mosaic.astype(np.float32, copy=False),
                        out_transform,
                        mosaic.shape[1],
                        mosaic.shape[0],
                    )
                    final_tile_mosaics[(day_key, bname)].append(tile_out)
                except Exception as me:
                    if verbose:
                        print(f"❌ Tile mosaic failed for {bname} {day_key} [tile {tile_tag}]: {me}")

        # ---------- Final mosaic over tiles ----------
        written_paths = []
        days = set()
        for (day_key, bname), tile_paths in sorted(final_tile_mosaics.items()):
            if not tile_paths:
                continue
            out_fp = os.path.join(output_folder, f"{filename_prefix}_{bname}_{day_key}.tif")
            if (not overwrite) and os.path.exists(out_fp):
                continue
            try:
                srcs = [rasterio.open(p) for p in tile_paths]
                mosaic, out_transform = rio_merge(srcs, method="first")
                for s in srcs:
                    s.close()
                if mosaic.ndim == 3 and mosaic.shape[0] == 1:
                    mosaic = mosaic[0]
                mosaic = _apply_roi_mask_if_needed(mosaic, out_transform, mosaic.shape[1], mosaic.shape[0])
                write_single_band_tif(out_fp, mosaic.astype(np.float32, copy=False), out_transform, mosaic.shape[1], mosaic.shape[0])
                written_paths.append(out_fp)
                days.add(day_key)
            except Exception as me:
                if verbose:
                    print(f"❌ Final mosaic failed for {bname} {day_key}: {me}")

        if verbose:
            print(f"✅ MODIS TOA complete. Tiles={ny}x{nx} Pairs={len(pairs)} Days={len(days)} Written={len(written_paths)}")

        if dask_client:
            try:
                dask_client.close()
                if dask_cluster:
                    dask_cluster.close()
            except Exception:
                pass

        return {
            "processed_pairs": len(pairs),
            "written": len(written_paths),
            "days": len(days),
            "paths": written_paths,
            "dashboard": dashboard_url,
        }
    
    
    
    def download_modis_toa_v15(
        self,
        band_list: list[str] | str,
        output_folder: str,
        roi: tuple[float, float, float, float] | str,
        start_date: str,
        end_date: str,
        *,
        platform: str = "terra",         # "terra" | "aqua" | "both"
        res_deg: float = 0.0045,         # ~500 m @ equator
        radius_m: int = 4000,            # swath->grid nearest-neighbor radius (m)
        filename_prefix: str = "modis_toa",
        overwrite: bool = False,
        verbose: bool = True,
        edl_username: str | None = None,
        edl_password: str | None = None,
        login_strategy: str | None = None,
        temp_dir: str | None = None,
        # parallel knobs (used inside each tile)
        use_dask: bool = True,
        n_workers: int | str = "auto",
        threads_per_worker: int | str = "auto",
        scheduler: str = "processes",
        # Split ROI bbox into ny x nx tiles (sequential tiles → low RAM)
        n_roi_split: int | tuple[int, int] = 100,
        # Progress bars for tiles and per-tile granules
        show_progress: bool = True,
        remove_cache: bool = False,
    ) -> dict:
        """
        Download MODIS L1B TOA reflectance (HKM, 500 m) and write one GeoTIFF per band per day.

        Features:
        - ROI can be a bbox (minx,miny,maxx,maxy) or a vector file path (.geojson/.shp/.parquet).
          If vector, the pipeline grids the bbox of the geometry AND masks everything outside polygon(s).
        - Processes ROI in tiles (ny×nx) to reduce memory.
        - Per-granule tile rasters -> per-tile daily mosaics -> final daily mosaics clipped to ROI.

        Output:
        - {output_folder}/_granule_tifs/  (per-granule per-tile tifs)
        - {output_folder}/_tile_mosaics/ (per-day per-tile mosaics masked to ROI if vector)
        - {output_folder}/{prefix}_{Band}_{YYYYMMDD}.tif (final mosaics masked to ROI if vector)
        """
        import os, re, math, warnings, tempfile, logging
        from collections import defaultdict
        from datetime import datetime, timedelta

        import numpy as np

        # Optional: progress bars
        try:
            from tqdm.auto import tqdm as _tqdm
        except Exception:
            _tqdm = None

        # Earthdata/IO deps
        try:
            import earthaccess as ea
        except Exception as e:
            raise RuntimeError("earthaccess is required. pip install earthaccess") from e
        try:
            import rasterio
            from rasterio.merge import merge as rio_merge
            from rasterio.transform import from_origin
            from rasterio.features import rasterize
            from pyresample import geometry, kd_tree
        except Exception as e:
            raise RuntimeError("Dependencies missing. pip install rasterio pyresample") from e
        try:
            import h5py  # optional, rare HDF5 MODIS
        except Exception:
            h5py = None

        # Vector ROI support (GeoPandas/Shapely)
        roi_geom = None
        if isinstance(roi, str):
            try:
                import geopandas as gpd
                from shapely.ops import unary_union
                from shapely.geometry import mapping
            except Exception as e:
                raise RuntimeError("Vector ROI requires geopandas and shapely. pip install geopandas shapely") from e

            if not os.path.exists(roi):
                raise FileNotFoundError(f"ROI vector file not found: {roi}")

            gdf = gpd.read_file(roi)
            if gdf.empty:
                raise ValueError("ROI vector has no features.")
            # Project to EPSG:4326 for this pipeline
            if gdf.crs is None or str(gdf.crs).upper() not in ("EPSG:4326", "OGC:CRS84"):
                gdf = gdf.to_crs("EPSG:4326")
            # Union all geometries
            roi_geom = unary_union([geom for geom in gdf.geometry if geom and not geom.is_empty])
            if roi_geom.is_empty:
                raise ValueError("ROI geometry is empty after union.")
            minx, miny, maxx, maxy = roi_geom.bounds
        else:
            # bbox path
            minx, miny, maxx, maxy = map(float, roi)
            if (maxx - minx) <= 0 or (maxy - miny) <= 0:
                raise ValueError("roi must be (min_lon, min_lat, max_lon, max_lat) with positive area.")

        # ---------- IO and environment ----------
        os.makedirs(output_folder, exist_ok=True)
        cache_dir = os.path.join(output_folder, "_earthaccess_cache")
        os.makedirs(cache_dir, exist_ok=True)
        granule_tif_dir = os.path.join(output_folder, "_granule_tifs")
        os.makedirs(granule_tif_dir, exist_ok=True)
        tile_mosaic_dir = os.path.join(output_folder, "_tile_mosaics")
        os.makedirs(tile_mosaic_dir, exist_ok=True)

        tmp_root = temp_dir or os.path.join(output_folder, "_tmp")
        os.makedirs(tmp_root, exist_ok=True)
        os.environ.setdefault("TEMP", tmp_root)
        os.environ.setdefault("TMP", tmp_root)
        os.environ.setdefault("TMPDIR", tmp_root)
        os.environ.setdefault("CPL_TMPDIR", tmp_root)
        os.environ.setdefault("GDAL_CACHEMAX", "256")
        tempfile.tempdir = tmp_root

        # ---------- Dask (used inside each tile only) ----------
        dask_client = None
        dask_cluster = None
        dashboard_url = None
        if use_dask:
            try:
                from dask.distributed import Client, LocalCluster
                if n_workers == "auto":
                    n_workers = max(1, (os.cpu_count() or 2) - 1)
                if threads_per_worker == "auto":
                    threads_per_worker = 1 if scheduler == "processes" else max(1, (os.cpu_count() or 2) // int(n_workers))
                dask_cluster = LocalCluster(
                    n_workers=int(n_workers),
                    threads_per_worker=int(threads_per_worker),
                    processes=(scheduler == "processes"),
                    silence_logs=logging.CRITICAL,
                )
                dask_client = Client(dask_cluster, set_as_default=True)
                dask_client.wait_for_workers(int(n_workers))
                dashboard_url = getattr(dask_client, "dashboard_link", None)
                if verbose:
                    print(f"⚙️  Dask ready: workers={n_workers}, threads/worker={threads_per_worker}, mode={scheduler}")
                    if dashboard_url:
                        print(f"📊 Dask dashboard: {dashboard_url}")
            except Exception as e:
                if verbose:
                    print(f"⚠️ Dask unavailable ({e}). Running serial.")
                use_dask = False
                dask_client = None
                dask_cluster = None

        # ---------- Bands and datasets ----------
        HKM_DATASETS = [
            ("EV_250_Aggr500_RefSB", {0: "B01", 1: "B02"}),
            ("EV_500_RefSB",         {0: "B03", 1: "B04", 2: "B05", 3: "B06", 4: "B07"}),
        ]
        ALL_BANDS = ["B01", "B02", "B03", "B04", "B05", "B06", "B07"]
        if isinstance(band_list, str) and band_list.lower() == "all":
            bands_wanted = set(ALL_BANDS)
        else:
            bands_wanted = set([str(b).upper() for b in band_list])
            unknown = bands_wanted - set(ALL_BANDS)
            if unknown:
                raise ValueError(f"Unknown bands requested: {sorted(unknown)}")

        # ---------- Login ----------
        if verbose:
            print("🔐 Logging into earthaccess (LAADS)...")
        try:
            if edl_username and edl_password:
                ea.login(strategy=(login_strategy or "interactive"), username=edl_username, password=edl_password, persist=True)
            elif login_strategy:
                ea.login(strategy=login_strategy, persist=True)
            else:
                ea.login(persist=True)
        except Exception as e:
            raise RuntimeError(f"earthaccess login failed: {e}")

        # ---------- Helpers ----------
        def _granule_name(granule) -> str:
            if isinstance(granule, str):
                return os.path.basename(granule)
            # UMM metadata
            try:
                umm = getattr(granule, "umm", None)
                if isinstance(umm, dict):
                    for k in ("GranuleUR", "GranuleID", "title"):
                        v = umm.get(k)
                        if isinstance(v, str) and v:
                            return v
            except Exception:
                pass
            # meta/metadata dicts
            for attr in ("meta", "metadata"):
                try:
                    md = getattr(granule, attr, None)
                    if isinstance(md, dict):
                        for k in ("granule_ur", "GranuleUR", "title"):
                            v = md.get(k)
                            if isinstance(v, str) and v:
                                return v
                except Exception:
                    pass
            # links (method or list)
            links = getattr(granule, "data_links", None) or getattr(granule, "links", None) or []
            try:
                if callable(links):
                    links = links()
            except Exception:
                links = []
            for url in links:
                if not url:
                    continue
                base = os.path.basename(str(url).split("?")[0])
                if base:
                    return base
            # assets dict
            try:
                assets = getattr(granule, "assets", None)
                if isinstance(assets, dict):
                    for a in assets.values():
                        href = a.get("href") if isinstance(a, dict) else None
                        if href:
                            base = os.path.basename(str(href).split("?")[0])
                            if base:
                                return base
            except Exception:
                pass
            return ""

        def token_Ayyyydoy_hhmm(name: str) -> str | None:
            m = re.search(r"\.A(\d{7})\.(\d{4})\.", name)
            return f"A{m.group(1)}.{m.group(2)}" if m else None

        def day_key_from_name(name: str) -> str:
            m = re.search(r"\.A(\d{4})(\d{3})\.\d{4}\.", name)
            if not m:
                # fallback YYYYMMDD somewhere in name
                m2 = re.search(r"(20\d{6})", name)
                if m2:
                    return m2.group(1)
                raise ValueError(f"Cannot parse day key from name: {name}")
            year, doy = int(m.group(1)), int(m.group(2))
            dt = datetime(year, 1, 1) + timedelta(days=doy - 1)
            return dt.strftime("%Y%m%d")

        def _day_key_from_any(granule, local_path: str | None):
            name = _granule_name(granule)
            if not name and local_path:
                name = os.path.basename(local_path)
            try:
                return day_key_from_name(name)
            except Exception:
                return None

        def _granule_token(name: str) -> str:
            m = re.search(r"\.A(\d{7})\.(\d{4})\.", name or "")
            if m:
                return f"A{m.group(1)}{m.group(2)}"
            base = os.path.splitext(os.path.basename(name or "gran"))[0]
            return re.sub(r"[^A-Za-z0-9]+", "", base)[-22:] or "gran"

        def _cached_local_path_for_granule(granule) -> str | None:
            links = getattr(granule, "data_links", None) or getattr(granule, "links", None) or []
            try:
                if callable(links):
                    links = links()
            except Exception:
                links = []
            for url in links:
                if not url:
                    continue
                base = os.path.basename(str(url).split("?")[0])
                if base:
                    fp = os.path.join(cache_dir, base)
                    if os.path.exists(fp):
                        return fp
            name = _granule_name(granule)
            if name:
                for cand in (name, f"{name}.hdf", f"{name}.HDF", f"{name}.h5", f"{name}.he5"):
                    fp = os.path.join(cache_dir, cand)
                    if os.path.exists(fp):
                        return fp
                try:
                    for f in os.listdir(cache_dir):
                        if f.startswith(os.path.splitext(name)[0]):
                            fp = os.path.join(cache_dir, f)
                            if os.path.isfile(fp):
                                return fp
                except Exception:
                    pass
            return None

        def open_granule_filelike(granule) -> str:
            if isinstance(granule, str) and os.path.isfile(granule):
                return granule
            cached = _cached_local_path_for_granule(granule)
            if cached:
                return cached
            paths = ea.download([granule], provider="LAADS", local_path=cache_dir)
            if isinstance(paths, dict):
                local_path = next(iter(paths.values()), None)
            elif isinstance(paths, (list, tuple)):
                local_path = paths[0] if paths else None
            else:
                local_path = None
            if not local_path or (not os.path.exists(local_path)):
                raise FileNotFoundError("earthaccess returned no local path for granule")
            if verbose:
                print(f"Downloaded: {os.path.basename(local_path)}")
            return local_path

        def read_latlon_from_mod03(geo_path: str):
            # try HDF5 first (rare)
            if h5py is not None:
                try:
                    with h5py.File(geo_path, "r") as g:
                        for lat_key, lon_key in [
                            ("MODIS_Swath_Type_GEO/Geolocation Fields/Latitude", "MODIS_Swath_Type_GEO/Geolocation Fields/Longitude"),
                            ("MODIS_Swath_Type_L1B/Geolocation Fields/Latitude", "MODIS_Swath_Type_L1B/Geolocation Fields/Longitude"),
                        ]:
                            if lat_key in g and lon_key in g:
                                lat = np.array(g[lat_key], dtype=np.float32)
                                lon = np.array(g[lon_key], dtype=np.float32)
                                return lat, lon
                except Exception:
                    pass
            # HDF4 via pyhdf
            try:
                from pyhdf.SD import SD, SDC
            except Exception as e:
                raise RuntimeError("pyhdf is required to read MOD03 (HDF4). conda install -c conda-forge pyhdf") from e
            sd = SD(geo_path, SDC.READ)
            try:
                lat = sd.select("Latitude")[:]
                lon = sd.select("Longitude")[:]
                return np.array(lat, dtype=np.float32), np.array(lon, dtype=np.float32)
            finally:
                sd.end()

        def read_toa_from_mod02hkm(l1b_path: str) -> dict[str, np.ndarray]:
            out: dict[str, np.ndarray] = {}
            try:
                from pyhdf.SD import SD, SDC
            except Exception as e:
                raise RuntimeError("pyhdf is required to read MOD02HKM (HDF4). conda install -c conda-forge pyhdf") from e

            def _attr_value(attrs, key):
                try:
                    return attrs.get(key, (None,))[0]
                except Exception:
                    return None

            def _as_scalar(v, idx, default_scalar):
                if v is None:
                    return float(default_scalar)
                if isinstance(v, (list, tuple, np.ndarray)):
                    try:
                        return float(v[idx])
                    except Exception:
                        try:
                            return float(v[0])
                        except Exception:
                            return float(default_scalar)
                try:
                    return float(v)
                except Exception:
                    return float(default_scalar)

            sd = SD(l1b_path, SDC.READ)
            try:
                for dset_name, band_map in HKM_DATASETS:
                    if dset_name not in sd.datasets():
                        continue
                    ds = sd.select(dset_name)
                    data = ds[:]  # (bands, lines, samples)
                    attrs = ds.attributes(full=1)

                    scale_raw = (
                        _attr_value(attrs, "scale_factor")
                        or _attr_value(attrs, "reflectance_scales")
                        or _attr_value(attrs, "radiance_scales")
                        or 1.0
                    )
                    offset_raw = (
                        _attr_value(attrs, "add_offset")
                        or _attr_value(attrs, "reflectance_offsets")
                        or _attr_value(attrs, "radiance_offsets")
                        or 0.0
                    )
                    fill_raw = _attr_value(attrs, "_FillValue")

                    if data.ndim != 3:
                        continue

                    for bi, bname in band_map.items():
                        if bi >= data.shape[0]:
                            continue
                        scale_i = _as_scalar(scale_raw, bi, 1.0)
                        offset_i = _as_scalar(offset_raw, bi, 0.0)
                        arr = data[bi].astype(np.float32, copy=False)
                        if fill_raw is not None:
                            try:
                                fill_i = _as_scalar(fill_raw, bi, np.nan)
                                if np.isfinite(fill_i):
                                    mask = arr == fill_i
                                    if np.any(mask):
                                        arr[mask] = np.nan
                            except Exception:
                                pass
                        if scale_i != 1.0 or offset_i != 0.0:
                            arr = arr * scale_i + offset_i
                        out[bname] = arr
            finally:
                sd.end()
            return out

        def _align_geo_to_band(lat, lon, band_arr: np.ndarray):
            lat = np.array(lat, dtype=np.float32, copy=False)
            lon = np.array(lon, dtype=np.float32, copy=False)
            lon = np.where(lon > 180.0, lon - 360.0, lon)
            lat = np.clip(lat, -90.0, 90.0)
            bl, bs = int(band_arr.shape[-2]), int(band_arr.shape[-1])
            gl, gs = int(lat.shape[-2]), int(lat.shape[-1])
            if (gl, gs) == (bs, bl):
                lat, lon = lat.T, lon.T
                gl, gs = lat.shape
            if (gl, gs) != (bl, bs):
                rl = bl // gl if gl and (bl % gl == 0) else 1
                rs = bs // gs if gs and (bs % gs == 0) else 1
                if rl == rs and rl in (2,):
                    lat = np.repeat(np.repeat(lat, rl, axis=0), rl, axis=1)
                    lon = np.repeat(np.repeat(lon, rl, axis=0), rl, axis=1)
                    gl, gs = lat.shape
            if (gl, gs) != (bl, bs):
                raise ValueError(f"Geolocation/band shape mismatch: latlon={gl}x{gs} vs band={bl}x{bs}")
            return lat, lon

        def swath_to_grid(band_arr, lat_, lon_, area_def_, radius_):
            # align, then flatten valid samples for memory-friendly resampling
            lat_a, lon_a = _align_geo_to_band(lat_, lon_, band_arr)
            vals = band_arr.astype(np.float32, copy=False).ravel()
            lats = lat_a.ravel()
            lons = lon_a.ravel()
            valid = np.isfinite(vals)
            if not np.any(valid):
                return np.full((area_def_.shape[0], area_def_.shape[1]), np.nan, dtype=np.float32)
            vals = vals[valid]
            lats = lats[valid]
            lons = lons[valid]
            swath_def = geometry.SwathDefinition(lons=lons, lats=lats)
            with warnings.catch_warnings():
                warnings.simplefilter("ignore", category=RuntimeWarning)
                grid = kd_tree.resample_nearest(
                    swath_def,
                    vals,
                    area_def_,
                    radius_of_influence=radius_,
                    fill_value=np.nan,
                    nprocs=1,
                    reduce_data=True,
                )
            return grid.astype(np.float32, copy=False)

        # Tile-level processing function (per swath pair)
        def _process_pair_tile(sw_g, geo_g, area_def_t, transform_t, width_t, height_t, tile_tag: str):
            res = []
            sw_path = None
            geo_path = None
            try:
                sw_path = open_granule_filelike(sw_g)
                geo_path = open_granule_filelike(geo_g)
                sw_name = _granule_name(sw_g) or os.path.basename(sw_path)
                gtok = _granule_token(sw_name)
                day_key = _day_key_from_any(sw_g, sw_path) or "unknown"

                if day_key != "unknown" and (not overwrite):
                    all_exist = all(os.path.exists(os.path.join(output_folder, f"{filename_prefix}_{b}_{day_key}.tif"))
                                    for b in bands_wanted)
                    if all_exist:
                        # report paths for refcounting/deletion
                        res.append(("paths", day_key, gtok, sw_path, geo_path, tile_tag))
                        return res

                lat, lon = read_latlon_from_mod03(geo_path)
                bands = read_toa_from_mod02hkm(sw_path)
                if not bands:
                    res.append(("paths", day_key, gtok, sw_path, geo_path, tile_tag))
                    return res

                for bname, arr in bands.items():
                    if bname not in bands_wanted:
                        continue
                    if arr is None or not np.isfinite(arr).any():
                        continue
                    grid = swath_to_grid(arr, lat, lon, area_def_t, radius_m)
                    grid = _apply_roi_mask_if_needed(grid, transform_t, width_t, height_t)
                    tif_path = os.path.join(
                        granule_tif_dir,
                        f"{filename_prefix}_{bname}_{day_key}_{gtok}_tile{tile_tag}.tif"
                    )
                    write_single_band_tif(tif_path, grid, transform_t, width_t, height_t)
                    res.append(("tif", day_key, bname, tif_path, tile_tag))

                # one paths record per tile for refcounting
                res.append(("paths", day_key, gtok, sw_path, geo_path, tile_tag))
                return res
            except Exception as e:
                if verbose:
                    dbg = os.path.basename(sw_path) if sw_path else _granule_name(sw_g)
                    print(f"❌ Failed processing {dbg} [tile {tile_tag}]: {e}")
                # still emit paths for refcounting if available
                if sw_path or geo_path:
                    res.append(("paths", _day_key_from_any(sw_g, sw_path) or "unknown",
                                _granule_token(_granule_name(sw_g) or ""), sw_path, geo_path, tile_tag))
                return res
        
        def write_single_band_tif(path, arr, transform, width, height):
            profile = {
                "driver": "GTiff",
                "height": int(height),
                "width": int(width),
                "count": 1,
                "dtype": "float32",
                "crs": "EPSG:4326",
                "transform": transform,
                "compress": "deflate",
                "predictor": 2,
                "tiled": True,
                "blockxsize": 256,
                "blockysize": 256,
                "nodata": np.float32(np.nan),
            }
            os.makedirs(os.path.dirname(path) or ".", exist_ok=True)
            with rasterio.open(path, "w", **profile) as dst:
                dst.write(arr, 1)

        def make_target_grid(bbox, res_deg_):
            x0, y0, x1, y1 = bbox
            width = int(math.ceil((x1 - x0) / res_deg_))
            height = int(math.ceil((y1 - y0) / res_deg_))
            transform = from_origin(x0, y1, res_deg_, res_deg_)
            area_def = geometry.AreaDefinition(
                "roi_ll",
                "regular latlon grid",
                "epsg4326",
                {"proj": "longlat", "datum": "WGS84"},
                width,
                height,
                [x0, y0, x1, y1],
            )
            return area_def, transform, width, height

        def _normalize_split(n) -> tuple[int, int]:
            if isinstance(n, (list, tuple)) and len(n) == 2:
                return max(1, int(n[0])), max(1, int(n[1]))
            n = max(1, int(n))
            return n, n

        def _split_bbox(bbox: tuple[float, float, float, float], ny: int, nx: int):
            x0, y0, x1, y1 = bbox
            dx = (x1 - x0) / nx
            dy = (y1 - y0) / ny
            tiles = []
            for iy in range(ny):
                ty0 = y0 + iy * dy
                ty1 = ty0 + dy
                for ix in range(nx):
                    tx0 = x0 + ix * dx
                    tx1 = tx0 + dx
                    tiles.append((tx0, ty0, tx1, ty1))
            return tiles

        def search(product, start_dt, end_dt, bbox):
            return ea.search_data(
                short_name=product,
                temporal=(start_dt, end_dt),
                bounding_box=bbox,
                provider="LAADS",
                granule_name="*.hdf",
            )

        def pair_l1b_with_geo(l1b_list, geo_list):
            geo_by_token = {}
            for g in geo_list:
                tok = token_Ayyyydoy_hhmm(_granule_name(g) or "")
                if tok:
                    geo_by_token[tok] = g
            pairs_ = []
            for sw in l1b_list:
                tok = token_Ayyyydoy_hhmm(_granule_name(sw) or "")
                if tok and tok in geo_by_token:
                    pairs_.append((sw, geo_by_token[tok]))
            return pairs_

        # ---------- Search ----------
        start_dt = datetime.strptime(start_date, "%Y-%m-%d")
        end_dt = datetime.strptime(end_date, "%Y-%m-%d")
        l1b, geo = [], []
        use_terra = platform.lower() in ("terra", "both")
        use_aqua = platform.lower() in ("aqua", "both")
        if use_terra:
            l1b += search("MOD02HKM", start_dt, end_dt, (minx, miny, maxx, maxy))
            geo += search("MOD03", start_dt, end_dt, (minx, miny, maxx, maxy))
        if use_aqua:
            l1b += search("MYD02HKM", start_dt, end_dt, (minx, miny, maxx, maxy))
            geo += search("MYD03", start_dt, end_dt, (minx, miny, maxx, maxy))

        pairs = pair_l1b_with_geo(l1b, geo)
        if not pairs:
            if verbose:
                print("No matching MODIS L1B/MOD03 pairs found for the criteria.")
            if dask_client:
                try:
                    dask_client.close()
                    if dask_cluster:
                        dask_cluster.close()
                except Exception:
                    pass
            return {"processed_pairs": 0, "written": 0, "days": 0, "paths": [], "dashboard": dashboard_url}

        # ---------- Skip entire days when all outputs exist ----------
        if not overwrite:
            def _pair_day_key(p):
                sw_g, _ = p
                try:
                    return day_key_from_name(_granule_name(sw_g))
                except Exception:
                    return None
            day_keys = set(filter(None, (_pair_day_key(p) for p in pairs)))
            skip_days = set()
            for d in day_keys:
                all_exist = all(os.path.exists(os.path.join(output_folder, f"{filename_prefix}_{b}_{d}.tif"))
                                for b in bands_wanted)
                if all_exist:
                    skip_days.add(d)
                    if verbose:
                        dtf = datetime.strptime(d, "%Y%m%d").strftime("%Y-%m-%d")
                        print(f"Skipping {dtf} (all outputs present).")
            if skip_days:
                pairs = [p for p in pairs if _pair_day_key(p) not in skip_days]
                if not pairs:
                    if dask_client:
                        try:
                            dask_client.close()
                            if dask_cluster:
                                dask_cluster.close()
                        except Exception:
                            pass
                    return {"processed_pairs": 0, "written": 0, "days": 0, "paths": [], "dashboard": dashboard_url}

        ny, nx = _normalize_split(n_roi_split)
        tile_bboxes = _split_bbox((minx, miny, maxx, maxy), ny, nx)

        # Granule-serial, tile-parallel mode: process one swath pair at a time, delete its HDFs,
        # then move to the next. This ensures previous HDFs are removed before next download.
        if remove_cache:
            from collections import defaultdict
            per_tile_groups_global = defaultdict(list)   # (day_key, band, tile_tag) -> [granule tile tifs]
            final_tile_mosaics = defaultdict(list)       # (day_key, band) -> [tile mosaic paths]

            def _tile_tag(idx1: int) -> str:
                ty, tx = divmod(idx1 - 1, nx)
                return f"{ty}x{tx}"

            pair_iter = pairs
            if show_progress and _tqdm is not None:
                pair_iter = _tqdm(pairs, desc="Granules (serial, tiles parallel)", unit="gran")

            for sw_g, geo_g in pair_iter:
                sw_path = None
                geo_path = None
                try:
                    # Download/reuse cache for this pair
                    sw_path = open_granule_filelike(sw_g)
                    geo_path = open_granule_filelike(geo_g)

                    # Resolve day key; skip if all outputs for that day already exist
                    day_key = _day_key_from_any(sw_g, sw_path) or "unknown"
                    if day_key != "unknown" and (not overwrite):
                        all_exist = all(
                            os.path.exists(os.path.join(output_folder, f"{filename_prefix}_{b}_{day_key}.tif"))
                            for b in (ALL_BANDS if bands_wanted == set(ALL_BANDS) else bands_wanted)
                        )
                        if all_exist:
                            if verbose:
                                print(f"Skip swath (all outputs exist for {day_key}).")
                            continue

                    # Fan out all tiles for this swath on Dask (or serial)
                    futures = []
                    results_lists = []
                    for idx1, bbox_t in enumerate(tile_bboxes, start=1):
                        area_def_t, transform_t, width_t, height_t = make_target_grid(bbox_t, res_deg)
                        tile_tag = _tile_tag(idx1)
                        if use_dask and dask_client:
                            futures.append(
                                dask_client.submit(
                                    _process_pair_tile,
                                    sw_path,
                                    geo_path,
                                    area_def_t,
                                    transform_t,
                                    width_t,
                                    height_t,
                                    tile_tag,
                                )
                            )
                        else:
                            results_lists.append(
                                _process_pair_tile(
                                    sw_path, geo_path, area_def_t, transform_t, width_t, height_t, tile_tag
                                )
                            )
                    if futures:
                        results_lists = dask_client.gather(futures)

                    # Collect per-granule tile outputs
                    for lst in results_lists:
                        for rec in (lst or []):
                            if not rec:
                                continue
                            kind, day_key_rec, bname, tif_path, tile_tag = rec
                            if kind == "tif" and day_key_rec != "unknown":
                                per_tile_groups_global[(day_key_rec, bname, tile_tag)].append(tif_path)
                finally:
                    # Always delete HDFs for the just-processed granule before downloading next
                    for p in (sw_path, geo_path):
                        try:
                            if p and os.path.isfile(p):
                                os.remove(p)
                        except Exception:
                            pass
                    if verbose and (sw_path or geo_path):
                        print("Removed cached HDFs for completed swath.")

            # Build per-tile mosaics across granules
            for (day_key, bname, tile_tag), tif_list in sorted(per_tile_groups_global.items()):
                if not tif_list:
                    continue
                tile_out = os.path.join(tile_mosaic_dir, f"{filename_prefix}_{bname}_{day_key}_tile{tile_tag}.tif")
                if (not overwrite) and os.path.exists(tile_out):
                    final_tile_mosaics[(day_key, bname)].append(tile_out)
                    continue
                try:
                    srcs = [rasterio.open(p) for p in tif_list]
                    mosaic, out_transform = rio_merge(srcs, method="first")
                    for s in srcs:
                        s.close()
                    if mosaic.ndim == 3 and mosaic.shape[0] == 1:
                        mosaic = mosaic[0]
                    mosaic = _apply_roi_mask_if_needed(mosaic, out_transform, mosaic.shape[1], mosaic.shape[0])
                    write_single_band_tif(
                        tile_out,
                        mosaic.astype(np.float32, copy=False),
                        out_transform,
                        mosaic.shape[1],
                        mosaic.shape[0],
                    )
                    final_tile_mosaics[(day_key, bname)].append(tile_out)
                except Exception as me:
                    if verbose:
                        print(f"Tile mosaic failed for {bname} {day_key} [tile {tile_tag}]: {me}")

            # Final mosaic over tiles per day/band
            written_paths = []
            days = set()
            for (day_key, bname), tile_paths in sorted(final_tile_mosaics.items()):
                if not tile_paths:
                    continue
                out_fp = os.path.join(output_folder, f"{filename_prefix}_{bname}_{day_key}.tif")
                if (not overwrite) and os.path.exists(out_fp):
                    continue
                try:
                    srcs = [rasterio.open(p) for p in tile_paths]
                    mosaic, out_transform = rio_merge(srcs, method="first")
                    for s in srcs:
                        s.close()
                    if mosaic.ndim == 3 and mosaic.shape[0] == 1:
                        mosaic = mosaic[0]
                    mosaic = _apply_roi_mask_if_needed(mosaic, out_transform, mosaic.shape[1], mosaic.shape[0])
                    write_single_band_tif(
                        out_fp,
                        mosaic.astype(np.float32, copy=False),
                        out_transform,
                        mosaic.shape[1],
                        mosaic.shape[0],
                    )
                    written_paths.append(out_fp)
                    days.add(day_key)
                except Exception as me:
                    if verbose:
                        print(f"Final mosaic failed for {bname} {day_key}: {me}")

            if verbose:
                print(f"MODIS TOA complete. Tiles={ny}x{nx} Pairs={len(pairs)} Days={len(days)} Written={len(written_paths)}")

            if dask_client:
                try:
                    dask_client.close()
                    if dask_cluster:
                        dask_cluster.close()
                except Exception:
                    pass

            return {
                "processed_pairs": len(pairs),
                "written": len(written_paths),
                "days": len(days),
                "paths": written_paths,
                "dashboard": None,
            }
    
    
    
    def download_modis_toa_v11(
        self,
        band_list: list[str] | str,
        output_folder: str,
        roi: tuple[float, float, float, float] | str,
        start_date: str,
        end_date: str,
        *,
        platform: str = "terra",         # "terra" | "aqua" | "both"
        res_deg: float = 0.0045,         # ~500 m @ equator
        radius_m: int = 4000,            # swath->grid nearest-neighbor radius (m)
        filename_prefix: str = "modis_toa",
        overwrite: bool = False,
        verbose: bool = True,
        edl_username: str | None = None,
        edl_password: str | None = None,
        login_strategy: str | None = None,
        temp_dir: str | None = None,
        # parallel knobs (used inside each tile)
        use_dask: bool = True,
        n_workers: int | str = "auto",
        threads_per_worker: int | str = "auto",
        scheduler: str = "processes",
        # Split ROI bbox into ny x nx tiles (sequential tiles → low RAM)
        n_roi_split: int | tuple[int, int] = 100,
        # Progress bars for tiles and per-tile granules
        show_progress: bool = True,
        remove_cache: bool = False,
    ) -> dict:
        """
        Download MODIS L1B TOA reflectance (HKM, 500 m) and write one GeoTIFF per band per day.

        Features:
        - ROI can be a bbox (minx,miny,maxx,maxy) or a vector file path (.geojson/.shp/.parquet).
          If vector, the pipeline grids the bbox of the geometry AND masks everything outside polygon(s).
        - Processes ROI in tiles (ny×nx) to reduce memory.
        - Per-granule tile rasters -> per-tile daily mosaics -> final daily mosaics clipped to ROI.

        Output:
        - {output_folder}/_granule_tifs/  (per-granule per-tile tifs)
        - {output_folder}/_tile_mosaics/ (per-day per-tile mosaics masked to ROI if vector)
        - {output_folder}/{prefix}_{Band}_{YYYYMMDD}.tif (final mosaics masked to ROI if vector)
        """
        import os, re, math, warnings, tempfile, logging
        from collections import defaultdict
        from datetime import datetime, timedelta

        import numpy as np

        # Optional: progress bars
        try:
            from tqdm.auto import tqdm as _tqdm
        except Exception:
            _tqdm = None

        # Earthdata/IO deps
        try:
            import earthaccess as ea
        except Exception as e:
            raise RuntimeError("earthaccess is required. pip install earthaccess") from e
        try:
            import rasterio
            from rasterio.merge import merge as rio_merge
            from rasterio.transform import from_origin
            from rasterio.features import rasterize
            from pyresample import geometry, kd_tree
        except Exception as e:
            raise RuntimeError("Dependencies missing. pip install rasterio pyresample") from e
        try:
            import h5py  # optional, rare HDF5 MODIS
        except Exception:
            h5py = None

        # Vector ROI support (GeoPandas/Shapely)
        roi_geom = None
        if isinstance(roi, str):
            try:
                import geopandas as gpd
                from shapely.ops import unary_union
                from shapely.geometry import mapping
            except Exception as e:
                raise RuntimeError("Vector ROI requires geopandas and shapely. pip install geopandas shapely") from e

            if not os.path.exists(roi):
                raise FileNotFoundError(f"ROI vector file not found: {roi}")

            gdf = gpd.read_file(roi)
            if gdf.empty:
                raise ValueError("ROI vector has no features.")
            # Project to EPSG:4326 for this pipeline
            if gdf.crs is None or str(gdf.crs).upper() not in ("EPSG:4326", "OGC:CRS84"):
                gdf = gdf.to_crs("EPSG:4326")
            # Union all geometries
            roi_geom = unary_union([geom for geom in gdf.geometry if geom and not geom.is_empty])
            if roi_geom.is_empty:
                raise ValueError("ROI geometry is empty after union.")
            minx, miny, maxx, maxy = roi_geom.bounds
        else:
            # bbox path
            minx, miny, maxx, maxy = map(float, roi)
            if (maxx - minx) <= 0 or (maxy - miny) <= 0:
                raise ValueError("roi must be (min_lon, min_lat, max_lon, max_lat) with positive area.")

        # ---------- IO and environment ----------
        os.makedirs(output_folder, exist_ok=True)
        cache_dir = os.path.join(output_folder, "_earthaccess_cache")
        os.makedirs(cache_dir, exist_ok=True)
        granule_tif_dir = os.path.join(output_folder, "_granule_tifs")
        os.makedirs(granule_tif_dir, exist_ok=True)
        tile_mosaic_dir = os.path.join(output_folder, "_tile_mosaics")
        os.makedirs(tile_mosaic_dir, exist_ok=True)

        tmp_root = temp_dir or os.path.join(output_folder, "_tmp")
        os.makedirs(tmp_root, exist_ok=True)
        os.environ.setdefault("TEMP", tmp_root)
        os.environ.setdefault("TMP", tmp_root)
        os.environ.setdefault("TMPDIR", tmp_root)
        os.environ.setdefault("CPL_TMPDIR", tmp_root)
        os.environ.setdefault("GDAL_CACHEMAX", "256")
        tempfile.tempdir = tmp_root

        # ---------- Dask (used inside each tile only) ----------
        dask_client = None
        dask_cluster = None
        dashboard_url = None
        if use_dask:
            try:
                from dask.distributed import Client, LocalCluster
                if n_workers == "auto":
                    n_workers = max(1, (os.cpu_count() or 2) - 1)
                if threads_per_worker == "auto":
                    threads_per_worker = 1 if scheduler == "processes" else max(1, (os.cpu_count() or 2) // int(n_workers))
                dask_cluster = LocalCluster(
                    n_workers=int(n_workers),
                    threads_per_worker=int(threads_per_worker),
                    processes=(scheduler == "processes"),
                    silence_logs=logging.CRITICAL,
                )
                dask_client = Client(dask_cluster, set_as_default=True)
                dask_client.wait_for_workers(int(n_workers))
                dashboard_url = getattr(dask_client, "dashboard_link", None)
                if verbose:
                    print(f"⚙️  Dask ready: workers={n_workers}, threads/worker={threads_per_worker}, mode={scheduler}")
                    if dashboard_url:
                        print(f"📊 Dask dashboard: {dashboard_url}")
            except Exception as e:
                if verbose:
                    print(f"⚠️ Dask unavailable ({e}). Running serial.")
                use_dask = False
                dask_client = None
                dask_cluster = None

        # ---------- Bands and datasets ----------
        HKM_DATASETS = [
            ("EV_250_Aggr500_RefSB", {0: "B01", 1: "B02"}),
            ("EV_500_RefSB",         {0: "B03", 1: "B04", 2: "B05", 3: "B06", 4: "B07"}),
        ]
        ALL_BANDS = ["B01", "B02", "B03", "B04", "B05", "B06", "B07"]
        if isinstance(band_list, str) and band_list.lower() == "all":
            bands_wanted = set(ALL_BANDS)
        else:
            bands_wanted = set([str(b).upper() for b in band_list])
            unknown = bands_wanted - set(ALL_BANDS)
            if unknown:
                raise ValueError(f"Unknown bands requested: {sorted(unknown)}")

        # ---------- Login ----------
        if verbose:
            print("🔐 Logging into earthaccess (LAADS)...")
        try:
            if edl_username and edl_password:
                ea.login(strategy=(login_strategy or "interactive"), username=edl_username, password=edl_password, persist=True)
            elif login_strategy:
                ea.login(strategy=login_strategy, persist=True)
            else:
                ea.login(persist=True)
        except Exception as e:
            raise RuntimeError(f"earthaccess login failed: {e}")

        # ---------- Helpers ----------
        def _granule_name(granule) -> str:
            if isinstance(granule, str):
                return os.path.basename(granule)
            # UMM metadata
            try:
                umm = getattr(granule, "umm", None)
                if isinstance(umm, dict):
                    for k in ("GranuleUR", "GranuleID", "title"):
                        v = umm.get(k)
                        if isinstance(v, str) and v:
                            return v
            except Exception:
                pass
            # meta/metadata dicts
            for attr in ("meta", "metadata"):
                try:
                    md = getattr(granule, attr, None)
                    if isinstance(md, dict):
                        for k in ("granule_ur", "GranuleUR", "title"):
                            v = md.get(k)
                            if isinstance(v, str) and v:
                                return v
                except Exception:
                    pass
            # links (method or list)
            links = getattr(granule, "data_links", None) or getattr(granule, "links", None) or []
            try:
                if callable(links):
                    links = links()
            except Exception:
                links = []
            for url in links:
                if not url:
                    continue
                base = os.path.basename(str(url).split("?")[0])
                if base:
                    return base
            # assets dict
            try:
                assets = getattr(granule, "assets", None)
                if isinstance(assets, dict):
                    for a in assets.values():
                        href = a.get("href") if isinstance(a, dict) else None
                        if href:
                            base = os.path.basename(str(href).split("?")[0])
                            if base:
                                return base
            except Exception:
                pass
            return ""

        def token_Ayyyydoy_hhmm(name: str) -> str | None:
            m = re.search(r"\.A(\d{7})\.(\d{4})\.", name)
            return f"A{m.group(1)}.{m.group(2)}" if m else None

        def day_key_from_name(name: str) -> str:
            m = re.search(r"\.A(\d{4})(\d{3})\.\d{4}\.", name)
            if not m:
                # fallback YYYYMMDD somewhere in name
                m2 = re.search(r"(20\d{6})", name)
                if m2:
                    return m2.group(1)
                raise ValueError(f"Cannot parse day key from name: {name}")
            year, doy = int(m.group(1)), int(m.group(2))
            dt = datetime(year, 1, 1) + timedelta(days=doy - 1)
            return dt.strftime("%Y%m%d")

        def _day_key_from_any(granule, local_path: str | None):
            name = _granule_name(granule)
            if not name and local_path:
                name = os.path.basename(local_path)
            try:
                return day_key_from_name(name)
            except Exception:
                return None

        def _granule_token(name: str) -> str:
            m = re.search(r"\.A(\d{7})\.(\d{4})\.", name or "")
            if m:
                return f"A{m.group(1)}{m.group(2)}"
            base = os.path.splitext(os.path.basename(name or "gran"))[0]
            return re.sub(r"[^A-Za-z0-9]+", "", base)[-22:] or "gran"

        def _cached_local_path_for_granule(granule) -> str | None:
            links = getattr(granule, "data_links", None) or getattr(granule, "links", None) or []
            try:
                if callable(links):
                    links = links()
            except Exception:
                links = []
            for url in links:
                if not url:
                    continue
                base = os.path.basename(str(url).split("?")[0])
                if base:
                    fp = os.path.join(cache_dir, base)
                    if os.path.exists(fp):
                        return fp
            name = _granule_name(granule)
            if name:
                for cand in (name, f"{name}.hdf", f"{name}.HDF", f"{name}.h5", f"{name}.he5"):
                    fp = os.path.join(cache_dir, cand)
                    if os.path.exists(fp):
                        return fp
                try:
                    for f in os.listdir(cache_dir):
                        if f.startswith(os.path.splitext(name)[0]):
                            fp = os.path.join(cache_dir, f)
                            if os.path.isfile(fp):
                                return fp
                except Exception:
                    pass
            return None

        def open_granule_filelike(granule) -> str:
            cached = _cached_local_path_for_granule(granule)
            if cached:
                if verbose:
                    print(f"Using cached HDF: {os.path.basename(cached)}")
                return cached
            # Download to cache
            paths = ea.download([granule], provider="LAADS", local_path=cache_dir)
            if isinstance(paths, dict):
                local_path = next(iter(paths.values()), None)
                if isinstance(local_path, (list, tuple)):
                    local_path = local_path[0] if local_path else None
            elif isinstance(paths, (list, tuple)):
                local_path = paths[0] if paths else None
            else:
                local_path = paths
            if not local_path or (not os.path.exists(local_path)):
                raise RuntimeError("Download failed or returned no local path.")
            if verbose:
                print(f"Downloaded HDF: {os.path.basename(local_path)}")
            return local_path

        def read_latlon_from_mod03(geo_path: str):
            # try HDF5 first (rare)
            if h5py is not None:
                try:
                    with h5py.File(geo_path, "r") as g:
                        for lat_key, lon_key in [
                            ("MODIS_Swath_Type_GEO/Geolocation Fields/Latitude", "MODIS_Swath_Type_GEO/Geolocation Fields/Longitude"),
                            ("MODIS_Swath_Type_L1B/Geolocation Fields/Latitude", "MODIS_Swath_Type_L1B/Geolocation Fields/Longitude"),
                        ]:
                            if lat_key in g and lon_key in g:
                                lat = np.array(g[lat_key], dtype=np.float32)
                                lon = np.array(g[lon_key], dtype=np.float32)
                                return lat, lon
                except Exception:
                    pass
            # HDF4 via pyhdf
            try:
                from pyhdf.SD import SD, SDC
            except Exception as e:
                raise RuntimeError("pyhdf is required to read MOD03 (HDF4). conda install -c conda-forge pyhdf") from e
            sd = SD(geo_path, SDC.READ)
            try:
                lat = sd.select("Latitude")[:]
                lon = sd.select("Longitude")[:]
                return np.array(lat, dtype=np.float32), np.array(lon, dtype=np.float32)
            finally:
                sd.end()

        def read_toa_from_mod02hkm(l1b_path: str) -> dict[str, np.ndarray]:
            out: dict[str, np.ndarray] = {}
            try:
                from pyhdf.SD import SD, SDC
            except Exception as e:
                raise RuntimeError("pyhdf is required to read MOD02HKM (HDF4). conda install -c conda-forge pyhdf") from e

            def _attr_value(attrs, key):
                try:
                    return attrs.get(key, (None,))[0]
                except Exception:
                    return None

            def _as_scalar(v, idx, default_scalar):
                if v is None:
                    return float(default_scalar)
                if isinstance(v, (list, tuple, np.ndarray)):
                    try:
                        return float(v[idx])
                    except Exception:
                        try:
                            return float(v[0])
                        except Exception:
                            return float(default_scalar)
                try:
                    return float(v)
                except Exception:
                    return float(default_scalar)

            sd = SD(l1b_path, SDC.READ)
            try:
                for dset_name, band_map in HKM_DATASETS:
                    if dset_name not in sd.datasets():
                        continue
                    ds = sd.select(dset_name)
                    data = ds[:]  # (bands, lines, samples)
                    attrs = ds.attributes(full=1)

                    scale_raw = (
                        _attr_value(attrs, "scale_factor")
                        or _attr_value(attrs, "reflectance_scales")
                        or _attr_value(attrs, "radiance_scales")
                        or 1.0
                    )
                    offset_raw = (
                        _attr_value(attrs, "add_offset")
                        or _attr_value(attrs, "reflectance_offsets")
                        or _attr_value(attrs, "radiance_offsets")
                        or 0.0
                    )
                    fill_raw = _attr_value(attrs, "_FillValue")

                    if data.ndim != 3:
                        continue

                    for bi, bname in band_map.items():
                        if bi >= data.shape[0]:
                            continue
                        scale_i = _as_scalar(scale_raw, bi, 1.0)
                        offset_i = _as_scalar(offset_raw, bi, 0.0)
                        arr = data[bi].astype(np.float32, copy=False)
                        if fill_raw is not None:
                            try:
                                fill_i = _as_scalar(fill_raw, bi, np.nan)
                                if np.isfinite(fill_i):
                                    mask = arr == fill_i
                                    if np.any(mask):
                                        arr[mask] = np.nan
                            except Exception:
                                pass
                        if scale_i != 1.0 or offset_i != 0.0:
                            arr = arr * scale_i + offset_i
                        out[bname] = arr
            finally:
                sd.end()
            return out

        def _align_geo_to_band(lat, lon, band_arr: np.ndarray):
            lat = np.array(lat, dtype=np.float32, copy=False)
            lon = np.array(lon, dtype=np.float32, copy=False)
            lon = np.where(lon > 180.0, lon - 360.0, lon)
            lat = np.clip(lat, -90.0, 90.0)
            bl, bs = int(band_arr.shape[-2]), int(band_arr.shape[-1])
            gl, gs = int(lat.shape[-2]), int(lat.shape[-1])
            if (gl, gs) == (bs, bl):
                lat, lon = lat.T, lon.T
                gl, gs = lat.shape
            if (gl, gs) != (bl, bs):
                rl = bl // gl if gl and (bl % gl == 0) else 1
                rs = bs // gs if gs and (bs % gs == 0) else 1
                if rl == rs and rl in (2,):
                    lat = np.repeat(np.repeat(lat, rl, axis=0), rl, axis=1)
                    lon = np.repeat(np.repeat(lon, rl, axis=0), rl, axis=1)
                    gl, gs = lat.shape
            if (gl, gs) != (bl, bs):
                raise ValueError(f"Geolocation/band shape mismatch: latlon={gl}x{gs} vs band={bl}x{bs}")
            return lat, lon

        def swath_to_grid(band_arr, lat_, lon_, area_def_, radius_):
            # align, then flatten valid samples for memory-friendly resampling
            lat_a, lon_a = _align_geo_to_band(lat_, lon_, band_arr)
            vals = band_arr.astype(np.float32, copy=False).ravel()
            lats = lat_a.ravel()
            lons = lon_a.ravel()
            valid = np.isfinite(vals)
            if not np.any(valid):
                return np.full((area_def_.shape[0], area_def_.shape[1]), np.nan, dtype=np.float32)
            vals = vals[valid]
            lats = lats[valid]
            lons = lons[valid]
            swath_def = geometry.SwathDefinition(lons=lons, lats=lats)
            with warnings.catch_warnings():
                warnings.simplefilter("ignore", category=RuntimeWarning)
                grid = kd_tree.resample_nearest(
                    swath_def,
                    vals,
                    area_def_,
                    radius_of_influence=radius_,
                    fill_value=np.nan,
                    nprocs=1,
                    reduce_data=True,
                )
            return grid.astype(np.float32, copy=False)

        def write_single_band_tif(path, arr, transform, width, height):
            profile = {
                "driver": "GTiff",
                "height": int(height),
                "width": int(width),
                "count": 1,
                "dtype": "float32",
                "crs": "EPSG:4326",
                "transform": transform,
                "compress": "deflate",
                "predictor": 2,
                "tiled": True,
                "blockxsize": 256,
                "blockysize": 256,
                "nodata": np.float32(np.nan),
            }
            os.makedirs(os.path.dirname(path) or ".", exist_ok=True)
            with rasterio.open(path, "w", **profile) as dst:
                dst.write(arr, 1)

        def make_target_grid(bbox, res_deg_):
            x0, y0, x1, y1 = bbox
            width = int(math.ceil((x1 - x0) / res_deg_))
            height = int(math.ceil((y1 - y0) / res_deg_))
            transform = from_origin(x0, y1, res_deg_, res_deg_)
            area_def = geometry.AreaDefinition(
                "roi_ll",
                "regular latlon grid",
                "epsg4326",
                {"proj": "longlat", "datum": "WGS84"},
                width,
                height,
                [x0, y0, x1, y1],
            )
            return area_def, transform, width, height

        def _normalize_split(n) -> tuple[int, int]:
            if isinstance(n, (list, tuple)) and len(n) == 2:
                return max(1, int(n[0])), max(1, int(n[1]))
            n = max(1, int(n))
            return n, n

        def _split_bbox(bbox: tuple[float, float, float, float], ny: int, nx: int):
            x0, y0, x1, y1 = bbox
            dx = (x1 - x0) / nx
            dy = (y1 - y0) / ny
            tiles = []
            for iy in range(ny):
                ty0 = y0 + iy * dy
                ty1 = ty0 + dy
                for ix in range(nx):
                    tx0 = x0 + ix * dx
                    tx1 = tx0 + dx
                    tiles.append((tx0, ty0, tx1, ty1))
            return tiles

        def search(product, start_dt, end_dt, bbox):
            return ea.search_data(
                short_name=product,
                temporal=(start_dt, end_dt),
                bounding_box=bbox,
                provider="LAADS",
                granule_name="*.hdf",
            )

        def pair_l1b_with_geo(l1b_list, geo_list):
            geo_by_token = {}
            for g in geo_list:
                tok = token_Ayyyydoy_hhmm(_granule_name(g) or "")
                if tok:
                    geo_by_token[tok] = g
            pairs_ = []
            for sw in l1b_list:
                tok = token_Ayyyydoy_hhmm(_granule_name(sw) or "")
                if tok and tok in geo_by_token:
                    pairs_.append((sw, geo_by_token[tok]))
            return pairs_

        # ---------- Search ----------
        start_dt = datetime.strptime(start_date, "%Y-%m-%d")
        end_dt = datetime.strptime(end_date, "%Y-%m-%d")
        l1b, geo = [], []
        use_terra = platform.lower() in ("terra", "both")
        use_aqua = platform.lower() in ("aqua", "both")
        if use_terra:
            l1b += search("MOD02HKM", start_dt, end_dt, (minx, miny, maxx, maxy))
            geo += search("MOD03", start_dt, end_dt, (minx, miny, maxx, maxy))
        if use_aqua:
            l1b += search("MYD02HKM", start_dt, end_dt, (minx, miny, maxx, maxy))
            geo += search("MYD03", start_dt, end_dt, (minx, miny, maxx, maxy))

        pairs = pair_l1b_with_geo(l1b, geo)
        if not pairs:
            if verbose:
                print("No matching MODIS L1B/MOD03 pairs found for the criteria.")
            if dask_client:
                try:
                    dask_client.close()
                    if dask_cluster:
                        dask_cluster.close()
                except Exception:
                    pass
            return {"processed_pairs": 0, "written": 0, "days": 0, "paths": [], "dashboard": dashboard_url}

        # ---------- Skip entire days when all outputs exist ----------
        if not overwrite:
            def _pair_day_key(p):
                sw_g, _ = p
                try:
                    return day_key_from_name(_granule_name(sw_g))
                except Exception:
                    return None
            day_keys = set(filter(None, (_pair_day_key(p) for p in pairs)))
            skip_days = set()
            for d in day_keys:
                all_exist = all(os.path.exists(os.path.join(output_folder, f"{filename_prefix}_{b}_{d}.tif"))
                                for b in bands_wanted)
                if all_exist:
                    skip_days.add(d)
                    if verbose:
                        dtf = datetime.strptime(d, "%Y%m%d").strftime("%Y-%m-%d")
                        print(f"Skipping {dtf} (all outputs present).")
            if skip_days:
                pairs = [p for p in pairs if _pair_day_key(p) not in skip_days]
                if not pairs:
                    if dask_client:
                        try:
                            dask_client.close()
                            if dask_cluster:
                                dask_cluster.close()
                        except Exception:
                            pass
                    return {"processed_pairs": 0, "written": 0, "days": 0, "paths": [], "dashboard": dashboard_url}

        # ---------- Tiling over ROI bbox ----------
        ny, nx = _normalize_split(n_roi_split)
        tile_bboxes = _split_bbox((minx, miny, maxx, maxy), ny, nx)

        # NEW: refcount per (day_key, granule_token) to delete HDFs right after last tile of that day
        from collections import defaultdict as _dd
        expected_tiles = len(tile_bboxes)
        seen_per_pair_day: dict[tuple[str, str], int] = _dd(int)  # (day_key, token) -> tiles seen
        pair_paths_day: dict[tuple[str, str], tuple[str | None, str | None]] = {}  # -> (sw_path, geo_path)
        deleted_keys: set[tuple[str, str]] = set()

        # Prepare per-granule deletion counters
        # key = _granule_token(swath_name); each pair is used once per tile
        expected_per_pair: dict[str, int] = {}
        for sw_g, _geo_g in pairs:
            try:
                k = _granule_token(_granule_name(sw_g) or "")
            except Exception:
                k = _granule_token(os.path.basename(_cached_local_path_for_granule(sw_g) or ""))
            expected_per_pair[k] = len(tile_bboxes)

        from collections import defaultdict as _dd
        seen_per_pair: dict[str, int] = _dd(int)     # increments once per tile
        pair_paths: dict[str, tuple[str | None, str | None]] = {}  # key -> (sw_path, geo_path)
        deleted_pairs: set[str] = set()

        # ROI mask helper for a tile grid
        def _apply_roi_mask_if_needed(arr2d: np.ndarray, transform, width, height):
            if roi_geom is None:
                return arr2d
            try:
                mask = rasterize(
                    [(roi_geom, 1)],
                    out_shape=(int(height), int(width)),
                    transform=transform,
                    fill=0,
                    all_touched=False,
                    dtype="uint8",
                )
                out = arr2d.copy()
                out[mask == 0] = np.nan
                return out
            except Exception as e:
                if verbose:
                    print(f"⚠️ ROI rasterize failed, skipping mask on this tile: {e}")
                return arr2d

        # Tile-level processing function (per swath pair)
        def _process_pair_tile(sw_g, geo_g, area_def_t, transform_t, width_t, height_t, tile_tag: str):
            res = []
            sw_path = None
            geo_path = None
            try:
                sw_path = open_granule_filelike(sw_g)
                geo_path = open_granule_filelike(geo_g)
                sw_name = _granule_name(sw_g) or os.path.basename(sw_path)
                gtok = _granule_token(sw_name)
                day_key = _day_key_from_any(sw_g, sw_path) or "unknown"

                if day_key != "unknown" and (not overwrite):
                    all_exist = all(os.path.exists(os.path.join(output_folder, f"{filename_prefix}_{b}_{day_key}.tif"))
                                    for b in bands_wanted)
                    if all_exist:
                        # report paths for refcounting/deletion
                        res.append(("paths", day_key, gtok, sw_path, geo_path, tile_tag))
                        return res

                lat, lon = read_latlon_from_mod03(geo_path)
                bands = read_toa_from_mod02hkm(sw_path)
                if not bands:
                    res.append(("paths", day_key, gtok, sw_path, geo_path, tile_tag))
                    return res

                for bname, arr in bands.items():
                    if bname not in bands_wanted:
                        continue
                    if arr is None or not np.isfinite(arr).any():
                        continue
                    grid = swath_to_grid(arr, lat, lon, area_def_t, radius_m)
                    grid = _apply_roi_mask_if_needed(grid, transform_t, width_t, height_t)
                    tif_path = os.path.join(
                        granule_tif_dir,
                        f"{filename_prefix}_{bname}_{day_key}_{gtok}_tile{tile_tag}.tif"
                    )
                    write_single_band_tif(tif_path, grid, transform_t, width_t, height_t)
                    res.append(("tif", day_key, bname, tif_path, tile_tag))

                # one paths record per tile for refcounting
                res.append(("paths", day_key, gtok, sw_path, geo_path, tile_tag))
                return res
            except Exception as e:
                if verbose:
                    dbg = os.path.basename(sw_path) if sw_path else _granule_name(sw_g)
                    print(f"❌ Failed processing {dbg} [tile {tile_tag}]: {e}")
                # still emit paths for refcounting if available
                if sw_path or geo_path:
                    res.append(("paths", _day_key_from_any(sw_g, sw_path) or "unknown",
                                _granule_token(_granule_name(sw_g) or ""), sw_path, geo_path, tile_tag))
                return res

        final_tile_mosaics = defaultdict(list)  # (day, band) -> [tile mosaic paths]

        # Progress wrapper
        tile_iter = enumerate(tile_bboxes, start=1)
        if show_progress and _tqdm is not None:
            tile_iter = _tqdm(tile_iter, total=len(tile_bboxes), desc=f"Tiles {ny}x{nx}", unit="tile")

        for idx1, bbox_t in tile_iter:
            area_def_t, transform_t, width_t, height_t = make_target_grid(bbox_t, res_deg)
            ty, tx = divmod(idx1 - 1, nx)
            tile_tag = f"{ty}x{tx}"
            if verbose and (not show_progress or _tqdm is None):
                print(f"🧩 Tile {tile_tag} bbox={bbox_t} grid=({height_t},{width_t})")

            # Schedule tasks for this tile
            results_t = []
            if use_dask and dask_client:
                from dask import delayed
                from dask.distributed import as_completed
                tasks = [delayed(_process_pair_tile)(sw_g, geo_g, area_def_t, transform_t, width_t, height_t, tile_tag)
                         for (sw_g, geo_g) in pairs]
                futures = [dask_client.compute(t) for t in tasks]

                inner_pbar = None
                if show_progress and _tqdm is not None:
                    inner_pbar = _tqdm(total=len(futures), desc=f"Tile {tile_tag}", unit="gran", leave=False)

                for f in as_completed(futures):
                    try:
                        results_t.append(f.result())
                    except Exception as e:
                        if verbose:
                            print(f"❌ Granule failed on tile {tile_tag}: {e}")
                    if inner_pbar is not None:
                        inner_pbar.update(1)

                if inner_pbar is not None:
                    inner_pbar.close()
                try:
                    dask_client.cancel(futures)
                except Exception:
                    pass
            else:
                gran_iter = pairs
                if show_progress and _tqdm is not None:
                    gran_iter = _tqdm(pairs, desc=f"Tile {tile_tag}", unit="gran", leave=False)
                for sw_g, geo_g in gran_iter:
                    results_t.append(_process_pair_tile(sw_g, geo_g, area_def_t, transform_t, width_t, height_t, tile_tag))

            # Group per day+band and mosaic this tile across granules
            # Group per day+band and mosaic this tile across granules
            per_tile_groups = _dd(list)  # (day, band) -> [granule tile tif]
            for lst in results_t:
                for rec in lst:
                    if not rec:
                        continue
                    kind = rec[0]
                    if kind == "tif":
                        _, day_key, bname, tif_path, _ = rec
                        if day_key != "unknown":
                            per_tile_groups[(day_key, bname)].append(tif_path)
                    elif kind == "paths":
                        # NEW: refcount and delete when last tile for this (day, granule) is done
                        _, day_key, gtok, swp, geop, _ = rec
                        key = (day_key, gtok)
                        if key not in pair_paths_day:
                            pair_paths_day[key] = (swp, geop)
                        seen_per_pair_day[key] += 1
                        if remove_cache and day_key != "unknown" and key not in deleted_keys and seen_per_pair_day[key] >= expected_tiles:
                            for p in pair_paths_day.get(key, (None, None)):
                                try:
                                    if p and os.path.isfile(p):
                                        os.remove(p)
                                except Exception:
                                    pass
                            deleted_keys.add(key)
                            if verbose:
                                print(f"🧹 Removed cached HDFs for {key[1]} on {key[0]}")

            for (day_key, bname), tif_list in sorted(per_tile_groups.items()):
                if not tif_list:
                    continue
                tile_out = os.path.join(tile_mosaic_dir, f"{filename_prefix}_{bname}_{day_key}_tile{tile_tag}.tif")
                if (not overwrite) and os.path.exists(tile_out):
                    final_tile_mosaics[(day_key, bname)].append(tile_out)
                    continue
                try:
                    srcs = [rasterio.open(p) for p in tif_list]
                    mosaic, out_transform = rio_merge(srcs, method="first")
                    for s in srcs:
                        s.close()
                    # drop band axis if present
                    if mosaic.ndim == 3 and mosaic.shape[0] == 1:
                        mosaic = mosaic[0]
                    # Mask ROI again after merge (cheap; ensures clean edges)
                    mosaic = _apply_roi_mask_if_needed(mosaic, out_transform, mosaic.shape[1], mosaic.shape[0])
                    write_single_band_tif(
                        tile_out,
                        mosaic.astype(np.float32, copy=False),
                        out_transform,
                        mosaic.shape[1],
                        mosaic.shape[0],
                    )
                    final_tile_mosaics[(day_key, bname)].append(tile_out)
                except Exception as me:
                    if verbose:
                        print(f"❌ Tile mosaic failed for {bname} {day_key} [tile {tile_tag}]: {me}")

        # ---------- Final mosaic over all tiles ----------
        written_paths = []
        days = set()
        for (day_key, bname), tile_paths in sorted(final_tile_mosaics.items()):
            if not tile_paths:
                continue
            out_fp = os.path.join(output_folder, f"{filename_prefix}_{bname}_{day_key}.tif")
            if (not overwrite) and os.path.exists(out_fp):
                continue
            try:
                srcs = [rasterio.open(p) for p in tile_paths]
                mosaic, out_transform = rio_merge(srcs, method="first")
                for s in srcs:
                    s.close()
                if mosaic.ndim == 3 and mosaic.shape[0] == 1:
                    mosaic = mosaic[0]
                # Final ROI mask for safety
                mosaic = _apply_roi_mask_if_needed(mosaic, out_transform, mosaic.shape[1], mosaic.shape[0])
                write_single_band_tif(out_fp, mosaic.astype(np.float32, copy=False), out_transform, mosaic.shape[1], mosaic.shape[0])
                written_paths.append(out_fp)
                days.add(day_key)
            except Exception as me:
                if verbose:
                    print(f"❌ Final mosaic failed for {bname} {day_key}: {me}")

        if verbose:
            print(f"✅ MODIS TOA complete. Tiles={ny}x{nx} Pairs={len(pairs)} Days={len(days)} Written={len(written_paths)}")

        if dask_client:
            try:
                dask_client.close()
                if dask_cluster:
                    dask_cluster.close()
            except Exception:
                pass

        return {
            "processed_pairs": len(pairs),
            "written": len(written_paths),
            "days": len(days),
            "paths": written_paths,
            "dashboard": dashboard_url,
        }
    
    
    def download_modis_toa_v10(
        self,
        band_list: list[str] | str,
        output_folder: str,
        roi: tuple[float, float, float, float] | str,
        start_date: str,
        end_date: str,
        *,
        platform: str = "terra",         # "terra" | "aqua" | "both"
        res_deg: float = 0.0045,         # ~500 m @ equator
        radius_m: int = 4000,            # swath->grid nearest-neighbor radius (m)
        filename_prefix: str = "modis_toa",
        overwrite: bool = False,
        verbose: bool = True,
        edl_username: str | None = None,
        edl_password: str | None = None,
        login_strategy: str | None = None,
        temp_dir: str | None = None,
        # parallel knobs (used inside each tile)
        use_dask: bool = True,
        n_workers: int | str = "auto",
        threads_per_worker: int | str = "auto",
        scheduler: str = "processes",
        # Split ROI bbox into ny x nx tiles (sequential tiles → low RAM)
        n_roi_split: int | tuple[int, int] = 100,
        # Progress bars for tiles and per-tile granules
        show_progress: bool = True,
        remove_cache: bool = False,
    ) -> dict:
        """
        Download MODIS L1B TOA reflectance (HKM, 500 m) and write one GeoTIFF per band per day.

        Features:
        - ROI can be a bbox (minx,miny,maxx,maxy) or a vector file path (.geojson/.shp/.parquet).
          If vector, the pipeline grids the bbox of the geometry AND masks everything outside polygon(s).
        - Processes ROI in tiles (ny×nx) to reduce memory.
        - Per-granule tile rasters -> per-tile daily mosaics -> final daily mosaics clipped to ROI.

        Output:
        - {output_folder}/_granule_tifs/  (per-granule per-tile tifs)
        - {output_folder}/_tile_mosaics/ (per-day per-tile mosaics masked to ROI if vector)
        - {output_folder}/{prefix}_{Band}_{YYYYMMDD}.tif (final mosaics masked to ROI if vector)
        """
        import os, re, math, warnings, tempfile, logging
        from collections import defaultdict
        from datetime import datetime, timedelta

        import numpy as np

        # Optional: progress bars
        try:
            from tqdm.auto import tqdm as _tqdm
        except Exception:
            _tqdm = None

        # Earthdata/IO deps
        try:
            import earthaccess as ea
        except Exception as e:
            raise RuntimeError("earthaccess is required. pip install earthaccess") from e
        try:
            import rasterio
            from rasterio.merge import merge as rio_merge
            from rasterio.transform import from_origin
            from rasterio.features import rasterize
            from pyresample import geometry, kd_tree
        except Exception as e:
            raise RuntimeError("Dependencies missing. pip install rasterio pyresample") from e
        try:
            import h5py  # optional, rare HDF5 MODIS
        except Exception:
            h5py = None

        # Vector ROI support (GeoPandas/Shapely)
        roi_geom = None
        if isinstance(roi, str):
            try:
                import geopandas as gpd
                from shapely.ops import unary_union
                from shapely.geometry import mapping
            except Exception as e:
                raise RuntimeError("Vector ROI requires geopandas and shapely. pip install geopandas shapely") from e

            if not os.path.exists(roi):
                raise FileNotFoundError(f"ROI vector file not found: {roi}")

            gdf = gpd.read_file(roi)
            if gdf.empty:
                raise ValueError("ROI vector has no features.")
            # Project to EPSG:4326 for this pipeline
            if gdf.crs is None or str(gdf.crs).upper() not in ("EPSG:4326", "OGC:CRS84"):
                gdf = gdf.to_crs("EPSG:4326")
            # Union all geometries
            roi_geom = unary_union([geom for geom in gdf.geometry if geom and not geom.is_empty])
            if roi_geom.is_empty:
                raise ValueError("ROI geometry is empty after union.")
            minx, miny, maxx, maxy = roi_geom.bounds
        else:
            # bbox path
            minx, miny, maxx, maxy = map(float, roi)
            if (maxx - minx) <= 0 or (maxy - miny) <= 0:
                raise ValueError("roi must be (min_lon, min_lat, max_lon, max_lat) with positive area.")

        # ---------- IO and environment ----------
        os.makedirs(output_folder, exist_ok=True)
        cache_dir = os.path.join(output_folder, "_earthaccess_cache")
        os.makedirs(cache_dir, exist_ok=True)
        granule_tif_dir = os.path.join(output_folder, "_granule_tifs")
        os.makedirs(granule_tif_dir, exist_ok=True)
        tile_mosaic_dir = os.path.join(output_folder, "_tile_mosaics")
        os.makedirs(tile_mosaic_dir, exist_ok=True)

        tmp_root = temp_dir or os.path.join(output_folder, "_tmp")
        os.makedirs(tmp_root, exist_ok=True)
        os.environ.setdefault("TEMP", tmp_root)
        os.environ.setdefault("TMP", tmp_root)
        os.environ.setdefault("TMPDIR", tmp_root)
        os.environ.setdefault("CPL_TMPDIR", tmp_root)
        os.environ.setdefault("GDAL_CACHEMAX", "256")
        tempfile.tempdir = tmp_root

        # ---------- Dask (used inside each tile only) ----------
        dask_client = None
        dask_cluster = None
        dashboard_url = None
        if use_dask:
            try:
                from dask.distributed import Client, LocalCluster
                if n_workers == "auto":
                    n_workers = max(1, (os.cpu_count() or 2) - 1)
                if threads_per_worker == "auto":
                    threads_per_worker = 1 if scheduler == "processes" else max(1, (os.cpu_count() or 2) // int(n_workers))
                dask_cluster = LocalCluster(
                    n_workers=int(n_workers),
                    threads_per_worker=int(threads_per_worker),
                    processes=(scheduler == "processes"),
                    silence_logs=logging.CRITICAL,
                )
                dask_client = Client(dask_cluster, set_as_default=True)
                dask_client.wait_for_workers(int(n_workers))
                dashboard_url = getattr(dask_client, "dashboard_link", None)
                if verbose:
                    print(f"⚙️  Dask ready: workers={n_workers}, threads/worker={threads_per_worker}, mode={scheduler}")
                    if dashboard_url:
                        print(f"📊 Dask dashboard: {dashboard_url}")
            except Exception as e:
                if verbose:
                    print(f"⚠️ Dask unavailable ({e}). Running serial.")
                use_dask = False
                dask_client = None
                dask_cluster = None

        # ---------- Bands and datasets ----------
        HKM_DATASETS = [
            ("EV_250_Aggr500_RefSB", {0: "B01", 1: "B02"}),
            ("EV_500_RefSB",         {0: "B03", 1: "B04", 2: "B05", 3: "B06", 4: "B07"}),
        ]
        ALL_BANDS = ["B01", "B02", "B03", "B04", "B05", "B06", "B07"]
        if isinstance(band_list, str) and band_list.lower() == "all":
            bands_wanted = set(ALL_BANDS)
        else:
            bands_wanted = set([str(b).upper() for b in band_list])
            unknown = bands_wanted - set(ALL_BANDS)
            if unknown:
                raise ValueError(f"Unknown bands requested: {sorted(unknown)}")

        # ---------- Login ----------
        if verbose:
            print("🔐 Logging into earthaccess (LAADS)...")
        try:
            if edl_username and edl_password:
                ea.login(strategy=(login_strategy or "interactive"), username=edl_username, password=edl_password, persist=True)
            elif login_strategy:
                ea.login(strategy=login_strategy, persist=True)
            else:
                ea.login(persist=True)
        except Exception as e:
            raise RuntimeError(f"earthaccess login failed: {e}")

        # ---------- Helpers ----------
        def _granule_name(granule) -> str:
            if isinstance(granule, str):
                return os.path.basename(granule)
            # UMM metadata
            try:
                umm = getattr(granule, "umm", None)
                if isinstance(umm, dict):
                    for k in ("GranuleUR", "GranuleID", "title"):
                        v = umm.get(k)
                        if isinstance(v, str) and v:
                            return v
            except Exception:
                pass
            # meta/metadata dicts
            for attr in ("meta", "metadata"):
                try:
                    md = getattr(granule, attr, None)
                    if isinstance(md, dict):
                        for k in ("granule_ur", "GranuleUR", "title"):
                            v = md.get(k)
                            if isinstance(v, str) and v:
                                return v
                except Exception:
                    pass
            # links (method or list)
            links = getattr(granule, "data_links", None) or getattr(granule, "links", None) or []
            try:
                if callable(links):
                    links = links()
            except Exception:
                links = []
            for url in links:
                if not url:
                    continue
                base = os.path.basename(str(url).split("?")[0])
                if base:
                    return base
            # assets dict
            try:
                assets = getattr(granule, "assets", None)
                if isinstance(assets, dict):
                    for a in assets.values():
                        href = a.get("href") if isinstance(a, dict) else None
                        if href:
                            base = os.path.basename(str(href).split("?")[0])
                            if base:
                                return base
            except Exception:
                pass
            return ""

        def token_Ayyyydoy_hhmm(name: str) -> str | None:
            m = re.search(r"\.A(\d{7})\.(\d{4})\.", name)
            return f"A{m.group(1)}.{m.group(2)}" if m else None

        def day_key_from_name(name: str) -> str:
            m = re.search(r"\.A(\d{4})(\d{3})\.\d{4}\.", name)
            if not m:
                # fallback YYYYMMDD somewhere in name
                m2 = re.search(r"(20\d{6})", name)
                if m2:
                    return m2.group(1)
                raise ValueError(f"Cannot parse day key from name: {name}")
            year, doy = int(m.group(1)), int(m.group(2))
            dt = datetime(year, 1, 1) + timedelta(days=doy - 1)
            return dt.strftime("%Y%m%d")

        def _day_key_from_any(granule, local_path: str | None):
            name = _granule_name(granule)
            if not name and local_path:
                name = os.path.basename(local_path)
            try:
                return day_key_from_name(name)
            except Exception:
                return None

        def _granule_token(name: str) -> str:
            m = re.search(r"\.A(\d{7})\.(\d{4})\.", name or "")
            if m:
                return f"A{m.group(1)}{m.group(2)}"
            base = os.path.splitext(os.path.basename(name or "gran"))[0]
            return re.sub(r"[^A-Za-z0-9]+", "", base)[-22:] or "gran"

        def _cached_local_path_for_granule(granule) -> str | None:
            links = getattr(granule, "data_links", None) or getattr(granule, "links", None) or []
            try:
                if callable(links):
                    links = links()
            except Exception:
                links = []
            for url in links:
                if not url:
                    continue
                base = os.path.basename(str(url).split("?")[0])
                if base:
                    fp = os.path.join(cache_dir, base)
                    if os.path.exists(fp):
                        return fp
            name = _granule_name(granule)
            if name:
                for cand in (name, f"{name}.hdf", f"{name}.HDF", f"{name}.h5", f"{name}.he5"):
                    fp = os.path.join(cache_dir, cand)
                    if os.path.exists(fp):
                        return fp
                try:
                    for f in os.listdir(cache_dir):
                        if f.startswith(os.path.splitext(name)[0]):
                            fp = os.path.join(cache_dir, f)
                            if os.path.isfile(fp):
                                return fp
                except Exception:
                    pass
            return None

        def open_granule_filelike(granule) -> str:
            cached = _cached_local_path_for_granule(granule)
            if cached:
                if verbose:
                    print(f"Using cached HDF: {os.path.basename(cached)}")
                return cached
            # Download to cache
            paths = ea.download([granule], provider="LAADS", local_path=cache_dir)
            if isinstance(paths, dict):
                local_path = next(iter(paths.values()), None)
                if isinstance(local_path, (list, tuple)):
                    local_path = local_path[0] if local_path else None
            elif isinstance(paths, (list, tuple)):
                local_path = paths[0] if paths else None
            else:
                local_path = paths
            if not local_path or (not os.path.exists(local_path)):
                raise RuntimeError("Download failed or returned no local path.")
            if verbose:
                print(f"Downloaded HDF: {os.path.basename(local_path)}")
            return local_path

        def read_latlon_from_mod03(geo_path: str):
            # try HDF5 first (rare)
            if h5py is not None:
                try:
                    with h5py.File(geo_path, "r") as g:
                        for lat_key, lon_key in [
                            ("MODIS_Swath_Type_GEO/Geolocation Fields/Latitude", "MODIS_Swath_Type_GEO/Geolocation Fields/Longitude"),
                            ("MODIS_Swath_Type_L1B/Geolocation Fields/Latitude", "MODIS_Swath_Type_L1B/Geolocation Fields/Longitude"),
                        ]:
                            if lat_key in g and lon_key in g:
                                lat = np.array(g[lat_key], dtype=np.float32)
                                lon = np.array(g[lon_key], dtype=np.float32)
                                return lat, lon
                except Exception:
                    pass
            # HDF4 via pyhdf
            try:
                from pyhdf.SD import SD, SDC
            except Exception as e:
                raise RuntimeError("pyhdf is required to read MOD03 (HDF4). conda install -c conda-forge pyhdf") from e
            sd = SD(geo_path, SDC.READ)
            try:
                lat = sd.select("Latitude")[:]
                lon = sd.select("Longitude")[:]
                return np.array(lat, dtype=np.float32), np.array(lon, dtype=np.float32)
            finally:
                sd.end()

        def read_toa_from_mod02hkm(l1b_path: str) -> dict[str, np.ndarray]:
            out: dict[str, np.ndarray] = {}
            try:
                from pyhdf.SD import SD, SDC
            except Exception as e:
                raise RuntimeError("pyhdf is required to read MOD02HKM (HDF4). conda install -c conda-forge pyhdf") from e

            def _attr_value(attrs, key):
                try:
                    return attrs.get(key, (None,))[0]
                except Exception:
                    return None

            def _as_scalar(v, idx, default_scalar):
                if v is None:
                    return float(default_scalar)
                if isinstance(v, (list, tuple, np.ndarray)):
                    try:
                        return float(v[idx])
                    except Exception:
                        try:
                            return float(v[0])
                        except Exception:
                            return float(default_scalar)
                try:
                    return float(v)
                except Exception:
                    return float(default_scalar)

            sd = SD(l1b_path, SDC.READ)
            try:
                for dset_name, band_map in HKM_DATASETS:
                    if dset_name not in sd.datasets():
                        continue
                    ds = sd.select(dset_name)
                    data = ds[:]  # (bands, lines, samples)
                    attrs = ds.attributes(full=1)

                    scale_raw = (
                        _attr_value(attrs, "scale_factor")
                        or _attr_value(attrs, "reflectance_scales")
                        or _attr_value(attrs, "radiance_scales")
                        or 1.0
                    )
                    offset_raw = (
                        _attr_value(attrs, "add_offset")
                        or _attr_value(attrs, "reflectance_offsets")
                        or _attr_value(attrs, "radiance_offsets")
                        or 0.0
                    )
                    fill_raw = _attr_value(attrs, "_FillValue")

                    if data.ndim != 3:
                        continue

                    for bi, bname in band_map.items():
                        if bi >= data.shape[0]:
                            continue
                        scale_i = _as_scalar(scale_raw, bi, 1.0)
                        offset_i = _as_scalar(offset_raw, bi, 0.0)
                        arr = data[bi].astype(np.float32, copy=False)
                        if fill_raw is not None:
                            try:
                                fill_i = _as_scalar(fill_raw, bi, np.nan)
                                if np.isfinite(fill_i):
                                    mask = arr == fill_i
                                    if np.any(mask):
                                        arr[mask] = np.nan
                            except Exception:
                                pass
                        if scale_i != 1.0 or offset_i != 0.0:
                            arr = arr * scale_i + offset_i
                        out[bname] = arr
            finally:
                sd.end()
            return out

        def _align_geo_to_band(lat, lon, band_arr: np.ndarray):
            lat = np.array(lat, dtype=np.float32, copy=False)
            lon = np.array(lon, dtype=np.float32, copy=False)
            lon = np.where(lon > 180.0, lon - 360.0, lon)
            lat = np.clip(lat, -90.0, 90.0)
            bl, bs = int(band_arr.shape[-2]), int(band_arr.shape[-1])
            gl, gs = int(lat.shape[-2]), int(lat.shape[-1])
            if (gl, gs) == (bs, bl):
                lat, lon = lat.T, lon.T
                gl, gs = lat.shape
            if (gl, gs) != (bl, bs):
                rl = bl // gl if gl and (bl % gl == 0) else 1
                rs = bs // gs if gs and (bs % gs == 0) else 1
                if rl == rs and rl in (2,):
                    lat = np.repeat(np.repeat(lat, rl, axis=0), rl, axis=1)
                    lon = np.repeat(np.repeat(lon, rl, axis=0), rl, axis=1)
                    gl, gs = lat.shape
            if (gl, gs) != (bl, bs):
                raise ValueError(f"Geolocation/band shape mismatch: latlon={gl}x{gs} vs band={bl}x{bs}")
            return lat, lon

        def swath_to_grid(band_arr, lat_, lon_, area_def_, radius_):
            # align, then flatten valid samples for memory-friendly resampling
            lat_a, lon_a = _align_geo_to_band(lat_, lon_, band_arr)
            vals = band_arr.astype(np.float32, copy=False).ravel()
            lats = lat_a.ravel()
            lons = lon_a.ravel()
            valid = np.isfinite(vals)
            if not np.any(valid):
                return np.full((area_def_.shape[0], area_def_.shape[1]), np.nan, dtype=np.float32)
            vals = vals[valid]
            lats = lats[valid]
            lons = lons[valid]
            swath_def = geometry.SwathDefinition(lons=lons, lats=lats)
            with warnings.catch_warnings():
                warnings.simplefilter("ignore", category=RuntimeWarning)
                grid = kd_tree.resample_nearest(
                    swath_def,
                    vals,
                    area_def_,
                    radius_of_influence=radius_,
                    fill_value=np.nan,
                    nprocs=1,
                    reduce_data=True,
                )
            return grid.astype(np.float32, copy=False)

        def write_single_band_tif(path, arr, transform, width, height):
            profile = {
                "driver": "GTiff",
                "height": int(height),
                "width": int(width),
                "count": 1,
                "dtype": "float32",
                "crs": "EPSG:4326",
                "transform": transform,
                "compress": "deflate",
                "predictor": 2,
                "tiled": True,
                "blockxsize": 256,
                "blockysize": 256,
                "nodata": np.float32(np.nan),
            }
            os.makedirs(os.path.dirname(path) or ".", exist_ok=True)
            with rasterio.open(path, "w", **profile) as dst:
                dst.write(arr, 1)

        def make_target_grid(bbox, res_deg_):
            x0, y0, x1, y1 = bbox
            width = int(math.ceil((x1 - x0) / res_deg_))
            height = int(math.ceil((y1 - y0) / res_deg_))
            transform = from_origin(x0, y1, res_deg_, res_deg_)
            area_def = geometry.AreaDefinition(
                "roi_ll",
                "regular latlon grid",
                "epsg4326",
                {"proj": "longlat", "datum": "WGS84"},
                width,
                height,
                [x0, y0, x1, y1],
            )
            return area_def, transform, width, height

        def _normalize_split(n) -> tuple[int, int]:
            if isinstance(n, (list, tuple)) and len(n) == 2:
                return max(1, int(n[0])), max(1, int(n[1]))
            n = max(1, int(n))
            return n, n

        def _split_bbox(bbox: tuple[float, float, float, float], ny: int, nx: int):
            x0, y0, x1, y1 = bbox
            dx = (x1 - x0) / nx
            dy = (y1 - y0) / ny
            tiles = []
            for iy in range(ny):
                ty0 = y0 + iy * dy
                ty1 = ty0 + dy
                for ix in range(nx):
                    tx0 = x0 + ix * dx
                    tx1 = tx0 + dx
                    tiles.append((tx0, ty0, tx1, ty1))
            return tiles

        def search(product, start_dt, end_dt, bbox):
            return ea.search_data(
                short_name=product,
                temporal=(start_dt, end_dt),
                bounding_box=bbox,
                provider="LAADS",
                granule_name="*.hdf",
            )

        def pair_l1b_with_geo(l1b_list, geo_list):
            geo_by_token = {}
            for g in geo_list:
                tok = token_Ayyyydoy_hhmm(_granule_name(g) or "")
                if tok:
                    geo_by_token[tok] = g
            pairs_ = []
            for sw in l1b_list:
                tok = token_Ayyyydoy_hhmm(_granule_name(sw) or "")
                if tok and tok in geo_by_token:
                    pairs_.append((sw, geo_by_token[tok]))
            return pairs_

        # ---------- Search ----------
        start_dt = datetime.strptime(start_date, "%Y-%m-%d")
        end_dt = datetime.strptime(end_date, "%Y-%m-%d")
        l1b, geo = [], []
        use_terra = platform.lower() in ("terra", "both")
        use_aqua = platform.lower() in ("aqua", "both")
        if use_terra:
            l1b += search("MOD02HKM", start_dt, end_dt, (minx, miny, maxx, maxy))
            geo += search("MOD03", start_dt, end_dt, (minx, miny, maxx, maxy))
        if use_aqua:
            l1b += search("MYD02HKM", start_dt, end_dt, (minx, miny, maxx, maxy))
            geo += search("MYD03", start_dt, end_dt, (minx, miny, maxx, maxy))

        pairs = pair_l1b_with_geo(l1b, geo)
        if not pairs:
            if verbose:
                print("No matching MODIS L1B/MOD03 pairs found for the criteria.")
            if dask_client:
                try:
                    dask_client.close()
                    if dask_cluster:
                        dask_cluster.close()
                except Exception:
                    pass
            return {"processed_pairs": 0, "written": 0, "days": 0, "paths": [], "dashboard": dashboard_url}

        # ---------- Skip entire days when all outputs exist ----------
        if not overwrite:
            def _pair_day_key(p):
                sw_g, _ = p
                try:
                    return day_key_from_name(_granule_name(sw_g))
                except Exception:
                    return None
            day_keys = set(filter(None, (_pair_day_key(p) for p in pairs)))
            skip_days = set()
            for d in day_keys:
                all_exist = all(os.path.exists(os.path.join(output_folder, f"{filename_prefix}_{b}_{d}.tif"))
                                for b in bands_wanted)
                if all_exist:
                    skip_days.add(d)
                    if verbose:
                        dtf = datetime.strptime(d, "%Y%m%d").strftime("%Y-%m-%d")
                        print(f"Skipping {dtf} (all outputs present).")
            if skip_days:
                pairs = [p for p in pairs if _pair_day_key(p) not in skip_days]
                if not pairs:
                    if dask_client:
                        try:
                            dask_client.close()
                            if dask_cluster:
                                dask_cluster.close()
                        except Exception:
                            pass
                    return {"processed_pairs": 0, "written": 0, "days": 0, "paths": [], "dashboard": dashboard_url}

        # ---------- Tiling over ROI bbox ----------
        ny, nx = _normalize_split(n_roi_split)
        tile_bboxes = _split_bbox((minx, miny, maxx, maxy), ny, nx)

        # NEW: refcount per (day_key, granule_token) to delete HDFs right after last tile of that day
        from collections import defaultdict as _dd
        expected_tiles = len(tile_bboxes)
        seen_per_pair_day: dict[tuple[str, str], int] = _dd(int)  # (day_key, token) -> tiles seen
        pair_paths_day: dict[tuple[str, str], tuple[str | None, str | None]] = {}  # -> (sw_path, geo_path)
        deleted_keys: set[tuple[str, str]] = set()

        # Prepare per-granule deletion counters
        # key = _granule_token(swath_name); each pair is used once per tile
        expected_per_pair: dict[str, int] = {}
        for sw_g, _geo_g in pairs:
            try:
                k = _granule_token(_granule_name(sw_g) or "")
            except Exception:
                k = _granule_token(os.path.basename(_cached_local_path_for_granule(sw_g) or ""))
            expected_per_pair[k] = len(tile_bboxes)

        from collections import defaultdict as _dd
        seen_per_pair: dict[str, int] = _dd(int)     # increments once per tile
        pair_paths: dict[str, tuple[str | None, str | None]] = {}  # key -> (sw_path, geo_path)
        deleted_pairs: set[str] = set()

        # ROI mask helper for a tile grid
        def _apply_roi_mask_if_needed(arr2d: np.ndarray, transform, width, height):
            if roi_geom is None:
                return arr2d
            try:
                mask = rasterize(
                    [(roi_geom, 1)],
                    out_shape=(int(height), int(width)),
                    transform=transform,
                    fill=0,
                    all_touched=False,
                    dtype="uint8",
                )
                out = arr2d.copy()
                out[mask == 0] = np.nan
                return out
            except Exception as e:
                if verbose:
                    print(f"⚠️ ROI rasterize failed, skipping mask on this tile: {e}")
                return arr2d

        # Tile-level processing function (per swath pair)
        def _process_pair_tile(sw_g, geo_g, area_def_t, transform_t, width_t, height_t, tile_tag: str):
            res = []
            sw_path = None
            geo_path = None
            try:
                sw_path = open_granule_filelike(sw_g)
                geo_path = open_granule_filelike(geo_g)
                sw_name = _granule_name(sw_g) or os.path.basename(sw_path)
                gtok = _granule_token(sw_name)
                day_key = _day_key_from_any(sw_g, sw_path) or "unknown"

                if day_key != "unknown" and (not overwrite):
                    all_exist = all(os.path.exists(os.path.join(output_folder, f"{filename_prefix}_{b}_{day_key}.tif"))
                                    for b in bands_wanted)
                    if all_exist:
                        # report paths for refcounting/deletion
                        res.append(("paths", day_key, gtok, sw_path, geo_path, tile_tag))
                        return res

                lat, lon = read_latlon_from_mod03(geo_path)
                bands = read_toa_from_mod02hkm(sw_path)
                if not bands:
                    res.append(("paths", day_key, gtok, sw_path, geo_path, tile_tag))
                    return res

                for bname, arr in bands.items():
                    if bname not in bands_wanted:
                        continue
                    if arr is None or not np.isfinite(arr).any():
                        continue
                    grid = swath_to_grid(arr, lat, lon, area_def_t, radius_m)
                    grid = _apply_roi_mask_if_needed(grid, transform_t, width_t, height_t)
                    tif_path = os.path.join(
                        granule_tif_dir,
                        f"{filename_prefix}_{bname}_{day_key}_{gtok}_tile{tile_tag}.tif"
                    )
                    write_single_band_tif(tif_path, grid, transform_t, width_t, height_t)
                    res.append(("tif", day_key, bname, tif_path, tile_tag))

                # one paths record per tile for refcounting
                res.append(("paths", day_key, gtok, sw_path, geo_path, tile_tag))
                return res
            except Exception as e:
                if verbose:
                    dbg = os.path.basename(sw_path) if sw_path else _granule_name(sw_g)
                    print(f"❌ Failed processing {dbg} [tile {tile_tag}]: {e}")
                # still emit paths for refcounting if available
                if sw_path or geo_path:
                    res.append(("paths", _day_key_from_any(sw_g, sw_path) or "unknown",
                                _granule_token(_granule_name(sw_g) or ""), sw_path, geo_path, tile_tag))
                return res

        final_tile_mosaics = defaultdict(list)  # (day, band) -> [tile mosaic paths]

        # Progress wrapper
        tile_iter = enumerate(tile_bboxes, start=1)
        if show_progress and _tqdm is not None:
            tile_iter = _tqdm(tile_iter, total=len(tile_bboxes), desc=f"Tiles {ny}x{nx}", unit="tile")

        for idx1, bbox_t in tile_iter:
            area_def_t, transform_t, width_t, height_t = make_target_grid(bbox_t, res_deg)
            ty, tx = divmod(idx1 - 1, nx)
            tile_tag = f"{ty}x{tx}"
            if verbose and (not show_progress or _tqdm is None):
                print(f"🧩 Tile {tile_tag} bbox={bbox_t} grid=({height_t},{width_t})")

            # Schedule tasks for this tile
            results_t = []
            if use_dask and dask_client:
                from dask import delayed
                from dask.distributed import as_completed
                tasks = [delayed(_process_pair_tile)(sw_g, geo_g, area_def_t, transform_t, width_t, height_t, tile_tag)
                         for (sw_g, geo_g) in pairs]
                futures = [dask_client.compute(t) for t in tasks]

                inner_pbar = None
                if show_progress and _tqdm is not None:
                    inner_pbar = _tqdm(total=len(futures), desc=f"Tile {tile_tag}", unit="gran", leave=False)

                for f in as_completed(futures):
                    try:
                        results_t.append(f.result())
                    except Exception as e:
                        if verbose:
                            print(f"❌ Granule failed on tile {tile_tag}: {e}")
                    if inner_pbar is not None:
                        inner_pbar.update(1)

                if inner_pbar is not None:
                    inner_pbar.close()
                try:
                    dask_client.cancel(futures)
                except Exception:
                    pass
            else:
                gran_iter = pairs
                if show_progress and _tqdm is not None:
                    gran_iter = _tqdm(pairs, desc=f"Tile {tile_tag}", unit="gran", leave=False)
                for sw_g, geo_g in gran_iter:
                    results_t.append(_process_pair_tile(sw_g, geo_g, area_def_t, transform_t, width_t, height_t, tile_tag))

            # Group per day+band and mosaic this tile across granules
            # Group per day+band and mosaic this tile across granules
            per_tile_groups = _dd(list)  # (day, band) -> [granule tile tif]
            for lst in results_t:
                for rec in lst:
                    if not rec:
                        continue
                    kind = rec[0]
                    if kind == "tif":
                        _, day_key, bname, tif_path, _ = rec
                        if day_key != "unknown":
                            per_tile_groups[(day_key, bname)].append(tif_path)
                    elif kind == "paths":
                        # NEW: refcount and delete when last tile for this (day, granule) is done
                        _, day_key, gtok, swp, geop, _ = rec
                        key = (day_key, gtok)
                        if key not in pair_paths_day:
                            pair_paths_day[key] = (swp, geop)
                        seen_per_pair_day[key] += 1
                        if remove_cache and day_key != "unknown" and key not in deleted_keys and seen_per_pair_day[key] >= expected_tiles:
                            for p in pair_paths_day.get(key, (None, None)):
                                try:
                                    if p and os.path.isfile(p):
                                        os.remove(p)
                                except Exception:
                                    pass
                            deleted_keys.add(key)
                            if verbose:
                                print(f"🧹 Removed cached HDFs for {key[1]} on {key[0]}")

            for (day_key, bname), tif_list in sorted(per_tile_groups.items()):
                if not tif_list:
                    continue
                tile_out = os.path.join(tile_mosaic_dir, f"{filename_prefix}_{bname}_{day_key}_tile{tile_tag}.tif")
                if (not overwrite) and os.path.exists(tile_out):
                    final_tile_mosaics[(day_key, bname)].append(tile_out)
                    continue
                try:
                    srcs = [rasterio.open(p) for p in tif_list]
                    mosaic, out_transform = rio_merge(srcs, method="first")
                    for s in srcs:
                        s.close()
                    # drop band axis if present
                    if mosaic.ndim == 3 and mosaic.shape[0] == 1:
                        mosaic = mosaic[0]
                    # Mask ROI again after merge (cheap; ensures clean edges)
                    mosaic = _apply_roi_mask_if_needed(mosaic, out_transform, mosaic.shape[1], mosaic.shape[0])
                    write_single_band_tif(
                        tile_out,
                        mosaic.astype(np.float32, copy=False),
                        out_transform,
                        mosaic.shape[1],
                        mosaic.shape[0],
                    )
                    final_tile_mosaics[(day_key, bname)].append(tile_out)
                except Exception as me:
                    if verbose:
                        print(f"❌ Tile mosaic failed for {bname} {day_key} [tile {tile_tag}]: {me}")

        # ---------- Final mosaic over all tiles ----------
        written_paths = []
        days = set()
        for (day_key, bname), tile_paths in sorted(final_tile_mosaics.items()):
            if not tile_paths:
                continue
            out_fp = os.path.join(output_folder, f"{filename_prefix}_{bname}_{day_key}.tif")
            if (not overwrite) and os.path.exists(out_fp):
                continue
            try:
                srcs = [rasterio.open(p) for p in tile_paths]
                mosaic, out_transform = rio_merge(srcs, method="first")
                for s in srcs:
                    s.close()
                if mosaic.ndim == 3 and mosaic.shape[0] == 1:
                    mosaic = mosaic[0]
                # Final ROI mask for safety
                mosaic = _apply_roi_mask_if_needed(mosaic, out_transform, mosaic.shape[1], mosaic.shape[0])
                write_single_band_tif(out_fp, mosaic.astype(np.float32, copy=False), out_transform, mosaic.shape[1], mosaic.shape[0])
                written_paths.append(out_fp)
                days.add(day_key)
            except Exception as me:
                if verbose:
                    print(f"❌ Final mosaic failed for {bname} {day_key}: {me}")

        if verbose:
            print(f"✅ MODIS TOA complete. Tiles={ny}x{nx} Pairs={len(pairs)} Days={len(days)} Written={len(written_paths)}")

        if dask_client:
            try:
                dask_client.close()
                if dask_cluster:
                    dask_cluster.close()
            except Exception:
                pass

        return {
            "processed_pairs": len(pairs),
            "written": len(written_paths),
            "days": len(days),
            "paths": written_paths,
            "dashboard": dashboard_url,
        }
    
    
    def download_modis_toa_bbox(
        self,
        band_list: list[str] | str,
        output_folder: str,
        roi: tuple[float, float, float, float],
        start_date: str,
        end_date: str,
        *,
        platform: str = "terra",         # "terra" | "aqua" | "both"
        res_deg: float = 0.0045,         # ~500 m @ equator
        radius_m: int = 4000,            # swath->grid nearest-neighbor radius (m)
        filename_prefix: str = "modis_toa",
        overwrite: bool = False,
        verbose: bool = True,
        edl_username: str | None = None,
        edl_password: str | None = None,
        login_strategy: str | None = None,
        temp_dir: str | None = None,
        # parallel knobs (used inside each tile)
        use_dask: bool = True,
        n_workers: int | str = "auto",
        threads_per_worker: int | str = "auto",
        scheduler: str = "processes",
        # NEW: split ROI into ny x nx tiles and process sequentially to reduce RAM
        n_roi_split: int | tuple[int, int] = 1000,
    ) -> dict:
        """
        Download MODIS L1B TOA reflectance (HKM, 500 m) and write one GeoTIFF per band per day.
        Processes the ROI in tiles to avoid memory pressure, writing:
        - per-granule per-tile GeoTIFFs under {output}/_granule_tifs
        - per-tile daily mosaics under {output}/_tile_mosaics
        - final full-ROI daily mosaics: {output}/{filename_prefix}_{Bxx}_{YYYYMMDD}.tif
        """
        import os, re, math, tempfile, warnings, logging
        from collections import defaultdict
        from datetime import datetime, timedelta
        import numpy as np

        try:
            import earthaccess as ea
        except Exception as e:
            raise RuntimeError("earthaccess is required. pip install earthaccess") from e
        try:
            import rasterio
            from rasterio.merge import merge as rio_merge
            from rasterio.transform import from_origin
            from pyresample import geometry, kd_tree
        except Exception as e:
            raise RuntimeError("Dependencies missing. pip install rasterio pyresample") from e
        try:
            import h5py  # optional, for rare HDF5 MODIS
        except Exception:
            h5py = None

        # ---------- IO and environment ----------
        minx, miny, maxx, maxy = map(float, roi)
        if (maxx - minx) <= 0 or (maxy - miny) <= 0:
            raise ValueError("roi must be (min_lon, min_lat, max_lon, max_lat) with positive area.")

        os.makedirs(output_folder, exist_ok=True)
        cache_dir = os.path.join(output_folder, "_earthaccess_cache")
        os.makedirs(cache_dir, exist_ok=True)
        granule_tif_dir = os.path.join(output_folder, "_granule_tifs")
        os.makedirs(granule_tif_dir, exist_ok=True)
        tile_mosaic_dir = os.path.join(output_folder, "_tile_mosaics")
        os.makedirs(tile_mosaic_dir, exist_ok=True)

        tmp_root = temp_dir or os.path.join(output_folder, "_tmp")
        os.makedirs(tmp_root, exist_ok=True)
        os.environ.setdefault("TEMP", tmp_root)
        os.environ.setdefault("TMP", tmp_root)
        os.environ.setdefault("TMPDIR", tmp_root)
        os.environ.setdefault("CPL_TMPDIR", tmp_root)
        os.environ.setdefault("GDAL_CACHEMAX", "256")
        tempfile.tempdir = tmp_root

        # ---------- Dask (used inside each tile only) ----------
        dask_client = None
        dask_cluster = None
        dashboard_url = None
        if use_dask:
            try:
                from dask.distributed import Client, LocalCluster
                if n_workers == "auto":
                    n_workers = max(1, (os.cpu_count() or 2) - 1)
                if threads_per_worker == "auto":
                    threads_per_worker = 1 if scheduler == "processes" else max(1, (os.cpu_count() or 2) // int(n_workers))
                dask_cluster = LocalCluster(
                    n_workers=int(n_workers),
                    threads_per_worker=int(threads_per_worker),
                    processes=(scheduler == "processes"),
                    silence_logs=logging.CRITICAL,
                )
                dask_client = Client(dask_cluster, set_as_default=True)
                dask_client.wait_for_workers(int(n_workers))
                dashboard_url = getattr(dask_client, "dashboard_link", None)
                if verbose:
                    print(f"⚙️  Dask ready: workers={n_workers}, threads/worker={threads_per_worker}, mode={scheduler}")
                    if dashboard_url:
                        print(f"📊 Dask dashboard: {dashboard_url}")
            except Exception as e:
                if verbose:
                    print(f"⚠️ Dask unavailable ({e}). Running serial.")
                use_dask = False
                dask_client = None
                dask_cluster = None

        # ---------- Bands and datasets ----------
        HKM_DATASETS = [
            ("EV_250_Aggr500_RefSB", {0: "B01", 1: "B02"}),
            ("EV_500_RefSB",         {0: "B03", 1: "B04", 2: "B05", 3: "B06", 4: "B07"}),
        ]
        ALL_BANDS = ["B01", "B02", "B03", "B04", "B05", "B06", "B07"]
        if isinstance(band_list, str) and band_list.lower() == "all":
            bands_wanted = set(ALL_BANDS)
        else:
            bands_wanted = set([str(b).upper() for b in band_list])
            unknown = bands_wanted - set(ALL_BANDS)
            if unknown:
                raise ValueError(f"Unknown bands requested: {sorted(unknown)}")

        # ---------- Login ----------
        if verbose:
            print("🔐 Logging into earthaccess (LAADS)...")
        try:
            if edl_username and edl_password:
                ea.login(strategy=(login_strategy or "interactive"), username=edl_username, password=edl_password, persist=True)
            elif login_strategy:
                ea.login(strategy=login_strategy, persist=True)
            else:
                ea.login(persist=True)
        except Exception as e:
            raise RuntimeError(f"earthaccess login failed: {e}")

        # ---------- Helpers ----------
        def _granule_name(granule) -> str:
            if isinstance(granule, str):
                return os.path.basename(granule)
            # UMM metadata
            try:
                umm = getattr(granule, "umm", None)
                if isinstance(umm, dict):
                    for k in ("GranuleUR", "GranuleID", "title"):
                        v = umm.get(k)
                        if isinstance(v, str) and v:
                            return v
            except Exception:
                pass
            # meta/metadata dicts
            for attr in ("meta", "metadata"):
                try:
                    md = getattr(granule, attr, None)
                    if isinstance(md, dict):
                        for k in ("granule_ur", "GranuleUR", "title"):
                            v = md.get(k)
                            if isinstance(v, str) and v:
                                return v
                except Exception:
                    pass
            # links (method or list)
            links = getattr(granule, "data_links", None) or getattr(granule, "links", None) or []
            try:
                if callable(links):
                    links = links()
            except Exception:
                links = []
            for url in links:
                if not url:
                    continue
                base = os.path.basename(str(url).split("?")[0])
                if base:
                    return base
            # assets dict
            try:
                assets = getattr(granule, "assets", None)
                if isinstance(assets, dict):
                    for a in assets.values():
                        href = a.get("href") if isinstance(a, dict) else None
                        if href:
                            base = os.path.basename(str(href).split("?")[0])
                            if base:
                                return base
            except Exception:
                pass
            return ""

        def token_Ayyyydoy_hhmm(name: str) -> str | None:
            m = re.search(r"\.A(\d{7})\.(\d{4})\.", name)
            return f"A{m.group(1)}.{m.group(2)}" if m else None

        def day_key_from_name(name: str) -> str:
            m = re.search(r"\.A(\d{4})(\d{3})\.\d{4}\.", name)
            if not m:
                # fallback YYYYMMDD somewhere in name
                m2 = re.search(r"(20\d{6})", name)
                if m2:
                    return m2.group(1)
                raise ValueError(f"Cannot parse day key from name: {name}")
            year, doy = int(m.group(1)), int(m.group(2))
            dt = datetime(year, 1, 1) + timedelta(days=doy - 1)
            return dt.strftime("%Y%m%d")

        def _day_key_from_any(granule, local_path: str | None):
            name = _granule_name(granule)
            if not name and local_path:
                name = os.path.basename(local_path)
            try:
                return day_key_from_name(name)
            except Exception:
                return None

        def _granule_token(name: str) -> str:
            m = re.search(r"\.A(\d{7})\.(\d{4})\.", name or "")
            if m:
                return f"A{m.group(1)}{m.group(2)}"
            base = os.path.splitext(os.path.basename(name or "gran"))[0]
            return re.sub(r"[^A-Za-z0-9]+", "", base)[-22:] or "gran"

        def _cached_local_path_for_granule(granule) -> str | None:
            links = getattr(granule, "data_links", None) or getattr(granule, "links", None) or []
            try:
                if callable(links):
                    links = links()
            except Exception:
                links = []
            for url in links:
                if not url:
                    continue
                base = os.path.basename(str(url).split("?")[0])
                if base:
                    fp = os.path.join(cache_dir, base)
                    if os.path.exists(fp):
                        return fp
            name = _granule_name(granule)
            if name:
                for cand in (name, f"{name}.hdf", f"{name}.HDF", f"{name}.h5", f"{name}.he5"):
                    fp = os.path.join(cache_dir, cand)
                    if os.path.exists(fp):
                        return fp
                try:
                    for f in os.listdir(cache_dir):
                        if f.startswith(os.path.splitext(name)[0]):
                            fp = os.path.join(cache_dir, f)
                            if os.path.isfile(fp):
                                return fp
                except Exception:
                    pass
            return None

        def open_granule_filelike(granule) -> str:
            cached = _cached_local_path_for_granule(granule)
            if cached:
                if verbose:
                    print(f"Using cached HDF: {os.path.basename(cached)}")
                return cached
            # Download to cache
            paths = ea.download([granule], provider="LAADS", local_path=cache_dir)
            if isinstance(paths, dict):
                local_path = next(iter(paths.values()), None)
                if isinstance(local_path, (list, tuple)):
                    local_path = local_path[0] if local_path else None
            elif isinstance(paths, (list, tuple)):
                local_path = paths[0] if paths else None
            else:
                local_path = paths
            if not local_path or (not os.path.exists(local_path)):
                raise RuntimeError("Download failed or returned no local path.")
            if verbose:
                print(f"Downloaded HDF: {os.path.basename(local_path)}")
            return local_path

        def read_latlon_from_mod03(geo_path: str):
            # try HDF5 (rare)
            if h5py is not None:
                try:
                    with h5py.File(geo_path, "r") as g:
                        # Common EOS5 paths (not always present)
                        for cand in [
                            "MODIS_Swath_Type_L1B/Geolocation Fields/Latitude",
                            "MODIS_Swath_Type_L1B/Geolocation Fields/Longitude",
                        ]:
                            pass
                except Exception:
                    pass
            # HDF4 via pyhdf
            try:
                from pyhdf.SD import SD, SDC
            except Exception as e:
                raise RuntimeError("pyhdf is required to read MOD03 (HDF4). conda install -c conda-forge pyhdf") from e
            sd = SD(geo_path, SDC.READ)
            try:
                lat = sd.select("Latitude")[:]
                lon = sd.select("Longitude")[:]
                return np.array(lat, dtype=np.float32), np.array(lon, dtype=np.float32)
            finally:
                sd.end()

        def read_toa_from_mod02hkm(l1b_path: str) -> dict[str, np.ndarray]:
            out: dict[str, np.ndarray] = {}
            try:
                from pyhdf.SD import SD, SDC
            except Exception as e:
                raise RuntimeError("pyhdf is required to read MOD02HKM (HDF4). conda install -c conda-forge pyhdf") from e

            def _attr_value(attrs, key):
                try:
                    return attrs.get(key, (None,))[0]
                except Exception:
                    return None

            def _as_scalar(v, idx, default_scalar):
                if v is None:
                    return float(default_scalar)
                if isinstance(v, (list, tuple, np.ndarray)):
                    try:
                        return float(v[idx])
                    except Exception:
                        try:
                            return float(v[0])
                        except Exception:
                            return float(default_scalar)
                try:
                    return float(v)
                except Exception:
                    return float(default_scalar)

            sd = SD(l1b_path, SDC.READ)
            try:
                for dset_name, band_map in HKM_DATASETS:
                    if dset_name not in sd.datasets():
                        continue
                    ds = sd.select(dset_name)
                    data = ds[:]  # (bands, lines, samples)
                    attrs = ds.attributes(full=1)

                    scale_raw = (
                        _attr_value(attrs, "scale_factor")
                        or _attr_value(attrs, "reflectance_scales")
                        or _attr_value(attrs, "radiance_scales")
                        or 1.0
                    )
                    offset_raw = (
                        _attr_value(attrs, "add_offset")
                        or _attr_value(attrs, "reflectance_offsets")
                        or _attr_value(attrs, "radiance_offsets")
                        or 0.0
                    )
                    fill_raw = _attr_value(attrs, "_FillValue")

                    if data.ndim != 3:
                        continue

                    for bi, bname in band_map.items():
                        if bi >= data.shape[0]:
                            continue
                        scale_i = _as_scalar(scale_raw, bi, 1.0)
                        offset_i = _as_scalar(offset_raw, bi, 0.0)
                        arr = data[bi].astype(np.float32, copy=False)
                        if fill_raw is not None:
                            try:
                                fill_i = _as_scalar(fill_raw, bi, np.nan)
                                if np.isfinite(fill_i):
                                    mask = arr == fill_i
                                    if np.any(mask):
                                        arr[mask] = np.nan
                            except Exception:
                                pass
                        if scale_i != 1.0 or offset_i != 0.0:
                            arr = arr * scale_i + offset_i
                        out[bname] = arr
            finally:
                sd.end()
            return out

        def _align_geo_to_band(lat, lon, band_arr: np.ndarray):
            lat = np.array(lat, dtype=np.float32, copy=False)
            lon = np.array(lon, dtype=np.float32, copy=False)
            lon = np.where(lon > 180.0, lon - 360.0, lon)
            lat = np.clip(lat, -90.0, 90.0)
            bl, bs = int(band_arr.shape[-2]), int(band_arr.shape[-1])
            gl, gs = int(lat.shape[-2]), int(lat.shape[-1])
            if (gl, gs) == (bs, bl):
                lat, lon = lat.T, lon.T
                gl, gs = lat.shape
            if (gl, gs) != (bl, bs):
                rl = bl // gl if gl and (bl % gl == 0) else 1
                rs = bs // gs if gs and (bs % gs == 0) else 1
                if rl == rs and rl in (2,):
                    lat = np.repeat(np.repeat(lat, rl, axis=0), rl, axis=1)
                    lon = np.repeat(np.repeat(lon, rl, axis=0), rl, axis=1)
                    gl, gs = lat.shape
            if (gl, gs) != (bl, bs):
                raise ValueError(f"Geolocation/band shape mismatch: latlon={gl}x{gs} vs band={bl}x{bs}")
            return lat, lon

        def swath_to_grid(band_arr, lat_, lon_, area_def_, radius_):
            # memory-friendly resampling: flatten valid samples
            lat_a, lon_a = _align_geo_to_band(lat_, lon_, band_arr)
            vals = band_arr.astype(np.float32, copy=False).ravel()
            lats = lat_a.ravel()
            lons = lon_a.ravel()
            valid = np.isfinite(vals)
            if not np.any(valid):
                return np.full((area_def_.shape[0], area_def_.shape[1]), np.nan, dtype=np.float32)
            vals = vals[valid]
            lats = lats[valid]
            lons = lons[valid]
            swath_def = geometry.SwathDefinition(lons=lons, lats=lats)
            with warnings.catch_warnings():
                warnings.simplefilter("ignore", category=RuntimeWarning)
                grid = kd_tree.resample_nearest(
                    swath_def,
                    vals,
                    area_def_,
                    radius_of_influence=radius_,
                    fill_value=np.nan,
                    nprocs=1,
                    reduce_data=True,
                )
            return grid.astype(np.float32, copy=False)

        def write_single_band_tif(path, arr, transform, width, height):
            profile = {
                "driver": "GTiff",
                "height": int(height),
                "width": int(width),
                "count": 1,
                "dtype": "float32",
                "crs": "EPSG:4326",
                "transform": transform,
                "compress": "deflate",
                "predictor": 2,
                "tiled": True,
                "blockxsize": 256,
                "blockysize": 256,
                "nodata": np.float32(np.nan),
            }
            os.makedirs(os.path.dirname(path) or ".", exist_ok=True)
            with rasterio.open(path, "w", **profile) as dst:
                dst.write(arr, 1)

        def make_target_grid(bbox, res_deg_):
            x0, y0, x1, y1 = bbox
            width = int(math.ceil((x1 - x0) / res_deg_))
            height = int(math.ceil((y1 - y0) / res_deg_))
            transform = from_origin(x0, y1, res_deg_, res_deg_)
            area_def = geometry.AreaDefinition(
                "roi_ll",
                "regular latlon grid",
                "epsg4326",
                {"proj": "longlat", "datum": "WGS84"},
                width,
                height,
                [x0, y0, x1, y1],
            )
            return area_def, transform, width, height

        def _normalize_split(n) -> tuple[int, int]:
            if isinstance(n, (list, tuple)) and len(n) == 2:
                return max(1, int(n[0])), max(1, int(n[1]))
            n = max(1, int(n))
            return n, n

        def _split_bbox(bbox: tuple[float, float, float, float], ny: int, nx: int):
            x0, y0, x1, y1 = bbox
            dx = (x1 - x0) / nx
            dy = (y1 - y0) / ny
            tiles = []
            for iy in range(ny):
                ty0 = y0 + iy * dy
                ty1 = ty0 + dy
                for ix in range(nx):
                    tx0 = x0 + ix * dx
                    tx1 = tx0 + dx
                    tiles.append((tx0, ty0, tx1, ty1))
            return tiles

        def search(product, start_dt, end_dt, bbox):
            return ea.search_data(
                short_name=product,
                temporal=(start_dt, end_dt),
                bounding_box=bbox,
                provider="LAADS",
                granule_name="*.hdf",
            )

        def pair_l1b_with_geo(l1b_list, geo_list):
            geo_by_token = {}
            for g in geo_list:
                name = _granule_name(g)
                tok = token_Ayyyydoy_hhmm(name) or ""
                if tok:
                    geo_by_token[tok] = g
            pairs = []
            for sw in l1b_list:
                name = _granule_name(sw)
                tok = token_Ayyyydoy_hhmm(name) or ""
                if tok and tok in geo_by_token:
                    pairs.append((sw, geo_by_token[tok]))
            return pairs

        # ---------- Search ----------
        start_dt = datetime.strptime(start_date, "%Y-%m-%d")
        end_dt = datetime.strptime(end_date, "%Y-%m-%d")
        l1b, geo = [], []
        use_terra = platform.lower() in ("terra", "both")
        use_aqua = platform.lower() in ("aqua", "both")
        if use_terra:
            l1b += search("MOD02HKM", start_dt, end_dt, (minx, miny, maxx, maxy))
            geo += search("MOD03", start_dt, end_dt, (minx, miny, maxx, maxy))
        if use_aqua:
            l1b += search("MYD02HKM", start_dt, end_dt, (minx, miny, maxx, maxy))
            geo += search("MYD03", start_dt, end_dt, (minx, miny, maxx, maxy))

        pairs = pair_l1b_with_geo(l1b, geo)
        if not pairs:
            if verbose:
                print("No matching MODIS L1B/MOD03 pairs found for the criteria.")
            if dask_client:
                try:
                    dask_client.close()
                    if dask_cluster:
                        dask_cluster.close()
                except Exception:
                    pass
            return {"processed_pairs": 0, "written": 0, "days": 0, "paths": [], "dashboard": dashboard_url}

        # ---------- Skip days that already exist ----------
        if not overwrite:
            def _pair_day_key(p):
                sw_g, _ = p
                try:
                    return day_key_from_name(_granule_name(sw_g))
                except Exception:
                    return None
            day_keys = set(filter(None, (_pair_day_key(p) for p in pairs)))
            skip_days = set()
            for d in day_keys:
                all_exist = all(os.path.exists(os.path.join(output_folder, f"{filename_prefix}_{b}_{d}.tif"))
                                for b in (ALL_BANDS if bands_wanted == set(ALL_BANDS) else bands_wanted))
                if all_exist:
                    skip_days.add(d)
                    if verbose:
                        dtf = datetime.strptime(d, "%Y%m%d").strftime("%Y-%m-%d")
                        print(f"Skipping data for day {dtf} (all outputs already exist).")
            if skip_days:
                pairs = [p for p in pairs if _pair_day_key(p) not in skip_days]
                if not pairs:
                    if verbose:
                        print("All days skipped (existing outputs). Nothing to process.")
                    if dask_client:
                        try:
                            dask_client.close()
                            if dask_cluster:
                                dask_cluster.close()
                        except Exception:
                            pass
                    return {"processed_pairs": 0, "written": 0, "days": 0, "paths": [], "dashboard": dashboard_url}

        # ---------- Per-tile processing ----------
        ny, nx = _normalize_split(n_roi_split)
        tile_bboxes = _split_bbox((minx, miny, maxx, maxy), ny, nx)

        def _process_pair_tile(sw_g, geo_g, area_def_t, transform_t, width_t, height_t, tile_tag: str):
            res = []
            sw_path = None
            geo_path = None
            try:
                sw_path = open_granule_filelike(sw_g)
                geo_path = open_granule_filelike(geo_g)
                sw_name = _granule_name(sw_g) or os.path.basename(sw_path)
                day_key = _day_key_from_any(sw_g, sw_path) or "unknown"

                if day_key != "unknown" and (not overwrite):
                    all_exist = all(os.path.exists(os.path.join(output_folder, f"{filename_prefix}_{b}_{day_key}.tif"))
                                    for b in bands_wanted)
                    if all_exist:
                        return []

                lat, lon = read_latlon_from_mod03(geo_path)
                bands = read_toa_from_mod02hkm(sw_path)
                if not bands:
                    return []

                gtok = _granule_token(sw_name)
                for bname, arr in bands.items():
                    if bname not in bands_wanted:
                        continue
                    if arr is None or not np.isfinite(arr).any():
                        continue
                    grid = swath_to_grid(arr, lat, lon, area_def_t, radius_m)
                    tif_path = os.path.join(
                        granule_tif_dir,
                        f"{filename_prefix}_{bname}_{day_key}_{gtok}_tile{tile_tag}.tif"
                    )
                    write_single_band_tif(tif_path, grid, transform_t, width_t, height_t)
                    res.append(("tif", day_key, bname, tif_path, tile_tag))
                return res
            except Exception as e:
                if verbose:
                    dbg = os.path.basename(sw_path) if sw_path else _granule_name(sw_g)
                    print(f"❌ Failed processing {dbg} [tile {tile_tag}]: {e}")
                return []

        final_tile_mosaics = defaultdict(list)  # (day, band) -> [tile mosaic paths]

        for tile_idx, bbox_t in enumerate(tile_bboxes):
            area_def_t, transform_t, width_t, height_t = make_target_grid(bbox_t, res_deg)
            ty, tx = divmod(tile_idx, nx)
            tile_tag = f"{ty}x{tx}"
            if verbose:
                print(f"🧩 Tile {tile_tag} bbox={bbox_t} grid=({height_t},{width_t})")

            # Schedule tasks for this tile
            results_t = []
            if use_dask and dask_client:
                from dask import delayed
                tasks = [delayed(_process_pair_tile)(sw_g, geo_g, area_def_t, transform_t, width_t, height_t, tile_tag)
                        for (sw_g, geo_g) in pairs]
                futures = dask_client.compute(tasks)
                try:
                    results_t = dask_client.gather(futures)
                finally:
                    try:
                        dask_client.cancel(futures)
                    except Exception:
                        pass
            else:
                for sw_g, geo_g in pairs:
                    results_t.append(_process_pair_tile(sw_g, geo_g, area_def_t, transform_t, width_t, height_t, tile_tag))

            # Group per day+band and mosaic this tile across granules
            per_tile_groups = defaultdict(list)  # (day, band) -> [granule tile tif]
            for lst in results_t:
                for rec in lst:
                    if not rec:
                        continue
                    kind, day_key, bname, tif_path, _ = rec
                    if kind == "tif" and day_key != "unknown":
                        per_tile_groups[(day_key, bname)].append(tif_path)

            for (day_key, bname), tif_list in sorted(per_tile_groups.items()):
                if not tif_list:
                    continue
                tile_out = os.path.join(tile_mosaic_dir, f"{filename_prefix}_{bname}_{day_key}_tile{tile_tag}.tif")
                if (not overwrite) and os.path.exists(tile_out):
                    final_tile_mosaics[(day_key, bname)].append(tile_out)
                    continue
                try:
                    srcs = [rasterio.open(p) for p in tif_list]
                    mosaic, out_transform = rio_merge(srcs, method="first")
                    for s in srcs:
                        s.close()
                    if mosaic.ndim == 3 and mosaic.shape[0] == 1:
                        mosaic = mosaic[0]
                    write_single_band_tif(tile_out, mosaic.astype(np.float32, copy=False), out_transform,
                                        mosaic.shape[1], mosaic.shape[0])
                    final_tile_mosaics[(day_key, bname)].append(tile_out)
                except Exception as me:
                    if verbose:
                        print(f"❌ Tile mosaic failed for {bname} {day_key} [tile {tile_tag}]: {me}")

        # ---------- Final mosaic over all tiles ----------
        written_paths = []
        days = set()
        for (day_key, bname), tile_paths in sorted(final_tile_mosaics.items()):
            if not tile_paths:
                continue
            out_fp = os.path.join(output_folder, f"{filename_prefix}_{bname}_{day_key}.tif")
            if (not overwrite) and os.path.exists(out_fp):
                continue
            try:
                srcs = [rasterio.open(p) for p in tile_paths]
                mosaic, out_transform = rio_merge(srcs, method="first")
                for s in srcs:
                    s.close()
                if mosaic.ndim == 3 and mosaic.shape[0] == 1:
                    mosaic = mosaic[0]
                write_single_band_tif(out_fp, mosaic.astype(np.float32, copy=False), out_transform,
                                    mosaic.shape[1], mosaic.shape[0])
                written_paths.append(out_fp)
                days.add(day_key)
            except Exception as me:
                if verbose:
                    print(f"❌ Final mosaic failed for {bname} {day_key}: {me}")

        if verbose:
            print(f"✅ MODIS TOA complete. Tiles={ny}x{nx} Pairs={len(pairs)} Days={len(days)} Written={len(written_paths)}")

        if dask_client:
            try:
                dask_client.close()
                if dask_cluster:
                    dask_cluster.close()
            except Exception:
                pass

        return {
            "processed_pairs": len(pairs),
            "written": len(written_paths),
            "days": len(days),
            "paths": written_paths,
            "dashboard": dashboard_url,
        }
    
    
    def download_modis_toa_v2(
        self,
        band_list: list[str] | str,
        output_folder: str,
        roi: tuple[float, float, float, float],
        start_date: str,
        end_date: str,
        *,
        platform: str = "terra",         # "terra" | "aqua" | "both"
        res_deg: float = 0.0045,         # ~500 m @ equator
        radius_m: int = 4000,            # swath->grid nearest-neighbor radius (m)
        filename_prefix: str = "modis_toa",
        overwrite: bool = False,
        verbose: bool = True,
        edl_username: str | None = None,
        edl_password: str | None = None,
        login_strategy: str | None = None,
        temp_dir: str | None = None,
        # NEW: parallel & performance knobs
        use_dask: bool = True,
        n_workers: int | str = "auto",
        threads_per_worker: int | str = "auto",
        scheduler: str = "processes",    # "processes" strongly recommended with h5py
        chunk_write: bool = False        # keep False; TIFF writing is sequential by default
    ) -> dict:
        """
        Download MODIS L1B TOA reflectance (HKM, 500m) and write one GeoTIFF per band per day.

        - Parallelizes swath->grid projection with Dask (per-pair) to speed up processing.
        - Uses processes by default (h5py is not thread-safe).
        - Reuses your earthaccess cache and temp throttling.
        """
        from collections import defaultdict
        from datetime import datetime, timedelta

        try:
            import earthaccess as ea
        except Exception as e:
            raise RuntimeError("earthaccess is required. pip install earthaccess") from e

        try:
            import h5py
            import numpy as np
            import rasterio
            from rasterio.transform import from_origin
            from pyresample import geometry, kd_tree
            import math, os, re, warnings, tempfile
        except Exception as e:
            raise RuntimeError("Dependencies missing. pip install rasterio pyresample h5py numpy") from e
        
        
        minx, miny, maxx, maxy = float(roi[0]), float(roi[1]), float(roi[2]), float(roi[3])

        # Optional Dask
        dask_client = None
        dask_cluster = None
        dashboard_url = None
        if use_dask:
            try:
                from dask.distributed import Client, LocalCluster
                import logging, os
                # autos
                if n_workers == "auto":
                    n_workers = max(1, (os.cpu_count() or 2) - 1)
                if threads_per_worker == "auto":
                    threads_per_worker = 1 if scheduler == "processes" else max(1, (os.cpu_count() or 2) // int(n_workers))
                # start a quiet LocalCluster
                dask_cluster = LocalCluster(
                    n_workers=int(n_workers),
                    threads_per_worker=int(threads_per_worker),
                    processes=(scheduler == "processes"),
                    silence_logs=logging.CRITICAL
                )
                dask_client = Client(dask_cluster, set_as_default=True)
                dask_client.wait_for_workers(int(n_workers))
                dashboard_url = getattr(dask_client, "dashboard_link", None)
                if verbose:
                    print(f"⚙️  Dask up: workers={n_workers}, threads/worker={threads_per_worker}, mode={scheduler}")
                    if dashboard_url:
                        print(f"📊 Dask dashboard: {dashboard_url}")
            except Exception as e:
                if verbose:
                    print(f"⚠️ Dask unavailable ({e}). Falling back to serial.")
                use_dask = False
                dask_client = None
                dask_cluster = None

        # Constants for HKM TOA datasets
        HKM_DATASETS = [
            ("EV_250_Aggr500_RefSB", {0: "B01", 1: "B02"}),
            ("EV_500_RefSB",         {0: "B03", 1: "B04", 2: "B05", 3: "B06", 4: "B07"}),
        ]
        ALL_BANDS = ["B01", "B02", "B03", "B04", "B05", "B06", "B07"]

        # Normalize bands
        if isinstance(band_list, str) and band_list.lower() == "all":
            bands_wanted = set(ALL_BANDS)
        else:
            bands_wanted = set([str(b).upper() for b in band_list])
            unknown = bands_wanted - set(ALL_BANDS)
            if unknown:
                raise ValueError(f"Unknown bands requested: {sorted(unknown)}")

        # Validate ROI
        if not (isinstance(roi, (list, tuple)) and len(roi) == 4):
            raise ValueError("roi must be (min_lon, min_lat, max_lon, max_lat)")
        minx, miny, maxx, maxy = float(roi[0]), float(roi[1]), float(roi[2]), float(roi[3])

        # Output dirs
        os.makedirs(output_folder, exist_ok=True)
        cache_dir = os.path.join(output_folder, "_earthaccess_cache")
        os.makedirs(cache_dir, exist_ok=True)
        granule_tif_dir = os.path.join(output_folder, "_granule_tifs")  # NEW: per-granule TIFF cache
        os.makedirs(granule_tif_dir, exist_ok=True)

        tmp_root = temp_dir or os.path.join(output_folder, "_tmp")
        os.makedirs(tmp_root, exist_ok=True)
        # Temp envs for Windows/GDAL friendliness
        os.environ.setdefault("TEMP", tmp_root)
        os.environ.setdefault("TMP", tmp_root)
        os.environ.setdefault("TMPDIR", tmp_root)
        os.environ.setdefault("CPL_TMPDIR", tmp_root)
        os.environ.setdefault("GDAL_CACHEMAX", "256")
        tempfile.tempdir = tmp_root

        # Login to Earthdata
        if verbose:
            print("🔐 Logging into earthaccess (LAADS)...")
        try:
            if edl_username and edl_password:
                ea.login(strategy=(login_strategy or "interactive"), username=edl_username, password=edl_password, persist=True)
            elif login_strategy:
                ea.login(strategy=login_strategy, persist=True)
            else:
                ea.login(persist=True)
        except Exception as e:
            raise RuntimeError(f"earthaccess login failed: {e}")

        # Helpers (same as before; kept defined inside for Dask pickling)
        def _granule_name(granule) -> str:
            """
            Robustly extract a display/name from earthaccess DataGranule across versions.
            Also accepts a plain string path (cached local file) and returns its basename.
            """
            # direct path fallback
            if isinstance(granule, str):
                return os.path.basename(granule)

            # 1) UMM metadata
            try:
                umm = getattr(granule, "umm", None)
                if isinstance(umm, dict):
                    for k in ("GranuleUR", "title"):
                        v = umm.get(k)
                        if isinstance(v, str) and v:
                            return v
            except Exception:
                pass

            # 2) meta/metadata dicts
            for attr in ("meta", "metadata"):
                try:
                    md = getattr(granule, attr, None)
                    if isinstance(md, dict):
                        v = md.get("granule_ur") or md.get("GranuleUR") or md.get("title")
                        if isinstance(v, str) and v:
                            return v
                except Exception:
                    pass

            # 3) links/data_links (method or list)
            links = getattr(granule, "data_links", None) or getattr(granule, "links", None) or []
            try:
                if callable(links):
                    links = links()
            except Exception:
                links = []
            for url in links:
                if not url:
                    continue
                base = os.path.basename(str(url).split("?")[0])
                if base:
                    return base

            # 4) assets dict (href)
            try:
                assets = getattr(granule, "assets", None)
                if isinstance(assets, dict):
                    for a in assets.values():
                        href = a.get("href") if isinstance(a, dict) else None
                        if href:
                            base = os.path.basename(str(href).split("?")[0])
                            if base:
                                return base
            except Exception:
                pass

            return ""
        
        def token_Ayyyydoy_hhmm(name: str) -> str | None:
            m = re.search(r"\.A(\d{7}\.\d{4})\.", name)
            return m.group(1) if m else None

        
        
        def day_key_from_name(name: str) -> str:
            m = re.search(r"\.A(\d{4})(\d{3})\.\d{4}\.", name)
            if not m:
                raise ValueError(f"Could not parse date from granule name: {name}")
            year, doy = int(m.group(1)), int(m.group(2))
            dt = datetime(year, 1, 1) + timedelta(days=doy - 1)
            return dt.strftime("%Y%m%d")
        
        def _day_key_from_any(sw_granule, sw_local_path: str | None):
            """
            Get YYYYMMDD from the granule name; fallback to local filename if needed.
            """
            name = _granule_name(sw_granule)
            if not name and sw_local_path:
                name = os.path.basename(sw_local_path)
            try:
                return day_key_from_name(name)
            except Exception:
                return None
        
        def make_target_grid(bbox, res_deg_):
            x0, y0, x1, y1 = bbox
            width = int(math.ceil((x1 - x0) / res_deg_))
            height = int(math.ceil((y1 - y0) / res_deg_))
            transform = from_origin(x0, y1, res_deg_, res_deg_)
            area_def = geometry.AreaDefinition(
                "roi_ll",
                "regular latlon grid",
                "epsg4326",
                {"proj": "longlat", "datum": "WGS84"},
                width,
                height,
                [x0, y0, x1, y1],
            )
            return area_def, transform, width, height

        def search(product, start_dt, end_dt, bbox):
            return ea.search_data(
                short_name=product,
                temporal=(start_dt, end_dt),
                bounding_box=bbox,
                provider="LAADS",
                granule_name="*.hdf",
            )

        def pair_l1b_with_geo(l1b_list, geo_list):
            geo_by_token = {}
            for g in geo_list:
                name = _granule_name(g)
                tok = token_Ayyyydoy_hhmm(name) or ""
                if tok:
                    geo_by_token[tok] = g
            pairs = []
            for sw in l1b_list:
                name = _granule_name(sw)
                tok = token_Ayyyydoy_hhmm(name) or ""
                if tok and tok in geo_by_token:
                    pairs.append((sw, geo_by_token[tok]))
            return pairs

        def _cached_local_path_for_granule(granule) -> str | None:
            """
            Return local HDF path if already in cache_dir, else None.
            """
            # 1) Exact filename from data links
            links = getattr(granule, "data_links", None) or getattr(granule, "links", None) or []
            try:
                if callable(links):
                    links = links()
            except Exception:
                links = []
            for url in links:
                if not url:
                    continue
                base = os.path.basename(str(url).split("?")[0])
                if base:
                    fp = os.path.join(cache_dir, base)
                    if os.path.exists(fp):
                        return fp
            # 2) Fallback via derived name
            name = _granule_name(granule)
            if name:
                candidates = [name, f"{name}.hdf", f"{name}.HDF", f"{name}.h5", f"{name}.he5"]
                for cand in candidates:
                    fp = os.path.join(cache_dir, cand)
                    if os.path.exists(fp):
                        return fp
                # prefix match
                try:
                    for f in os.listdir(cache_dir):
                        if f.startswith(name):
                            fp = os.path.join(cache_dir, f)
                            if os.path.isfile(fp):
                                return fp
                except Exception:
                    pass
            return None
        
        
        def date_from_Ayyyydoy(s: str) -> datetime:
            m = re.search(r"A(\d{4})(\d{3})", s)
            if not m:
                raise ValueError(f"Cannot parse token: {s}")
            year, doy = int(m.group(1)), int(m.group(2))
            return datetime(year, 1, 1) + timedelta(days=doy - 1)
        
        
        def open_granule_filelike(granule) -> str:
            """
            Return local path to granule. If present in cache, reuse it (no download).
            """
            cached = _cached_local_path_for_granule(granule)
            if cached:
                if verbose:
                    print(f"Using cached HDF: {os.path.basename(cached)}")
                return cached
            # Download only if not cached
            paths = ea.download([granule], provider="LAADS", local_path=cache_dir)
            if isinstance(paths, dict):
                local_path = next(iter(paths.values()), None)
                if isinstance(local_path, (list, tuple)):
                    local_path = local_path[0] if local_path else None
            elif isinstance(paths, (list, tuple)):
                local_path = paths[0] if paths else None
            else:
                local_path = paths
            if not local_path or (not os.path.exists(local_path)):
                raise RuntimeError("Download failed or returned no local path.")
            if verbose:
                print(f"Downloaded HDF: {os.path.basename(local_path)}")
            return local_path
        
        
        def read_latlon_from_mod03(geo_path: str):
            """
            Read Latitude/Longitude arrays from MOD03/MYD03 geolocation granule.
            Tries HDF5 first, then HDF4 (pyhdf).
            """
            # HDF5 (rare for these)
            try:
                import h5py
                with h5py.File(geo_path, "r") as f:
                    # common HDF5 keys if converted
                    for cand in ("/Geolocation/Latitude", "/Geolocation/Longitude"):
                        pass
                # fallthrough to HDF4 if not present
            except Exception:
                pass

            # HDF4 via pyhdf (most LAADS .hdf)
            try:
                from pyhdf.SD import SD, SDC  # ensure dependency present
            except Exception as e:
                raise RuntimeError(f"pyhdf is required to read {os.path.basename(geo_path)} (HDF4): {e}") from e

            sd = SD(geo_path, SDC.READ)
            try:
                lat = sd.select("Latitude")[:]
                lon = sd.select("Longitude")[:]
                return np.array(lat, dtype=np.float32), np.array(lon, dtype=np.float32)
            finally:
                sd.end()

        def read_toa_from_mod02hkm(l1b_path: str) -> dict[str, np.ndarray]:
            """
            Read TOA reflectance per band from MOD02HKM/MYD02HKM (HDF4).
            Returns dict {"B01": 2D, ...}; applies scale/offset; NaN for fills.
            """
            out: dict[str, np.ndarray] = {}
            try:
                from pyhdf.SD import SD, SDC
            except Exception as e:
                raise RuntimeError(f"pyhdf is required to read {os.path.basename(l1b_path)} (HDF4): {e}") from e

            def _attr_value(attrs, key):
                try:
                    return attrs.get(key, (None,))[0]
                except Exception:
                    return None

            def _as_scalar(v, idx, default_scalar):
                if v is None:
                    return float(default_scalar)
                if isinstance(v, (list, tuple, np.ndarray)):
                    try:
                        return float(v[idx])
                    except Exception:
                        try:
                            return float(v[0])
                        except Exception:
                            return float(default_scalar)
                try:
                    return float(v)
                except Exception:
                    return float(default_scalar)

            sd = SD(l1b_path, SDC.READ)
            try:
                for dset_name, band_map in HKM_DATASETS:
                    if dset_name not in sd.datasets():
                        continue
                    ds = sd.select(dset_name)
                    data = ds[:]  # (bands, lines, samples)
                    attrs = ds.attributes(full=1)

                    scale_raw = (
                        _attr_value(attrs, "scale_factor")
                        or _attr_value(attrs, "reflectance_scales")
                        or _attr_value(attrs, "radiance_scales")
                        or 1.0
                    )
                    offset_raw = (
                        _attr_value(attrs, "add_offset")
                        or _attr_value(attrs, "reflectance_offsets")
                        or _attr_value(attrs, "radiance_offsets")
                        or 0.0
                    )
                    fill_raw = _attr_value(attrs, "_FillValue")

                    if data.ndim != 3:
                        continue

                    for bi, bname in band_map.items():
                        if bi >= data.shape[0]:
                            continue
                        scale_i = _as_scalar(scale_raw, bi, 1.0)
                        offset_i = _as_scalar(offset_raw, bi, 0.0)
                        # read band slice and convert to float32
                        arr = data[bi].astype(np.float32, copy=False)
                        # apply fill without building huge temporaries
                        if fill_raw is not None:
                            try:
                                fill_i = _as_scalar(fill_raw, bi, np.nan)
                                if np.isfinite(fill_i):
                                    # in-place replace using masked iteration to avoid extra copies
                                    mask = arr == fill_i
                                    if np.any(mask):
                                        arr[mask] = np.nan
                            except Exception:
                                pass
                        # scale/offset
                        if scale_i != 1.0 or offset_i != 0.0:
                            arr = arr * scale_i + offset_i
                        out[bname] = arr
            finally:
                sd.end()
            return out
        
        
        
        def _align_geo_to_band(lat, lon, band_arr: np.ndarray):
            lat = np.array(lat, dtype=np.float32, copy=False)
            lon = np.array(lon, dtype=np.float32, copy=False)
            lon = np.where(lon > 180.0, lon - 360.0, lon)
            lat = np.clip(lat, -90.0, 90.0)
            bl, bs = int(band_arr.shape[-2]), int(band_arr.shape[-1])
            gl, gs = int(lat.shape[-2]), int(lat.shape[-1])
            # handle transposed geolocation
            if (gl, gs) == (bs, bl):
                lat, lon = lat.T, lon.T
                gl, gs = lat.shape
            # upsample 1km geolocation to 500m if clean integer ratio (2x)
            if (gl, gs) != (bl, bs):
                rl = bl // gl if gl and (bl % gl == 0) else 1
                rs = bs // gs if gs and (bs % gs == 0) else 1
                if rl == rs and rl in (2,):
                    lat = np.repeat(np.repeat(lat, rl, axis=0), rl, axis=1)
                    lon = np.repeat(np.repeat(lon, rl, axis=0), rl, axis=1)
                    gl, gs = lat.shape
            if (gl, gs) != (bl, bs):
                raise ValueError(f"Geolocation/band shape mismatch: latlon={gl}x{gs} vs band={bl}x{bs}")
            return lat, lon
        
        
        def _subset_swath_to_roi(lat_a: np.ndarray, lon_a: np.ndarray, band_a: np.ndarray):
            """
            Return lat/lon/band sliced to a small ROI bbox to reduce memory.
            Uses a coarse downsampled mask to find row/col bounds, then crops.
            """
            h, w = band_a.shape
            # choose sampling step to cap sampled grid to ~1M cells
            target_cells = 1_000_000
            step = max(1, int(np.sqrt((h * w) / target_cells)))
            lat_s = lat_a[::step, ::step]
            lon_s = lon_a[::step, ::step]
            m_s = (lat_s >= (miny - 0.2)) & (lat_s <= (maxy + 0.2)) & (lon_s >= (minx - 0.2)) & (lon_s <= (maxx + 0.2))
            if not np.any(m_s):
                # nothing overlaps; return None to signal skip
                return None
            rows_s = np.where(m_s.any(axis=1))[0]
            cols_s = np.where(m_s.any(axis=0))[0]
            r0 = max(0, rows_s[0] * step - 2 * step)
            r1 = min(h, (rows_s[-1] + 1) * step + 2 * step)
            c0 = max(0, cols_s[0] * step - 2 * step)
            c1 = min(w, (cols_s[-1] + 1) * step + 2 * step)
            return (lat_a[r0:r1, c0:c1], lon_a[r0:r1, c0:c1], band_a[r0:r1, c0:c1])

        def swath_to_grid(band_arr, lat_, lon_, area_def_, radius_):
            # align geolocation and optionally subset to ROI to keep arrays small
            lat_a, lon_a = _align_geo_to_band(lat_, lon_, band_arr)
            subset = _subset_swath_to_roi(lat_a, lon_a, band_arr)
            if subset is None:
                # no overlap with ROI; return all-NaN tile
                return np.full((area_def_.shape[0], area_def_.shape[1]), np.nan, dtype=np.float32)
            lat_c, lon_c, val_c = subset

            # flatten to 1D to reduce KD-tree memory, and drop NaNs early
            vals = val_c.astype(np.float32, copy=False).ravel()
            lats = lat_c.ravel()
            lons = lon_c.ravel()
            valid = np.isfinite(vals)
            if not np.any(valid):
                return np.full((area_def_.shape[0], area_def_.shape[1]), np.nan, dtype=np.float32)
            vals = vals[valid]
            lats = lats[valid]
            lons = lons[valid]

            swath_def = geometry.SwathDefinition(lons=lons, lats=lats)
            with warnings.catch_warnings():
                warnings.simplefilter("ignore", category=RuntimeWarning)
                grid = kd_tree.resample_nearest(
                    swath_def,
                    vals,
                    area_def_,
                    radius_of_influence=radius_,
                    fill_value=np.nan,
                    nprocs=1,
                    reduce_data=True,   # memory-friendly
                )
            return grid.astype(np.float32, copy=False)

        def write_single_band_tif(path, arr, transform, width, height):
            profile = {
                "driver": "GTiff",
                "height": height,
                "width": width,
                "count": 1,
                "dtype": "float32",
                "crs": "EPSG:4326",
                "transform": transform,
                "compress": "deflate",
                "predictor": 2,
                "tiled": True,
                "blockxsize": 256,
                "blockysize": 256,
                "nodata": np.float32(np.nan),
            }
            os.makedirs(os.path.dirname(path) or ".", exist_ok=True)
            with rasterio.open(path, "w", **profile) as dst:
                dst.write(arr, 1)

        # Target grid
        area_def, transform, width, height = make_target_grid((minx, miny, maxx, maxy), res_deg)

        start_dt = datetime.strptime(start_date, "%Y-%m-%d")
        end_dt = datetime.strptime(end_date, "%Y-%m-%d")

        # Search
        l1b, geo = [], []
        use_terra = platform.lower() in ("terra", "both")
        use_aqua = platform.lower() in ("aqua", "both")

        if use_terra:
            l1b += search("MOD02HKM", start_dt, end_dt, (minx, miny, maxx, maxy))
            geo += search("MOD03", start_dt, end_dt, (minx, miny, maxx, maxy))
        if use_aqua:
            l1b += search("MYD02HKM", start_dt, end_dt, (minx, miny, maxx, maxy))
            geo += search("MYD03", start_dt, end_dt, (minx, miny, maxx, maxy))

        pairs = pair_l1b_with_geo(l1b, geo)
        if not pairs:
            if verbose:
                print("No matching MODIS L1B/MOD03 pairs found for the criteria.")
            if dask_client:
                try:
                    dask_client.close()
                    if dask_cluster:
                        dask_cluster.close()
                except Exception:
                    pass
            return {"processed_pairs": 0, "written": 0, "days": 0, "paths": [], "dashboard": dashboard_url}

        # Skip whole days if all requested outputs already exist (avoid any download)
        if not overwrite:
            def _pair_day_key(p):
                sw_g, _ = p
                try:
                    return day_key_from_name(_granule_name(sw_g))
                except Exception:
                    return None

            day_keys = set(filter(None, (_pair_day_key(p) for p in pairs)))
            skip_days = set()
            for d in day_keys:
                all_exist = all(os.path.exists(os.path.join(output_folder, f"{filename_prefix}_{b}_{d}.tif"))
                                for b in (ALL_BANDS if isinstance(band_list, str) and band_list.lower() == "all"
                                          else [str(b).upper() for b in band_list]))
                if all_exist:
                    skip_days.add(d)
                    if verbose:
                        formated_date = datetime.strptime(d, "%Y%m%d").strftime("%Y-%m-%d") 
                        print(f"Skipping data for day {formated_date} (all outputs already exist).")
            if skip_days:
                pairs = [p for p in pairs if _pair_day_key(p) not in skip_days]
                if not pairs:
                    if verbose:
                        print("All days skipped (existing outputs). Nothing to download/process.")
                    if dask_client:
                        try:
                            dask_client.close()
                            if dask_cluster:
                                dask_cluster.close()
                        except Exception:
                            pass
                    return {"processed_pairs": 0, "written": 0, "days": 0, "paths": [], "dashboard": dashboard_url}

        # Build tasks: each returns list of (day_key, band_name, grid)
        def _process_pair(sw_g, geo_g):
            res = []
            sw_path = None
            geo_path = None
            try:
                # Open local HDFs (reuse cache if present; else download)
                sw_path = open_granule_filelike(sw_g)
                geo_path = open_granule_filelike(geo_g)

                day_key = _day_key_from_any(sw_g, sw_path) or "unknown"
                if day_key != "unknown" and (not overwrite):
                    # skip whole day if all outputs exist
                    all_exist = all(
                        os.path.exists(os.path.join(output_folder, f"{filename_prefix}_{b}_{day_key}.tif"))
                        for b in bands_wanted
                    )
                    if all_exist:
                        if verbose:
                            print(f"Skipping data for day {day_key} (all outputs already exist).")
                        return []

                # Read geolocation and bands
                lat, lon = read_latlon_from_mod03(geo_path)
                bands = read_toa_from_mod02hkm(sw_path)
                if not bands:
                    if verbose:
                        print(f"⚠️ No TOA bands parsed from {os.path.basename(sw_path)}")
                    return []

                added = 0
                for bname, arr in bands.items():
                    if bname not in bands_wanted:
                        continue
                    if arr is None or not np.isfinite(arr).any():
                        continue
                    grid = swath_to_grid(arr, lat, lon, area_def, radius_m)
                    res.append((day_key, bname, grid))
                    added += 1

                if verbose and added == 0:
                    print(f"⚠️ No requested bands produced grids for {os.path.basename(sw_path)} (day {day_key}).")

                return res
            except Exception as e:
                if verbose:
                    dbg = os.path.basename(sw_path) if sw_path else _granule_name(sw_g)
                    print(f"❌ Failed processing {dbg}: {e}")
                return []
        
        tasks = []
        if use_dask:
            from dask import delayed
            for sw_g, geo_g in pairs:
                tasks.append(delayed(_process_pair)(sw_g, geo_g))
            if verbose:
                print(f"🧮 Scheduling {len(tasks)} swath tasks...")
            results = []
            dask_futures = None
            try:
                # submit and gather explicitly to allow clean shutdown
                dask_futures = dask_client.compute(tasks)  # list of futures
                results = dask_client.gather(dask_futures)
            except Exception as e:
                if verbose:
                    print(f"⚠️ Dask execution failed: {e}. Falling back to serial.")
                use_dask = False
                results = []
            finally:
                # ensure futures are cancelled before closing client
                try:
                    if dask_futures:
                        dask_client.cancel(dask_futures)
                except Exception:
                    pass
        if not use_dask:
            # Serial fallback
            results = []
            for sw_g, geo_g in (pairs):
                results.append(_process_pair(sw_g, geo_g))

        # Aggregate: day+band -> list of grids
        day_band_grids: dict[tuple[str, str], list[np.ndarray]] = defaultdict(list)
        for lst in results:
            for day_key, bname, grid in lst:
                if day_key == "unknown":
                    continue
                day_band_grids[(day_key, bname)].append(grid)

        
        
        # Write composites
        written_paths = []
        days = set(k[0] for k in day_band_grids.keys())
        for (day_key, bname), stack in sorted(day_band_grids.items()):
            out_fp = os.path.join(output_folder, f"{filename_prefix}_{bname}_{day_key}.tif")
            if (not overwrite) and os.path.exists(out_fp):
                continue
            if not stack:
                continue
            with warnings.catch_warnings():
                warnings.simplefilter("ignore", category=RuntimeWarning)
                # nanmean composite across swaths
                comp = np.nanmean(np.stack(stack, axis=0), axis=0).astype(np.float32, copy=False)
            write_single_band_tif(out_fp, comp, transform, width, height)
            written_paths.append(out_fp)

        if verbose and not day_band_grids:
            print("⚠️ No day/band grids collected. Check pyhdf installation and band selection.")
        
        if verbose:
            print(f"✅ MODIS TOA complete. Pairs={len(pairs)} Days={len(days)} Written={len(written_paths)}")

        if dask_client:
            try:
                # close client then cluster to avoid background send on closed comm
                dask_client.close()
                if dask_cluster:
                    dask_cluster.close()
            except Exception:
                pass

        return {
            "processed_pairs": len(pairs),
            "written": len(written_paths),
            "days": len(days),
            "paths": written_paths,
            "dashboard": dashboard_url,
        }
    
    def download_modis_toa_no_dask(
        self,
        band_list: list[str] | str,
        output_folder: str,
        roi: tuple[float, float, float, float],
        start_date: str,
        end_date: str,
        *,
        platform: str = "terra",         # "terra" | "aqua" | "both"
        res_deg: float = 0.0045,         # ~500 m @ equator
        radius_m: int = 4000,            # swath->grid nearest-neighbor radius (m)
        filename_prefix: str = "modis_toa",
        overwrite: bool = False,
        verbose: bool = True,
        edl_username: str | None = None,
        edl_password: str | None = None,
        login_strategy: str | None = None,
        temp_dir: str | None = None
    ) -> dict:
        """
        Download MODIS L1B TOA reflectance (HKM, 500m) and write one GeoTIFF per band per day.

        - Uses earthaccess to search LAADS and downloads granules to a cache folder.
        - If a granule HDF is already in cache, it is reused (no re-download).
        - Handles HDF4 via pyhdf fallback; HDF5 via h5py when available.
        - Projects swaths to a regular lon/lat grid over ROI using pyresample.
        """
        import os, re, math, warnings, tempfile
        from collections import defaultdict
        from datetime import datetime, timedelta

        import numpy as np

        try:
            import earthaccess as ea
        except Exception as e:
            raise RuntimeError("earthaccess is required. pip install earthaccess") from e

        try:
            import rasterio
            from rasterio.transform import from_origin
            from pyresample import geometry, kd_tree
        except Exception as e:
            raise RuntimeError("Dependencies missing. pip install rasterio pyresample") from e

        # Constants for HKM TOA datasets
        HKM_DATASETS = [
            ("EV_250_Aggr500_RefSB", {0: "B01", 1: "B02"}),
            ("EV_500_RefSB",         {0: "B03", 1: "B04", 2: "B05", 3: "B06", 4: "B07"}),
        ]
        ALL_BANDS = ["B01", "B02", "B03", "B04", "B05", "B06", "B07"]

        # Normalize bands
        if isinstance(band_list, str) and band_list.lower() == "all":
            bands_wanted = set(ALL_BANDS)
        else:
            bands_wanted = set([str(b).upper() for b in band_list])
            unknown = bands_wanted - set(ALL_BANDS)
            if unknown:
                raise ValueError(f"Unknown bands requested: {sorted(unknown)}")

        # Validate ROI
        if not (isinstance(roi, (list, tuple)) and len(roi) == 4):
            raise ValueError("roi must be (min_lon, min_lat, max_lon, max_lat)")
        minx, miny, maxx, maxy = float(roi[0]), float(roi[1]), float(roi[2]), float(roi[3])

        # Output dirs
        os.makedirs(output_folder, exist_ok=True)
        cache_dir = os.path.join(output_folder, "_earthaccess_cache")
        os.makedirs(cache_dir, exist_ok=True)
        
        
        tmp_root = temp_dir or os.path.join(output_folder, "_tmp")
        os.makedirs(tmp_root, exist_ok=True)
        # Point Python/OS/GDAL temps to this folder (Windows honors TEMP/TMP)
        os.environ.setdefault("TEMP", tmp_root)
        os.environ.setdefault("TMP", tmp_root)
        os.environ.setdefault("TMPDIR", tmp_root)       # some libs honor this on Windows too
        os.environ.setdefault("CPL_TMPDIR", tmp_root)   # GDAL/Rasterio temp
        # Limit GDAL in-memory cache (MB) to reduce RAM pressure
        os.environ.setdefault("GDAL_CACHEMAX", "256")
        # Make Python's tempfile use it in-process as well
        tempfile.tempdir = tmp_root

        # Login to Earthdata
        if verbose:
            print("🔐 Logging into earthaccess (LAADS)...")
        try:
            if edl_username and edl_password:
                ea.login(strategy=(login_strategy or "interactive"), username=edl_username, password=edl_password, persist=True)
            elif login_strategy:
                ea.login(strategy=login_strategy, persist=True)
            else:
                ea.login(persist=True)
        except Exception as e:
            raise RuntimeError(f"earthaccess login failed: {e}")

        # Helpers
        
        def _granule_name(granule) -> str:
            """
            Robustly extract a display/name from earthaccess DataGranule across versions.
            Tries UMM (GranuleUR), meta fields, then the first HTTPS data link basename.
            """
            name = ""
            try:
                umm = getattr(granule, "umm", None) or {}
                # Common keys in UMM
                name = (
                    umm.get("GranuleUR")
                    or umm.get("GranuleID")
                    or (umm.get("DataGranule") or {}).get("ProducerGranuleId")
                    or ""
                )
                if not name:
                    meta = getattr(granule, "meta", None) or {}
                    name = meta.get("GranuleUR") or meta.get("title") or ""
                if not name:
                    links = granule.data_links(access="https")
                    if links:
                        name = os.path.basename(links[0])
            except Exception:
                pass
            return name
        
        def token_Ayyyydoy_hhmm(name: str) -> str | None:
            m = re.search(r"\.A(\d{7}\.\d{4})\.", name)
            return m.group(1) if m else None

        def day_key_from_name(name: str) -> str:
            m = re.search(r"\.A(\d{4})(\d{3})\.\d{4}\.", name)
            if not m:
                # fallback: try YYYYMMDD present in name
                m2 = re.search(r"(20\d{6})", name)
                if m2:
                    return m2.group(1)
                raise ValueError(f"Cannot parse day key from name: {name}")
            year, doy = int(m.group(1)), int(m.group(2))
            dt = datetime(year, 1, 1) + timedelta(days=doy - 1)
            return dt.strftime("%Y%m%d")

        def make_target_grid(bbox, res_deg_):
            x0, y0, x1, y1 = bbox
            width = int(math.ceil((x1 - x0) / res_deg_))
            height = int(math.ceil((y1 - y0) / res_deg_))
            transform = from_origin(x0, y1, res_deg_, res_deg_)
            area_def = geometry.AreaDefinition(
                "roi_ll",
                "regular latlon grid",
                "epsg4326",
                {"proj": "longlat", "datum": "WGS84"},
                width,
                height,
                [x0, y0, x1, y1],
            )
            return area_def, transform, width, height

        def search(product, start_dt, end_dt, bbox):
            return ea.search_data(
                short_name=product,
                temporal=(start_dt, end_dt),
                bounding_box=bbox,
                provider="LAADS",
                granule_name="*.hdf",
            )

        def pair_l1b_with_geo(l1b_list, geo_list):
            geo_by_token = {}
            for g in geo_list:
                name = _granule_name(g)
                tok = token_Ayyyydoy_hhmm(name) or ""
                if tok:
                    geo_by_token[tok] = g
            pairs = []
            for sw in l1b_list:
                name = _granule_name(sw)
                tok = token_Ayyyydoy_hhmm(name) or ""
                if tok and tok in geo_by_token:
                    pairs.append((sw, geo_by_token[tok]))
            return pairs

        def _cached_local_path_for_granule(granule) -> str | None:
            # Check by download link filename
            try:
                links = granule.data_links(access="https")
            except Exception:
                links = []
            for url in (links or []):
                base = os.path.basename(url)
                cand = os.path.join(cache_dir, base)
                if os.path.exists(cand):
                    return cand
            # Try using extracted name prefix
            name = _granule_name(granule)
            if name:
                # exact filename
                cand = os.path.join(cache_dir, name)
                if os.path.exists(cand):
                    return cand
                # prefix match (some downloads add query tokens)
                for fn in os.listdir(cache_dir):
                    if fn.startswith(os.path.splitext(name)[0]):
                        cand = os.path.join(cache_dir, fn)
                        if os.path.exists(cand):
                            return cand
            return None

        def open_granule_filelike(granule):
            """
            Return local path to HDF granule; if present in cache, reuse; otherwise download to cache.
            """
            cached = _cached_local_path_for_granule(granule)
            if cached:
                return cached
            try:
                paths = ea.download([granule], provider="LAADS", local_path=cache_dir)
            except Exception as e:
                raise RuntimeError(f"earthaccess.download failed: {e}")
            if isinstance(paths, dict):
                first = next(iter(paths.values()))
                local_path = first[0] if isinstance(first, (list, tuple)) else first
            elif isinstance(paths, (list, tuple)):
                local_path = paths[0]
            else:
                local_path = str(paths)
            return local_path

        def read_latlon_from_mod03(geo_path: str):
            """
            Read Latitude/Longitude arrays from MOD03/MYD03 geolocation granule.
            Tries HDF5 first, then HDF4 (pyhdf).
            """
            # HDF5
            try:
                import h5py
                with h5py.File(geo_path, "r") as g:
                    # Try common groups
                    for grp in ("MODIS_Swath_Type_GEO", "MODIS_Swath_Type_L1B"):
                        lat_p = f"{grp}/Geolocation Fields/Latitude"
                        lon_p = f"{grp}/Geolocation Fields/Longitude"
                        if lat_p in g and lon_p in g:
                            lat = g[lat_p][:]
                            lon = g[lon_p][:]
                            return lat.astype(np.float32), lon.astype(np.float32)
                    # Root-level datasets fallback
                    if "Latitude" in g and "Longitude" in g:
                        lat = g["Latitude"][:]
                        lon = g["Longitude"][:]
                        return lat.astype(np.float32), lon.astype(np.float32)
            except Exception:
                pass

            # HDF4
            try:
                from pyhdf.SD import SD, SDC
            except Exception as e:
                raise RuntimeError(
                    "pyhdf is required to read HDF4 MODIS geolocation files. "
                    "Install on Windows with: conda install -c conda-forge pyhdf"
                ) from e
            sd = SD(geo_path, SDC.READ)
            try:
                lat = sd.select("Latitude")[:].astype(np.float32)
                lon = sd.select("Longitude")[:].astype(np.float32)
                return lat, lon
            finally:
                sd.end()

        def read_toa_from_mod02hkm(l1b_path: str) -> dict[str, np.ndarray]:
            """
            Read TOA reflectance 2D arrays per band from MOD02HKM/MYD02HKM.
            Returns dict {"B01": 2D, ...}.
            """
            out: dict[str, np.ndarray] = {}

            def _apply_scale(arr, scale, offset, fill):
                arr = arr.astype(np.float32, copy=False)
                if fill is not None:
                    arr = np.where(arr == fill, np.nan, arr)
                if scale is not None:
                    # L1B uses: reflectance = (DN - offset) * scale
                    off = 0.0 if offset is None else float(offset)
                    arr = (arr - off) * float(scale)
                return arr

            # HDF5 path
            try:
                import h5py
                with h5py.File(l1b_path, "r") as f:
                    def _get_dset(name):
                        if name in f:
                            return f[name]
                        if f"MODIS_SWATH_Type_L1B/{name}" in f:
                            return f[f"MODIS_SWATH_Type_L1B/{name}"]
                        return None

                    for dname, idx_map in HKM_DATASETS:
                        d = _get_dset(dname)
                        if d is None:
                            continue
                        data = d[:]  # (nbands, lines, samples)
                        scales = d.attrs.get("reflectance_scales", None)
                        offsets = d.attrs.get("reflectance_offsets", None)
                        fill = d.attrs.get("_FillValue", None)
                        # Normalize offset/scale containers
                        if isinstance(fill, (np.ndarray, list)) and len(np.array(fill).shape) > 0:
                            try:
                                fill = float(np.array(fill).ravel()[0])
                            except Exception:
                                fill = None
                        for b_idx, b_name in idx_map.items():
                            if data.ndim != 3 or b_idx >= data.shape[0]:
                                continue
                            s = float(scales[b_idx]) if scales is not None else None
                            o = float(offsets[b_idx]) if offsets is not None else None
                            out[b_name] = _apply_scale(data[b_idx], s, o, fill)
                if out:
                    return out
            except Exception:
                pass

            # HDF4 path
            try:
                from pyhdf.SD import SD, SDC
            except Exception as e:
                raise RuntimeError(
                    "pyhdf is required to read HDF4 MODIS L1B files. "
                    "Install on Windows with: conda install -c conda-forge pyhdf"
                ) from e
            sd = SD(l1b_path, SDC.READ)
            try:
                for dname, idx_map in HKM_DATASETS:
                    if dname not in sd.datasets().keys():
                        continue
                    sds = sd.select(dname)
                    data = sds[:]  # (nbands, lines, samples)
                    attrs = sds.attributes()
                    scales = attrs.get("reflectance_scales", None)
                    offsets = attrs.get("reflectance_offsets", None)
                    fill = attrs.get("_FillValue", None)
                    if isinstance(fill, (list, np.ndarray)):
                        try:
                            fill = float(np.array(fill).ravel()[0])
                        except Exception:
                            fill = None
                    for b_idx, b_name in idx_map.items():
                        if data.ndim != 3 or b_idx >= data.shape[0]:
                            continue
                        s = float(scales[b_idx]) if scales is not None else None
                        o = float(offsets[b_idx]) if offsets is not None else None
                        out[b_name] = _apply_scale(data[b_idx, :, :], s, o, fill)
            finally:
                sd.end()
            return out

        def _align_geo_to_band(lat, lon, band_arr: np.ndarray):
            """
            Ensure lat/lon shape matches band_arr (lines, samples).
            - MOD03 is 1km, swath is 500m: upsample by factor 2 via repeat.
            - Fix transposed cases.
            - Normalize lon to [-180, 180] and clamp lat to [-90, 90].
            """
            lat = np.array(lat, dtype=np.float32, copy=False)
            lon = np.array(lon, dtype=np.float32, copy=False)

            lon = np.where(lon > 180.0, lon - 360.0, lon)
            lat = np.clip(lat, -90.0, 90.0)

            bl, bs = int(band_arr.shape[-2]), int(band_arr.shape[-1])
            gl, gs = int(lat.shape[-2]), int(lat.shape[-1])

            # transpose if needed
            if (gl, gs) == (bs, bl):
                lat, lon = lat.T, lon.T
                gl, gs = lat.shape

            if (gl, gs) != (bl, bs):
                rl = bl // gl if gl and (bl % gl == 0) else 1
                rs = bs // gs if gs and (bs % gs == 0) else 1
                if rl == rs and rl in (2, 3, 4):
                    lat = np.repeat(np.repeat(lat, rl, axis=0), rl, axis=1)
                    lon = np.repeat(np.repeat(lon, rl, axis=0), rl, axis=1)
                    gl, gs = lat.shape

            if (gl, gs) != (bl, bs):
                raise ValueError(f"Geolocation/band shape mismatch: latlon={gl}x{gs} vs band={bl}x{bs}")

            return lat, lon

        def swath_to_grid(band_arr, lat_, lon_, area_def_, radius_):
            lat_a, lon_a = _align_geo_to_band(lat_, lon_, band_arr)
            swath_def = geometry.SwathDefinition(lons=lon_a, lats=lat_a)
            with warnings.catch_warnings():
                warnings.simplefilter("ignore", category=RuntimeWarning)
                grid = kd_tree.resample_nearest(
                    swath_def,
                    band_arr.astype(np.float32, copy=False),
                    area_def_,
                    radius_of_influence=radius_,
                    fill_value=np.nan,
                    nprocs=1
                )
            return grid.astype(np.float32, copy=False)

        def write_single_band_tif(path, arr, transform, width, height):
            profile = {
                "driver": "GTiff",
                "height": height,
                "width": width,
                "count": 1,
                "dtype": "float32",
                "crs": "EPSG:4326",
                "transform": transform,
                "compress": "deflate",
                "predictor": 2,
                "tiled": True,
                "blockxsize": 256,
                "blockysize": 256,
                "nodata": np.float32(np.nan),
            }
            os.makedirs(os.path.dirname(path) or ".", exist_ok=True)
            with rasterio.open(path, "w", **profile) as dst:
                dst.write(arr, 1)

        
        # Build target grid
        area_def, transform, width, height = make_target_grid((minx, miny, maxx, maxy), res_deg)

        start_dt = datetime.strptime(start_date, "%Y-%m-%d")
        end_dt = datetime.strptime(end_date, "%Y-%m-%d")

        # Search swath (L1B) + geolocation
        l1b, geo = [], []
        use_terra = platform.lower() in ("terra", "both")
        use_aqua = platform.lower() in ("aqua", "both")

        if use_terra:
            l1b += search("MOD02HKM", start_dt, end_dt, (minx, miny, maxx, maxy))
            geo += search("MOD03", start_dt, end_dt, (minx, miny, maxx, maxy))
        if use_aqua:
            l1b += search("MYD02HKM", start_dt, end_dt, (minx, miny, maxx, maxy))
            geo += search("MYD03", start_dt, end_dt, (minx, miny, maxx, maxy))

        pairs = pair_l1b_with_geo(l1b, geo)
        if not pairs:
            if verbose:
                print("No matching MODIS L1B/MOD03 pairs found for the criteria.")
            return {"processed_pairs": 0, "written": 0, "days": 0, "paths": []}

        # Per-day collector
        daily = defaultdict(lambda: defaultdict(list))  # daily[YYYYMMDD][Bxx] -> list of grids

        iterator = pairs
        if verbose:
            try:
                from tqdm import tqdm as _tqdm
                iterator = _tqdm(pairs, desc="Projecting swaths")
            except Exception:
                pass

        for sw_g, geo_g in iterator:
            sw_name = _granule_name(sw_g) or "unknown"
            try:
                day_key = day_key_from_name(sw_name)
            except Exception:
                t0 = getattr(sw_g, "meta", {}).get("time_start") if hasattr(sw_g, "meta") else None
                if t0:
                    try:
                        day_key = datetime.fromisoformat(str(t0).replace("Z", "")).strftime("%Y%m%d")
                    except Exception:
                        day_key = "unknown"
                else:
                    day_key = "unknown"

            # Skip if all outputs for this day already exist (fast path)
            maybe_all_exist = all(
                os.path.exists(os.path.join(output_folder, f"{filename_prefix}_{b}_{day_key}.tif"))
                for b in bands_wanted
            )
            if maybe_all_exist and not overwrite:
                continue

            sw_path = open_granule_filelike(sw_g)
            geo_path = open_granule_filelike(geo_g)

            try:
                lat, lon = read_latlon_from_mod03(geo_path)
                bands = read_toa_from_mod02hkm(sw_path)
            except Exception as e:
                if verbose:
                    print(f"Error processing granules: {e}")
                continue

            for bname, arr in bands.items():
                if bname not in bands_wanted:
                    continue
                if arr is None or not np.isfinite(arr).any():
                    continue
                try:
                    grid = swath_to_grid(arr, lat, lon, area_def, radius_m)
                    daily[day_key][bname].append(grid)
                except Exception as e:
                    if verbose:
                        print(f"Resample error {bname}: {e}")

        # Write ONE GeoTIFF per band per day (nanmean composite)
        written_paths = []
        for day_key, band_dict in sorted(daily.items()):
            for b in sorted(bands_wanted):
                out_fp = os.path.join(output_folder, f"{filename_prefix}_{b}_{day_key}.tif")
                if (not overwrite) and os.path.exists(out_fp):
                    continue
                stack = band_dict.get(b, [])
                if not stack:
                    continue
                # nanmean across swaths
                with warnings.catch_warnings():
                    warnings.simplefilter("ignore", category=RuntimeWarning)
                    comp = np.nanmean(np.stack(stack, axis=0), axis=0).astype(np.float32, copy=False)
                write_single_band_tif(out_fp, comp, transform, width, height)
                written_paths.append(out_fp)

        if verbose:
            print(f"✅ MODIS TOA complete. Pairs={len(pairs)} Days={len(daily)} Written={len(written_paths)}")

        return {
            "processed_pairs": len(pairs),
            "written": len(written_paths),
            "days": len(daily),
            "paths": written_paths,
        }
    
    
    
    def download_modis_toa_old(
        self,
        band_list: list[str] | str,
        output_folder: str,
        roi: tuple[float, float, float, float],
        start_date: str,
        end_date: str,
        *,
        platform: str = "terra",         # "terra" | "aqua" | "both"
        res_deg: float = 0.0045,         # ~500 m @ equator
        radius_m: int = 4000,            # swath->grid nearest-neighbor radius (m)
        filename_prefix: str = "modis_toa",
        overwrite: bool = False,
        verbose: bool = True,
        edl_username: str = "elhachimi_ch",     # NEW: Earthdata Login username
        edl_password: str = "Jihad12345+@",     # NEW: Earthdata Login password
        login_strategy: str = "interactive"    # e.g. "interactive" | "netrc" | "environment"
    ) -> dict:
        """
        Download MODIS L1B TOA reflectance (HKM, 500m) and write one GeoTIFF per band per day.

        Inputs:
          - band_list: list of bands subset of ["B01","B02","B03","B04","B05","B06","B07"] or "all"
          - output_folder: destination directory
          - roi: (min_lon, min_lat, max_lon, max_lat)
          - start_date, end_date: "YYYY-MM-DD"
          - platform: "terra" (MOD02HKM/MOD03), "aqua" (MYD02HKM/MYD03), or "both"
          - res_deg: output grid resolution in degrees
          - radius_m: resampling radius (meters) for nearest neighbor
          - filename_prefix: filename prefix for outputs
          - overwrite: overwrite existing outputs

        Returns: dict summary with counts and written paths.
        """
        import os, re, math
        from collections import defaultdict
        from datetime import datetime, timedelta

        import numpy as np
        from tqdm import tqdm
        

        try:
            import earthaccess as ea
        except Exception as e:
            raise RuntimeError("earthaccess is required. pip install earthaccess") from e
        try:
            import h5py
            import rasterio
            from rasterio.transform import from_origin
            from pyresample import geometry, kd_tree
        except Exception as e:
            raise RuntimeError("Dependencies missing. pip install h5py rasterio pyresample tqdm") from e

        # MODIS HKM TOA datasets: B01..B07 (500 m; B01-02 aggregated)
        HKM_DATASETS = [
            ("EV_250_Aggr500_RefSB", {0: "B01", 1: "B02"}),
            ("EV_500_RefSB",         {0: "B03", 1: "B04", 2: "B05", 3: "B06", 4: "B07"}),
        ]
        ALL_BANDS = ["B01", "B02", "B03", "B04", "B05", "B06", "B07"]

        # Normalize bands
        if isinstance(band_list, str) and band_list.lower() == "all":
            bands_wanted = set(ALL_BANDS)
        else:
            bands_wanted = set([b.upper() for b in band_list])
            unknown = bands_wanted - set(ALL_BANDS)
            if unknown:
                raise ValueError(f"Unsupported bands: {sorted(unknown)}. Allowed: {ALL_BANDS}")

        # Validate ROI
        if not (isinstance(roi, (list, tuple)) and len(roi) == 4):
            raise ValueError("roi must be (min_lon, min_lat, max_lon, max_lat)")
        minx, miny, maxx, maxy = float(roi[0]), float(roi[1]), float(roi[2]), float(roi[3])

        os.makedirs(output_folder, exist_ok=True)
        cache_dir = os.path.join(output_folder, "_earthaccess_cache")
        os.makedirs(cache_dir, exist_ok=True)

        # Login (non-interactive if creds provided)
        if verbose:
            print("🔐 Logging into earthaccess (LAADS)...")
        try:
            ea.login(strategy=login_strategy, persist=True)
        except Exception as e:
            raise RuntimeError(f"earthaccess login failed: {e}")

        # Helpers from reference script
        
        def _align_geo_to_band(lat, lon, band_arr):
            """
            Ensure lat/lon shape matches band_arr (lines, samples).
            - If 1km geoloc with 500m data: repeat by factor 2.
            - If transposed: fix.
            - Normalize longitudes to [-180, 180] and clamp lats.
            """
            lat = np.array(lat, dtype=np.float32, copy=False)
            lon = np.array(lon, dtype=np.float32, copy=False)

            # Fix 0..360 -> -180..180
            lon = np.where(lon > 180.0, lon - 360.0, lon)
            # Clamp lat
            lat = np.clip(lat, -90.0, 90.0)

            bl, bs = band_arr.shape[-2], band_arr.shape[-1]
            gl, gs = lat.shape[-2], lat.shape[-1]

            # Transposed geolocation?
            if (gl, gs) == (bs, bl):
                lat, lon = lat.T, lon.T
                gl, gs = lat.shape

            # Simple integer upscale (e.g., 1km -> 500m)
            rl = bl // gl if gl and (bl % gl == 0) else 1
            rs = bs // gs if gs and (bs % gs == 0) else 1
            if (gl != bl) or (gs != bs):
                if rl == rs and rl in (2, 3, 4):  # common MODIS scale factors
                    lat = np.repeat(np.repeat(lat, rl, axis=0), rl, axis=1)
                    lon = np.repeat(np.repeat(lon, rl, axis=0), rl, axis=1)
                    gl, gs = lat.shape
                else:
                    # Last resort: if shapes still don't match but areas differ slightly, try nearest resize
                    if (gl != bl) or (gs != bs):
                        raise ValueError(f"Geolocation/band shape mismatch after alignment: latlon={gl}x{gs} vs band={bl}x{bs}")

            return lat.astype(np.float32, copy=False), lon.astype(np.float32, copy=False)
        
        
        def make_target_grid(bbox, res_deg_):
            x0, y0, x1, y1 = bbox
            width = int(math.ceil((x1 - x0) / res_deg_))
            height = int(math.ceil((y1 - y0) / res_deg_))
            transform = from_origin(x0, y1, res_deg_, res_deg_)
            area_def = geometry.AreaDefinition(
                "roi_ll",
                "regular latlon grid",
                "epsg4326",
                {"proj": "longlat", "datum": "WGS84"},
                width,
                height,
                [x0, y0, x1, y1],
            )
            return area_def, transform, width, height

        def search(product, start_dt, end_dt, bbox):
            return ea.search_data(
                short_name=product,
                temporal=(start_dt, end_dt),
                bounding_box=bbox,
                provider="LAADS",
                granule_name="*.hdf",
            )

        def token_Ayyyydoy_hhmm(s):
            m = re.search(r"\.A(\d{7}\.\d{4})\.", s)
            return m.group(1) if m else None

        def day_key_from_name(s):
            m = re.search(r"\.A(\d{4})(\d{3})\.\d{4}\.", s)
            if not m:
                return None
            year, doy = int(m.group(1)), int(m.group(2))
            dt = datetime(year, 1, 1) + timedelta(days=doy - 1)
            return dt.strftime("%Y%m%d")

        def pair_l1b_with_geo(l1b_list, geo_list):
            geo_by_token = {}
            for g in geo_list:
                hrefs = g.data_links()
                if not hrefs:
                    continue
                t = token_Ayyyydoy_hhmm(hrefs[0])
                if t:
                    geo_by_token[t] = g
            pairs = []
            for sw in l1b_list:
                hrefs = sw.data_links()
                if not hrefs:
                    continue
                t = token_Ayyyydoy_hhmm(hrefs[0])
                if t in geo_by_token:
                    pairs.append((sw, geo_by_token[t]))
            return pairs

        def open_granule_filelike(granule):
            """
            Robust local-path opener: download to a cache folder and return the local file path.
            Avoids issues with file-like objects and h5py.
            """
            try:
                # LAADS provider required for MODIS/MYD
                paths = ea.download([granule], provider="LAADS", local_path=cache_dir)
                # earthaccess may return a list or a dict; normalize to first path
                if isinstance(paths, dict):
                    # dict: {Granule: [paths]}
                    first = next(iter(paths.values()))
                    local_path = first[0] if isinstance(first, (list, tuple)) else first
                elif isinstance(paths, (list, tuple)):
                    local_path = paths[0]
                else:
                    local_path = str(paths)
                hrefs = granule.data_links(access="https")
                url = hrefs[0] if hrefs else ""
                return local_path, url
            except Exception as e:
                raise RuntimeError(f"earthaccess.download failed: {e}")

        def read_latlon_from_mod03(geo_path: str):
            """
            Read Latitude/Longitude from MOD03 geolocation granule.
            Tries HDF5 (h5py) first, then falls back to HDF4 (pyhdf.SD).
            """
            import numpy as np
            try:
                import h5py
                with h5py.File(geo_path, "r") as g:
                    # HDF5/HDF-EOS5 layout
                    lat = g["MODIS_Swath_Type_L1B/Geolocation Fields/Latitude"][:].astype(np.float32)
                    lon = g["MODIS_Swath_Type_L1B/Geolocation Fields/Longitude"][:].astype(np.float32)
                    return lat, lon
            except Exception:
                # HDF4 fallback (common for MOD03)
                try:
                    from pyhdf.SD import SD, SDC
                except Exception as e:
                    raise RuntimeError(
                        "pyhdf is required to read HDF4 MODIS geolocation files. "
                        "Install with: conda install -c conda-forge pyhdf"
                    ) from e
                sd = SD(geo_path, SDC.READ)
                lat = sd.select("Latitude")[:].astype(np.float32)
                lon = sd.select("Longitude")[:].astype(np.float32)
                sd.end()
                return lat, lon

        def read_toa_from_mod02hkm(l1b_path: str):
            """
            Read TOA reflectance per band from MOD02HKM.
            Tries HDF5 first, then HDF4 (pyhdf). Returns dict {"B01": 2D, ...}.
            """
            import numpy as np
            out = {}
            # helper to apply scale/offset and fill
            def _apply_scale(arr, scale, offset, fill):
                arr = arr.astype(np.float32, copy=False)
                if fill is not None:
                    arr = np.where(arr == fill, np.nan, arr)
                if scale is not None and offset is not None:
                    arr = (arr - offset) * scale
                return arr

            # Attempt HDF5
            try:
                import h5py
                with h5py.File(l1b_path, "r") as f:
                    for dset_name, idx_map in HKM_DATASETS:
                        if dset_name not in f:
                            continue
                        d = f[dset_name]
                        data = d[:]  # (bands, lines, samples)
                        scales = d.attrs.get("reflectance_scales", None)
                        offsets = d.attrs.get("reflectance_offsets", None)
                        fill = d.attrs.get("_FillValue", None)
                        if isinstance(fill, np.ndarray):
                            fill = fill[0]
                        for b_idx, b_name in idx_map.items():
                            if b_idx >= data.shape[0]:
                                continue
                            arr = data[b_idx]
                            s = (scales[b_idx] if scales is not None else None)
                            o = (offsets[b_idx] if offsets is not None else None)
                            out[b_name] = _apply_scale(arr, float(s) if s is not None else None,
                                                       float(o) if o is not None else None, fill)
                return out
            except Exception:
                pass

            # HDF4 fallback
            try:
                from pyhdf.SD import SD, SDC
            except Exception as e:
                raise RuntimeError(
                    "pyhdf is required to read HDF4 MODIS swath files. "
                    "Install with: conda install -c conda-forge pyhdf"
                ) from e

            sd = SD(l1b_path, SDC.READ)
            try:
                for dset_name, idx_map in HKM_DATASETS:
                    # Some collections expose these as SDS names directly
                    if dset_name not in [s for s in sd.datasets().keys()]:
                        # try next if not present
                        continue
                    sds = sd.select(dset_name)
                    # pyhdf returns array with first dim = band
                    data = sds[:]
                    attrs = sds.attributes()
                    scales = attrs.get("reflectance_scales", None)
                    offsets = attrs.get("reflectance_offsets", None)
                    fill = attrs.get("_FillValue", None)
                    if isinstance(fill, (list, np.ndarray)):
                        fill = fill[0]
                    for b_idx, b_name in idx_map.items():
                        if data.ndim != 3 or b_idx >= data.shape[0]:
                            continue
                        arr = data[b_idx, :, :]
                        s = (scales[b_idx] if scales is not None else None)
                        o = (offsets[b_idx] if offsets is not None else None)
                        out[b_name] = _apply_scale(arr, float(s) if s is not None else None,
                                                   float(o) if o is not None else None, fill)
            finally:
                sd.end()
            return out
        
        
        def swath_to_grid(band_arr, lat_, lon_, area_def_, radius_):
            # Ensure geolocation matches band shape
            lat_a, lon_a = _align_geo_to_band(lat_, lon_, band_arr)

            # pyresample expects same shape for swath and data
            swath_def = geometry.SwathDefinition(lons=lon_a, lats=lat_a)
            grid = kd_tree.resample_nearest(
                swath_def,
                band_arr.astype(np.float32, copy=False),
                area_def_,
                radius_of_influence=radius_,
                fill_value=np.nan,
                nprocs=1
            )
            return grid.astype(np.float32)

        def write_single_band_tif(path, arr, transform, width, height):
            profile = {
                "driver": "GTiff",
                "height": height,
                "width": width,
                "count": 1,
                "dtype": "float32",
                "crs": "EPSG:4326",
                "transform": transform,
                "compress": "deflate",
                "predictor": 2,
                "tiled": True,
                "blockxsize": 256,
                "blockysize": 256,
                "nodata": np.nan,
            }
            with rasterio.open(path, "w", **profile) as dst:
                dst.write(arr, 1)

        
        
        
        
        # Build target grid
        area_def, transform, width, height = make_target_grid((minx, miny, maxx, maxy), res_deg)

        start_dt = datetime.strptime(start_date, "%Y-%m-%d")
        end_dt = datetime.strptime(end_date, "%Y-%m-%d")

        # Search L1B + GEO
        l1b, geo = [], []
        use_terra = platform.lower() in ("terra", "both")
        use_aqua = platform.lower() in ("aqua", "both")
        if use_terra:
            l1b += search("MOD02HKM", start_dt, end_dt, (minx, miny, maxx, maxy))
            geo += search("MOD03", start_dt, end_dt, (minx, miny, maxx, maxy))
        if use_aqua:
            l1b += search("MYD02HKM", start_dt, end_dt, (minx, miny, maxx, maxy))
            geo += search("MYD03", start_dt, end_dt, (minx, miny, maxx, maxy))

        pairs = pair_l1b_with_geo(l1b, geo)
        if not pairs:
            if verbose:
                print("⚠️ No MODIS HKM pairs found for the given dates/ROI.")
            return {"processed_pairs": 0, "written": 0, "days": 0, "paths": []}

        daily = defaultdict(lambda: defaultdict(list))  # daily[YYYYMMDD][Bxx] -> list of grids
        
        
        

        it = tqdm(pairs, desc="Projecting swaths", disable=not verbose)
        for sw_g, geo_g in it:
            sw_f, sw_url = open_granule_filelike(sw_g)
            geo_f, geo_url = open_granule_filelike(geo_g)
            try:
                lat, lon = read_latlon_from_mod03(geo_f)
                bands = read_toa_from_mod02hkm(sw_f)
                # Define day_key based on a date variable
                day_key = datetime.now().strftime('%Y-%m-%d')  # Example: using current date
            except Exception as e:
                print(f"Error processing granules: {e}")
                continue  # Skip to the next iteration if there's an error
            # ...existing code...
            for bname, arr in bands.items():
                if bname not in bands_wanted:
                    continue
                if arr is None or np.all(np.isnan(arr)):
                    continue
                try:
                    # align and resample
                    grid = swath_to_grid(arr, lat, lon, area_def, radius_m)
                    daily[day_key][bname].append(grid)
                except Exception as e:
                    if verbose:
                        print(f"Resample error {bname}: {e}")

        # Write ONE GeoTIFF per band per day
        written_paths = []
        for day_key, band_dict in sorted(daily.items()):
            for b in sorted(bands_wanted):
                stacks = band_dict.get(b, [])
                if not stacks:
                    continue
                out_path = os.path.join(output_folder, f"{filename_prefix}_{day_key}_{b}.tif")
                if (not overwrite) and os.path.exists(out_path):
                    written_paths.append(out_path)
                    continue
                mosaic = np.nanmedian(np.stack(stacks, axis=0), axis=0).astype(np.float32)
                write_single_band_tif(out_path, mosaic, transform, width, height)
                if verbose:
                    print("Wrote:", out_path)
                written_paths.append(out_path)

        return {
            "processed_pairs": len(pairs),
            "written": len(written_paths),
            "days": len(daily),
            "paths": written_paths,
        }                
    
    
    def download_bands_poi_tif(self, band_names_list='all', poi_lon_lat_list=[-7.6010799,31.6606874], 
                               start_date='2017-01-01',
                               end_date='2017-01-30',
                               product_name='landsat8',
                               level='raw_bands',
                               metadata=False):
        
        if product_name == 'landsat8':
            if self.backend == 'gee':
                if level == 'raw_bands':
                    if band_names_list == 'all':
                        band_names_list = ['B1', 'B2', 'B3', 'B4', 'B5', 'B6', 'B7', 'B8', 'B9', 'B10', 'B11']
                                       
                    # Define your region of interest (ROI) using a geometry (e.g., a point, polygon, or feature collection)
                    roi = ee.Geometry.Point(poi_lon_lat_list)
                    #roi = ee.Geometry.Point(-122.084, 37.422)

                    # Define the Landsat 8 image collection
                    filtered_roi_date = ee.ImageCollection("LANDSAT/LC08/C02/T1")\
                    .filterDate(start_date, end_date)\
                    .filterBounds(roi) \
                    .sort('CLOUD_COVER')\
                    
                    # Select the required bands for NDVI calculation
                    filtred_bands = filtered_roi_date.select(band_names_list)

                    #geemap.ee_export_image_to_drive(image, filename=output_folder + '/' + image_id+'.tif', region=roi, folder=output_folder)
                    #geemap.ee_export_image_to_drive(image, region=roi, folder=output_folder)
                    geemap.ee_export_image_collection(filtred_bands, out_dir='data/landsat8', region=roi)
                    
                elif level == 'sr':
                    if band_names_list == 'all':
                        band_names_list = ['SR_B1', 'SR_B2', 'SR_B3', 'SR_B4', 'SR_B5', 'SR_B6', 'SR_B7']
                                       
                    # Define your region of interest (ROI) using a geometry (e.g., a point, polygon, or feature collection)
                    roi = ee.Geometry.Point(poi_lon_lat_list)
                    #roi = ee.Geometry.Point(-122.084, 37.422)

                    # Define the Landsat 8 image collection
                    filtered_roi_date = ee.ImageCollection("LANDSAT/LC08/C02/T1_L2")\
                    .filterDate(start_date, end_date)\
                    .filterBounds(roi) \
                    .sort('CLOUD_COVER')\
                    
                    # Select the required bands
                    filtred_bands = filtered_roi_date.select(band_names_list)
                    
                    #geemap.ee_export_image_to_drive(image, filename=output_folder + '/' + image_id+'.tif', region=roi, folder=output_folder)
                    #geemap.ee_export_image_to_drive(image, region=roi, folder=output_folder)
                    geemap.ee_export_image_collection(filtred_bands, out_dir='data/landsat8', region=roi)
                
                elif level == 'toa':
                    if band_names_list == 'all':
                        band_names_list = ['B1', 'B2', 'B3', 'B4', 'B5', 'B6', 'B7', 'B8', 'B9', 'B10', 'B11']
                                       
                    # Define your region of interest (ROI) using a geometry (e.g., a point, polygon, or feature collection)
                    roi = ee.Geometry.Point(poi_lon_lat_list)
                    #roi = ee.Geometry.Point(-122.084, 37.422)

                    # Define the Landsat 8 image collection
                    filtered_roi_date = ee.ImageCollection("LANDSAT/LC08/C02/T1_TOA")\
                    .filterDate(start_date, end_date)\
                    .filterBounds(roi) \
                    .sort('CLOUD_COVER')\
                    
                    # Select the required bands
                    filtred_bands = filtered_roi_date.select(band_names_list)
                    
                    
                    if metadata is True:
                        geemap.ee_export_image_collection(filtred_bands, out_dir='data/landsat8', region=roi, format='ZIPPED_GEO_TIFF')
                        print('okk')
                    else:
                        geemap.ee_export_image_collection(filtred_bands, out_dir='data/landsat8', region=roi)
                    #geemap.ee_export_image_to_drive(image, filename=output_folder + '/' + image_id+'.tif', region=roi, folder=output_folder)
                    #geemap.ee_export_image_to_drive(image, region=roi, folder=output_folder)
    
    def download_dem_tif(
        self,
        roi,
        file_path: str = "data/dem/dem.tif",
        product: str = "srtm",
        spatial_resolution: int = 1000,
    ):
        """Download a DEM GeoTIFF from GEE for a given ROI.

        The ROI can be provided as:

        - A bounding box: [min_lon, min_lat, max_lon, max_lat]
        - A list of polygon coordinates: [[lon, lat], ...]
        - A path to a vector file: .shp, .geojson, .json, .parquet, etc.

        Args:
            roi: Bounding box, polygon coordinates, or vector file path.
            file_path (str): Full output path for the DEM GeoTIFF.
            product (str): DEM product identifier (currently only 'srtm' used).
            spatial_resolution (int): Output resolution in meters.
        """

        # Ensure output directory exists
        out_dir = os.path.dirname(file_path) or "data/dem"
        self.check_directory_existance(out_dir)
        ful_path = file_path if os.path.isabs(file_path) else os.path.join(out_dir, os.path.basename(file_path))

        if self.backend != "gee":
            raise NotImplementedError("download_dem_tif currently supports only 'gee' backend.")

        # Build Earth Engine geometry from roi
        ee_roi = None

        # Case 1: roi is a path to a vector file
        if isinstance(roi, str) or isinstance(roi, os.PathLike):
            import geopandas as gpd

            vpath = str(roi)
            if vpath.lower().endswith((".parquet", ".pq")):
                gdf = gpd.read_parquet(vpath)
            else:
                gdf = gpd.read_file(vpath)
            # Ensure WGS84
            if gdf.crs is not None:
                gdf = gdf.to_crs(epsg=4326)
            geom = gdf.geometry.unary_union
            ee_roi = ee.Geometry(mapping(geom))

        # Case 2: roi is a bbox [minx, miny, maxx, maxy]
        elif isinstance(roi, (list, tuple)) and len(roi) == 4 and all(
            isinstance(v, (int, float)) for v in roi
        ):
            ee_roi = ee.Geometry.BBox(*roi)

        # Case 3: roi is a list of [lon, lat] coordinates (polygon)
        elif isinstance(roi, (list, tuple)) and roi and isinstance(roi[0], (list, tuple)):
            ee_roi = ee.Geometry.Polygon(roi)

        else:
            raise ValueError("roi must be a bbox, polygon coordinate list, or vector file path.")

        # Select DEM product (currently only SRTM implemented)
        if product.lower() == "srtm":
            dem_img = ee.Image("USGS/SRTMGL1_003")
        else:
            raise NotImplementedError(f"DEM product '{product}' is not implemented.")

        # Reproject to desired spatial resolution
        dem_resampled = dem_img.reproject(crs=dem_img.projection(), scale=spatial_resolution)

        print(ful_path)

        # --- Robust export with size-aware chunking (same strategy as download_bands_gee_chunked) ---
        try:
            # Probe full request to catch "Total request size" errors early
            self._probe_download(dem_resampled, ee_roi, spatial_resolution, crs=getattr(self, "default_crs", "EPSG:4326"))

            # If probe succeeds, do a normal export
            geemap.ee_export_image(
                ee_object=dem_resampled,
                filename=ful_path,
                region=ee_roi,
                scale=spatial_resolution,
                crs=getattr(self, "default_crs", "EPSG:4326"),
            )
            print(f"Downloaded DEM: {ful_path}")
            return

        except Exception as e:
            msg = str(e)
            print(f"Direct DEM export failed: {msg}")

            # Only fall back to chunked download for size-related errors
            if ("Total request size" in msg) or ("less than or equal to" in msg) or ("Pixel grid dimensions" in msg):
                print("Large DEM export detected. Falling back to chunked download.")

                # Use same tiling strategy as export_band_with_fallback
                geometry_bbox = self._get_bbox_from_geometry(ee_roi)
                nx = ny = 2
                max_grid = 512

                base_name = os.path.splitext(os.path.basename(ful_path))[0]

                while nx <= max_grid:
                    tiles = self._split_bbox(geometry_bbox, nx, ny)
                    tile_paths = []
                    print(f"Trying DEM grid {nx}x{ny} ({len(tiles)} chunks)")

                    grid_ok = True
                    for i, tile in enumerate(tiles):
                        chunk_path = os.path.join(out_dir, f"{base_name}_chunk_{i}.tif")

                        # Skip if chunk already exists
                        if os.path.exists(chunk_path):
                            print(f"DEM chunk {i} already exists, skipping download.")
                            tile_paths.append(chunk_path)
                            continue

                        try:
                            tile_geom = ee.Geometry.BBox(*tile)

                            # Probe each chunk to ensure it's within limits
                            self._probe_download(dem_resampled, tile_geom, spatial_resolution, crs=getattr(self, "default_crs", "EPSG:4326"))

                            geemap.ee_export_image(
                                ee_object=dem_resampled,
                                filename=chunk_path,
                                region=tile_geom,
                                scale=spatial_resolution,
                                crs=getattr(self, "default_crs", "EPSG:4326"),
                            )
                            tile_paths.append(chunk_path)

                        except Exception as e2:
                            print(f"DEM chunk {i} failed: {e2}")
                            # cleanup partials from this grid attempt
                            for p in tile_paths:
                                try:
                                    os.remove(p)
                                except Exception:
                                    pass
                            grid_ok = False
                            break

                    if grid_ok and tile_paths:
                        try:
                            self._mosaic_tiles(tile_paths, ful_path)
                            print(f"Downloaded DEM (chunked+mosaic): {ful_path}")
                            return
                        except Exception as em:
                            print(f"Failed to mosaic DEM chunks: {em}")
                            # try a finer grid
                            for p in tile_paths:
                                try:
                                    os.remove(p)
                                except Exception:
                                    pass
                            nx *= 2
                            ny *= 2
                    else:
                        # try a finer grid
                        nx *= 2
                        ny *= 2

                print("Chunked DEM export ultimately failed.")
                return

            # Non-size error: log and do not retry
            print("Non-size error while exporting DEM; not retrying.")
            return
                
    def lat_meters_to_degrees(lat_meters):
        return lat_meters / 111320

    def lon_meters_to_degrees(lon_meters, lat_degrees):
        return lon_meters / (111320 * math.cos(math.radians(lat_degrees))) 

    def map_eto_priestley_taylor(self, input_folder, output_folder,
                                  ta_max_prefix='temperature_2m_max',
                                  ta_min_prefix='temperature_2m_min',
                                  rh_max_prefix='relative_humidity_2m_max',
                                  rh_min_prefix='relative_humidity_2m_min',
                                  rs_mean_prefix='surface_solar_radiation_downwards_sum',
                                  elevation_path='elevation.tif',
                                  prefix_eto='eto_pt', roi_bbox=None,
                                  start_date=None, end_date=None,
                                  unit_temperatures='k',
                                  unit_radiation='j/m2',
                                  alpha=1.26,
                                  verbose=False):

        ti = time.time()
        os.makedirs(output_folder, exist_ok=True)
        rs_files = sorted(glob(os.path.join(input_folder, f"{rs_mean_prefix}_*.tif")))
        if not rs_files:
            print("❌ No input files found for rs_mean_*.tif")
            return

        file_groups = []
        seen_dates = set()
        for path in rs_files:
            match = re.search(r'(\d{8})', os.path.basename(path))
            if not match:
                continue
            date_str = match.group(1)
            if date_str in seen_dates:
                continue

            date = pd.to_datetime(date_str, format="%Y%m%d")
            if start_date and date < pd.to_datetime(parse_date(start_date)):
                continue
            if end_date and date > pd.to_datetime(parse_date(end_date)):
                continue

            group = {
                'ta_max': os.path.join(input_folder, f"{ta_max_prefix}_{date_str}.tif"),
                'ta_min': os.path.join(input_folder, f"{ta_min_prefix}_{date_str}.tif"),
                'rh_max': os.path.join(input_folder, f"{rh_max_prefix}_{date_str}.tif"),
                'rh_min': os.path.join(input_folder, f"{rh_min_prefix}_{date_str}.tif"),
                'rs_mean': os.path.join(input_folder, f"{rs_mean_prefix}_{date_str}.tif"),
                'elevation': elevation_path
            }

            if all(os.path.exists(p) for p in group.values()):
                file_groups.append((date_str, group))
                seen_dates.add(date_str)
            else:
                if verbose:
                    print(f"❌ Missing one or more files for date: {date_str}")

        existing_date_count = 0
        print(f"🛠 Processing {len(file_groups)} Priestley-Taylor ETo dates...")
        for date_str, group in tqdm(file_groups, desc="PT ETo mapping", unit="date"):
            out_path = os.path.join(output_folder, f"{prefix_eto}_{date_str}.tif")
            if os.path.exists(out_path):
                existing_date_count += 1
                if verbose:
                    print(f"⚠️ Skipping existing file: {out_path}")
                continue

            try:
                arrays = {}
                meta = None
                for key, tif_path in group.items():
                    with rasterio.open(tif_path) as src:
                        if roi_bbox:
                            data, transform, m = GeospatialDataToolkit.crop_raster_aligned(src, roi_bbox)
                        else:
                            data = src.read(1).astype("float32")
                            m = src.meta.copy()
                        arrays[key] = data
                        meta = m

                if unit_radiation.lower() == 'w/m2':
                    rs_mean = arrays['rs_mean'] * 0.0864
                elif unit_radiation.lower() == 'j/m2':
                    rs_mean = arrays['rs_mean'] / 1e6
                elif unit_radiation.lower() == 'mj/m2':
                    rs_mean = arrays['rs_mean']
                else:
                    rs_mean = arrays['rs_mean']

                ta_max = arrays['ta_max']
                ta_min = arrays['ta_min']
                if unit_temperatures.lower() == 'k':
                    ta_max -= 273.15
                    ta_min -= 273.15

                ta_mean = (ta_max + ta_min) / 2
                rh_max = arrays['rh_max']
                rh_min = arrays['rh_min']
                elevation = arrays['elevation']

                ta_max_k = ta_max + 273.16
                ta_min_k = ta_min + 273.16

                es_max = 0.6108 * np.exp((17.27 * ta_max) / (ta_max + 237.3))
                es_min = 0.6108 * np.exp((17.27 * ta_min) / (ta_min + 237.3))
                ea_max_term = es_max * (rh_min / 100)
                ea_min_term = es_min * (rh_max / 100)
                ea = (ea_max_term + ea_min_term) / 2

                delta = GeospatialDataToolkit.slope_saturation_vapor_pressure_curve(ta_mean)
                gamma = GeospatialDataToolkit.psychrometric_constant(elevation, ta_mean)

                height, width = ta_max.shape
                lat = np.zeros((height, width), dtype="float32")
                with rasterio.open(group['ta_max']) as ref:
                    rows, cols = np.indices((height, width))
                    _, lat = ref.transform * (cols + 0.5, rows + 0.5)

                ra = GeospatialDataToolkit.extraterrestrial_radiation_daily(lat, GeospatialDataToolkit.doy(date_str))
                rso = (0.75 + (2e-5 * elevation)) * ra
                rns = (1 - GeospatialDataToolkit.ALBEDO) * rs_mean

                rnl = GeospatialDataToolkit.SIGMA * (((ta_max_k ** 4 + ta_min_k ** 4) / 2) *
                               (0.34 - (0.14 * np.sqrt(ea))) *
                               ((1.35 * (rs_mean / rso)) - 0.35))

                rn = rns - rnl
                eto = (alpha * delta * (rn - 0) * 0.408) / (delta + gamma)

                eto = np.clip(eto, 0, 15)

                with rasterio.open(out_path, 'w', **meta) as dst:
                    dst.write(eto.astype("float32"), 1)

                if verbose:
                    print(f"✅ Saved: {out_path}")

            except Exception as e:
                print(f"❌ Failed on {date_str}: {e}")

        duration = time.time() - ti
        print(f"🕒 Duration: {duration:.2f} seconds")
        print(f"✅ Processed {len(file_groups) - existing_date_count} rasters, skipped existing {existing_date_count} rasters.")
        print(f"📁 Output saved in: {output_folder}")
    
    
    def clip_raster_batch(self, input_folder, output_folder, roi,
                          suffix=None,
                          prefix_input=None, prefix_output=None,
                          start_date=None, end_date=None, verbose=False):
        """
        Clip raster files in a folder to a specified vector geometry or bounding box.

        Args:
              input_folder (str): Folder with input raster TIFFs.
              output_folder (str): Folder to save clipped rasters.
              roi: Region of interest. Can be a bbox [minx, miny, maxx, maxy]
                  or a path to a vector file (.shp, .geojson, .json, .parquet, etc.).
              suffix (str or None): Suffix to append to clipped output filenames. If None, no suffix is added.
            prefix_input (str or None): If set, only files whose names start with this prefix are processed.
            prefix_output (str or None): If set, used as the prefix of output filenames.
            start_date (str): Optional filter for file date (YYYY-MM-DD).
            end_date (str): Optional filter for file date (YYYY-MM-DD).
            verbose (bool): Print detailed logging.

        Returns:
            None
        """
        import os
        import rasterio
        from rasterio.mask import mask
        from rasterio.windows import from_bounds
        from glob import glob
        import geopandas as gpd
        import numpy as np
        import pandas as pd
        import re
        from tqdm import tqdm

        os.makedirs(output_folder, exist_ok=True)

        # Build clipping geometry from roi (bbox or vector file)
        clip_shapes = None
        # Case 1: bbox [minx, miny, maxx, maxy]
        if isinstance(roi, (list, tuple)) and len(roi) == 4 and all(isinstance(v, (int, float)) for v in roi):
            minx, miny, maxx, maxy = roi
            clip_shapes = [gpd.GeoSeries.from_bbox((minx, miny, maxx, maxy)).unary_union]
        # Case 2: path to vector file
        elif isinstance(roi, str) and os.path.exists(roi):
            ext = os.path.splitext(roi)[1].lower()
            if ext in [".parquet", ".pq"]:
                gdf = gpd.read_parquet(roi)
            else:
                gdf = gpd.read_file(roi)
            clip_shapes = gdf.geometry.values
        else:
            raise ValueError("roi must be a bbox [minx, miny, maxx, maxy] or a valid vector file path.")

        # Build file list, optionally filtered by input prefix
        if prefix_input is None:
            pattern = '*.tif'
        else:
            pattern = f"{prefix_input}*.tif"

        files = sorted(glob(os.path.join(input_folder, pattern)))
        filtered_files = []
        for f in files:
            match = re.search(r'(\d{8})', os.path.basename(f))
            if match:
                date_str = match.group(1)
                date = pd.to_datetime(date_str, format="%Y%m%d")
                if start_date and date < pd.to_datetime(start_date):
                    continue
                if end_date and date > pd.to_datetime(end_date):
                    continue
                filtered_files.append(f)

        print(f"🛠 Clipping {len(filtered_files)} raster files...")
        for fpath in tqdm(filtered_files, desc="Clipping", unit="file"):
            base = os.path.basename(fpath)

            # Derive output base name
            if prefix_output:
                if prefix_input and base.startswith(prefix_input):
                    # Replace the input prefix with the desired output prefix
                    rest = base[len(prefix_input):]
                    base_out = f"{prefix_output}{rest}"
                else:
                    # Just prepend the output prefix
                    base_out = f"{prefix_output}_{base}"
            else:
                base_out = base

            # Build output filename, respecting optional suffix
            if suffix is None or str(suffix) == "":
                out_fname = base_out
            else:
                if base_out.lower().endswith('.tif'):
                    out_fname = base_out[:-4] + f'_{suffix}.tif'
                else:
                    out_fname = f"{base_out}_{suffix}.tif"
            out_path = os.path.join(output_folder, out_fname)

            if os.path.exists(out_path):
                if verbose:
                    print(f"⚠️ Skipping existing: {out_path}")
                continue

            try:
                with rasterio.open(fpath) as src:
                    out_image, out_transform = mask(src, clip_shapes, crop=True)
                    out_meta = src.meta.copy()
                    out_meta.update({
                        "height": out_image.shape[1],
                        "width": out_image.shape[2],
                        "transform": out_transform
                    })

                    with rasterio.open(out_path, "w", **out_meta) as dest:
                        dest.write(out_image)

                    if verbose:
                        print(f"✅ Saved: {out_path}")
            except Exception as e:
                print(f"❌ Failed on {fpath}: {e}")

        print(f"✅ All clipping operations completed. Output saved in: {output_folder}")
    
    def normalize_rasters(self,
                          input_folder,
                          output_folder,
                          roi=None,
                          prefix_input=None,
                          prefix_output=None,
                          start_date=None,
                          end_date=None,
                          suffix: str = "norm",
                          method: str = "minmax",
                          verbose: bool = False):
        """Apply normalization to rasters in a folder.

        Currently supports per-band min-max scaling using statistics
        computed inside a region of interest (roi).

        Args:
            input_folder (str): Folder with input raster TIFFs.
              output_folder (str): Folder to save normalized rasters.
              roi: Optional region of interest. If provided, can be a bbox
                  [minx, miny, maxx, maxy] or a path to a vector file
                  (.shp, .geojson, .json, .parquet, etc.). If None, stats
                  are computed over the full raster.
            prefix_input (str or None): If set, only files whose names start with this prefix are processed.
            prefix_output (str or None): If set, used as the prefix of output filenames.
            start_date (str or None): Optional filter for file date (YYYY-MM-DD).
            end_date (str or None): Optional filter for file date (YYYY-MM-DD).
            suffix (str): Suffix to append before .tif in output filenames.
            method (str): Normalization method. Currently only 'minmax' is implemented.
            verbose (bool): Print detailed logging.
        """
        import os
        from glob import glob
        import re
        import numpy as np
        import pandas as pd
        import geopandas as gpd
        import rasterio
        from rasterio.mask import mask
        from tqdm import tqdm

        if method.lower() != "minmax":
            raise ValueError("Only 'minmax' normalization is currently supported.")

        os.makedirs(output_folder, exist_ok=True)

        # Build ROI geometry (bbox or vector file) if provided
        clip_shapes = None
        if roi is not None:
            if isinstance(roi, (list, tuple)) and len(roi) == 4 and all(isinstance(v, (int, float)) for v in roi):
                minx, miny, maxx, maxy = roi
                clip_shapes = [gpd.GeoSeries.from_bbox((minx, miny, maxx, maxy)).unary_union]
            elif isinstance(roi, str) and os.path.exists(roi):
                ext = os.path.splitext(roi)[1].lower()
                if ext in [".parquet", ".pq"]:
                    gdf = gpd.read_parquet(roi)
                else:
                    gdf = gpd.read_file(roi)
                clip_shapes = gdf.geometry.values
            else:
                raise ValueError("roi must be a bbox [minx, miny, maxx, maxy] or a valid vector file path when provided.")

        # Build file list, optionally filtered by input prefix
        pattern = "*.tif" if prefix_input is None else f"{prefix_input}*.tif"
        files = sorted(glob(os.path.join(input_folder, pattern)))

        # If start_date/end_date specified, filter by embedded YYYYMMDD in filename;
        # otherwise, keep all files that match the prefix pattern.
        filtered_files = []
        if start_date or end_date:
            for f in files:
                match = re.search(r"(\d{8})", os.path.basename(f))
                if match:
                    date_str = match.group(1)
                    date = pd.to_datetime(date_str, format="%Y%m%d")
                    if start_date and date < pd.to_datetime(start_date):
                        continue
                    if end_date and date > pd.to_datetime(end_date):
                        continue
                    filtered_files.append(f)
        else:
            filtered_files = files

        print(f"🛠 Normalizing {len(filtered_files)} raster files...")

        for fpath in tqdm(filtered_files, desc="Normalizing", unit="file"):
            base = os.path.basename(fpath)

            # Derive output base name
            if prefix_output:
                if prefix_input and base.startswith(prefix_input):
                    rest = base[len(prefix_input):]
                    base_out = f"{prefix_output}{rest}"
                else:
                    base_out = f"{prefix_output}_{base}"
            else:
                base_out = base

            # Build output filename with configurable suffix
            if suffix:
                out_fname = base_out.replace(".tif", f"_{suffix}.tif")
            else:
                out_fname = base_out
            out_path = os.path.join(output_folder, out_fname)

            if os.path.exists(out_path):
                if verbose:
                    print(f"⚠️ Skipping existing: {out_path}")
                continue

            try:
                with rasterio.open(fpath) as src:
                    # Compute per-band stats, using ROI if provided
                    band_mins = []
                    band_maxs = []

                    if clip_shapes is not None:
                        roi_data, _ = mask(src, clip_shapes, crop=True)
                        source_for_stats = roi_data
                    else:
                        source_for_stats = src.read().astype("float32")

                    # source_for_stats: (bands, rows, cols)
                    for i in range(source_for_stats.shape[0]):
                        band = np.ma.masked_invalid(source_for_stats[i])
                        if np.ma.count(band) == 0:
                            band_mins.append(None)
                            band_maxs.append(None)
                            continue
                        band_mins.append(float(band.min()))
                        band_maxs.append(float(band.max()))

                    # Read full raster to apply normalization
                    data = src.read().astype("float32")
                    nodata = src.nodata

                    if nodata is not None:
                        nodata_mask = data == nodata
                        data = np.where(nodata_mask, np.nan, data)

                    for i in range(data.shape[0]):
                        vmin = band_mins[i]
                        vmax = band_maxs[i]
                        if vmin is None or vmax is None or vmax <= vmin:
                            continue

                        band = data[i]
                        valid = ~np.isnan(band)
                        if not np.any(valid):
                            continue

                        denom = vmax - vmin
                        band[valid] = (band[valid] - vmin) / denom
                        data[i] = band

                    if nodata is not None:
                        data = np.where(np.isnan(data), nodata, data)

                    out_meta = src.meta.copy()
                    out_meta.update({"dtype": rasterio.float32})

                    with rasterio.open(out_path, "w", **out_meta) as dst:
                        dst.write(data.astype("float32"))

                    if verbose:
                        print(f"✅ Saved normalized raster: {out_path}")
            except Exception as e:
                print(f"❌ Failed to normalize {fpath}: {e}")

        print(f"✅ All normalization operations completed. Output saved in: {output_folder}")

    def remove_regex_in_name_rasters(self,
                                     input_folder,
                                     output_folder=None,
                                     pattern: str = "",
                                     show_progress: bool = True,
                                     overwrite: bool = False):
        """Remove a regex pattern from raster filenames and copy files.

        Args:
            input_folder (str): Folder containing input raster TIFFs.
            output_folder (str or None): Folder to save renamed rasters.
                If None, files are renamed in-place within input_folder.
            pattern (str): Regular expression to remove from each filename.
            show_progress (bool): If True, display a tqdm progress bar.
            overwrite (bool): If True, overwrite existing files in output_folder.
        """
        import os
        import re
        from glob import glob
        from shutil import copy2
        from tqdm import tqdm

        # If no output folder provided, operate in-place in the input folder
        dest_folder = output_folder or input_folder
        os.makedirs(dest_folder, exist_ok=True)

        files = sorted(glob(os.path.join(input_folder, "*.tif")))
        iterator = tqdm(files, desc="Renaming rasters", unit="file", disable=not show_progress)

        regex = re.compile(pattern) if pattern else None

        for fpath in iterator:
            base = os.path.basename(fpath)

            if regex is not None:
                # Remove all occurrences of the regex pattern from the filename
                new_base = regex.sub("", base)
            else:
                new_base = base

            # If nothing changed, keep original name
            if not new_base:
                new_base = base

            out_path = os.path.join(dest_folder, new_base)

            # If destination equals source path, nothing to do
            if os.path.abspath(out_path) == os.path.abspath(fpath):
                continue

            if os.path.exists(out_path) and not overwrite:
                continue

            # If writing back into the same folder, rename in place; otherwise copy
            if os.path.abspath(os.path.dirname(fpath)) == os.path.abspath(dest_folder):
                os.rename(fpath, out_path)
            else:
                copy2(fpath, out_path)

        print(f"✅ Finished renaming rasters. Output saved in: {dest_folder}")

    def delete_files_regex(self,
                           input_folder,
                           pattern: str,
                           show_progress: bool = True,
                           recursive: bool = False) -> int:
        """
        Delete files in a folder whose names match a regular expression pattern.

        Args:
            input_folder (str): Folder containing files to delete.
            pattern (str): Regular expression; any filename that matches will be deleted.
            show_progress (bool): If True, display a tqdm progress bar.
            recursive (bool): If True, scan subfolders as well; otherwise only the top-level.

        Returns:
            int: Number of files deleted.
        """
        import os
        import re
        from glob import glob
        from tqdm import tqdm

        if not os.path.isdir(input_folder):
            print(f"❌ Input folder does not exist: {input_folder}")
            return 0

        if not pattern:
            print("❌ Empty pattern provided; nothing to delete.")
            return 0

        regex = re.compile(pattern)

        if recursive:
            candidates = glob(os.path.join(input_folder, "**", "*"), recursive=True)
        else:
            candidates = [os.path.join(input_folder, name) for name in os.listdir(input_folder)]

        files = [p for p in candidates if os.path.isfile(p)]
        matches = [p for p in files if regex.search(os.path.basename(p))]

        deleted = 0
        iterator = tqdm(matches, desc="Deleting files", unit="file", disable=not show_progress)
        for fpath in iterator:
            try:
                os.remove(fpath)
                deleted += 1
            except Exception as e:
                print(f"⚠️ Failed to delete {fpath}: {e}")

        print(f"✅ Deleted {deleted} files from: {input_folder}")
        return deleted

    def missing_data_statistics(self, input_folder, variable_prefixes_list, nodata_value=None, roi_bbox=None, start_date=None, end_date=None, verbose=False):
        """
        Generate and pretty print grouped statistics about missing data for each raster variable, including reporting missing dates.

        Args:
            input_folder (str): Folder containing raster TIFFs.
            variable_prefixes_list (list): List of variable name prefixes to analyze.
            nodata_value (float or None): If provided, count this value as missing.
            roi_bbox (tuple or None): Bounding box (minx, miny, maxx, maxy) to restrict analysis.
            start_date (str or None): Start date (YYYY-MM-DD) to filter files.
            end_date (str or None): End date (YYYY-MM-DD) to filter files.
            verbose (bool): Print detailed statistics.

        Returns:
            dict: {variable: {'total_pixels': int, 'missing_pixels': int, 'missing_percentage': float, 'missing_dates': list}}
        """
        import os
        import rasterio
        import numpy as np
        from glob import glob
        from tqdm import tqdm
        from rasterio.windows import from_bounds
        from dateutil.parser import parse as parse_date
        import pandas as pd
        import re

        stats = {}

        for var_prefix in variable_prefixes_list:
            pattern = os.path.join(input_folder, f"{var_prefix}_*.tif")
            files = sorted(glob(pattern))

            filtered_files = {}
            all_dates = []

            for f in files:
                match = re.search(r'(\d{8})', os.path.basename(f))
                if match:
                    date_str = match.group(1)
                    date = pd.to_datetime(date_str, format="%Y%m%d")
                    if start_date and date < pd.to_datetime(parse_date(start_date)):
                        continue
                    if end_date and date > pd.to_datetime(parse_date(end_date)):
                        continue
                    filtered_files[date_str] = f
                    all_dates.append(date_str)

            # Determine expected date range
            expected_dates = []
            if start_date and end_date:
                date_range = pd.date_range(start=start_date, end=end_date, freq='D')
                expected_dates = [d.strftime('%Y%m%d') for d in date_range]

            missing_dates = sorted(list(set(expected_dates) - set(all_dates))) if expected_dates else []

            print(f"🔍 Analyzing {len(filtered_files)} files for variable '{var_prefix}'...")
            total_pixels = 0
            total_missing = 0

            for date_str, tif_path in tqdm(filtered_files.items(), desc=f"Processing {var_prefix}", unit="file"):
                try:
                    with rasterio.open(tif_path) as src:
                        if roi_bbox:
                            data, _, _ = GeospatialDataToolkit.crop_raster_aligned(src, roi_bbox)
                        else:
                            data = src.read(1).astype("float32")

                        file_nodata = src.nodata if src.nodata is not None else nodata_value

                        total = data.size
                        missing = np.count_nonzero(np.isnan(data))

                        if file_nodata is not None:
                            missing += np.count_nonzero(data == file_nodata)

                        total_pixels += total
                        total_missing += missing

                        if verbose:
                            missing_pct = 100 * (missing / total) if total > 0 else 0
                            print(f"  • {os.path.basename(tif_path)}: {missing} missing / {total} total ({missing_pct:.2f}%)")

                except Exception as e:
                    print(f"❌ Failed reading {tif_path}: {e}")

            missing_percentage = 100 * (total_missing / total_pixels) if total_pixels > 0 else 0
            stats[var_prefix] = {
                'total_pixels': total_pixels,
                'missing_pixels': total_missing,
                'missing_percentage': missing_percentage,
                'missing_dates': missing_dates
            }

            print(f"\n📑 Summary for '{var_prefix}': {total_missing} missing / {total_pixels} total ({missing_percentage:.2f}%)")
            if missing_dates:
                print(f"  ⚠️ Missing dates: {', '.join(missing_dates)}")
            print()

        return stats

    def raster_statistics_grouped(self,
                                  input_folder,
                                  variable_prefixes_list,
                                  roi_bbox=None,
                                  start_date=None,
                                  end_date=None,
                                  nodata_value=None,
                                  show_progress: bool = True,
                                  verbose: bool = False):
        """
        Compute and print grouped statistics (min, max, mean, median) for GeoTIFF rasters.

        Files are grouped by their filename prefixes provided in ``variable_prefixes_list``.
        Supports optional ROI clipping via a bounding box and date filtering based on
        YYYYMMDD embedded in the filename.

        Args:
            input_folder (str): Folder containing raster TIFFs.
            variable_prefixes_list (list[str]): List of filename prefixes to group by.
            roi_bbox (tuple or None): Optional bbox [minx, miny, maxx, maxy] to clip before computing stats.
            start_date (str or None): Start date (YYYY-MM-DD) for filtering files.
            end_date (str or None): End date (YYYY-MM-DD) for filtering files.
            nodata_value (float|int or None): Value to treat as missing; if None, uses src.nodata and finite checks.
            show_progress (bool): If True, show a progress bar.
            verbose (bool): If True, print per-file stats.

        Returns:
            dict: {prefix: {"min": float, "max": float, "mean": float, "median": float, "n_files": int, "n_pixels": int}}
        """
        import os
        import re
        from glob import glob
        import numpy as np
        import pandas as pd
        import rasterio
        from rasterio.windows import from_bounds
        from tqdm import tqdm

        results = {}

        for var_prefix in variable_prefixes_list:
            pattern = f"{var_prefix}*.tif"
            files = sorted(glob(os.path.join(input_folder, pattern)))

            # Filter by date if requested
            filtered_files = []
            for f in files:
                m = re.search(r"(\d{8})", os.path.basename(f))
                if m:
                    date_str = m.group(1)
                    date = pd.to_datetime(date_str, format="%Y%m%d")
                    if start_date and date < pd.to_datetime(start_date):
                        continue
                    if end_date and date > pd.to_datetime(end_date):
                        continue
                filtered_files.append(f)

            if not filtered_files:
                print(f"⚠️ No files found for prefix '{var_prefix}' after filtering.")
                results[var_prefix] = {"min": np.nan, "max": np.nan, "mean": np.nan, "median": np.nan, "n_files": 0, "n_pixels": 0}
                continue

            iterator = tqdm(filtered_files, desc=f"Stats: {var_prefix}", unit="file", disable=not show_progress)

            global_min = np.inf
            global_max = -np.inf
            total_sum = 0.0
            total_count = 0
            med_counts = []  # list of (median_value, pixel_count)

            for fpath in iterator:
                try:
                    with rasterio.open(fpath) as src:
                        window = None
                        if roi_bbox is not None and isinstance(roi_bbox, (list, tuple)) and len(roi_bbox) == 4:
                            minx, miny, maxx, maxy = roi_bbox
                            window = from_bounds(minx, miny, maxx, maxy, transform=src.transform)
                        arr = src.read(1, window=window)
                        arr = arr.astype(np.float32, copy=False)

                        # Build mask for valid values
                        mask_valid = np.isfinite(arr)
                        if nodata_value is not None:
                            mask_valid &= (arr != nodata_value)
                        elif src.nodata is not None:
                            mask_valid &= (arr != src.nodata)

                        if not mask_valid.any():
                            if verbose:
                                print(f"   ⚠️ No valid pixels in {os.path.basename(fpath)}")
                            continue

                        vals = arr[mask_valid]

                        # Per-file stats
                        f_min = float(np.min(vals))
                        f_max = float(np.max(vals))
                        f_sum = float(np.sum(vals))
                        f_count = int(vals.size)
                        f_median = float(np.median(vals))

                        # Aggregate
                        global_min = min(global_min, f_min)
                        global_max = max(global_max, f_max)
                        total_sum += f_sum
                        total_count += f_count
                        med_counts.append((f_median, f_count))

                        if verbose:
                            f_mean = f_sum / max(f_count, 1)
                            print(f"   {os.path.basename(fpath)} -> min={f_min:.4f}, max={f_max:.4f}, mean={f_mean:.4f}, median={f_median:.4f}, n={f_count}")

                except Exception as e:
                    print(f"❌ Failed reading {fpath}: {e}")

            if total_count == 0:
                print(f"⚠️ No valid pixels aggregated for prefix '{var_prefix}'.")
                results[var_prefix] = {"min": np.nan, "max": np.nan, "mean": np.nan, "median": np.nan, "n_files": len(filtered_files), "n_pixels": 0}
                continue

            # Weighted median across per-file medians
            med_counts.sort(key=lambda x: x[0])
            cum = 0
            half = total_count / 2.0
            weighted_median = med_counts[0][0]
            for mval, cnt in med_counts:
                cum += cnt
                if cum >= half:
                    weighted_median = mval
                    break

            global_mean = total_sum / total_count

            results[var_prefix] = {
                "min": float(global_min),
                "max": float(global_max),
                "mean": float(global_mean),
                "median": float(weighted_median),
                "n_files": len(filtered_files),
                "n_pixels": int(total_count),
            }

        # Pretty print summary
        print("\n📊 Raster statistics summary:")
        for var_prefix, stats in results.items():
            print(f" - {var_prefix}: min={stats['min']:.4f} | max={stats['max']:.4f} | mean={stats['mean']:.4f} | median={stats['median']:.4f} | files={stats['n_files']} | pixels={stats['n_pixels']}")

        return results

    def harmonize_rasters(self,
                          source_to_fill_raster_prefix,
                          gap_filling_raster_prefix,
                          harmonized_raster_prefix,
                          source_folder,
                          gap_filling_folder,
                          harmonized_folder,
                          roi_bbox=None,
                          start_date='2000-01-01',
                          end_date='2001-01-01',
                          nodata_value=None,
                          overwrite=True,
                          verbose=False):
        """
        Harmonize rasters by filling missing values in source rasters using gap-filling rasters.
        Terra is typically the source, and Aqua is used to fill gaps.

        Args:
            source_to_fill_raster_prefix (str): Prefix of source raster (e.g. 'terra').
            gap_filling_raster_prefix (str): Prefix of secondary raster (e.g. 'aqua').
            harmonized_raster_prefix (str): Prefix for output files (e.g. 'harmonized').
            source_folder (str): Folder containing source rasters.
            gap_filling_folder (str): Folder containing gap-filling rasters.
            harmonized_folder (str): Output folder for harmonized rasters.
            roi_bbox (tuple): Bounding box (minx, miny, maxx, maxy).
            start_date (str): Start date (YYYY-MM-DD).
            end_date (str): End date (YYYY-MM-DD).
            nodata_value (float|int or None): Value considered as missing.
            overwrite (bool): Whether to overwrite existing harmonized rasters.
            verbose (bool): Print detailed per-file stats.

        Returns:
            None
        """
        os.makedirs(harmonized_folder, exist_ok=True)

        date_range = pd.date_range(start=start_date, end=end_date, freq='D')
        processed = 0

        for date in tqdm(date_range, desc="Harmonizing", unit="day"):
            date_str = date.strftime("%Y%m%d")
            source_fp = source_folder + f"/{source_to_fill_raster_prefix}_{date_str}.tif"
            gap_fp = gap_filling_folder + f"/{gap_filling_raster_prefix}_{date_str}.tif"
            output_fp = harmonized_folder + f"/{harmonized_raster_prefix}_{date_str}.tif"

            if not overwrite and os.path.exists(output_fp):
                continue

            if not os.path.exists(source_fp) or not os.path.exists(gap_fp):
                if verbose:
                    print(f"⚠️ Missing raster(s) files for {date} — skipped")
                    print(f"  Source: {source_fp}")
                    print(f"Or  Gap-filling: {gap_fp}")
                continue

            try:
                with rasterio.open(source_fp) as src1, rasterio.open(gap_fp) as src2:
                    if roi_bbox:
                        # Get pixel-aligned window from bounding box
                        window = src1.window(*roi_bbox)
                        window = window.round_offsets().round_lengths()  # 🔒 important to align perfectly
                        data1 = src1.read(1, window=window).astype("float32")
                        data2 = src2.read(1, window=window).astype("float32")
                        transform = src1.window_transform(window)
                        height, width = data1.shape
                    else:
                        data1 = src1.read(1).astype('float32')
                        data2 = src2.read(1).astype('float32')
                        transform = src1.transform
                        height, width = src1.height, src1.width

                    if nodata_value is None:
                        nodata_value = np.nan

                    mask = np.isnan(data1)
                    if nodata_value is not None:
                        mask |= (data1 == nodata_value)

                    filled = np.where(mask, data2, data1)

                    profile = src1.profile
                    profile.update(
                        dtype='float32',
                        height=height,
                        width=width,
                        transform=transform,
                        crs=src1.crs,
                        compress='lzw',
                        nodata=nodata_value
                    )

                    with rasterio.open(output_fp, 'w', **profile) as dst:
                        dst.write(filled, 1)


                    if verbose:
                        filled_count = np.count_nonzero(mask)
                        print(f"✅ {date_str}: Filled {filled_count} pixels → {os.path.basename(output_fp)}")

                    processed += 1

            except Exception as e:
                print(f"❌ Failed to process {date_str}: {e}")

        print(f"\n✅ Harmonization complete: {processed} files generated in '{harmonized_folder}'\n")

    
    
    def count_value_occurrences(self, input_folder, variable_prefixes_list, value_to_count, roi_bbox=None, start_date=None, end_date=None, verbose=False):
        """
        Count occurrences of a specific value for raster variables, supporting date and bbox filtering.

        Args:
            input_folder (str): Folder containing raster files.
            variable_prefixes_list (list): List of variable prefixes (e.g., ['ndvi', 'temp']).
            value_to_count (float or int): Value to count occurrences for.
            roi_bbox (tuple or None): Bounding box (minx, miny, maxx, maxy) to clip before counting.
            start_date (str or None): Start date filter (YYYY-MM-DD).
            end_date (str or None): End date filter (YYYY-MM-DD).
            verbose (bool): Print detailed per-file stats.

        Returns:
            dict: {variable_prefix: {'total_occurrences': int, 'file_occurrences': {filename: count}}}
        """
        stats = {}

        for var_prefix in variable_prefixes_list:
            pattern = os.path.join(input_folder, f"{var_prefix}_*.tif")
            files = sorted(glob(pattern))

            filtered_files = {}
            all_dates = []

            for f in files:
                match = re.search(r'(\d{8})', os.path.basename(f))
                if match:
                    date_str = match.group(1)
                    date = pd.to_datetime(date_str, format="%Y%m%d")
                    if start_date and date < pd.to_datetime(parse_date(start_date)):
                        continue
                    if end_date and date > pd.to_datetime(parse_date(end_date)):
                        continue
                    filtered_files[date_str] = f
                    all_dates.append(date_str)

            print(f"🔎 Counting value `{value_to_count}` in {len(filtered_files)} files for variable '{var_prefix}'...")

            total_occurrences = 0
            file_occurrences = {}

            for date_str, tif_path in tqdm(filtered_files.items(), desc=f"Processing {var_prefix}", unit="file"):
                try:
                    with rasterio.open(tif_path) as src:
                        if roi_bbox:
                            window = src.window(*roi_bbox)
                            window = window.round_offsets().round_lengths()  # Ensure pixel alignment
                            data = src.read(1, window=window)
                        else:
                            data = src.read(1)

                        count = np.count_nonzero(data == value_to_count)
                        file_occurrences[os.path.basename(tif_path)] = count
                        total_occurrences += count

                        if verbose:
                            print(f"  • {os.path.basename(tif_path)}: {count} occurrences")

                except Exception as e:
                    print(f"❌ Failed reading {tif_path}: {e}")

            stats[var_prefix] = {
                'total_occurrences': total_occurrences,
                'file_occurrences': file_occurrences
            }

            print(f"\n📑 Summary for '{var_prefix}': {total_occurrences} occurrences of value `{value_to_count}`\n")

        return stats
    
    
    def count_expression_occurrences(self,
                                    input_folder,
                                    variable_prefixes_list,
                                    expression_lambda_fn,
                                    roi_bbox=None,
                                    start_date=None,
                                    end_date=None,
                                    verbose=False):
        """
        Count the number of pixels satisfying a condition (expression) for raster variables, with support for date and ROI filters.

        Args:
            input_folder (str): Folder containing raster TIFFs.
            variable_prefixes_list (list): List of variable name prefixes (e.g., ['ndvi', 'temp']).
            expression_fn (function): A lambda or function like `lambda x: x < 0` to apply on each pixel array.
            roi_bbox (tuple or None): Bounding box (minx, miny, maxx, maxy) to restrict analysis.
            start_date (str or None): Start date (YYYY-MM-DD) to filter files.
            end_date (str or None): End date (YYYY-MM-DD) to filter files.
            verbose (bool): Print detailed statistics per file.

        Returns:
            dict: {variable: {'total_occurrences': int, 'file_occurrences': {filename: count}}}
        """
        import os
        import rasterio
        import numpy as np
        from glob import glob
        from tqdm import tqdm
        from rasterio.windows import from_bounds
        from dateutil.parser import parse as parse_date
        import pandas as pd
        import re

        stats = {}

        for var_prefix in variable_prefixes_list:
            pattern = os.path.join(input_folder, f"{var_prefix}_*.tif")
            files = sorted(glob(pattern))

            filtered_files = {}
            all_dates = []

            for f in files:
                match = re.search(r'(\d{8})', os.path.basename(f))
                if match:
                    date_str = match.group(1)
                    date = pd.to_datetime(date_str, format="%Y%m%d")
                    if start_date and date < pd.to_datetime(parse_date(start_date)):
                        continue
                    if end_date and date > pd.to_datetime(parse_date(end_date)):
                        continue
                    filtered_files[date_str] = f
                    all_dates.append(date_str)

            print(f"🔎 Evaluating expression on {len(filtered_files)} files for variable '{var_prefix}'...")

            total_occurrences = 0
            file_occurrences = {}

            for date_str, tif_path in tqdm(filtered_files.items(), desc=f"Processing {var_prefix}", unit="file"):
                try:
                    with rasterio.open(tif_path) as src:
                        if roi_bbox:
                            window = src.window(*roi_bbox)
                            window = window.round_offsets().round_lengths()  # Ensure pixel alignment
                            data = src.read(1, window=window)
                        else:
                            data = src.read(1)

                        condition_mask = expression_lambda_fn(data)
                        count = np.count_nonzero(condition_mask)

                        file_occurrences[os.path.basename(tif_path)] = count
                        total_occurrences += count

                        if verbose:
                            print(f"  • {os.path.basename(tif_path)}: {count} matching pixels")

                except Exception as e:
                    print(f"❌ Failed reading {tif_path}: {e}")

            stats[var_prefix] = {
                'total_occurrences': total_occurrences,
                'file_occurrences': file_occurrences
            }

            print(f"\n📑 Summary for '{var_prefix}': {total_occurrences} total matching pixels\n")

        return stats

    
    def zfill_rasters_to_reference(self,
                                  input_folder,
                                  output_folder,
                                  reference_tif,
                                  input_prefix,
                                  output_prefix,
                                  fill_value=None,
                                  roi_bbox=None,
                                  start_date='2000-01-01',
                                  end_date='2001-01-01',
                                  overwrite=True,
                                  verbose=False):
        """
        Resize raster files to match the extent and shape of a reference raster, 
        filling any added areas with a specified value.
        
        Parameters:
        -----------
        input_folder : str
            Folder containing input rasters to resize.
        output_folder : str
            Folder to save resized rasters.
        reference_tif : str
            Path to the reference raster that defines the target extent and resolution.
        input_prefix : str
            Filename prefix to process.
        output_prefix : str
            Prefix to use in output files.
        fill_value : float or None
            Value to fill in added pixels. If None, will use the nodata value of each source raster.
        roi_bbox : list
            Optional bounding box [minx, miny, maxx, maxy] to crop results.
        start_date : str
            Start date in YYYY-MM-DD format.
        end_date : str
            End date in YYYY-MM-DD format.
        overwrite : bool
            Whether to overwrite existing files.
        verbose : bool
            Print detailed progress info.
        
        Returns:
        --------
        None
        """
        from glob import glob
        from rasterio.warp import reproject, Resampling, calculate_default_transform
        from rasterio.windows import from_bounds
        from tqdm import tqdm
        from datetime import datetime
        import numpy as np
        import pandas as pd
        import os
    
        os.makedirs(output_folder, exist_ok=True)
    
        # Parse date range
        date_range = pd.date_range(start=start_date, end=end_date, freq='D')
    
        # Read reference raster to get target metadata
        with rasterio.open(reference_tif) as ref:
            ref_crs = ref.crs
            ref_transform = ref.transform
            ref_width = ref.width
            ref_height = ref.height
            ref_bounds = ref.bounds
            ref_profile = ref.profile.copy()
            ref_nodata = ref.nodata
    
        # Initialize counter for processed files
        processed_count = 0
    
        # Create iterator with progress bar
        for date in tqdm(date_range, desc="Zfilling rasters", unit="day"):
            date_str = date.strftime("%Y%m%d")
    
            in_fp = os.path.join(input_folder, f"{input_prefix}_{date_str}.tif")
            out_fp = os.path.join(output_folder, f"{output_prefix}_{date_str}.tif")
    
            # Skip if input doesn't exist
            if not os.path.exists(in_fp):
                if verbose:
                    print(f"❌ Input file does not exist: {in_fp}")
                continue
    
            # Skip if output exists and we're not overwriting
            if not overwrite and os.path.exists(out_fp):
                if verbose:
                    print(f"⚠️ Output exists, skipping: {out_fp}")
                continue
    
            try:
                with rasterio.open(in_fp) as src:
                    src_nodata = src.nodata
                    # Use source nodata value if fill_value is None
                    fill_val = fill_value if fill_value is not None else src_nodata
                    
                    # Prepare destination array (filled with the fill value)
                    dst_array = np.full((ref_height, ref_width), fill_val, dtype=src.dtypes[0])
                    
                    # Reproject source data to reference grid
                    reproject(
                        source=rasterio.band(src, 1),
                        destination=dst_array,
                        src_transform=src.transform,
                        src_crs=src.crs,
                        dst_transform=ref_transform,
                        dst_crs=ref_crs,
                        resampling=Resampling.nearest,  # Use nearest for discrete data, bilinear for continuous
                        src_nodata=src_nodata,
                        dst_nodata=fill_val
                    )
                    
                    # Prepare output profile
                    out_profile = ref_profile.copy()
                    out_profile.update(
                        dtype=src.dtypes[0],
                        count=1,
                        nodata=fill_val,
                        compress='lzw'
                    )
                    
                    # Apply ROI crop if specified
                    if roi_bbox:
                        with rasterio.open(reference_tif) as ref:
                            window = ref.window(*roi_bbox)
                            window = window.round_offsets().round_lengths()  # Ensure pixel alignment
                            transform = ref.window_transform(window)
                            
                            # Crop the data
                            dst_array = dst_array[
                                int(window.row_off):int(window.row_off + window.height),
                                int(window.col_off):int(window.col_off + window.width)
                            ]
                            
                            # Update profile for cropped output
                            out_profile.update(
                                height=dst_array.shape[0],
                                width=dst_array.shape[1],
                                transform=transform
                            )
                    
                    # Write output raster
                    with rasterio.open(out_fp, 'w', **out_profile) as dst:
                        dst.write(dst_array, 1)
                    
                    if verbose:
                        print(f"✅ Zfilled: {out_fp}")
                    
                    processed_count += 1
    
            except Exception as e:
                print(f"❌ Failed to zfill {in_fp}: {e}")
    
        print(f"\n✅ Zfilling complete: {processed_count} rasters saved in '{output_folder}'\n")
    

    def align_rasters_to_reference(self,
                                input_folder,
                                output_folder,
                                reference_tif,
                                input_prefix,
                                output_prefix=None,
                                roi_bbox=None,
                                start_date='2000-01-01',
                                end_date='2001-01-01',
                                resampling_method=Resampling.nearest,
                                overwrite=True,
                                verbose=False):
        """
        Align all raster files in a folder to match the CRS, resolution, shape, and transform of a reference raster,
        optionally cropping to an ROI. The resampling is by default set to nearest neighbor, which preserves exact pixel values (no interpolation unless absolutely necessary).

        Args:
            input_folder (str): Folder containing input rasters.
            output_folder (str): Folder to save aligned rasters.
            reference_tif (str): Path to the reference raster.
            input_prefix (str): Filename prefix to process.
            output_prefix (str): Prefix to use in aligned output files.
            roi_bbox (list): Optional bounding box [minx, miny, maxx, maxy].
            start_date (str): Start date in YYYY-MM-DD format.
            end_date (str): End date in YYYY-MM-DD format.
            resampling_method (rasterio.enums.Resampling): Resampling method to use.
            overwrite (bool): Whether to overwrite existing files.
            verbose (bool): Print detailed progress info.

        Returns:
            None
        """
        import os
        from glob import glob
        import rasterio
        from rasterio.warp import reproject, Resampling
        from rasterio.windows import from_bounds
        import numpy as np
        import pandas as pd
        from tqdm import tqdm

        os.makedirs(output_folder, exist_ok=True)

        date_range = pd.date_range(start=start_date, end=end_date, freq='D')

        with rasterio.open(reference_tif) as ref:
            ref_crs = ref.crs
            ref_transform = ref.transform
            ref_width = ref.width
            ref_height = ref.height
            ref_profile = ref.profile.copy()

        aligned_count = 0

        for date in tqdm(date_range, desc="Aligning", unit="day"):
            date_str = date.strftime("%Y%m%d")

            in_fp = os.path.join(input_folder, f"{input_prefix}_{date_str}.tif")
            if not output_prefix:
                out_fp = os.path.join(output_folder, f"{input_prefix}_{date_str}.tif")
            else:
                out_fp = os.path.join(output_folder, f"{output_prefix}_{input_prefix}_{date_str}.tif")

            
            if not os.path.exists(in_fp):
                print(f'File does not exist: {in_fp}')
                continue

            if not overwrite and os.path.exists(out_fp):
                continue

            try:
                with rasterio.open(in_fp) as src:
                    src_data = src.read(1).astype('float32')
                    src_transform = src.transform
                    src_crs = src.crs

                    if roi_bbox:
                        src_data, src_transform, _ = self.crop_raster_aligned(src, roi_bbox)

                    dst_array = np.empty((ref_height, ref_width), dtype='float32')

                    reproject(
                        source=src_data,
                        destination=dst_array,
                        src_transform=src_transform,
                        src_crs=src_crs,
                        dst_transform=ref_transform,
                        dst_crs=ref_crs,
                        resampling=resampling_method,
                    )

                    out_profile = ref_profile.copy()
                    out_profile.update(dtype='float32', compress='lzw')

                    with rasterio.open(out_fp, 'w', **out_profile) as dst:
                        dst.write(dst_array, 1)

                    if verbose:
                        print(f"✅ Aligned: {out_fp}")

                    aligned_count += 1

            except Exception as e:
                print(f"❌ Failed to align {in_fp}: {e}")

        print(f"\n✅ Alignment complete: {aligned_count} rasters saved in '{output_folder}'\n")
    
    def upsampling_rasters(self,
                            input_folder,
                            reference_tif,
                            output_folder,
                            input_prefix,
                            output_prefix=None,
                            start_date='2000-01-01',
                            end_date='2001-01-01',
                            resampling_method=Resampling.nearest):
        """Upsample rasters to match the grid of a reference raster.

        This resamples each daily raster matching ``input_prefix`` onto the
        spatial grid (CRS, transform, resolution, width, height) of
        ``reference_tif``, using a chosen resampling method (nearest-neighbor
        by default, or bilinear for continuous fields).

        Args:
            input_folder (str): Folder containing input rasters to upsample.
            reference_tif (str): Path to the reference raster defining target grid.
            output_folder (str): Folder to save upsampled rasters.
            input_prefix (str): Filename prefix of input rasters.
            output_prefix (str or None): Prefix for output files. If None,
                the input_prefix is preserved.
            start_date (str): Start date (YYYY-MM-DD).
            end_date (str): End date (YYYY-MM-DD).
            resampling_method (rasterio.enums.Resampling): Resampling method
                to use (e.g. Resampling.nearest, Resampling.bilinear).

        Returns:
            None
        """
        import os
        import numpy as np
        import rasterio
        from rasterio.warp import reproject, Resampling
        import pandas as pd
        from tqdm import tqdm

        os.makedirs(output_folder, exist_ok=True)

        # Target grid from reference
        with rasterio.open(reference_tif) as ref:
            ref_crs = ref.crs
            ref_transform = ref.transform
            ref_width = ref.width
            ref_height = ref.height
            ref_profile = ref.profile.copy()

        date_range = pd.date_range(start=start_date, end=end_date, freq='D')
        processed_count = 0

        for date in tqdm(date_range, desc="Upsampling", unit="day"):
            date_str = date.strftime("%Y%m%d")

            in_fp = os.path.join(input_folder, f"{input_prefix}_{date_str}.tif")
            if output_prefix is None:
                out_fp = os.path.join(output_folder, f"{input_prefix}_{date_str}.tif")
            else:
                out_fp = os.path.join(output_folder, f"{output_prefix}_{input_prefix}_{date_str}.tif")

            if not os.path.exists(in_fp):
                continue

            try:
                with rasterio.open(in_fp) as src:
                    src_data = src.read(1).astype("float32")
                    src_transform = src.transform
                    src_crs = src.crs
                    src_nodata = src.nodata

                dst_array = np.empty((ref_height, ref_width), dtype="float32")

                reproject(
                    source=src_data,
                    destination=dst_array,
                    src_transform=src_transform,
                    src_crs=src_crs,
                    dst_transform=ref_transform,
                    dst_crs=ref_crs,
                    resampling=resampling_method,
                    src_nodata=src_nodata,
                    dst_nodata=src_nodata,
                )

                out_profile = ref_profile.copy()
                out_profile.update(
                    dtype="float32",
                    count=1,
                    nodata=src_nodata,
                    compress="lzw",
                )

                with rasterio.open(out_fp, "w", **out_profile) as dst:
                    dst.write(dst_array, 1)

                processed_count += 1

            except Exception as e:
                print(f"❌ Failed to upsample {in_fp}: {e}")

        print(f"\n✅ Upsampling complete: {processed_count} rasters saved in '{output_folder}'\n")
    
    def scale_offset_rasters(self,
                            input_folder,
                            output_folder,
                            input_prefix,
                            output_prefix=None,
                            start_date='2000-01-01',
                            end_date='2001-01-01',
                            scale: float = 1.0,
                            offset: float = 0.0,
                            nan_val=None,
                            overwrite=True,
                            verbose=False):
        """Apply only scale/offset (and optional NaN replacement) to a date series of rasters.

        This does *not* perform any alignment or reprojection. It simply reads each
        input raster, optionally replaces a specific value by NaN, applies
        ``value * scale + offset``, and writes to ``output_folder`` keeping the
        original grid and metadata.

        Args:
            input_folder (str): Folder containing input rasters.
            output_folder (str): Folder to save processed rasters.
            input_prefix (str): Filename prefix to process.
            output_prefix (str): Prefix to use in output files. If ``None``, reuse ``input_prefix``.
            start_date (str): Start date in YYYY-MM-DD format.
            end_date (str): End date in YYYY-MM-DD format.
            scale (float): Multiplicative scale to apply to values.
            offset (float): Additive offset to apply after scaling.
            nan_val (float or int or None): If provided, replace this value by ``NaN`` before
                scaling/offset.
            overwrite (bool): Whether to overwrite existing files.
            verbose (bool): Print detailed progress info.

        Returns:
            None
        """
        import os
        import rasterio
        import numpy as np
        import pandas as pd
        from tqdm import tqdm

        os.makedirs(output_folder, exist_ok=True)

        date_range = pd.date_range(start=start_date, end=end_date, freq='D')

        processed_count = 0

        for date in tqdm(date_range, desc="Scale/offset", unit="day"):
            date_str = date.strftime("%Y%m%d")

            in_fp = os.path.join(input_folder, f"{input_prefix}_{date_str}.tif")
            if not output_prefix:
                out_fp = os.path.join(output_folder, f"{input_prefix}_{date_str}.tif")
            else:
                out_fp = os.path.join(output_folder, f"{output_prefix}_{input_prefix}_{date_str}.tif")

            if not os.path.exists(in_fp):
                if verbose:
                    print(f"File does not exist: {in_fp}")
                continue

            if not overwrite and os.path.exists(out_fp):
                if verbose:
                    print(f"Output exists, skipping: {out_fp}")
                continue

            try:
                with rasterio.open(in_fp) as src:
                    data = src.read().astype("float32")  # [bands, H, W]
                    profile = src.profile.copy()

                # Apply NaN replacement if requested
                if nan_val is not None:
                    data[data == nan_val] = np.nan

                # Apply scale and offset
                if scale != 1.0 or offset != 0.0:
                    data = data * scale + offset

                # Force float32 if scaling/offsetting
                profile.update(dtype="float32", compress="lzw")

                with rasterio.open(out_fp, "w", **profile) as dst:
                    dst.write(data)

                if verbose:
                    print(f"✅ Scaled/offset: {out_fp}")

                processed_count += 1

            except Exception as e:
                print(f"❌ Failed to process {in_fp}: {e}")

        print(f"\n✅ Scale/offset complete: {processed_count} rasters saved in '{output_folder}'\n")
    
    def download_era5_land_roi(self, variables_list, roi_bbox=[-18.0, -35.0, 52.0, 38.0], start_date='2000-01-01', end_date='2001-01-01', backend="gee", storage_format="zarr", output_folder="era5_land_africa_eto"):
        """
        Download ERA5-Land data for a given region of interest (ROI) and date range.

        Args:
            variables (list): List of variables to download (e.g., ['temperature_2m_max']).
            roi (ee.Geometry.Polygon): Region of interest in Earth Engine format.
            start_date (str): Start date (YYYY-MM-DD).
            end_date (str): End date (YYYY-MM-DD).
            backend (str): Source of data ('gee' for Google Earth Engine).
            storage_format (str): 'zarr' or 'netcdf'.
        """

        if isinstance(start_date, str) and isinstance(end_date, str):
            start_date = datetime.strptime(start_date, '%Y-%m-%d')
            end_date = datetime.strptime(end_date, '%Y-%m-%d')

        roi = ee.Geometry.BBox(*roi_bbox)

        if backend != "gee":
            raise NotImplementedError("Only 'gee' backend is currently supported.")

