    @staticmethod    
    def clip_raster_with_vector(
        raster_path,
        vector_path,
        output_path='clipped_raster.tif',
        vector_type='shp'):
        """
        Clips a raster file using a vector file and saves the output to a new file.

        Parameters:
        ----------
        raster_path : str
            The file path to the raster file (GeoTIFF).
        vector_path : str
            The file path to the vector file (e.g., shapefile or GeoJSON).
        output_path : str, optional
            The file path where the clipped raster will be saved (default is 'clipped_raster.tif').
        vector_type : str, optional
            The format of the vector file. Use 'shp' for shapefiles or 'geojson' for GeoJSON files (default is 'shp').

        Returns:
        -------
        None
        """
        
        # Check if the output file already exists
        if os.path.exists(output_path):
            print(f"File '{output_path}' already exists. Skipping processing.")
            return
        
        # Read the vector file using GeoPandas
        if vector_type == 'shp':
            vector_data = gpd.read_file(vector_path)
        elif vector_type == 'geojson':
            vector_data = gpd.read_file(vector_path)
        else:
            raise ValueError(f"Unsupported vector type: {vector_type}. Use 'shp' or 'geojson'.")
        
        with ProgressBar():
            # Open the raster file using rioxarray with Dask chunks for parallel reading
            raster = rioxarray.open_rasterio(raster_path, chunks=True)

            # Ensure the vector file is in the same CRS as the raster
            if vector_data.crs != raster.rio.crs:
                vector_data = vector_data.to_crs(raster.rio.crs)

            # Ensure the raster and shapefile have the same coordinate reference system (CRS)
            # Reproject the shapefile if necessary
            if not raster.rio.crs == vector_data.crs:
                vector_data = vector_data.to_crs(raster.rio.crs)

            # Clip the raster using the geometry of the shapefile
            # The geometry needs to be converted to GeoJSON-like format using shapely.mapping
            clipped_raster = raster.rio.clip(vector_data.geometry.apply(mapping), vector_data.crs)

            # Display the clipped raster's information
            print(clipped_raster)

            # Save the clipped raster to a new file
            clipped_raster.rio.to_raster(output_path)
            
            # Print confirmation message after saving the file
            print(f"File exported: {output_path}")
        
    @staticmethod
    def stack_rasters_time(
        raster_paths_as_list,
        date_start,
        freq='MS'
        ):
        
        # Step 1: Create a list to store the DataArrays
        raster_list = []

        # Step 2: Convert start_date to a pandas Timestamp
        current_date = pd.Timestamp(date_start)
        
        # Step 3: Iterate over the raster paths, load each raster, and assign the corresponding time
        for i, raster_path in enumerate(raster_paths_as_list):
            # Open each raster file using rioxarray
            raster = rioxarray.open_rasterio(raster_path, chunks=True)
            
            # Add the time dimension using the current date
            raster = raster.expand_dims(time=[current_date])
            
            # Append the raster to the list
            raster_list.append(raster)

            # Move to the next month
            current_date += pd.DateOffset(months=1)
        
        # Step 4: Concatenate all rasters along the time dimension
        stacked_raster = xr.concat(raster_list, dim="time")
        
        return stacked_raster
    
    @staticmethod
    def resample_tif_to_match_destination_tif(source_tif, destination_tif, output_tif='resampled.tif'):
        """
        Resamples a source TIFF file to match the resolution of a destination TIFF file
        using Dask for chunked processing and saves the output.

        Parameters:
        ----------
        source_tif : str
            The path to the source TIFF file.
        destination_tif : str
            The path to the destination TIFF file (the one whose resolution will be matched).
        output_tif : str
            The path where the resampled TIFF will be saved.
        """
        
        # Check if the output file already exists
        if os.path.exists(output_tif):
            print(f"File '{output_tif}' already exists. Skipping processing.")
            return

        with ProgressBar():
            # Step 1: Open the source and destination TIFF files using Dask chunking
            source_raster = rioxarray.open_rasterio(source_tif, chunks=True)  # Enable chunking with dask
            destination_raster = rioxarray.open_rasterio(destination_tif, chunks=True)  # Enable chunking with dask

            # Step 2: Get the resolution (pixel size) from the destination TIFF
            # Resolution is usually a tuple: (pixel_width, pixel_height)
            destination_resolution = destination_raster.rio.resolution()

            # Step 3: Resample the source raster to match the destination resolution
            # Use a resampling method suitable for the data type (nearest, bilinear, etc.)
            resampled_raster = source_raster.rio.reproject(
                destination_raster.rio.crs,  # Reproject to match the destination CRS
                resolution=destination_resolution,  # Set resolution to match the destination
                resampling=Resampling.bilinear  # Choose resampling method (e.g., bilinear for continuous data)
            )

            # Use ProgressBar to monitor Dask computations
            
            # Step 4: Save the resampled raster to the output file (this will trigger Dask computation)
            resampled_raster.rio.to_raster(output_tif)

        # Print confirmation message
        print(f"Resampled TIFF saved to {output_tif} with resolution {destination_resolution}")

    @staticmethod
    def mean_time_series(stacked_raster_with_time, freq='MS'):
        # 1. Calculate the mean along the time dimension
        mean_time_series = stacked_raster_with_time.mean(dim='time')
        
        #Instead of .compute(), you can use .persist() to keep intermediate results in memory across computations. This is useful if you need to perform multiple operations on the same dataset:
