    # Define a function to calculate LAI
    @staticmethod
    def estimate_lai_landsat8(image):
        """Estimate LAI based on equations 18 and 19 of METRIC allen et al. paper (2007)

        Args:
            image (_type_): _description_

        Returns:
            _type_: _description_
        """
        savi_expression = '((1 + L)*(B4 - B3))/(L + (B4 + B3))'
        savi_image = image.expression(savi_expression, {'B4': image.select("B4"), 
                                                        'B3': image.select("B3"),
                                                        'L': 0.5 # refer to the paper
                                                        }).rename('savi')
        image = image.addBands(savi_image)
        lai_expression = 'log((0.69 - savi)/0.59)/0.91'
        lai_image = image.expression(lai_expression, {'savi': image.select("savi"), 
                                                        }).rename('lai')
        
        
        lai_empirical_ndvi_expression = '−0.0897 + 1.424 * ndvi'
        return image.addBands(lai_image)
    
    # Define a function to calculate LAI
    @staticmethod
    def estimate_lai_landsat8_ndvi(image):
        """Estimate LAI based on equations 18 and 19 of METRIC allen et al. paper (2007)

        Args:
            image (_type_): _description_

        Returns:
            _type_: _description_
        """
        
        ndvi = image.normalizedDifference(['SR_B5', 'SR_B4']).rename('ndvi')
        image = image.addBands(ndvi)
        
        # forest
        #a, b = 0.899, 0.013
        
        # grasslands
        a, b = 0.731, 0.083
        
        # agricultural lands
        #a, b = 0.604, 0.166
        
        lai_empirical_ndvi_expression = '(a * ndvi) + b'
        lai_image = image.expression(lai_empirical_ndvi_expression, {'ndvi': image.select("ndvi"),
                                                                     'a': a,
                                                                     'b': b 
                                                        }).rename('lai')
        
        return image.addBands(lai_image)
    
    @staticmethod
    def calculate_salinity_indices_sentinel2(image):
        # Calculate the SRSI index
        NDVI = image.expression('(B8 - B4) / (B8 + B4)', {'B8': image.select("B8"), 'B4': image.select("B4")}).rename('NDVI')
        # Calculate the salinity indices
        SI_image = image.expression('(B3 + B4)**0.5', {'B3': image.select("B3"), 'B4': image.select("B4")}).rename('SI')
        SI1_image = image.expression('(B3 * B4)**0.5', {'B3': image.select("B3"), 'B4': image.select("B4")}).rename('SI1')
        SI2_image = image.expression('(B8**2 + B3**2 + B4**2)**0.5', {'B8': image.select("B8"), 'B3': image.select("B3"), 'B4': image.select("B4")}).rename('SI2')
        SI3_image = image.expression('(B3**2 + B4**2)**0.5', {'B3': image.select("B3"), 'B4': image.select("B4")}).rename('SI3')
        SI4_image = image.expression('B11 / B8', {'B11': image.select("B11"), 'B8': image.select("B8")}).rename('SI4')
        S1_image = image.expression('B2 / B4', {'B2': image.select("B2"), 'B4': image.select("B4")}).rename('S1')
        S2_image = image.expression('(B2 - B4) / (B2 + B4)', {'B2': image.select("B2"), 'B4': image.select("B4")}).rename('S2')
        S3_image = image.expression('B3 * B4 / B2', {'B3': image.select("B3"), 'B4': image.select("B4"), 'B2': image.select("B2")}).rename('S3')
        S5_image = image.expression('B2 * B4 / B3', {'B2': image.select("B2"), 'B4': image.select("B4"), 'B3': image.select("B3")}).rename('S5')
        S6_image = image.expression('B4 * B8 / B3', {'B4': image.select("B4"), 'B8': image.select("B8"), 'B3': image.select("B3")}).rename('S6')
        S7_image = image.expression('(B11 - B12) / (B11 + B12)', {'B11': image.select("B11"), 'B12': image.select("B12")}).rename('S7')
        S8_image = image.expression('(B3 + B4) / 2', {'B3': image.select("B3"), 'B4': image.select("B4")}).rename('S8')
        S9_image = image.expression('(B3 + B4 + B8) / 2', {'B3': image.select("B3"), 'B4': image.select("B4"), 'B8': image.select("B8")}).rename('S9')
        SI_T_image = image.expression('B4 / B8 * 100', {'B4': image.select("B4"), 'B8': image.select("B8")}).rename('SI_T')
        SSSI_1_image = image.expression('B4 - B8', {'B4': image.select("B4"), 'B8': image.select("B8")}).rename('SSSI_1')
        SSSI_2_image = image.expression('(B4 * B8 - B8 * B8) / B4', {'B4': image.select("B4"), 'B8': image.select("B8")}).rename('SSSI_2')
        NDSI_image = image.expression('(B8 - B11) / (B8 + B11)', {'B8': image.select("B8"), 'B11': image.select("B11")}).rename('NDSI')
        CRSI_image = image.expression('((B8 * B4 - B3 * B2) / (B8 * B4 + B3 * B2))**0.5', {'B8': image.select("B8"), 'B4': image.select("B4"), 'B3': image.select("B3"), 'B2': image.select("B2")}).rename('CRSI')
        SRSI_image = image.expression('((NDVI - 1)**2 + SI2)**0.5', {'NDVI': NDVI, 'SI2': SI2_image}).rename('SRSI')
        SAIO_image = image.expression('(B3 - B8) / (B2 + B8)', {'B3': image.select("B3"), 'B8': image.select("B8"), 'B2': image.select("B2")}).rename('SAIO')
        
        # Calculate the new indices
        CLEX_image = image.expression('B11 / B12', {'B11': image.select("B11"), 'B12': image.select("B12")}).rename('CLEX')
        GYEX_image = image.expression('(B11 - B8) / (B12 + B8)', {'B11': image.select("B11"), 'B8': image.select("B8"), 'B12': image.select("B12")}).rename('GYEX')
        CAEX_image = image.expression('(B3 + 0.1) / (B4 + 0.1)', {'B3': image.select("B3"), 'B4': image.select("B4")}).rename('CAEX')
        BI_image = image.expression('(B3 + B4) / 2', {'B3': image.select("B3"), 'B4': image.select("B4")}).rename('BI')

        # Calculate the new vegetation indices
        RVI_image = image.expression('B8 / B4', {'B8': image.select("B8"), 'B4': image.select("B4")}).rename('RVI')
        ENDVI_image = image.expression('(B8 + B11 - B4) / (B8 + B12 + B4)', {'B8': image.select("B8"), 'B11': image.select("B11"), 'B12': image.select("B12"), 'B4': image.select("B4")}).rename('ENDVI')
        IPVI_image = image.expression('B8 / (B8 + B4)', {'B8': image.select("B8"), 'B4': image.select("B4")}).rename('IPVI')
        GDVI_image = image.expression('(B11**2 - B4**2) / (B11**2 + B4**2)', {'B11': image.select("B11"), 'B4': image.select("B4")}).rename('GDVI')
        NLI_image = image.expression('(B11**2 - B4) / (B11**2 + B4)', {'B11': image.select("B11"), 'B4': image.select("B4")}).rename('NLI')
        GARI_image = image.expression('(B8 - (B3 + 1.7 * (B2 - B4))) / (B8 + (B3 + 1.7 * (B2 - B4)))', {'B8': image.select("B8"), 'B3': image.select("B3"), 'B2': image.select("B2"), 'B4': image.select("B4")}).rename('GARI')
        NDVI_image = image.expression('(B8 - B4) / (B8 + B4)', {'B8': image.select("B8"), 'B4': image.select("B4")}).rename('NDVI')
        DVI_image = image.expression('B8 - B4', {'B8': image.select("B8"), 'B4': image.select("B4")}).rename('DVI')
        EVI_image = image.expression('(1 + 0.2) * (B8 - B4) / (B8 + 2.4 * B4 + 1)', {'B8': image.select("B8"), 'B4': image.select("B4")}).rename('EVI')
        SAVI_image = image.expression('((B8 - B4) / (B8 + B4 + 0.5)) * (1 + 0.5)', {'B8': image.select("B8"), 'B4': image.select("B4")}).rename('SAVI')
        OSAVI_image = image.expression('(B8 - B4) / (B8 + B4 + 0.16)', {'B8': image.select("B8"), 'B4': image.select("B4")}).rename('OSAVI')
        GVMI_image = image.expression('((B8 + 0.1) - (B11 + 0.02)) / ((B8 + 0.1) + (B11 + 0.02))', {'B8': image.select("B8"), 'B11': image.select("B11")}).rename('GVMI')
        
        return image.addBands(SI_image).addBands(NDVI).addBands(SI1_image).addBands(SI2_image).addBands(SI3_image).addBands(SI4_image).addBands(S1_image).addBands(S2_image).addBands(S3_image).addBands(S5_image).addBands(S6_image).addBands(S7_image).addBands(S8_image).addBands(S9_image).addBands(SI_T_image).addBands(SSSI_1_image).addBands(SSSI_2_image).addBands(NDSI_image).addBands(CRSI_image).addBands(SRSI_image).addBands(SAIO_image).addBands(CLEX_image).addBands(GYEX_image).addBands(CAEX_image).addBands(BI_image).addBands(RVI_image).addBands(ENDVI_image).addBands(IPVI_image).addBands(GDVI_image).addBands(NLI_image).addBands(GARI_image).addBands(NDVI_image).addBands(DVI_image).addBands(EVI_image).addBands(SAVI_image).addBands(OSAVI_image).addBands(GVMI_image)
    
    # Define a function to calculate NDVI
    @staticmethod
    def keep_hour_0_forecasts(row):
        return row.hour == 0
            
    @staticmethod
    # Function to calculate monthly averages
    def monthly_aggregate_gee(image, poi):
        # Add a band for the month (1 to 12)
        image = image.set('month', image.date().get('month'))
        
        # Reduce the image to get the mean value for the region of interest
        mean_values = image.reduceRegion(
            reducer=ee.Reducer.mean(),
            geometry=poi,
            scale=10
        )
        
        return ee.Feature(poi, mean_values).set('system:time_start', image.get('system:time_start'))

    @staticmethod
    # Function to merge raw bands and reflectance bands
    def join_collections_function(image_a, image_b):
        return image_a.addBands(image_b)  # Merge bands
    
    def estimate_rho_air_density(p, ea, ta_k):
        '''Calculates the density of air.

        Parameters
        ----------
        p : float
            total air pressure (dry air + water vapour) (mb).
        ea : float
            water vapor pressure at reference height above canopy (mb).
        ta_k : float
            air temperature at reference height (Kelvin).

        Returns
        -------
        rho : float
            density of air (kg m-3).

        References
        ----------
        based on equation (2.6) from Brutsaert (2005): Hydrology - An Introduction (pp 25).'''

        # p is multiplied by 100 to convert from mb to Pascals
        rho = ((p * 100.0) / (R_d * ta_k)) * (1.0 - (1.0 - epsilon) * ea / p)
        return rho
    
    @staticmethod
    def flux_2_evapotranspiration(flux, t_c=20, time_domain=1):
        '''Converts heat flux units (W m-2) to evaporation rates (mm time-1) to a given temporal window

        Parameters
        ----------
        flux : float or numpy array
            heat flux value to be converted,
            usually refers to latent heat flux LE to be converted to ET
        t_c : float or numpy array
            environmental temperature in Kelvin. Default=20 Celsius
        time_domain : float
            Temporal window in hours. Default 1 hour (mm h-1)

        Returns
        -------
        et : float or numpy array
            evaporation rate at the time_domain. Default mm h-1
        '''
        # Calculate latent heat of vaporization
        lambda_ = GeospatialDataToolkit.estimate_lambda(t_c)  # J kg-1
        # Density of water
        rho_w = GeospatialDataToolkit.estimate_rho_w(t_c)  # kg m-3
        et = flux / (rho_w * lambda_)  # m s-1
        # Convert instantaneous rate to the time_domain rate
        et = et * 1e3 * time_domain * 3600.  # mm
        return et
    
    @staticmethod
    def estimate_lambda(ta_c):
        '''Calculates the latent heat of vaporization.

        Parameters
        ----------
        T_A_K : float
            Air temperature (Kelvin).

        Returns
        -------
        Lambda : float
            Latent heat of vaporisation (J kg-1).

        References
        ----------
        based on Eq. 3-1 Allen FAO98 '''

        Lambda = 1e6 * (2.501 - (2.361e-3 * ta_c))
        return Lambda
    
    @staticmethod
    def estimate_rho_w(t_c):
        """
        density of air-free water ata pressure of 101.325kPa
        :param t_c: temperature in cellsius
        :return:
        density of water (kg m-3)
        """
        rho_w = (999.83952 + 16.945176 * t_c - 7.9870401e-3 * t_c**2
                - 46.170461e-6 * t_c**3 + 105.56302e-9 * t_c**4
                - 280.54253e-12 * t_c**5) / (1 + 16.897850e-3 * t_c)

        return rho_w
    
    @staticmethod
    def estimate_pressure(z):
        ''' Calculates the barometric pressure above sea level.

        Parameters
        ----------
        z: float
            height above sea level (m).

        Returns
        -------
        p: float
            air pressure (Kpa).'''

        #p = 1013.25 * (1.0 - 2.225577e-5 * z)**5.25588
        
        p = 101.3 * (((293 - (0.0065 * z)) / (293)) ** 5.26)
        return p
    
    # Function to extract images from properties and add them as bands
    @staticmethod
    def extract_images(feature):
        feature = ee.Feature(feature)
        
        # Extract images from properties
        image1 = ee.Image(feature.get("primary"))
        image2 = ee.Image(feature.get("secondary"))
        
        # Optionally, you can add some preprocessing steps here
        
        # Add images as bands to an Image object
        image = image2.addBands(image1)
        
        # need to add the meta data of surface reflectance image in future if needed, ex: image = image.set('prop', 'val')
        
        # Return the image
        return image
    
    # Function to extract images from properties and add them as bands
    @staticmethod
    def estimate_emissivity_surface(image):
        
        # Define the conditions based on other bands
        #condition1 = image.select('LAI').lte(3)  # Example condition 1: pixels where 'band1' is less than 0
        #condition2 = image.select('LAI').gt(3)  # Example condition 1: pixels where 'band1' is less than 0

        # Define the expression to apply based on the condition
        expression = 'lai <=3 ? 0.95 + (lai * 0.01) : 0.98'

        # Apply the expression with condition using .where()
        #emissivity = image.where(condition1, expression1)
        
        # Define the expression to apply based on the condition
        emissivity = image.expression(expression,{
                'lai': image.select('lai'),
            }
        ).rename('emissivity_surface')
       
        return image.addBands(emissivity)
    
    def estimate_vapor_pressure(self, ta_c, rh=None):
        """
        Calculate actual vapor pressure (e) given temperature (T) in Celsius
        and relative humidity (RH) as a percentage.
        """
        # Calculate saturation vapor pressure (es) using Magnus-Tetens formula
        es = 6.112 * math.exp((17.67 * ta_c) / (ta_c + 243.5))
        
        if rh is None:
            return es
        e = (rh / 100) * es
        return e
    
    @staticmethod
    def estimate_r_lo(image):
        """
        Calculate actual vapor pressure (e) given temperature (T) in Celsius
        and relative humidity (RH) as a percentage.
        """
         # Stephan Boltzmann constant (W m-2 K-4)
        SB = 5.670373e-8
        
        # Define the expression to apply based on the condition
        expression = 'SB * emissivity_surface * (lst+273.15)**4'
        
        # Define the expression to apply based on the condition
        r_lo = image.expression(expression, {
                'lst': image.select('lst'),
                'emissivity_surface': image.select('emissivity_surface'),
                'SB': SB,
            }
        ).rename('r_lo')
        
        return image.addBands(r_lo)
    
    def estimate_r_li(self, ta_c, ts_c):
        """
        Calculate actual vapor pressure (e) given temperature (T) in Celsius
        and relative humidity (RH) as a percentage.
        """
        
        r_li = self.estimate_emissivity_atm(ta_c) * self.stephan_boltzmann(ts_c)
        
        return r_li
    
    @staticmethod
    def estimate_rn(row):
        """
        Calculate actual vapor pressure (e) given temperature (T) in Celsius
        and relative humidity (RH) as a percentage.
        """
        
        albedo = row['albedo']
        emissivity_surface = row['emissivity_surface']
        r_li = row['r_li']
        r_lo = row['r_lo']
        rs = row['rs']
        
        rn = ((1 - albedo) * rs) + r_li - r_lo - ((1 - emissivity_surface) * r_li)
        
        return rn
    
    @staticmethod
    def estimate_g(row):
        """
        Calculate actual vapor pressure (e) given temperature (T) in Celsius
        and relative humidity (RH) as a percentage.
        """
        
        albedo = row['albedo']
        lst = row['lst']
        ndvi = row['ndvi']
        rn = row['rn']
        
        g = rn * ((lst) * (0.0038 + (0.0074 * albedo)) * (1 - (0.98 * (ndvi**4))))
        
        return g
    
    def estimate_h(self, row):
        """
        Calculate actual vapor pressure (e) given temperature (T) in Celsius
        and relative humidity (RH) as a percentage.
        """
        
        rho = self.estimate_rho(row)
        cp = self.estimate_cp(row)
        lst_k = row['lst'] + 273.15
        ta_k = row['ta_c'] + 273.15
        
        h = (rho * cp * (ta_k - lst_k)) / self.estimate_r_ah(row)        
        return h
    
    def estimate_rho(self, row):
        '''Calculates the density of air.

        Parameters
        ----------
        p : float
            total air pressure (dry air + water vapour) (mb).
        ea : float
            water vapor pressure at reference height above canopy (mb).
        T_A_K : float
            air temperature at reference height (Kelvin).

        Returns
        -------
        rho : float
            density of air (kg m-3).

        References
        ----------
        based on equation (2.6) from Brutsaert (2005): Hydrology - An Introduction (pp 25).'''
        
        lst, ta_c, elevation = row['lst'], row['ta_c'], row['elevation']
        ta_k = ta_c + 273.15
        lst_k = lst + 273.15
        dt = ta_k - lst_k
        #ea = self.estimate_vapor_pressure(ta_c)
        p = self.estimate_pressure(elevation)
        # p is multiplied by 100 to convert from mb to Pascals
        #rho = ((p * 100.0) / (self.R_D * ta_k)) * (1.0 - (1.0 - self.epsilon) * ea / p)
        
        # convert pressure from millibars (mb) to pascals (Pa)
        
        
        rho = (1000 * p) / (1.01 * (lst - dt) * self.R_D)
        return rho
    
    def estimate_r_ah(self, row):
        '''Friction velocity.

        Parameters
        ----------
        u : float
            wind speed above the surface (m s-1).
        z_u : float
            wind speed measurement height (m).
        d_0 : float
            zero-plane displacement height (m).
        z_0M : float
            aerodynamic roughness length for momentum transport (m).

        References
        ----------
        .. [Brutsaert2005] Brutsaert, W. (2005). Hydrology: an introduction (Vol. 61, No. 8).
            Cambridge: Cambridge University Press.
        '''
        u_star = self.estimate_u_star(row) 
        z1 = 0.1
        z2 = 2
        r_ah = math.log(z2 / z1) / (u_star * self.KARMAN)
        return r_ah
    
    def estimate_u_star(self, row):
        '''Friction velocity.

        Parameters
        ----------
        u : float
            wind speed above the surface (m s-1).
        z_u : float
            wind speed measurement height (m).
        d_0 : float
            zero-plane displacement height (m).
        z_0M : float
            aerodynamic roughness length for momentum transport (m).

        References
        ----------
        .. [Brutsaert2005] Brutsaert, W. (2005). Hydrology: an introduction (Vol. 61, No. 8).
            Cambridge: Cambridge University Press.
        '''
        u200 = self.estimate_u_z(row)
        z_0m = self.estimate_z_0m(row)
        
        u_star = (u200 * self.KARMAN) / (math.log(200 / z_0m))
        return u_star
    
    def estimate_u_z(self, row, z=200):
        ''' estimate_momentum_roughness_length (z_0m).

        Parameters
        ----------
        u : float
            wind speed above the surface (m s-1).
        z_u : float
            wind speed measurement height (m).
        d_0 : float
            zero-plane displacement height (m).
        z_0M : float
            aerodynamic roughness length for momentum transport (m).

        References
        ----------
        .. [Brutsaert2005] Brutsaert, W. (2005). Hydrology: an introduction (Vol. 61, No. 8).
            Cambridge: Cambridge University Press.
        '''
        u = row['u']
        z_0m = self.estimate_z_0m(row)
        u200 = ( u * (math.log(z / z_0m))) / (math.log(2 / z_0m))
    
        return u200
    
    @staticmethod
    def estimate_z_0m(row):
        ''' estimate_momentum_roughness_length (z_0m).

        Parameters
        ----------
        u : float
            wind speed above the surface (m s-1).
        z_u : float
            wind speed measurement height (m).
        d_0 : float
            zero-plane displacement height (m).
        z_0M : float
            aerodynamic roughness length for momentum transport (m).

        References
        ----------
        .. [Brutsaert2005] Brutsaert, W. (2005). Hydrology: an introduction (Vol. 61, No. 8).
            Cambridge: Cambridge University Press.
        '''
        lai, ndvi = row['lai'], row['ndvi']
        
        z_0m = 0.018 * lai if ndvi > 0.2 else 0.005
    
        return z_0m
    
    @staticmethod
    def estimate_eta_inst(row):
        ''' estimate_momentum_roughness_length (z_0m).

        Parameters
        ----------
        u : float
            wind speed above the surface (m s-1).
        z_u : float
            wind speed measurement height (m).
        d_0 : float
            zero-plane displacement height (m).
        z_0M : float
            aerodynamic roughness length for momentum transport (m).

        References
        ----------
        .. [Brutsaert2005] Brutsaert, W. (2005). Hydrology: an introduction (Vol. 61, No. 8).
            Cambridge: Cambridge University Press.
        '''
        ta_c = row['ta_c']
        le = row['le']
        
        eta_inst = GeospatialDataToolkit.flux_2_evapotranspiration(le, ta_c) 
        
        return eta_inst
    
    @staticmethod
    def estimate_le(row):
        ''' estimate_momentum_roughness_length (z_0m).

        Parameters
        ----------
        u : float
            wind speed above the surface (m s-1).
        z_u : float
            wind speed measurement height (m).
        d_0 : float
            zero-plane displacement height (m).
        z_0M : float
            aerodynamic roughness length for momentum transport (m).

        References
        ----------
        .. [Brutsaert2005] Brutsaert, W. (2005). Hydrology: an introduction (Vol. 61, No. 8).
            Cambridge: Cambridge University Press.
        '''
        rn = row['rn']
        h = row['h']
        g = row['g']
        
        le = rn - g - h
        
        return le
    
    def estimate_cp(self, row):
        ''' Calculates the heat capacity of air at constant pressure.

        Parameters
        ----------
        p : float
            total air pressure (dry air + water vapour) (mb).
        ea : float
            water vapor pressure at reference height above canopy (mb).

        Returns
        -------
        c_p : heat capacity of (moist) air at constant pressure (J kg-1 K-1).

        References
        ----------
        based on equation (6.1) from Maarten Ambaum (2010):
        Thermal Physics of the Atmosphere (pp 109).'''
        
        ta_c, elevation = row['ta_c'], row['elevation']
        
        ea = self.estimate_vapor_pressure(ta_c)
        p = self.estimate_pressure(elevation)

        # first calculate specific humidity, rearanged eq (5.22) from Maarten
        # Ambaum (2010), (pp 100)
        q = self.epsilon * ea / (p + (self.epsilon - 1.0) * ea)
        # then the heat capacity of (moist) air
        c_p = (1.0 - q) * self.C_PD + q * self.C_PV
        return c_p
    
    @staticmethod
    def get_elevation(lon, lat):
        """
        Returns the elevation (in meters) and latitude (in degrees) for a given set of coordinates.
        Uses the Open Elevation API (https://open-elevation.com/) to obtain the elevation information.
        """
        # 'https://api.open-elevation.com/api/v1/lookup?locations=10,10|20,20|41.161758,-8.583933'
        url = f'https://api.opentopodata.org/v1/aster30m?locations={lat},{lon}'
        response = requests.get(url)
        print(response.json())
        data = response.json()
        elevation = data['results'][0]['elevation']
        #latitude = data['results'][0]['latitude']
        return elevation
    
    @staticmethod
    def estimate_albedo_landsat8(image):
        """
        Calculate actual vapor pressure (e) given temperature (T) in Celsius
        and relative humidity (RH) as a percentage.
        """
         # Stephan Boltzmann constant (W m-2 K-4)
        SB = 5.670373e-8
        
        # boradband albedo based on https://www.mdpi.com/2072-4292/13/4/799#
        #𝛼=0.356𝛼2+0.130𝛼4+0.373𝛼5+0.085𝛼6+0.072𝛼7−0.0018
        w2, w4, w5, w6, w7, b =0.356, 0.130, 0.373, 0.085, 0.072, -0.0018
        expression = '(w2 * b2) + (w4 * b4) + (w5 * b5) + (w6 * b6) + (w7 * b7) + b'
        
        # Define the expression to apply based on the condition
        albedo = image.expression(expression, {
                'w2': w2,
                'w4': w4,
                'w5': w5,
                'w6': w6,
                'w7': w7,
                'b': b,
                'b2': image.select('toa_B2'),
                'b4': image.select('toa_B4'),
                'b5': image.select('toa_B5'),
                'b6': image.select('toa_B6'),
                'b7': image.select('toa_B7'),
            }
        ).rename('albedo')
        
        return image.addBands(albedo)
    
    @staticmethod
    def topographic_correction_landsat8(image):
        """
        Calculate actual vapor pressure (e) given temperature (T) in Celsius
        and relative humidity (RH) as a percentage.
        """
         # Stephan Boltzmann constant (W m-2 K-4)
        
        
        expression = 'SR * (cos(SZA)/((cos(slope) * cos(SZA)) + (sin(slope) * sin(SZA) * cos(SUN_AZIMUTH - aspect))))'
        
        # Define the expression to apply based on the condition
        corrected = image.expression(expression, {
                'SR': image.select('SR_B2'),
                'SZA': ee.Image.constant(90).multiply(0.0174533).subtract(ee.Image.constant(image.get('SUN_ELEVATION')).multiply(0.0174533)),
                'SUN_AZIMUTH': ee.Image.constant(image.get('SUN_AZIMUTH')).multiply(0.0174533),
                'aspect': image.select('aspect'),
                'slope': image.select('slope'),
            }
        ).rename('SR_B2_tc')
        
        return image.addBands(corrected)
    
    @staticmethod
    def calculate_sza(image):
        """
        Calculate actual vapor pressure (e) given temperature (T) in Celsius
        and relative humidity (RH) as a percentage.
        """
         # Stephan Boltzmann constant (W m-2 K-4)
        
        
        # Kt - air turbidity coefficient (Kt = 1.0 for clear air and Kt = 0.5 for extremely turbid or polluted air; Kt = 1.0 was used in this study);
        
        # W (mm) - precipitable water, obtained as a function of RU (%); and W = 0.14 * ea * pressure_atm + 2.1
        
        # based on https://www.scielo.br/j/rbeaa/a/sX6cJjNXWMfHQ5p4h33B8Zz/
        
        
        # The value of atmospheric albedo can be obtained through a radiative transfer model and, in general, is situated between 0.025 and 0.040 (Allen et al., 2002). The value of 0.03 was adopted in the present study
        
        
        # Define the expression to apply based on the condition
        sza_image = image.expression('SZA', {
                'SZA': ee.Image.constant(90).multiply(0.0174533).subtract(ee.Image.constant(image.get('SUN_ELEVATION')).multiply(0.0174533)),
            }
        ).rename('SZA')
        
        return image.addBands(sza_image)
    
    @staticmethod
    def calculate_d_es(image):
        """
        Calculate actual vapor pressure (e) given temperature (T) in Celsius
        and relative humidity (RH) as a percentage.
        """
         # Stephan Boltzmann constant (W m-2 K-4)
        
        # Kt - air turbidity coefficient (Kt = 1.0 for clear air and Kt = 0.5 for extremely turbid or polluted air; Kt = 1.0 was used in this study);
        
        # W (mm) - precipitable water, obtained as a function of RU (%); and W = 0.14 * ea * pressure_atm + 2.1
        
        # based on https://www.scielo.br/j/rbeaa/a/sX6cJjNXWMfHQ5p4h33B8Zz/
        
        
        # The value of atmospheric albedo can be obtained through a radiative transfer model and, in general, is situated between 0.025 and 0.040 (Allen et al., 2002). The value of 0.03 was adopted in the present study
        
        
        # Define the expression to apply based on the condition
        sza_image = image.expression('d_es', {
                'd_es': ee.Image.constant(image.get('EARTH_SUN_DISTANCE')),
            }
        ).rename('d_es')
        
        return image.addBands(sza_image)
    
    @staticmethod
    def extract_sza_landsat8(image):
        """
        Calculate actual vapor pressure (e) given temperature (T) in Celsius
        and relative humidity (RH) as a percentage.
        """
         # Stephan Boltzmann constant (W m-2 K-4)
        
        
        # Kt - air turbidity coefficient (Kt = 1.0 for clear air and Kt = 0.5 for extremely turbid or polluted air; Kt = 1.0 was used in this study);
        
        # W (mm) - precipitable water, obtained as a function of RU (%); and W = 0.14 * ea * pressure_atm + 2.1
        
        # based on https://www.scielo.br/j/rbeaa/a/sX6cJjNXWMfHQ5p4h33B8Zz/
        
        
        # The value of atmospheric albedo can be obtained through a radiative transfer model and, in general, is situated between 0.025 and 0.040 (Allen et al., 2002). The value of 0.03 was adopted in the present study
        
        
        #e = 0.35 + 0.627 * exp((-(0.00146 * pressure_atm)/(1 * cos(SZA))) - 0.075 * ((W)/(cos(SZA)))**0.4)
        expression = 'sza'
        
        # Define the expression to apply based on the condition
        corrected = image.expression(expression, {
                'sza': ee.Image.constant(90).multiply(0.0174533).subtract(ee.Image.constant(image.get('SUN_ELEVATION')).multiply(0.0174533)),
            }
        ).rename('SZA')
        
        return image.addBands(corrected)
    
    @staticmethod
    def add_dem(image):
        dem = ee.Image('USGS/SRTMGL1_003')
        hillshade = ee.Terrain.hillshade(dem)
        slope = ee.Terrain.slope(dem)
        aspect = ee.Terrain.aspect(dem)
        # Convert slope and aspect to radians
        slope = slope.multiply(0.0174533)  # 1 degree = π/180 radians
        aspect = aspect.multiply(0.0174533)  # 1 degree = π/180 radians
        image = image.addBands(hillshade)
        image = image.addBands(slope)
        return image.addBands(aspect)
    
    def estimate_emissivity_atm(self, ta_c):
        '''Atmospheric emissivity

        Estimates the effective atmospheric emissivity for clear sky.

        Parameters
        ----------
        ea : float
            atmospheric vapour pressure (mb).
        t_a_k : float
            air temperature (Kelvin).

        Returns
        -------
        emiss_air : float
            effective atmospheric emissivity.

        References
        ----------
        .. [Brutsaert1975] Brutsaert, W. (1975) On a derivable formula for long-wave radiation
            from clear skies, Water Resour. Res., 11(5), 742-744,
            htpp://dx.doi.org/10.1029/WR011i005p00742.'''
            
        # Stephan Boltzmann constant (W m-2 K-4)
        SB = 5.670373e-8
            
        ta_k = ta_c + 273.15
        
        ea = self.estimate_vapor_pressure(ta_c)

        emiss_air = 1.24 * (ea / ta_k)**(1. / 7.)  # Eq. 11 in [Brutsaert1975]_

        return emiss_air
    
    @staticmethod
    def stephan_boltzmann(t_c):
        '''Calculates the total energy radiated by a blackbody.

        Parameters
        ----------
        t_k : float
            body temperature (Kelvin)

        Returns
        -------
         : float
            Emitted radiance (W m-2)'''
            
        # Stephan Boltzmann constant (W m-2 K-4)
        SB = 5.670373e-8
            
        t_k = t_c + 273.15
        
        return SB * (t_k ** 4)
    
    @staticmethod
    def calc_pressure(z):
        ''' Calculates the barometric pressure above sea level.

        Parameters
        ----------
        z: float
            height above sea level (m).

        Returns
        -------
        p: float
            air pressure (mb).'''

        p = 1013.25 * (1.0 - 2.225577e-5 * z)**5.25588
        return p
    
    # Function to apply scaling factors from metadata to an image
    @staticmethod
    def landsat8_toa_to_radiance_image(image, band_name):
        band = band_name[1:]
        
        multiplicative = ee.Image.constant(image.get('RADIANCE_MULT_BAND_' + band))
        additive = ee.Image.constant(image.get('RADIANCE_ADD_BAND_' + band))
        
        # Apply scaling factors to all bands
        scaled_image = image.select(band_name).multiply(multiplicative).add(additive).rename(band_name + '_radiance' )
        return image.addBands(scaled_image)
    
    # Function to apply scaling factors from metadata to an image
    def join_two_collections(self, collection_a, collection_b):
        # Initialize lists to store multiplicative and additive factors for all bands
        
        # joining condition
        condition = ee.Filter.equals(leftField='system:time_start', rightField='system:time_start')
        
        # Join collections based on image ID
        joined_collection = ee.Join.inner().apply(
            collection_a,
            collection_b,
            condition
        )
        
        # Convert FeatureCollection to a list
        feature_list = joined_collection.toList(joined_collection.size())
        # Map over the list to apply the extraction function
        final_collection = ee.ImageCollection.fromImages(feature_list.map(self.extract_images))
        
        return final_collection
    
    @staticmethod
    def landsat8_toa_to_band_reflectance_brazil(image, band_name):
        band = band_name[1:]
        
        multiplicative = ee.Image.constant(image.get('RADIANCE_MULT_BAND_' + band))
        additive = ee.Image.constant(image.get('RADIANCE_ADD_BAND_' + band))
        
        # Apply scaling factors to all bands
        scaled_image = image.select(band_name).multiply(multiplicative).add(additive).rename(band_name + '_radiance' )
        
        image = image.addBands(scaled_image)
        
        expression = band_name + '_radiance / cos(SZA/d_es**2)'
         # Define the expression to apply based on the condition
        corrected = scaled_image.expression(expression, {
                band_name + '_radiance': scaled_image.select(band_name + '_radiance'),
                'SZA': ee.Image.constant(90).multiply(0.0174533).subtract(ee.Image.constant(image.get('SUN_ELEVATION')).multiply(0.0174533)),
                'd_es': ee.Image.constant(image.get('EARTH_SUN_DISTANCE')),
            }
        ).rename('rb_' + band_name)
        
        return image.addBands(corrected)
    
    # Function to apply scaling factors from metadata to an image
    def join_two_collections(self, collection_a, collection_b):
        # Initialize lists to store multiplicative and additive factors for all bands
        
        # joining condition
        condition = ee.Filter.equals(leftField='system:time_start', rightField='system:time_start')
        
        # Join collections based on image ID
        joined_collection = ee.Join.inner().apply(
            collection_a,
            collection_b,
            condition
        )
        
        # Convert FeatureCollection to a list
        feature_list = joined_collection.toList(joined_collection.size())
        # Map over the list to apply the extraction function
        final_collection = ee.ImageCollection.fromImages(feature_list.map(self.extract_images))
        
        return final_collection
    
    # Define function to apply scaling factors
    @staticmethod
    def landsat8_surface_reflectance_scale_actors(image):
        optical_bands  = image.select('SR_B.').multiply(0.0000275).add(-0.2)
        thermal_bands  = image.select('ST_B.*').multiply(0.00341802).add(149.0)
        return image.addBands(optical_bands, None, True).addBands(thermal_bands, None, True)
    
    
    @staticmethod
    def add_cloud_cover_landsat8(image, poi):
        qa = image.select('pixel_qa')
        # Cloud shadow bits (3) and clouds bits (5)
        cloud_shadow_bit_mask = 1 << 3
        clouds_bit_mask = 1 << 5
        # Both flags should be set to zero, indicating clear conditions
        cloud_mask = qa.bitwiseAnd(cloud_shadow_bit_mask).eq(0).And(
                    qa.bitwiseAnd(clouds_bit_mask).eq(0))

        cloud_pixels = cloud_mask.Not()
        cloud_cover = cloud_pixels.reduceRegion(
            reducer=ee.Reducer.mean(),
            geometry=poi.buffer(1000),  # Check within a 1km radius around the point
            scale=30
        )
        
        return image.set('cloud_cover', ee.Number(cloud_cover.get('pixel_qa')))

    def check_directory_existance(self, directory_path='data'):
        if not os.path.exists(directory_path):
            os.makedirs(directory_path)
            print(f"Directory created: {directory_path}")
    
    @staticmethod
    def eto_penman_monteith_daily_v3(row):
        # input variables
        # T = 25.0  # air temperature in degrees Celsius
        # RH = 60.0  # relative humidity in percent
        # u2 = 2.0  # wind speed at 2 m height in m/s
        # Rs = 15.0  # incoming solar radiation in MJ/m2/day
        # lat = 35.0  # latitude in degrees
        
        ta_mean_c, rh_mean, u2_mean, rs_daily, lat, elevation, doy =  row['ta_mean'],  row['rh_mean'], row['ws_mean'], row['rs_daily'], row['lat'], row['elevation'], row['doy']
        
        # constants
        ALBEDO = 0.23  # Albedo coefficient for grass reference surface
        SIGMA = 0.000000004903  # Stefan-Boltzmann constant in MJ/K4/m2/day
        G = 0  # Soil heat flux density (MJ/m2/day)

        ta_mean_k = ta_mean_c + 273.16  # air temperature in Kelvin
        
        # saturation vapor pressure in kPa
        es = 0.6108 * math.exp((17.27 * ta_mean_c) / (ta_mean_c + 237.3))

        # actual vapor pressure in kPa
        ea = es * (rh_mean / 100)
        
        # in the absence of rh_max and rh_min
        #ea = (rh_mean / 100) * es
        
        # when using equipement where errors in estimation rh min can be large or when rh data integrity are in doubt use only rh_max term
        #ea = ea_min_term  
        
        delta = Lib.slope_saturation_vapor_pressure_curve(ta_mean_c) # slope of the vapor pressure curve in kPa/K
        
        # psychrometric constant in kPa/K
        gamma = Lib.psychrometric_constant(elevation, ta_mean_c)
        
        # Calculate u2
        u2 = u2_mean
        
        # Calculate extraterrestrial radiation
        ra = GeospatialDataToolkit.extraterrestrial_radiation(lat, doy)
        
        # Calculate clear sky solar radiation
        rso = (0.75 + (2e-5 * elevation)) * ra
        
        # Calculate net solar shortwave radiation 
        rns = (1 - ALBEDO) * rs_daily
        
        # Calculate net longwave radiation
        
        rnl = SIGMA * (math.pow(ta_mean_k, 4) * (0.34 - (0.14 * math.sqrt(ea))) * ((1.35 * (rs_daily / rso)) - 0.35))
        
        # Calculate net radiation
        rn = rns - rnl
        
        
        # decompose eto to two terms to facilitate the calculation
        """rng = 0.408 * rn
        radiation_term = ((delta) / (delta + (gamma * (1 + 0.34 * u2)))) * rng
        pt = (gamma) / (delta + gamma * (1 + (0.34 * u2)))
        tt = ((900) / (ta_mean + 273) ) * u2
        wind_term = pt * tt * (es - ea)
        eto = radiation_term + wind_term """
        
        #eto = ((0.408 * delta * (rn - G)) + gamma * (((900 * u2 * (es - ea)) / (ta_mean_c + 273)))) / (delta + (gamma * (1 + (0.34 * u2))))


        gamma1 = gamma * (1 + 0.34 * u2)

        den = delta + gamma1
        num1 = (0.408 * delta * rn) / den
        num2 = (gamma * (es - ea) * 900 * u2 / (ta_mean_c + 273)) / den
        pet = num1 + num2
        eto = pet
        # output result
        return eto
    
    @staticmethod
    def eto_penman_monteith_daily_not_maped(row):
        # input variables
        # T = 25.0  # air temperature in degrees Celsius
        # RH = 60.0  # relative humidity in percent
        # u2 = 2.0  # wind speed at 2 m height in m/s
        # Rs = 15.0  # incoming solar radiation in MJ/m2/day
        # lat = 35.0  # latitude in degrees
        
        G = 0  # Soil heat flux density (MJ/m2/day)
        
        ta_max, ta_min, rh_max, rh_min, u2_mean, rs_mean, lat, elevation, doy =  row['ta_max'], row['ta_min'], row['rh_max'], row['rh_min'], row['ws_mean'], row['rs_mean'], row['lat'], row['elevation'], row['doy']
        
        rs_mean *= 0.0864  # convert watts per square meter to megajoules per square meter 0.0288 = 60x60x8hours or 0.0864 for 24 hours

        ta_mean = (ta_max + ta_min) / 2
        ta_max_kelvin = ta_max + 273.16  # air temperature in Kelvin
        ta_min_kelvin = ta_min + 273.16  # air temperature in Kelvin
        
        # saturation vapor pressure in kPa
        es_max = 0.6108 * math.exp((17.27 * ta_max) / (ta_max + 237.3))
        es_min = 0.6108 * math.exp((17.27 * ta_min) / (ta_min + 237.3))
        es = (es_max + es_min) / 2
        
        # actual vapor pressure in kPa
        ea_max_term = es_max * (rh_min / 100)
        ea_min_term = es_min * (rh_max / 100)
        ea = (ea_max_term + ea_min_term) / 2
        
        # in the absence of rh_max and rh_min
        #ea = (rh_mean / 100) * es
        
        # when using equipement where errors in estimation rh min can be large or when rh data integrity are in doubt use only rh_max term
        #ea = ea_min_term  
        
        delta = Lib.slope_saturation_vapor_pressure_curve(ta_mean) # slope of the vapor pressure curve in kPa/K
        
        # psychrometric constant in kPa/K
        gamma = Lib.psychrometric_constant(elevation, ta_mean)
        
        # Calculate u2
        u2 = u2_mean
        
        # Calculate extraterrestrial radiation
        ra = Lib.extraterrestrial_radiation_daily(lat, doy)
        
        # Calculate clear sky solar radiation
        rso = (0.75 + (2e-5 * elevation)) * ra
        
        # Calculate net solar shortwave radiation 
        rns = (1 - Lib.ALBEDO) * rs_mean
        
        # Calculate net longwave radiation
        
        rnl = Lib.SIGMA * (((math.pow(ta_max_kelvin, 4) + math.pow(ta_min_kelvin, 4)) / 2) * (0.34 - (0.14 * math.sqrt(ea))) * ((1.35 * (rs_mean / rso)) - 0.35))
        
        # Calculate net radiation
        rn = rns - rnl
        
        
        # decompose eto to two terms to facilitate the calculation
        """rng = 0.408 * rn
        radiation_term = ((delta) / (delta + (gamma * (1 + 0.34 * u2)))) * rng
        pt = (gamma) / (delta + gamma * (1 + (0.34 * u2)))
        tt = ((900) / (ta_mean + 273) ) * u2
        wind_term = pt * tt * (es - ea)
        eto = radiation_term + wind_term """
        
        CD = 0.34
        CN = 900
        
        eto = ((0.408 * delta * (rn - G)) + gamma * (((CN * u2 * (es - ea)) / (ta_mean + 273)))) / (delta + (gamma * (1 + (CD * u2))))

        # output result
        return eto
    
    @staticmethod
    def eto_penman_monteith_hourly(
        row,
        ta_column_name,
        rs_column_name,
        rh_column_name,
        ws_column_name,
        tz_offset,
        reference_crop,
        ):
        # input variables
        # T = 25.0  # air temperature in degrees Celsius
        # RH = 60.0  # relative humidity in percent
        # u2 = 2.0  # wind speed at 2 m height in m/s
        # Rs = 15.0  # incoming solar radiation in MJ/m2/day
        # lat = 35.0  # latitude in degrees
        
        ta_c, rs, rh, u2, lat, elevation, doy, lon, hod =  row[ta_column_name], row[rs_column_name], row[rh_column_name], row[ws_column_name], row['lat'], row['elevation'], row['doy'], row['lon'], row['hod']
        
        # convert units
        rs *= 3.6e-3  # convert watts per square meter to megajoules per square meter 0.0288 = 60x60x8hours or 0.0864 for 24 hours
        ta_k = ta_c + 273.16  # air temperature in Kelvin
        
        lambda_heat = Lib.latent_heat_of_vaporization(ta_c)
        
        # saturation vapor pressure in kPa
        es = Lib.saturation_vapor_pressure(ta_c)
        
        ea = Lib.actual_vapor_pressure(ta_c, rh)
        
        epsilon_net = Lib.net_emissivity_of_surface(ta_c, rh)
        
        # slope of the vapor pressure curve in kPa/K
        delta = Lib.slope_saturation_vapor_pressure_curve(ta_c)
        
        # psychrometric constant in kPa/K
        gamma = Lib.psychrometric_constant(elevation, ta_c)
        
        # Calculate extraterrestrial radiation
        ra = Lib.extraterrestrial_radiation_hourly_v3(doy, lat, lon, hod, tz_offset)
        #ra = 1
        
        # Calculate net solar shortwave radiation 
        rns = (1 - Lib.ALBEDO) * rs
        
        # Rso
        rso = Lib.rso(ra, elevation)
        
        # cloudness factor
        f = Lib.cloudness_factor(rs, rso, Lib.solar_altitude_angle(lat, doy, hod))
        
        rnl = f * epsilon_net * Lib.stephan_boltzmann(ta_c)
      
        rn = (0.77 * rns) - rnl
        
        if reference_crop == 'grass':
            crop_dependent_factor = 37
            if rn > 0:
                g = 0.1 * rn
                # Bulk surface resistance and aerodynamic resistance coefficient
                CD = 0.24 
            else:
                g = 0.5 * rn
                # Bulk surface resistance and aerodynamic resistance coefficient
                CD = 0.96 
        elif reference_crop == 'alfalfa':
            crop_dependent_factor = 66
            if rn > 0:
                g = 0.01 * rn
                # Bulk surface resistance and aerodynamic resistance coefficient
                CD = 0.25 
            else:
                g = 0.2 * rn
                # Bulk surface resistance and aerodynamic resistance coefficient
                CD = 1.7
            
            
        # decompose eto to two terms to facilitate the calculation
        
        radiation = delta * (rn - g)
        
        denominator = delta + (gamma * (1 + (CD * u2)))
        
        radiation_term =(radiation) / (denominator * lambda_heat)
        
        # Aerodynamic Term
        aerodynamic_term = (gamma * ((crop_dependent_factor) / (ta_k)) * u2 * (es - ea)) / denominator
        
        
        eto = radiation_term + aerodynamic_term
            
        # output result
        return eto
    
    @staticmethod
    def eto_penman_monteith_daily_v2(
        row,
        ):
        # input variables
        # T = 25.0  # air temperature in degrees Celsius
        # RH = 60.0  # relative humidity in percent
        # u2 = 2.0  # wind speed at 2 m height in m/s
        # Rs = 15.0  # incoming solar radiation in MJ/m2/day
        # lat = 35.0  # latitude in degrees
        G = 0
        
        ta_mean_c, rs_daily, rh_mean, ws_mean, lat, elevation, doy =  row['ta_mean'], row['rs_daily'], row['rh_mean'], row['ws_mean'], row['lat'], row['elevation'], row['doy']
        
        ta_mean_k = ta_mean_c + 273.16  # air temperature in Kelvin
        
        lambda_heat = Lib.latent_heat_of_vaporization(ta_mean_c)
        
        # saturation vapor pressure in kPa
        es = Lib.saturation_vapor_pressure(ta_mean_c)
        
        # actual vapor pressure in kPa
        ea = Lib.actual_vapor_pressure(ta_mean_c, rh_mean)
        
        epsilon_net = 0.34 - (0.14 * math.sqrt(ea))
        
        # slope of the vapor pressure curve in kPa/K
        delta = Lib.slope_of_saturation_vapor_pressure(ta_mean_c)
        
        # psychrometric constant in kPa/K
        gamma = Lib.psychrometric_constant(elevation, ta_mean_c)
        
        # Calculate extraterrestrial radiation
        ra = Lib.extraterrestrial_radiation(lat, doy)
        
        # Calculate net solar shortwave radiation 
        rns = (1 - Lib.ALBEDO) * rs_daily
        
        # Rso
        rso = Lib.rso(ra, elevation)
        
        # cloudness factor
        f = Lib.cloudness_factor(rs_daily, rso)
        
        rnl = f * epsilon_net * Lib.stephan_boltzmann(ta_mean_c, 'd')
      
        rn = (0.77 * rns) - rnl
        
        
        crop_dependent_factor = 37
        if rn > 0:
            # Bulk surface resistance and aerodynamic resistance coefficient
            CD = 0.24 
        else:
            # Bulk surface resistance and aerodynamic resistance coefficient
            CD = 0.96 
        
        # decompose eto to two terms to facilitate the calculation
        
        radiation = delta * (rn - G)
        
        denominator = delta + (gamma * (1 + (CD * ws_mean)))
        
        radiation_term =(radiation) / (denominator * lambda_heat)
        
        # Aerodynamic Term
        aerodynamic_term = (gamma * ((crop_dependent_factor) / (ta_mean_k)) * ws_mean * (es - ea)) / denominator
        
        
        eto = radiation_term + aerodynamic_term
            
        # output result
        return eto
    
    @staticmethod
    def psychrometric_constant(elevation, ta_c):
        """
        Calculate the psychrometric constant for a given altitude.

        Parameters:
        altitude (float): Altitude above sea level in meters.

        Returns:
        float: Psychrometric constant in kPa/°C.
        """
        
        lambda_v = GeospatialDataToolkit.latent_heat_of_vaporization(ta_c)  # Latent heat of vaporization (MJ/kg)
        
        # Calculate atmospheric pressure based on altitude
        p = GeospatialDataToolkit.pressure(elevation)

        # Calculate psychrometric constant
        gamma = (GeospatialDataToolkit.CP * p) / (GeospatialDataToolkit.EPSILON * lambda_v)

        return gamma
    
    @staticmethod
    def solar_altitude_angle(latitude, doy, hod):
        """
        Calculate the solar altitude angle based on latitude, day of the year, and local solar time.

        Parameters:
        - latitude: float, latitude of the observer in degrees
        - day_of_year: int, day of the year (1 through 365 or 366)
        - local_solar_time: float, local solar time in hours (solar noon is 12.0)

        Returns:
        - solar_altitude: float, solar altitude angle in degrees
        """
        # Convert latitude to radians
        latitude_rad = math.radians(latitude)

        # Calculate solar declination
        declination = 23.45 * math.sin(math.radians((360 / 365) * (doy - 81)))

        # Convert declination to radians
        declination_rad = math.radians(declination)

        # Calculate the hour angle
        hour_angle = 15 * (hod - 12)  # degrees from solar noon
        hour_angle_rad = math.radians(hour_angle)

        # Calculate the solar altitude angle
        sin_alpha = math.sin(latitude_rad) * math.sin(declination_rad) + \
                    math.cos(latitude_rad) * math.cos(declination_rad) * math.cos(hour_angle_rad)

        # Arcsine to get the angle in radians and then convert to degrees
        solar_altitude_rad = math.asin(sin_alpha)
        solar_altitude_degrees = math.degrees(solar_altitude_rad)

        return solar_altitude_degrees
    
    @staticmethod
    def pressure(z):
        ''' Calculates the barometric pressure above sea level.

        Parameters
        ----------
        z: float
            height above sea level (m).

        Returns
        -------
        p: float
            air pressure (Kpa).'''
            
        P0 = 101.325  # Standard atmospheric pressure at sea level in kPa
        L = 0.0065    # Standard lapse rate in °C/m
        p = P0 * (((293 - (L * z)) / (293)) ** 5.26)

        return p
    
    def latent_heat_of_vaporization(ta_c):
        """
        Estimate the latent heat of vaporization of water as a function of temperature, in MJ/kg.
        
        Parameters:
        - temp_celsius: float, temperature in degrees Celsius
        
        Returns:
        - lambda_v: float, latent heat of vaporization in MJ/kg
        """
        # Constants for water vaporization (values in J/g)
        # This approximation assumes a linear decrease from 2501.3 J/g at 0°C to 2264.7 J/g at 100°C
        
        # Adjust latent heat based on temperature
        lambda_v = 2.501 - (0.002361 * ta_c)
        return lambda_v
    
    @staticmethod
    def density_of_water(t_c):
        """
        density of air-free water ata pressure of 101.325kPa
        :param t_c: temperature in cellsius
        :return:
        density of water (kg m-3)
        """
        rho_w = (999.83952 + 16.945176 * t_c - 7.9870401e-3 * t_c**2
                - 46.170461e-6 * t_c**3 + 105.56302e-9 * t_c**4
                - 280.54253e-12 * t_c**5) / (1 + 16.897850e-3 * t_c)

        return rho_w
    
    @staticmethod
    def flux_2_evapotranspiration(flux, t_c=20, time_domain=1):
        '''Converts heat flux units (W m-2) to evaporation rates (mm time-1) to a given temporal window

        Parameters
        ----------
        flux : float or numpy array
            heat flux value to be converted,
            usually refers to latent heat flux LE to be converted to ET
        t_c : float or numpy array
            environmental temperature in Kelvin. Default=20 Celsius
        time_domain : float
            Temporal window in hours. Default 1 hour (mm h-1)

        Returns
        -------
        et : float or numpy array
            evaporation rate at the time_domain. Default mm h-1
        '''
        # Calculate latent heat of vaporization
        lambda_ = Lib.latent_heat_of_vaporization(t_c) * 10e6  # J kg-1
        # Density of water
        rho_w = Lib.density_of_water(t_c)  # kg m-3
        et = flux / (rho_w * lambda_)  # m s-1
        # Convert instantaneous rate to the time_domain rate
        et = et * 1e3 * time_domain * 3600.  # mm
        return et
    
    @staticmethod
    def saturation_vapor_pressure(ta_c):
        """
        Calculate saturation vapor pressure (es) in kPa given temperature (T) in Celsius
        
        """
        # Calculate saturation vapor pressure (es) using Magnus-Tetens formula
        es = 0.6108 * np.exp((17.27 * ta_c) / (ta_c + 237.3))
        return es
    
    @staticmethod
    def actual_vapor_pressure(ta_c, rh):
        """
        Calculate actual vapor pressure (ea) in kPa given temperature (T) in Celsius
        and relative humidity (RH) as a percentage.
        """
        
        ea = (rh / 100) * Lib.saturation_vapor_pressure(ta_c)
        return ea
    
    @staticmethod
    def stephan_boltzmann(t_c, freq='h'):
        '''Calculates the total energy radiated by a blackbody.

        Parameters
        ----------
        t_c: float
            body temperature (Celsius)

        Returns
        -------
         : float
            Emitted radiance (MJ m-2)'''
        
        t_k = t_c + 273.15
            
        if freq == 'h':
            # Stephan Boltzmann constant (MJ m-2 K-4)
            SB = 2.04e-10
        elif freq == 'd':
            SB = 4.903e-9 # Stefan-Boltzmann constant in MJ/K4/m2/day
            
        return SB * (t_k ** 4)

    @staticmethod
    def estimate_r_li(ta_c, ts_c):
        """
        Calculate actual vapor pressure (e) given temperature (T) in Celsius
        and relative humidity (RH) as a percentage.
        """
        f = GeospatialDataToolkit.cloudness_factor(rso, rs, solar_alt_angle)
        r_li = f * GeospatialDataToolkit.stephan_boltzmann(ts_c)
        
        return r_li
    
    @staticmethod
    def cloudness_factor(rso, rs, solar_alt_angle):
        """
        Calculate actual vapor pressure (e) given temperature (T) in Celsius
        and relative humidity (RH) as a percentage.
        """
        
        if solar_alt_angle > 10:
            kt = rs / rso if rso > 0 else 0  # Avoid division by zero
            #kt = rs / rso
            f = (1.35 * kt) - 0.35
        
        elif solar_alt_angle <= 10:
            f = -1
        
        if f < 0:
            f = 0.595
        elif f > 1:
            f = 1
        
        return f
    
    @staticmethod
    def rso(ra, elevation):
        """
        Calculate clear-sky solar radiation based on extraterrestrial radiation and altitude.
        
        Parameters:
        - Ra: float, extraterrestrial radiation in MJ/m²/day
        - altitude: float, elevation above sea level in meters
        
        Returns:
        - Rso: float, clear-sky solar radiation in MJ/m²/day
        """
        rso = (0.75 + (2e-5 * elevation)) * ra
        return rso
    
    @staticmethod
    def inverse_relative_distance_factor(doy):
        """
        Calculate the inverse relative distance factor (dr) for Earth-Sun based on the day of the year.
        
        Parameters:
        - day_of_year: int, the day of the year (1 to 365 or 366 for a leap year)
        
        Returns:
        - dr: float, the inverse relative distance factor (dimensionless)
        
        Description:
        This function uses the cosine function to calculate the Earth-Sun distance variation effect.
        """
        return 1 + (0.033 * np.cos((2 * Lib.PI * doy) / 365))
    
    @staticmethod
    def net_longwave_radiation(ta_c, rh, rs, rso, epsilon=0.95):
        """
        Calculate the net longwave radiation, adjusting sky temperature based on empirical methods.
        
        Parameters:
        Ta (float): Air temperature in degrees Celsius.
        rh (float): Relative humidity in percent.
        Rs (float): Actual solar radiation in W/m2.
        Rso (float): Clear sky solar radiation in W/m2.
        epsilon (float): Emissivity of the surface (default 0.95).

        Returns:
        float: Net longwave radiation in W/m2.
        """
        sigma = 5.67e-8  # Stefan-Boltzmann constant in W/m2/K4
        ta_k = ta_c + 273.15  # Convert air temperature from Celsius to Kelvin

        # Calculate actual vapor pressure
        ea = 0.6108 * math.exp((17.27 * ta_c) / (ta_c + 237.3)) * (rh / 100)

        # Adjust sky temperature based on emissivity and air temperature
        sky_emissivity = 0.787 + 0.764 * math.log10(ea)
        Tsky_k = sky_emissivity * ta_k

        # Surface temperature approximated by air temperature (adjust if necessary)
        ts_k = ta_k
        
        # Estimate effective sky temperature
        # Clearness index
        kt = rs / rso if rso > 0 else 0  # Avoid division by zero
        # Calculate the net longwave radiation
        rn_l = sigma * (Tsky_k**4 - ts_k**4) * epsilon * ((1.35 * kt) - 0.35)

        return rn_l
    

    @staticmethod
    def get_elevation(lat, lon):
        """
        Returns the elevation (in meters) and latitude (in degrees) for a given set of coordinates.
        Uses the Open Elevation API (https://open-elevation.com/) to obtain the elevation information.
        """
        # 'https://api.open-elevation.com/api/v1/lookup?locations=10,10|20,20|41.161758,-8.583933'
        url = f'https://api.opentopodata.org/v1/aster30m?locations={lat},{lon}'
        response = requests.get(url)
        print(response.json())
        data = response.json()
        elevation = data['results'][0]['elevation']
        #latitude = data['results'][0]['latitude']
        return elevation
    
    @staticmethod
    def logarithmic_wind_profile(u, v, z_source=10, z_target=2, z0=0.03):
        """
        Calculate wind speed at 2 meters given wind speed components at 10 meters.
        
        Parameters:
        u10 (float): Wind speed component in the u-direction at 10 meters (m/s).
        v10 (float): Wind speed component in the v-direction at 10 meters (m/s).
        z_source (float): Source height where wind speed is measured (default is 10 meters).
        z_target (float): Target height where wind speed is to be estimated (default is 2 meters).
        z0 (float): Roughness length (default is 0.03 meters, adjust based on terrain).
                Typical values for roughness length:
                - Short grass: 0.01 - 0.03 meters
                - Tall grass: 0.1 - 0.2 meters
                - Crops: 0.05 - 0.25 meters (depending on height and density)
                - Shrubs: 0.1 - 0.5 meters
                - Forests: 1.0 - 2.0 meters (varies with tree height and density)
                - Urban areas: 0.5 - 1.5 meters (depends on building density and height)
        
        Returns:
        float: Estimated wind speed at 2 meters (m/s).
        """
        # Calculate wind speed at the source height (10 meters)
        wind_speed_source = math.sqrt(u**2 + v**2)
        
        # Calculate wind speed at the target height (2 meters) using the logarithmic wind profile
        wind_speed_target = wind_speed_source * (math.log(z_target / z0) / math.log(z_source / z0))
        
        return wind_speed_target
    
    @staticmethod    
    def relative_humidity_magnus(ta_c, dew_point_c):
        """
        Estimate relative humidity given dew point and air temperature using the Magnus formula.
        
        :param ta_c: Air temperature in Celsius
        :param dew_point_c: Dew point temperature in Celsius
        :return: Relative humidity in percentage
        """
        # Constants for the formula
        a = 17.62
        b = 243.12
        
        # Calculate alpha for dew point
        alpha_dp = (a * dew_point_c) / (b + dew_point_c)
        
        # Calculate alpha for temperature
        alpha_t = (a * ta_c) / (b + ta_c)
        
        # Calculate relative humidity
        rh = 100 * (math.exp(alpha_dp) / math.exp(alpha_t))
        
        return rh
    
    
    def relative_humidity_estimate_magnus(self, input_folder, output_folder,
                                     ta_prefix='temperature_2m_max', td_prefix='dewpoint_temperature_2m_max',
                                     rh_prefix='relative_humidity_2m_max', roi_bbox=None,
                                     start_date=None, end_date=None,
                                     a=17.62, b=243.12,
                                     unit='K',
                                     verbose=False):
        """
        Compute relative humidity from air temperature and dew point TIFFs using the Magnus formula.
        Parameters:
        - input_folder: str, path to the folder containing input TIFF files.
        - output_folder: str, path to the folder where output TIFFs will be saved.
        - ta_prefix: str, prefix for air temperature TIFF files.
        - td_prefix: str, prefix for dew point temperature TIFF files.
        - rh_prefix: str, prefix for output relative humidity TIFF files.
        - roi_bbox: tuple, bounding box for the region of interest (minx, miny, maxx, maxy).
        - start_date: str, start date in 'YYYY-MM-DD' format to filter input files.
        - end_date: str, end date in 'YYYY-MM-DD' format to filter input files.
        - a: float, constant for the Magnus formula (default 17.62).
        - b: float, constant for the Magnus formula (default 243.12).
        - unit: str, units for temperature ('C' for Celsius, 'K' for Kelvin).
        - verbose: bool, whether to print detailed processing information.
        Returns:
        - None, but saves relative humidity TIFF files in the output folder.
        """
        os.makedirs(output_folder, exist_ok=True)
        files_ta = sorted(glob(os.path.join(input_folder, f"{ta_prefix}_*.tif")))
        if not files_ta:
            print("❌ No input files found for air temperature.")
            return

        file_groups = []
        seen_dates = set()

        for path in files_ta:
            match = re.search(r'(\d{8})', os.path.basename(path))
            if not match:
                continue
            date_str = match.group(1)
            if date_str in seen_dates:
                continue
            date = pd.to_datetime(date_str, format="%Y%m%d")
            if start_date and date < pd.to_datetime(parse_date(start_date)):
                continue
            if end_date and date > pd.to_datetime(parse_date(end_date)):
                continue

            ta_path = os.path.join(input_folder, f"{ta_prefix}_{date_str}.tif")
            td_path = os.path.join(input_folder, f"{td_prefix}_{date_str}.tif")
            if os.path.exists(ta_path) and os.path.exists(td_path):
                file_groups.append((date_str, ta_path, td_path))
                seen_dates.add(date_str)
            else:
                if verbose:
                    print(f"❌ Missing files for {date_str}.")

        ti = time.time()
        skipped = 0
        for date_str, ta_path, td_path in tqdm(file_groups, desc="Relative Humidity Mapping", unit="day"):
            out_path = os.path.join(output_folder, f"{rh_prefix}_{date_str}.tif")
            if os.path.exists(out_path):
                skipped += 1
                if verbose:
                    print(f"⚠️ Skipping: {out_path}")
                continue

            try:
                with rasterio.open(ta_path) as src_ta, rasterio.open(td_path) as src_td:
                    ta_data = src_ta.read(1).astype("float32")
                    td_data = src_td.read(1).astype("float32")
                    meta = src_ta.meta.copy()

                    if roi_bbox:
                        # Use pixel-aligned window based on the source transform
                        window = src_ta.window(*roi_bbox)
                        window = window.round_offsets().round_lengths()

                        # Read cropped data
                        ta_data = src_ta.read(1, window=window).astype("float32")
                        td_data = src_td.read(1, window=window).astype("float32")

                        # Get aligned transform for that window
                        transform = src_ta.window_transform(window)

                        # Update metadata to match cropped output
                        meta.update({
                            "height": ta_data.shape[0],
                            "width": ta_data.shape[1],
                            "transform": transform
                        })

                
                # Convert temperatures from Kelvin to Celsius
                if unit == 'K':
                    ta_data -= 273.15
                    td_data -= 273.15
                
                # Apply Magnus formula
                alpha_dp = (a * td_data) / (b + td_data)
                alpha_t = (a * ta_data) / (b + ta_data)
                rh = 100 * (np.exp(alpha_dp) / np.exp(alpha_t))

                with rasterio.open(out_path, 'w', **meta) as dst:
                    dst.write(rh.astype("float32"), 1)

                if verbose:
                    print(f"✅ Saved: {out_path}")

            except Exception as e:
                print(f"❌ Failed on {date_str}: {e}")

        duration = time.time() - ti
        print(f"🕒 Duration: {duration:.2f} seconds")
        print(f"✅ Processed {len(file_groups) - skipped} rasters, skipped {skipped} existing files.")
        print(f"📁 Output saved in: {output_folder}")
    
    @staticmethod
    def slope_saturation_vapor_pressure_curve(t_c, method='standard'):
        """
        Calculate the slope of the saturation vapor pressure curve at a given temperature.
        
        Parameters:
        - temp_celsius: float, temperature in degrees Celsius
        
        Returns:
        - delta: float, slope of the vapor pressure curve in kPa/°C
        """
        # Calculate saturation vapor pressure at the current temperature
        es = GeospatialDataToolkit.saturation_vapor_pressure(t_c)
        
        # Calculate the slope of the vapor pressure curve
        delta = (4098 * es) / ((t_c + 237.3) ** 2)
        return delta
    
    @staticmethod
    def extraterrestrial_radiation_hourly_v3(doy, lat, lon, hod, tz_offset):
        """
        Calculate hourly extraterrestrial radiation (Ra) using Duffie and Beckman's approach and G_sc in MJ/m²/min.
        
        Parameters:
        - day_of_year: int, day of the year (1-365 or 366)
        - latitude: float, latitude in degrees
        - longitude: float, local longitude in degrees
        - standard_meridian: float, longitude of the standard time meridian for the time zone
        - local_time: float, local standard time hour (24-hour format)
        
        Returns:
        - Ra_h: float, hourly extraterrestrial radiation in MJ/m^2
        """
        # Convert latitude and longitude from degrees to radians
        latitude_rad = math.radians(lat)
        
        # Solar declination in radians
        delta = Lib.solar_declination(doy)
        
        # Adjust local time to solar time
        half_hour_before_solar_time = hod - 0.5 
        omega = Lib.solar_time_angle(Lib.solar_time(half_hour_before_solar_time, lat, lon, doy, tz_offset))
        
        # Calculate solar time angles at the start and end of the hour
        omega_1 = omega - (0.5 * (Lib.PI/12))
        omega_2 = omega + (0.5 * (Lib.PI/12))
        
        
        # Hourly extraterrestrial radiation calculation
        ra_h = ((60) / Lib.PI) * Lib.SOLAR_CONSTANT_MJ_MIN * Lib.inverse_relative_distance_factor(doy) * ((omega_2 - omega_1) * math.sin(latitude_rad) * math.sin(delta) + math.cos(latitude_rad) * math.cos(delta) * (math.sin(omega_2) - math.sin(omega_1)))
        
        return ra_h
    
    @staticmethod
    def time_zone_offset_current_location():
        local_time = datetime.now(pytz.timezone('UTC'))
        local_time = local_time.astimezone()  # Converts to local time zone
        offset = local_time.utcoffset().total_seconds() / 3600
        return offset
    
